def _apply_dark_title_bar(win):
    """Apply dark title bar to a Tk or Toplevel window on Windows."""
    if os.name != "nt":
        return
    try:
        from ctypes import windll, byref, c_int
        hwnd = windll.user32.GetParent(win.winfo_id())
        windll.dwmapi.DwmSetWindowAttribute(hwnd, 20, byref(c_int(1)), 4)
        windll.dwmapi.DwmSetWindowAttribute(hwnd, 35, byref(c_int(0x00120f0f)), 4)
    except Exception:
        pass

_apply_dark_title_bar(root)


def _dark_askquestion(title, message, yes_text="Yes", no_text="No"):
    """Show a dark-mode yes/no dialog on the main thread.

    Returns True if Yes was clicked, False otherwise.
    Must be called from the main (Tk) thread; uses root.wait_window() so the
    Tk event loop keeps running while the dialog is open.
    """
    _result = [None]

    _dlg = tk.Toplevel(root)
    _dlg.title(title)
    _dlg.configure(bg=C_BG)
    _dlg.resizable(False, False)
    _dlg.transient(root)
    _dlg.grab_set()
    _dlg.update_idletasks()
    _apply_dark_title_bar(_dlg)

    def _dismiss(val):
        _result[0] = val
        try:
            _dlg.destroy()
        except Exception:
            pass

    _dlg.protocol("WM_DELETE_WINDOW", lambda: _dismiss(False))
    _dlg.bind("<Escape>", lambda e: _dismiss(False))
    _dlg.bind("<Return>", lambda e: _dismiss(True))

    tk.Label(_dlg, text=message, bg=C_BG, fg=C_TEXT,
             font=("Segoe UI", 10), justify="left",
             wraplength=420).pack(fill="x", padx=20, pady=(14, 4))

    btn_row = tk.Frame(_dlg, bg=C_BG)
    btn_row.pack(padx=20, pady=(6, 14))
    tk.Button(btn_row, text=yes_text, bg="#3a6a3a", fg="#cccccc",
              relief="flat", font=("Segoe UI", 9, "bold"),
              cursor="hand2", command=lambda: _dismiss(True),
              width=10).pack(side="left", padx=(0, 8))
    tk.Button(btn_row, text=no_text, bg=C_BTN, fg=C_TEXT,
              relief="flat", font=("Segoe UI", 9),
              cursor="hand2", command=lambda: _dismiss(False),
              width=10).pack(side="left")

    _dlg.update_idletasks()
    # Center over root window, or screen center if root is minimized/off-screen
    _rx = root.winfo_rootx()
    _ry = root.winfo_rooty()
    if _rx <= 0 and _ry <= 0 and root.state() != "normal":
        _rx = root.winfo_screenwidth() // 2
        _ry = root.winfo_screenheight() // 2
    else:
        _rx += root.winfo_width() // 2
        _ry += root.winfo_height() // 2
    _dlg.geometry(f"+{_rx - _dlg.winfo_reqwidth() // 2}+{_ry - _dlg.winfo_reqheight() // 2}")

    root.wait_window(_dlg)
    return bool(_result[0])


def _dark_missing_channel_dialog(ch_name, expected_path):
    """Dark-mode dialog for a missing channel folder.

    Returns "remove", "locate", or "skip".
    Must be called from the main (Tk) thread.
    """
    _result = ["skip"]

    _dlg = tk.Toplevel(root)
    _dlg.title("Missing Channel Folder")
    _dlg.configure(bg=C_BG)
    _dlg.resizable(False, False)
    _dlg.transient(root)
    _dlg.grab_set()
    _dlg.update_idletasks()
    _apply_dark_title_bar(_dlg)

    def _dismiss(val):
        _result[0] = val
        try:
            _dlg.destroy()
        except Exception:
            pass

    _dlg.protocol("WM_DELETE_WINDOW", lambda: _dismiss("skip"))
    _dlg.bind("<Escape>", lambda e: _dismiss("skip"))

    tk.Label(_dlg, text=f"Cannot locate folder for \"{ch_name}\".",
             bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10, "bold"),
             justify="left").pack(fill="x", padx=20, pady=(16, 4))
    tk.Label(_dlg, text=f"Expected:\n{expected_path}",
             bg=C_BG, fg=C_DIM, font=("Segoe UI", 9),
             justify="left", wraplength=440).pack(fill="x", padx=20, pady=(0, 12))

    # Separator
    tk.Frame(_dlg, bg=C_BORDER, height=1).pack(fill="x", padx=20, pady=(0, 12))

    btn_row = tk.Frame(_dlg, bg=C_BG)
    btn_row.pack(padx=20, pady=(0, 16))

    tk.Button(btn_row, text="Remove Channel", bg=C_CANCEL, fg="#dddddd",
              relief="flat", font=("Segoe UI", 9, "bold"), cursor="hand2",
              command=lambda: _dismiss("remove"),
              padx=10, pady=4).pack(side="left", padx=(0, 8))

    tk.Button(btn_row, text="Locate Folder", bg=C_BTN, fg=C_TEXT,
              relief="flat", font=("Segoe UI", 9), cursor="hand2",
              command=lambda: _dismiss("locate"),
              padx=10, pady=4).pack(side="left", padx=(0, 8))

    tk.Button(btn_row, text="Skip", bg=C_BG, fg=C_DIM,
              relief="flat", font=("Segoe UI", 9), cursor="hand2",
              command=lambda: _dismiss("skip"),
              padx=10, pady=4).pack(side="left")

    _dlg.update_idletasks()
    _rx = root.winfo_rootx() + root.winfo_width() // 2
    _ry = root.winfo_rooty() + root.winfo_height() // 2
    _dlg.geometry(f"+{_rx - _dlg.winfo_reqwidth() // 2}+{_ry - _dlg.winfo_reqheight() // 2}")

    root.wait_window(_dlg)
    return _result[0]


def _entry(parent, maxlen=500, **kw):
    kw.setdefault("bg", C_INPUT)
    kw.setdefault("fg", C_TEXT)
    kw.setdefault("insertbackground", C_TEXT)
    kw.setdefault("relief", "flat")
    kw.setdefault("bd", 0)
    kw.setdefault("highlightthickness", 1)
    kw.setdefault("highlightbackground", C_BORDER_LT)
    kw.setdefault("highlightcolor", C_ACCENT)
    kw.setdefault("font", ("Segoe UI", 9))
    e = tk.Entry(parent, **kw)
    # Only add maxlen validation if caller didn't provide their own validator
    if maxlen and maxlen > 0 and 'validate' not in kw and 'validatecommand' not in kw:
        _vcmd = (e.register(lambda new_val, _ml=maxlen: len(new_val) <= _ml), '%P')
        e.config(validate="key", validatecommand=_vcmd)
    return e


def _placeholder(entry, text):
    _active = [True]

    def _show():
        if not entry.get():
            _active[0] = True
            entry.config(fg=C_DIM)
            entry.insert(0, text)

    entry.after(10, _show)

    def _on_focus_in(e):
        if _active[0]:
            _active[0] = False
            entry.delete(0, "end")
            entry.config(fg=C_TEXT)

    def _on_focus_out(e):
        content = entry.get()
        if not content:
            _active[0] = True
            entry.config(fg=C_DIM)
            entry.insert(0, text)
        elif _active[0] and content == text:
            # Placeholder is still showing — keep it dimmed
            entry.config(fg=C_DIM)
        else:
            _active[0] = False
            entry.config(fg=C_TEXT)

    _in_var_write = [False]

    def _on_var_write(*_args):
        """Re-show placeholder when StringVar is cleared programmatically."""
        if _in_var_write[0]:
            return
        _in_var_write[0] = True
        try:
            content = entry.get()
            if not content and str(entry.focus_get()) != str(entry):
                _active[0] = True
                entry.config(fg=C_DIM)
                entry.insert(0, text)
            elif content and content != text:
                _active[0] = False
                entry.config(fg=C_TEXT)
        except Exception:
            pass
        finally:
            _in_var_write[0] = False

    entry._ph_text = text
    entry._ph_active = _active

    entry.bind("<FocusIn>", _on_focus_in)
    entry.bind("<FocusOut>", _on_focus_out)

    # Watch the linked StringVar for programmatic changes
    try:
        _sv_name = entry.cget("textvariable")
        if _sv_name:
            entry.tk.call("trace", "add", "variable", _sv_name, "write",
                          entry.register(lambda *a: entry.after(1, _on_var_write)))
    except Exception:
        pass


def _real_get(entry):
    if hasattr(entry, "_ph_active") and entry._ph_active[0]:
        if entry.get() == entry._ph_text:
            return ""
        else:
            entry._ph_active[0] = False
            entry.config(fg=C_TEXT)
    return entry.get()


def _digits_only(P):
    """Validate command: only allow empty string or digits."""
    return P == "" or P.isdigit()


def _parse_duration(raw):
    """Strip non-digit chars and return int. Returns 0 for empty/invalid."""
    if not raw:
        return 0
    digits = re.sub(r'\D', '', str(raw).strip())
    return int(digits) if digits else 0


def _combo(parent, **kw):
    return ttk.Combobox(parent, **kw)


