def browse_vid_out():
    current_dir = videodir_var.get().strip()
    init_dir = current_dir if os.path.exists(current_dir) else BASE_DIR
    d = filedialog.askdirectory(initialdir=init_dir)
    if d:
        videodir_var.set(d)
        with config_lock:
            config["video_out_dir"] = d
        save_config(config)


