_CHAN_COL_LABELS = {
    "folder": "Folder",
    "res": "Res",
    "min": "Min",
    "max": "Max",
    "transcribed": "Transcribed",
    "metadata": "Metadata",
    "last_sync": "Last Sync",
    "num_vids": "# Vids",
    "size_on_disk": "Size",
    "url": "URL"
}
_chan_sort_state = {"col": None, "reverse": False}


def _sort_chan_tree(col, reverse):
    if col == "url": return
    _chan_sort_state["col"] = col
    _chan_sort_state["reverse"] = reverse
    l = [(settings_chan_tree.set(k, col), k) for k in settings_chan_tree.get_children('')]

    if col in ("min", "max"):
        def parse_val(s):
            if not s or s == "—": return 0
            if s.endswith("s"): return int(s[:-1])
            if s.endswith("m"): return int(s[:-1]) * 60
            return 0

        l.sort(key=lambda t: parse_val(t[0]), reverse=reverse)
    elif col == "res":
        def parse_res(s):
            if not s: return 0
            if s.endswith("p"): return int(s[:-1])
            if s == "best": return 9999
            try:
                return int(s)
            except Exception:
                return 0

        l.sort(key=lambda t: parse_res(t[0]), reverse=reverse)
    elif col == "last_sync":
        # Batch-read all channel last_sync values under a single lock acquisition
        with config_lock:
            _url_to_ls = {c["url"]: c.get("last_sync", "") for c in config.get("channels", [])}

        def get_ts(iid):
            url = settings_chan_tree.set(iid, "url")
            ls = _url_to_ls.get(url, "")
            if not ls:
                return 0
            try:
                return time.mktime(datetime.strptime(ls, "%Y-%m-%d %H:%M").timetuple())
            except Exception:
                return 0

        l.sort(key=lambda t: get_ts(t[1]), reverse=reverse)
    elif col == "num_vids":
        def parse_num(s):
            try:
                return int(s.replace(",", "")) if s and s != "—" else 0
            except Exception:
                return 0
        l.sort(key=lambda t: parse_num(t[0]), reverse=reverse)
    elif col == "size_on_disk":
        def parse_size(s):
            if not s or s == "—": return 0
            _units = {"B": 1, "KB": 1024, "MB": 1024**2, "GB": 1024**3, "TB": 1024**4}
            try:
                parts = s.split()
                return float(parts[0]) * _units.get(parts[1], 1)
            except Exception:
                return 0
        l.sort(key=lambda t: parse_size(t[0]), reverse=reverse)
    else:
        l.sort(key=lambda t: t[0].lower(), reverse=reverse)

    for index, (val, k) in enumerate(l):
        settings_chan_tree.move(k, '', index)
        settings_chan_tree.item(k, tags=("odd" if index % 2 else "even",))

    settings_chan_tree.heading(col, command=lambda: _sort_chan_tree(col, not reverse))

    arrow = " ▲" if not reverse else " ▼"
    for c, base_label in _CHAN_COL_LABELS.items():
        if c == "url": continue
        anchor = "w"
        if c == col:
            settings_chan_tree.heading(c, text=base_label + arrow, anchor=anchor)
        else:
            settings_chan_tree.heading(c, text=base_label, anchor=anchor)


