_chan_tree_dirty = False  # Flag: tree needs refresh next time Subs tab is shown


def refresh_channel_dropdowns():
    global _chan_tree_dirty
    with config_lock:
        # Shallow dict copy is sufficient — channel values are all scalars (str/int/bool)
        sorted_channels = sorted([dict(c) for c in config.get("channels", [])], key=lambda c: c.get("name", "").lower())
        names = [c.get("name", "") for c in sorted_channels]
    # config_lock released — all UI work below uses the snapshot
    chan_dropdown["values"] = names

    # If the Subs tab isn't visible and tree is already populated,
    # just mark dirty and skip the heavy tree update
    try:
        if settings_chan_tree.get_children('') and notebook.select() != str(tab_settings):
            _chan_tree_dirty = True
            return
    except Exception:
        pass

    _chan_tree_dirty = False
    _grand_total_bytes = 0

    # Batch lock acquisitions outside the per-channel loop to avoid O(N) lock overhead
    with _gpu_queue_lock:
        _gpu_queued_urls = {q.get("ch_url") for q in _gpu_queue if q["type"] in ("transcribe", "mt")}
    with _transcribe_queue_lock:
        _tq_urls = {q[1] for q in _transcribe_queue}
    with _disk_cache_lock:
        _disk_cache_snap = dict(_disk_cache)
    with _metadata_queue_lock:
        _mq_ch_names = {q["ch_name"] for q in _metadata_queue}

    # Build new row data
    new_rows = []
    for i, c in enumerate(sorted_channels):
        res = c.get("resolution", CHANNEL_DEFAULTS["resolution"])
        display_res = f"{res}p" if res.isdigit() else ("Audio" if res == "audio" else res)
        dur = c.get("min_duration", 0)
        dur_str = f"{dur // 60}m" if dur else "—"
        maxdur = c.get("max_duration", 0)
        maxdur_m = maxdur // 60 if maxdur else 0
        maxdur_str = f"{maxdur_m}m" if maxdur_m else "—"
        name_col = c['name']

        ls_raw = c.get("last_sync", "")
        ls_str = "Never"
        if ls_raw:
            try:
                dt = datetime.strptime(ls_raw, "%Y-%m-%d %H:%M")
                diff_mins = int((datetime.now() - dt).total_seconds() // 60)
                if diff_mins < 1:
                    ls_str = "just now"
                elif diff_mins < 60:
                    ls_str = f"{diff_mins}m ago"
                elif diff_mins < 1440:
                    ls_str = f"{diff_mins // 60}hr ago"
                elif diff_mins < 43200:
                    ls_str = f"{diff_mins // 1440}d ago"
                else:
                    ls_str = f"{diff_mins // 43200}mo ago"
            except Exception:
                ls_str = ls_raw[:12]

        # Compress column — checkmark if any compression settings enabled
        compress_str = "✓" if c.get("compress_enabled", False) and c.get("compress_level", "") in _QUALITY_OPTIONS else "—"

        # Transcribed status column — only show Running/Queued for transcription tasks, not encode
        auto_t = c.get("auto_transcribe", False)
        ch_url_t = c.get("url", "")
        t_complete = c.get("transcription_complete", False)
        _is_queued_t = ch_url_t in _gpu_queued_urls
        _is_running_t = False
        # Check GPU Tasks queue (already batched above)
        if _gpu_running and _gpu_current.get("ch_url") == ch_url_t:
            _cur_item = _gpu_current_item
            if _cur_item and _cur_item.get("type") in ("transcribe", "mt"):
                _is_running_t = True
        # Check standalone transcription (non-GPU path) — skip during sync/reorg/redownload
        # since _current_job["url"] is shared and may belong to the sync/redownload, not transcription
        if not _is_running_t and _transcribe_running and not _sync_running and not _reorg_running and not _redownload_running and _current_job.get("url") == ch_url_t:
            _is_running_t = True
        if not _is_queued_t:
            _is_queued_t = ch_url_t in _tq_urls
        t_pending = c.get("transcription_pending", 0)
        if _is_running_t:
            trans_str = "Running"
        elif _is_queued_t:
            trans_str = "Queued"
        elif t_complete and t_pending > 0:
            trans_str = f"✓ -{t_pending}"
        elif t_complete:
            trans_str = "✓ Done" if auto_t else "✓"
        elif auto_t:
            trans_str = "✓ Auto"
        else:
            trans_str = "—"

        # Metadata status column
        _ch_name_m = c.get("name", "")
        auto_m = c.get("auto_metadata", False)
        _is_running_m = _metadata_running and _current_job.get("_metadata_key", "").startswith(f"metadata:{_ch_name_m}:")
        _is_queued_m = _ch_name_m in _mq_ch_names
        _has_meta = _disk_cache_snap.get(ch_url_t, {}).get("has_metadata", False) if ch_url_t else False
        if _is_running_m:
            meta_str = "Running"
        elif _is_queued_m:
            meta_str = "Queued"
        elif _has_meta:
            meta_str = "✓ Done" if auto_m else "✓"
        elif auto_m:
            meta_str = "✓ Auto"
        else:
            meta_str = "—"

        # Look up # of vids and size on disk from the cache (populated by
        # background scan after startup, or by per-channel rescan after actions).
        # Shows "—" when no entry exists yet (scan still pending).
        _url_key = c.get("url", "")
        _cached = _disk_cache_snap.get(_url_key)
        if _cached:
            _num_vids = _cached["num_vids"]
            _ch_bytes = _cached["size_bytes"]
        else:
            _num_vids = 0
            _ch_bytes = 0
        _grand_total_bytes += _ch_bytes
        num_vids_str = f"{_num_vids:,}" if _num_vids else "—"
        size_str = _format_bytes(_ch_bytes)

        new_rows.append((name_col, display_res, dur_str, maxdur_str, compress_str, trans_str, meta_str, ls_str, num_vids_str, size_str, c['url']))

    # Incremental update: reuse existing tree items instead of delete-all + reinsert
    existing_iids = settings_chan_tree.get_children('')
    n_existing = len(existing_iids)
    n_new = len(new_rows)

    # Update rows that exist in both old and new
    for i in range(min(n_existing, n_new)):
        tag = "odd" if i % 2 else "even"
        settings_chan_tree.item(existing_iids[i], values=new_rows[i], tags=(tag,))

    # If we have more new rows than existing, insert the extras
    if n_new > n_existing:
        for i in range(n_existing, n_new):
            tag = "odd" if i % 2 else "even"
            settings_chan_tree.insert("", tk.END, values=new_rows[i], tags=(tag,))

    # If we have fewer new rows than existing, delete the extras
    elif n_existing > n_new:
        for iid in existing_iids[n_new:]:
            settings_chan_tree.delete(iid)

    # Update total size on disk label
    _total_str = f"Total: {_format_bytes(_grand_total_bytes)}" if _grand_total_bytes > 0 else ""
    _total_disk_var.set(_total_str)

    if _chan_sort_state["col"]:
        _sort_chan_tree(_chan_sort_state["col"], _chan_sort_state["reverse"])


_editing_channel = {"name": None}


def _set_edit_mode(ch):
    _editing_channel["name"] = ch["name"]
    _editing_channel["url"] = ch["url"]
    new_name_var.set(ch.get("folder_override", ch["name"]))
    new_url_var.set(ch["url"])
    new_res_var.set(ch.get("resolution", "720"))
    _min = ch.get("min_duration", 0)
    new_dur_var.set(str(_min // 60) if _min else "")
    _mx_secs = ch.get("max_duration", 0)
    new_maxdur_var.set(str(_mx_secs // 60) if _mx_secs else "")
    _m = ch.get("mode", "full")
    new_mode_var.set(_m)
    new_all_var.set(_m == "full")
    new_fromdate_var.set(_m == "date")
    stored_date = ch.get("date_after", "")
    if stored_date and len(stored_date) == 8:
        date_year_var.set(stored_date[:4])
        date_month_var.set(stored_date[4:6])
        date_day_var.set(stored_date[6:])
    else:
        date_year_var.set("")
        date_month_var.set("")
        date_day_var.set("")
    _toggle_date_entry()
    _sy = ch.get("split_years", False)
    _sm = ch.get("split_months", False)
    if _sy and _sm:
        new_folder_org_var.set("Years/Months")
    elif _sy:
        new_folder_org_var.set("Years")
    else:
        new_folder_org_var.set("None")
    new_auto_transcribe_var.set(ch.get("auto_transcribe", False))
    new_auto_metadata_var.set(ch.get("auto_metadata", False))
    new_compress_var.set(ch.get("compress_enabled", False))
    _cr = ch.get("compress_output_res", "")
    new_compress_res_var.set(f"{_cr}p" if _cr else "Original")  # set Res first → triggers quality combo enable
    _raw_level = ch.get("compress_level", "")
    new_compress_level_var.set(_LEVEL_MIGRATION.get(_raw_level, _raw_level))
    new_compress_batch_var.set(str(ch.get("compress_batch_size", 20)))
    add_channel_btn.config(text="💾 Update channel", state="normal", style="Warn.TButton")
    add_outer.config(text="Edit channel")
    _set_add_details_visible(True)
    cancel_edit_btn.pack(side="left", padx=(0, 8))
    # Show "Continue Redownload" button if there's an incomplete redownload for this channel
    _pending_res = _has_pending_redownload(ch.get("url", ""))
    if _pending_res:
        _pr_disp = "Best" if _pending_res == "best" else f"{_pending_res}p"
        continue_redownload_btn.config(text=f"↻ Continue Redownload ({_pr_disp})")
        continue_redownload_btn.pack(side="left", padx=(0, 8))
    else:
        continue_redownload_btn.pack_forget()
    reorg_done_label.pack_forget()

    new_name_entry.event_generate("<FocusOut>")
    _new_url_entry.event_generate("<FocusOut>")
    if ch.get("mode") != "date":
        _date_year_entry.event_generate("<FocusOut>")
        _date_month_entry.event_generate("<FocusOut>")
        _date_day_entry.event_generate("<FocusOut>")

    new_name_entry.focus_set()


def _clear_edit_mode():
    _editing_channel["name"] = None
    _editing_channel["url"] = None
    new_name_var.set("")
    new_url_var.set("")
    new_res_var.set("720")
    new_dur_var.set("")
    new_maxdur_var.set("")
    new_mode_var.set("sub")
    new_all_var.set(False)
    new_fromdate_var.set(False)
    date_year_var.set("")
    date_month_var.set("")
    date_day_var.set("")
    _toggle_date_entry()
    new_folder_org_var.set("None")
    new_auto_transcribe_var.set(False)
    new_auto_metadata_var.set(False)
    new_compress_var.set(False)
    new_compress_level_var.set("")
    new_compress_res_var.set("")
    new_compress_batch_var.set("20")
    add_channel_btn.config(text="Add channel", style="TButton", state="disabled")
    add_outer.config(text="Add channel")
    _set_add_details_visible(False)
    cancel_edit_btn.pack_forget()
    continue_redownload_btn.pack_forget()
    try:
        reorg_done_label.pack_forget()
    except Exception:
        pass

    new_name_entry.event_generate("<FocusOut>")
    _new_url_entry.event_generate("<FocusOut>")
    _date_year_entry.event_generate("<FocusOut>")
    _date_month_entry.event_generate("<FocusOut>")
    _date_day_entry.event_generate("<FocusOut>")


def on_channel_double_click(event):
    if settings_chan_tree.identify_region(event.x, event.y) != "cell":
        return
    sel = settings_chan_tree.selection()
    if not sel: return
    target_url = settings_chan_tree.set(sel[0], "url")
    with config_lock:
        channels = config.get("channels", [])
        for ch in channels:
            if ch["url"] == target_url:
                _set_edit_mode(copy.deepcopy(ch))
                break


settings_chan_tree.bind("<Double-Button-1>", on_channel_double_click)


