def _queue_pending_transcriptions():
    """Queue all channels with ✓ -X (new unprocessed videos) for GPU transcription."""
    with config_lock:
        out_dir = config.get("output_dir", "")
        channels = sorted(config.get("channels", []),
                          key=lambda c: c.get("name", "").lower())
    added = 0
    for ch in channels:
        if ch.get("transcription_complete", False) and ch.get("transcription_pending", 0) > 0:
            ch_name = ch.get("name", "")
            ch_url = ch.get("url", "")
            folder = os.path.join(out_dir, sanitize_folder(ch.get("folder_override", "") or ch_name))
            sy = ch.get("split_years", False)
            sm = ch.get("split_months", False)
            _add_to_gpu_queue({
                "type": "transcribe", "ch_name": ch_name, "ch_url": ch_url,
                "folder": folder, "split_years": sy, "split_months": sm,
                "combined": not sy
            })
            added += 1
    if added:
        log(f"  ↺ Queued {added} channel(s) with new videos for transcription.\n", "simpleline_green")
    else:
        log(f"  No channels with pending transcriptions found.\n", "dim")


def _queue_all_transcriptions():
    """Queue ALL channels for GPU transcription (right-click action)."""
    with config_lock:
        channels = copy.deepcopy(sorted(config.get("channels", []),
                          key=lambda c: c.get("name", "").lower()))
        out_dir = config.get("output_dir", "")
    n = len(channels)
    if n == 0:
        log(f"  No channels found.\n", "dim")
        return
    if not _dark_askquestion(
            "Queue All",
            f"Add ALL {n} channel(s) to the transcription queue?\n\n"
            f"This may take a long time for large libraries."):
        return
    added = 0
    for ch in channels:
        ch_name = ch.get("name", "")
        ch_url = ch.get("url", "")
        folder = os.path.join(out_dir, sanitize_folder(ch.get("folder_override", "") or ch_name))
        sy = ch.get("split_years", False)
        sm = ch.get("split_months", False)
        _add_to_gpu_queue({
            "type": "transcribe", "ch_name": ch_name, "ch_url": ch_url,
            "folder": folder, "split_years": sy, "split_months": sm,
            "combined": not sy
        })
        added += 1
    if added:
        log(f"  ↺ Queued ALL {added} channel(s) for transcription.\n", "simpleline_green")
    else:
        log(f"  No channels found.\n", "dim")


def _chan_ctx_transcribe():
    """Right-click → Transcribe channel. Shows dialog for org mode, then starts transcription."""
    ch = _ctx_channel["ch"]
    if not ch:
        return
    folder = _chan_ctx_get_folder()
    if not folder:
        return
    ch_name = ch["name"]
    ch_url = ch["url"]
    sy = ch.get("split_years", False)
    sm = ch.get("split_months", False)

    if not sy:
        # Unorganized — no dialog needed, just one big file
        _add_to_gpu_queue({"type": "transcribe", "ch_name": ch_name, "ch_url": ch_url,
                           "folder": folder, "split_years": False, "split_months": False, "combined": True})
        return

    # Show dialog: Combined vs Follow organization
    dlg = tk.Toplevel(root)
    dlg.title("Transcribe Channel")
    dlg.configure(bg=C_BG)
    dlg.resizable(False, False)
    dlg.transient(root)
    dlg.grab_set()
    dlg.update_idletasks()
    _apply_dark_title_bar(dlg)

    # Center on parent
    dlg.update_idletasks()
    pw, ph = root.winfo_width(), root.winfo_height()
    px, py = root.winfo_x(), root.winfo_y()
    dw, dh = 380, 200
    dlg.geometry(f"{dw}x{dh}+{px + (pw - dw) // 2}+{py + (ph - dh) // 2}")

    tk.Label(dlg, text=f"Transcribe: {ch_name}", bg=C_BG, fg=C_TEXT,
             font=("Segoe UI Semibold", 11)).pack(pady=(16, 4))
    tk.Label(dlg, text="Where should transcript files be placed?", bg=C_BG, fg=C_DIM,
             font=("Segoe UI", 9)).pack(pady=(0, 12))

    choice_var = tk.StringVar(value="follow")
    org_desc = "Year" if sy and not sm else "Year/Month"

    rb_frame = tk.Frame(dlg, bg=C_BG)
    rb_frame.pack(padx=20, anchor="w")
    tk.Radiobutton(rb_frame, text=f"Follow organization ({org_desc} folders)",
                   variable=choice_var, value="follow",
                   bg=C_BG, fg=C_TEXT, selectcolor=C_RAISED, activebackground=C_BG,
                   activeforeground=C_TEXT, font=("Segoe UI", 10)).pack(anchor="w", pady=2)
    tk.Radiobutton(rb_frame, text="Combined (one file for entire channel)",
                   variable=choice_var, value="combined",
                   bg=C_BG, fg=C_TEXT, selectcolor=C_RAISED, activebackground=C_BG,
                   activeforeground=C_TEXT, font=("Segoe UI", 10)).pack(anchor="w", pady=2)

    btn_frame = tk.Frame(dlg, bg=C_BG)
    btn_frame.pack(pady=(16, 0))

    def _on_ok():
        combined = choice_var.get() == "combined"
        dlg.destroy()
        _add_to_gpu_queue({"type": "transcribe", "ch_name": ch_name, "ch_url": ch_url,
                           "folder": folder, "split_years": sy, "split_months": sm, "combined": combined})

    ttk.Button(btn_frame, text="Start", command=_on_ok, style="Sync.TButton").pack(side="left", padx=4)
    ttk.Button(btn_frame, text="Cancel", command=dlg.destroy).pack(side="left", padx=4)

    dlg.bind("<Return>", lambda e: _on_ok())
    dlg.bind("<Escape>", lambda e: dlg.destroy())


_chan_ctx_menu.add_command(label="Transcribe Channel", command=_chan_ctx_transcribe)


def _chan_ctx_download_metadata():
    """Right-click → Download Metadata for the selected channel."""
    ch = _ctx_channel["ch"]
    if not ch:
        return
    folder = _chan_ctx_get_folder()
    if not folder:
        return
    ch_name = ch["name"]
    ch_url = ch["url"]
    sy = ch.get("split_years", False)
    sm = ch.get("split_months", False)

    # Check if metadata already exists — show choice dialog if so
    refresh = False
    tp = _tp_panel_ref[0]
    if tp:
        try:
            has_existing = False
            if sy:
                # Split channel — check if any per-year metadata exists
                for _yd in os.listdir(folder):
                    _yp = os.path.join(folder, _yd)
                    if os.path.isdir(_yp) and _yd.isdigit():
                        _mp, _ = tp._get_metadata_jsonl_path(
                            ch_name, folder, sy, sm, year=int(_yd), month=None)
                        if os.path.isfile(_mp):
                            has_existing = True
                            break
            else:
                meta_path, _ = tp._get_metadata_jsonl_path(
                    ch_name, folder, sy, sm, year=None, month=None)
                has_existing = bool(tp._read_metadata_jsonl(meta_path))
            if has_existing:
                choice = tp._metadata_choice_dialog(ch_name)
                if choice == "cancel":
                    return
                refresh = (choice == "refresh")
        except Exception:
            pass

    _add_to_metadata_queue(ch_name, ch_url, folder, sy, sm, None, None, ch_name, refresh=refresh)


_chan_ctx_menu.add_command(label="Download Metadata", command=_chan_ctx_download_metadata)

_chan_ctx_menu.add_separator()


def _chan_ctx_remove():
    ch = _ctx_channel["ch"]
    if not ch:
        return
    # Select the channel in the tree so remove_channel() can find it
    # (remove_channel has its own confirmation dialog)
    for item in settings_chan_tree.get_children():
        if settings_chan_tree.set(item, "url") == ch["url"]:
            settings_chan_tree.selection_set(item)
            on_chan_list_select(None)
            break
    remove_channel()


_chan_ctx_menu.add_command(label="Remove this channel", command=_chan_ctx_remove)

# Named indices for context menu items (update if menu order changes)
_CTX_IDX_SYNC = 0
_CTX_IDX_ORG_YEAR = 5
_CTX_IDX_ORG_MONTH = 6
_CTX_IDX_UNORG = 7
_CTX_IDX_REAPPLY = 9
_CTX_IDX_TRANSCRIBE = 11
_CTX_IDX_METADATA = 12


def _chan_ctx_show(event):
    row = settings_chan_tree.identify_row(event.y)
    if row:
        settings_chan_tree.selection_set(row)
        on_chan_list_select(None)
        target_url = settings_chan_tree.set(row, "url")
        with config_lock:
            for c in config.get("channels", []):
                if c["url"] == target_url:
                    _ctx_channel["ch"] = copy.deepcopy(c)
                    break
    else:
        _ctx_channel["ch"] = None

    if _ctx_channel["ch"]:
        ch = _ctx_channel["ch"]
        sy = ch.get("split_years", False)
        sm = ch.get("split_months", False)

        # Menu indices: 0=Sync, 1=Edit, 2=Open folder, 3=Open URL, 4=separator,
        #               5=Org Year, 6=Org Year/Month, 7=Un-Organize, 8=separator, 9=Re-apply,
        #               10=separator, 11=Transcribe, 12=Download Metadata, 13=separator, 14=Remove
        # Dynamic label: show "Add to Sync List" when a sync/reorg is running
        if _sync_running or _reorg_running or _redownload_running:
            # Check if this channel is already queued or actively syncing
            _ch_url = ch.get("url", "")
            with _sync_queue_lock:
                _already_queued = any(q["url"] == _ch_url for q in _sync_queue)
            _already_syncing = _current_job.get("url") == _ch_url
            if _already_queued or _already_syncing:
                _chan_ctx_menu.entryconfig(_CTX_IDX_SYNC, label="Already in Sync List",
                                          state="disabled",
                                          command=lambda: None)
            else:
                _chan_ctx_menu.entryconfig(_CTX_IDX_SYNC, label="Add to Sync List",
                                          state="normal", foreground=C_TEXT,
                                          command=_chan_ctx_sync_now)
        else:
            _chan_ctx_menu.entryconfig(_CTX_IDX_SYNC, label="Sync now",
                                      state="normal", foreground=C_TEXT,
                                      command=_chan_ctx_sync_now)

        # Dim the option matching the channel's current organization mode;
        # all others stay enabled (they will queue if a sync/reorg is running)
        for idx, is_current in ((_CTX_IDX_ORG_YEAR, sy and not sm), (_CTX_IDX_ORG_MONTH, sy and sm), (_CTX_IDX_UNORG, not sy and not sm)):
            if is_current:
                _chan_ctx_menu.entryconfig(idx, foreground=C_DIM, state="normal")
            else:
                _chan_ctx_menu.entryconfig(idx, foreground=C_TEXT, state="normal")
        _chan_ctx_menu.entryconfig(_CTX_IDX_REAPPLY, foreground=C_TEXT, state="normal")

        # Transcribe menu item (index 11) — now routes to GPU Tasks
        _ch_url_t = ch.get("url", "")
        # Check if this channel has any downloaded videos — use disk cache (populated at startup)
        # to avoid blocking the UI thread with os.walk on a slow drive.
        with _disk_cache_lock:
            _cached_vids = _disk_cache.get(_ch_url_t, {}).get("num_vids", 0)
        _has_videos = _cached_vids > 0
        # Check if this channel is already being transcribed via GPU Tasks
        _is_active_gpu = _gpu_running and _gpu_current.get("label") and _ch_url_t and _ch_url_t == _gpu_current.get("ch_url")
        with _gpu_queue_lock:
            _already_in_gpu = any(q.get("ch_url") == _ch_url_t for q in _gpu_queue)
            _gpu_has_items = bool(_gpu_queue)
        if not _has_videos:
            _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, label="No Videos — Sync First",
                                      state="disabled",
                                      command=lambda: None)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, activeforeground=C_DIM)
            except Exception:
                pass
        elif _is_active_gpu:
            _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, label="Channel Transcribing...",
                                      state="normal", foreground=C_DIM,
                                      command=lambda: None)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, activeforeground=C_DIM)
            except Exception:
                pass
        elif _already_in_gpu:
            _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, label="Already queued",
                                      state="normal", foreground=C_DIM,
                                      command=lambda: None)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, activeforeground=C_DIM)
            except Exception:
                pass
        else:
            _t_label = "Add Transc. to GPU Tasks" if (_gpu_has_items or _gpu_running) else "Transcribe Channel"
            _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, label=_t_label,
                                      state="normal", foreground=C_TEXT,
                                      command=_chan_ctx_transcribe)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_TRANSCRIBE, activeforeground=C_TEXT)
            except Exception:
                pass

        # Download Metadata menu item (index 12)
        _ch_name_m = ch.get("name", "")
        _is_running_meta = _metadata_running and _current_job.get("_metadata_key", "").startswith(f"metadata:{_ch_name_m}:")
        with _metadata_queue_lock:
            _already_queued_meta = any(q["ch_name"] == _ch_name_m for q in _metadata_queue)
        if _is_running_meta:
            _chan_ctx_menu.entryconfig(_CTX_IDX_METADATA, label="Downloading Metadata...",
                                      state="normal", foreground=C_DIM,
                                      command=lambda: None)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_METADATA, activeforeground=C_DIM)
            except Exception:
                pass
        elif _already_queued_meta:
            _chan_ctx_menu.entryconfig(_CTX_IDX_METADATA, label="Already queued",
                                      state="normal", foreground=C_DIM,
                                      command=lambda: None)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_METADATA, activeforeground=C_DIM)
            except Exception:
                pass
        else:
            _chan_ctx_menu.entryconfig(_CTX_IDX_METADATA, label="Download Metadata",
                                      state="normal", foreground=C_TEXT,
                                      command=_chan_ctx_download_metadata)
            try:
                _chan_ctx_menu.entryconfig(_CTX_IDX_METADATA, activeforeground=C_TEXT)
            except Exception:
                pass

        try:
            _chan_ctx_menu.tk_popup(event.x_root, event.y_root)
        finally:
            _chan_ctx_menu.grab_release()


settings_chan_tree.bind("<Button-3>", _chan_ctx_show)


