def _parse_date_input(raw):
    raw = raw.strip()
    if re.fullmatch(r'\d{8}', raw):
        return raw
    m = re.fullmatch(r'(\d{4})-(\d{2})-(\d{2})', raw)
    if m:
        return m.group(1) + m.group(2) + m.group(3)
    return None


def add_channel():
    url_error_var.set("")  # clear any stale validation error
    name = sanitize_folder(_real_get(new_name_entry).strip())
    url = _real_get(_new_url_entry).strip()
    if not name or not url: return

    dur_val = _parse_duration(new_dur_var.get()) * 60
    maxdur_val = _parse_duration(new_maxdur_var.get()) * 60

    mode = new_mode_var.get()
    date_after = ""
    if mode == "date":
        y = _real_get(_date_year_entry).strip()
        m = _real_get(_date_month_entry).strip()
        d = _real_get(_date_day_entry).strip()
        if not y or not re.fullmatch(r'\d{4}', y):
            url_error_var.set("Invalid date — Year is required (YYYY)")
            return
        m = m.zfill(2) if m else "01"
        d = d.zfill(2) if d else "01"
        if not re.fullmatch(r'\d{2}', m) or not re.fullmatch(r'\d{2}', d):
            url_error_var.set("Invalid date format")
            return
        date_after = y + m + d
        url_error_var.set("")

    editing_url = _editing_channel.get("url")

    # Capture old/new split settings before saving (for auto-reorganize on edit)
    old_split_years = False
    old_split_months = False
    new_years = new_split_years_var.get()
    new_months = new_split_months_var.get()
    # Track old/new resolution for redownload dialog
    # Capture new_res_val here — _clear_edit_mode() resets new_res_var before the dialog runs
    old_res = ""
    new_res_val = new_res_var.get()
    new_compress_batch_val = new_compress_batch_var.get()
    _new_compress = None  # sentinel — set inside the editing loop if channel found

    with config_lock:
        channels = config.setdefault("channels", [])

        if editing_url:
            for ch in channels:
                if ch["url"] == editing_url:
                    if name != ch["name"] and any(c["name"] == name for c in channels):
                        log(f"ERROR: A channel named '{name}' already exists.\n", "red")
                        return
                    if url != ch.get("url", "") and any(c["url"] == url and c["url"] != editing_url for c in channels):
                        log(f"ERROR: A channel with this URL already exists.\n", "red")
                        return

                    old_split_years = ch.get("split_years", False)
                    old_split_months = ch.get("split_months", False)
                    old_res = ch.get("resolution", "")

                    old_mode = ch.get("mode")
                    old_date_after = ch.get("date_after", "")
                    if old_mode != mode or old_date_after != date_after:
                        ch["initialized"] = False
                        ch["sync_complete"] = False
                        ch.pop("init_batch_after", None)
                        ch.pop("init_complete", None)

                        # If date filter was removed/changed, un-archive the previously
                        # filtered IDs so they can be downloaded on next sync
                        if old_mode == "date" and ch.get("date_archived_ids"):
                            _remove_ids_from_archive(ch["date_archived_ids"])
                            removed_count = len(ch["date_archived_ids"])
                            ch["date_archived_ids"] = []
                            log(f"  ✓ Removed {removed_count:,} date-filtered IDs from archive "
                                f"— they will be re-evaluated on next sync.\n", "green")

                    ch["folder_override"] = sanitize_folder(name)
                    ch["name"] = name
                    ch["url"] = url
                    ch["resolution"] = new_res_var.get()
                    ch["min_duration"] = dur_val
                    ch["max_duration"] = maxdur_val
                    ch["mode"] = mode
                    ch["date_after"] = date_after
                    ch["split_years"] = new_years
                    ch["split_months"] = new_months
                    ch["auto_transcribe"] = new_auto_transcribe_var.get()
                    ch["auto_metadata"] = new_auto_metadata_var.get()
                    _old_compress = ch.get("compress_enabled", False)
                    _old_c_level = ch.get("compress_level", "")
                    _old_c_res = ch.get("compress_output_res", "")
                    _new_compress = new_compress_var.get()
                    _new_c_level = new_compress_level_var.get()
                    _new_c_res_raw = new_compress_res_var.get()
                    _new_c_res = _new_c_res_raw.replace("p", "") if _new_c_res_raw != "Original" else ""
                    ch["compress_enabled"] = _new_compress
                    ch["compress_level"] = _new_c_level
                    ch["compress_output_res"] = _new_c_res
                    try:
                        ch["compress_batch_size"] = int(new_compress_batch_var.get())
                    except (ValueError, TypeError):
                        ch["compress_batch_size"] = 20
                    # Capture values needed after lock release to avoid stale ch reads
                    _ch_resolution_snap = ch.get("resolution", "720")
                    break
        else:
            if any(c["name"] == name for c in channels):
                log(f"ERROR: A channel named '{name}' already exists.\n", "red")
                return
            if any(c["url"] == url for c in channels):
                log(f"ERROR: A channel with this URL already exists.\n", "red")
                return
            channels.append({
                "name": name, "url": url, "resolution": new_res_var.get(),
                "min_duration": dur_val,
                "max_duration": maxdur_val,
                "mode": mode, "date_after": date_after, "initialized": False,
                "folder_override": sanitize_folder(name),
                "split_years": new_years,
                "split_months": new_months,
                "auto_transcribe": new_auto_transcribe_var.get(),
                "auto_metadata": new_auto_metadata_var.get(),
                "compress_enabled": new_compress_var.get(),
                "compress_level": new_compress_level_var.get(),
                "compress_output_res": (lambda v: v.replace("p", "") if v != "Original" else "")(new_compress_res_var.get()),
                "compress_batch_size": (lambda _v: max(1, int(_v)) if _v.strip().isdigit() else 20)(new_compress_batch_var.get()),
            })

    _clear_edit_mode()
    save_config(config)
    refresh_channel_dropdowns()

    # Don't auto-add newly subscribed channels to the sync queue —
    # initialization should only happen on manual sync or full sync-subbed run.

    # Auto-reorganize existing downloads if split settings changed during edit
    if editing_url and (old_split_years != new_years or old_split_months != new_months):
        with config_lock:
            base = config.get("output_dir", "").strip() or BASE_DIR
        folder_path = os.path.join(base, sanitize_folder(name))
        _run_reorganize_auto(name, folder_path, new_years, new_months)

    # Offer to re-download & compress existing videos if compress settings changed
    _compress_changed = False
    if editing_url and _new_compress is not None:
        _compress_changed = (
            _new_compress and _new_c_level in _QUALITY_OPTIONS and
            (not _old_compress or _old_c_level != _new_c_level or _old_c_res != _new_c_res)
        )
        if _compress_changed:
            with config_lock:
                _bl_base = config.get("output_dir", "").strip() or BASE_DIR
            _bl_folder = os.path.join(_bl_base, sanitize_folder(name))
            if os.path.isdir(_bl_folder):
                # Count videos in a background thread to avoid blocking the main thread
                _bl_snap = {
                    "folder": _bl_folder, "name": name, "url": url,
                    "res": _ch_resolution_snap, "c_level": _new_c_level,
                    "c_res": _new_c_res, "years": new_years, "months": new_months,
                    "batch": int(new_compress_batch_val or "20"),
                }
                def _count_and_ask(_snap=_bl_snap):
                    _vid_exts = _VIDEO_EXTS
                    _bl_count = 0
                    for _r, _d, _f in os.walk(_snap["folder"]):
                        _d[:] = [d for d in _d if d not in ("_TEMP_COMPRESS", "_BACKLOG_TEMP")]
                        _bl_count += sum(1 for fn in _f if os.path.splitext(fn)[1].lower() in _vid_exts)
                    if _bl_count > 0:
                        def _show_dialog():
                            _bl_res_label = "Best" if _snap["res"] == "best" else f"{_snap['res']}p"
                            _bl_out_label = f" → {_snap['c_res']}p output" if _snap["c_res"] else ""
                            _bl_bitrate = _get_compress_bitrate(_snap["c_level"], _snap["c_res"])
                            _bl_ask = _dark_askquestion(
                                "Apply to Existing Videos",
                                f"Apply compression to {_bl_count:,} existing video(s)?\n\n"
                                f"Re-download at {_bl_res_label}{_bl_out_label}, "
                                f"quality: {_snap['c_level']} (~{_bl_bitrate} MB/hr)."
                            )
                            if _bl_ask:
                                _add_to_gpu_queue({
                                    "type": "backlog_encode",
                                    "ch_name": _snap["name"],
                                    "ch_url": _snap["url"],
                                    "folder": _snap["folder"],
                                    "resolution": _snap["res"],
                                    "bitrate_mbhr": _bl_bitrate,
                                    "output_res": _snap["c_res"],
                                    "split_years": _snap["years"],
                                    "split_months": _snap["months"],
                                    "batch_size": _snap["batch"],
                                })
                        root.after(0, _show_dialog)
                threading.Thread(target=_count_and_ask, daemon=True).start()

        # Offer to re-download existing videos at the new resolution when resolution
        # changed but compression settings did NOT change (compression already
        # includes a re-download step, so we skip this dialog if that dialog ran).
        if old_res and old_res != new_res_val and not _compress_changed:
            with config_lock:
                _rd_base = config.get("output_dir", "").strip() or BASE_DIR
            _rd_folder = os.path.join(_rd_base, sanitize_folder(name))
            if os.path.isdir(_rd_folder):
                _rd_snap = {
                    "folder": _rd_folder, "name": name, "url": url,
                    "old_res": old_res, "new_res_val": new_res_val
                }
                def _count_and_ask_rd(_snap=_rd_snap):
                    _vid_exts = _VIDEO_EXTS
                    _rd_count = 0
                    for _r, _d, _f in os.walk(_snap["folder"]):
                        _d[:] = [d for d in _d if d not in ("_TEMP_COMPRESS", "_BACKLOG_TEMP")]
                        _rd_count += sum(1 for fn in _f if os.path.splitext(fn)[1].lower() in _vid_exts)
                    if _rd_count > 0:
                        _old_res_label = "Best" if _snap["old_res"] == "best" else f"{_snap['old_res']}p"
                        _new_res_label = "Best" if _snap["new_res_val"] == "best" else f"{_snap['new_res_val']}p"
                        def _ask():
                            _rd_ask = _dark_askquestion(
                                "Apply to Existing Downloads",
                                f"Resolution changed from {_old_res_label} to {_new_res_label}.\n\n"
                                f"Re-download {_rd_count:,} existing video(s) at {_new_res_label}, "
                                f"replacing the originals?"
                            )
                            if _rd_ask:
                                _add_to_redownload_queue(_snap["name"], _snap["url"], _snap["folder"], _snap["new_res_val"])
                        _ui_queue.append(_ask)
                threading.Thread(target=_count_and_ask_rd, daemon=True).start()


def sync_single_channel(_from_queue=False):
    global _sync_running
    sel = settings_chan_tree.selection()
    if not sel:
        return
    target_url = settings_chan_tree.set(sel[0], "url")

    with config_lock:
        ch = None
        for c in config.get("channels", []):
            if c["url"] == target_url:
                ch = copy.deepcopy(c)
                break
        if not ch: return

    # If something is already running, queue instead of starting immediately
    # (_from_queue bypasses this check since the queue processor already owns the slot)
    if not _from_queue and (_sync_running or _reorg_running or _redownload_running):
        with _sync_queue_lock:
            if not any(q["url"] == ch["url"] for q in _sync_queue):
                _sync_queue.append(copy.deepcopy(ch))
                with _queue_order_lock:
                    _queue_order.append(("sync", ch["url"]))
                log(f"\n=== Added {ch['name']} to sync queue ===\n", "header")
            else:
                log(f"  ⚠ {ch['name']} is already in the sync queue.\n", "simpleline")
        _update_queue_btn()
        return

    with _session_totals_lock:
        for key in session_totals:
            session_totals[key] = 0
    cancel_event.clear()

    _schedule_autorun(0)

    sync_single_btn.config(state="disabled", text="⏳ Syncing...")
    _update_queue_btn()

    global _job_generation
    _job_generation += 1
    _my_gen = _job_generation

    _sync_running = True
    _update_global_pause_btn_sync()
    _start_internet_monitor()
    _current_job["label"] = f"Sync {ch['name']}"
    _current_job["url"] = ch["url"]
    global _current_sync_ch
    _current_sync_ch = copy.deepcopy(ch)
    _write_sync_progress()
    _tray_start_spin()
    _update_tray_tooltip(f"YT Archiver — Syncing {ch['name']}")
    _captured_outdir = outdir_var.get().strip() or BASE_DIR

    def _single_worker():
        global _sync_running, _current_sync_ch
        global _queue_batch_idx, _queue_batch_total, _queue_batch_dl, _queue_batch_err, _queue_batch_skip, _queue_batch_t_start
        # Clear walk cache from previous sync runs to prevent stale key accumulation
        if hasattr(internal_run_cmd_blocking, '_walk_cache'):
            internal_run_cmd_blocking._walk_cache.clear()
        _pfx_i = _queue_batch_idx if _queue_batch_total > 0 else 1
        _pfx_t = _queue_batch_total if _queue_batch_total > 0 else 1
        try:
            out_dir = _captured_outdir
            if not check_directory_writable(out_dir):
                log(f"ERROR: Cannot write to '{out_dir}'.\n", "red")
                return

            log(f"\n--- [{_pfx_i}/{_pfx_t}] SYNCING: {ch['name']} ---\n", "header")
            log(f"  Checking channel...\n", "dim")

            deferred_streams = []
            live_ids = []
            max_dur_ch = ch.get("max_duration", 0)
            if not cancel_event.is_set():
                live_videos = _prefetch_livestreams(ch["url"])
                if live_videos:
                    live_ids = [vid[0] for vid in live_videos]
                    if max_dur_ch:
                        log(f"  ⏭ {len(live_videos)} livestream(s) skipped (max-dur set).\n", "dim")
                        # Max-dur means these can never be downloaded — archive so they won't show up again
                        with io_lock:
                            try:
                                with open(ARCHIVE_FILE, "a", encoding="utf-8") as _af:
                                    for _lid, _lurl in live_videos:
                                        _af.write(f"youtube {_lid}\n")
                            except OSError as _e:
                                log(f"  WARNING: Could not write to archive file: {_e}\n", "red")
                    else:
                        for _lid, _lurl in live_videos:
                            deferred_streams.append((ch, _lurl, _lid))
                        _lnames = ", ".join(vid[0] for vid in live_videos)
                        log(f"\n", "livestream")
                        log(f"  ⚠  LIVESTREAM DETECTED — WILL DOWNLOAD AFTER SYNC  ⚠\n", "livestream")
                        log(f"  {len(live_videos)} stream(s) queued: {_lnames}\n", "livestream")
                        log(f"\n", "livestream")

            mode = ch.get("mode", "full")
            url = ch["url"]
            res = ch.get("resolution", "720")
            min_dur = ch.get("min_duration", 0)
            folder_ovr = ch.get("folder_override", "")
            is_init = ch.get("initialized", False)
            sync_complete = ch.get("sync_complete", True)
            # If channel completed full initialization, always treat as sync-complete
            # so --break-on-existing is used.  Without this, a cancelled sync on a
            # fully-archived channel leaves sync_complete=False, disabling the flag
            # and forcing yt-dlp to crawl every page of the channel listing.
            if ch.get("init_complete", False):
                sync_complete = True

            # --- Batch safety: check cooldown for large full-mode channels ---
            batch_limited = False
            if mode == "full" and not ch.get("init_complete", False):
                can_proceed, cooldown_str = _check_batch_cooldown(ch)
                if not can_proceed:
                    log(f"Skipping {ch['name']} — next batch after {cooldown_str}\n", "dim")
                    if _is_simple_mode:
                        _stop_simple_anim()
                        _cn = ch['name'] if len(ch['name']) <= 34 else ch['name'][:31] + "..."
                        log(f"[{_pfx_i}/{_pfx_t}] {_cn:<34} —  Downloaded: None, hit daily limit. Resets at {cooldown_str}\n", "simpleline")
                    return

            if mode == "sub" and not is_init:
                log("First sync: Archiving existing backlog...\n", "green")
                success = internal_run_subscribe_blocking(url)
                if cancel_event.is_set():
                    return
                if success:
                    with config_lock:
                        for cfg_ch in config.get("channels", []):
                            if cfg_ch["url"] == url: cfg_ch["initialized"] = True
                        save_config(config)
                    log("Initialization complete.\n", "green")
                else:
                    log(f"ERROR: Backlog archive failed for {ch['name']}.\n", "red")
                    return
            elif mode == "date" and not is_init:
                date_after = ch.get("date_after", "")
                if not date_after:
                    log(f"ERROR: date_after missing for {ch['name']}.\n", "red")
                    return
                log(f"First sync: Archiving videos before {date_after[:4]}-{date_after[4:6]}-{date_after[6:]}...\n",
                    "green")
                success = internal_run_subscribe_before_date(url, date_after)
                if cancel_event.is_set():
                    return
                if success:
                    with config_lock:
                        for cfg_ch in config.get("channels", []):
                            if cfg_ch["url"] == url: cfg_ch["initialized"] = True
                        save_config(config)
                else:
                    log(f"ERROR: Date-archive failed for {ch['name']}.\n", "red")
                    return

            with config_lock:
                for cfg_ch in config.get("channels", []):
                    if cfg_ch["url"] == url:
                        cfg_ch["sync_complete"] = False
                save_config(config)

            cmd = build_channel_cmd(url, out_dir, min_dur, res, folder_ovr,
                                    break_on_existing=is_init and sync_complete,
                                    max_dur=ch.get("max_duration", 0),
                                    split_years=ch.get("split_years", False),
                                    split_months=ch.get("split_months", False))
            if not cancel_event.is_set():
                # Always update anim state so switching to Simple mid-sync shows correct channel
                _simple_anim_state.update({"channel": ch['name'], "idx": _pfx_i, "total": _pfx_t,
                                           "dl_current": 0, "ch_total": 0})
                if _is_simple_mode:
                    _start_simple_anim(ch['name'], _pfx_i, _pfx_t)
                else:
                    log(f"  ▶ [{_pfx_i}/{_pfx_t}] {ch['name']}\n", "header")

                # Skip prefetch for uninitialized full-mode channels — it always returns 0
                # and fires 2 yt-dlp calls that may trigger YouTube rate-limiting before enumeration
                _skip_prefetch = (ch.get("mode", "full") == "full"
                                  and not ch.get("init_complete", False)
                                  and not ch.get("initialized", False))
                if _skip_prefetch:
                    ch_total = 0
                    log("  Skipping video count prefetch (uninitialized channel, going straight to enumeration).\n", "dim")
                else:
                    log("  Fetching video count...\n", "dim")
                    ch_total = _prefetch_total(url)
                if ch_total:
                    log(f"  Video count: {ch_total:,}\n", "dim")

                # --- Batch safety: limit large channel downloads ---
                _batch_pstart = 0
                _batch_cache_ids = None
                _batch_start_idx = 0
                _batch_end_idx = 0
                _all_cached_done = False
                if _should_batch_limit(ch, ch_total):
                    batch_limited = True

                    # Try cached batch flow
                    _batch_cache_ids, _cache_created = _load_or_create_batch_cache(url)
                    if cancel_event.is_set():
                        return

                    if _batch_cache_ids:
                        _batch_start_idx = ch.get("batch_resume_index", 0)

                        # On subsequent runs, check for new uploads
                        if not _cache_created and _batch_start_idx > 0:
                            log("  Checking for new uploads...\n", "dim")
                            _new_ids = _check_new_videos(url, _batch_cache_ids)
                            if _new_ids:
                                log(f"  Found {len(_new_ids)} new video(s), updating cache.\n", "green")
                                _new_set = set(_new_ids)
                                _batch_cache_ids = _new_ids + [x for x in _batch_cache_ids if x not in _new_set]
                                if _batch_start_idx > 0:
                                    _batch_start_idx += len(_new_ids)
                                try:
                                    with open(_get_batch_cache_path(url), "w", encoding="utf-8") as _cf:
                                        _cf.write("\n".join(_batch_cache_ids) + "\n")
                                except Exception:
                                    pass

                        # Pre-filter: skip already-archived IDs so yt-dlp doesn't waste
                        # time checking/skipping thousands of already-downloaded videos.
                        # Auto-advance through fully-archived batches.
                        _archived_set = _load_archived_ids()
                        _filtered_slice = None

                        while _batch_cache_ids and not cancel_event.is_set():
                            _batch_end_idx = min(_batch_start_idx + BATCH_LIMIT, len(_batch_cache_ids))
                            _batch_slice = _batch_cache_ids[_batch_start_idx:_batch_end_idx]
                            _filtered_slice = [vid for vid in _batch_slice if vid not in _archived_set]
                            _skipped_pre = len(_batch_slice) - len(_filtered_slice)

                            if _filtered_slice:
                                if _skipped_pre:
                                    log(f"  Skipped {_skipped_pre:,} already-downloaded IDs in batch.\n", "dim")
                                break  # Found videos to download

                            # Entire batch already archived — advance
                            log(f"  Batch {_batch_start_idx:,}-{_batch_end_idx:,} fully archived, advancing...\n", "dim")
                            _batch_start_idx = _batch_end_idx

                            if _batch_start_idx >= len(_batch_cache_ids):
                                # ALL videos in cache are already downloaded
                                _clear_batch_state(url, mark_complete=True)
                                log(f"  All {len(_batch_cache_ids):,} cached videos already downloaded. Initialization complete!\n", "green")
                                _all_cached_done = True
                                _batch_cache_ids = None
                                break

                        if _batch_cache_ids and _filtered_slice:
                            _bf_path = _build_batch_file(_filtered_slice)
                        else:
                            _bf_path = None

                        if _bf_path:
                            cmd = build_channel_cmd(url, out_dir, min_dur, res, folder_ovr,
                                                    break_on_existing=False,
                                                    max_dur=ch.get("max_duration", 0),
                                                    split_years=ch.get("split_years", False),
                                                    split_months=ch.get("split_months", False),
                                                    max_downloads=BATCH_LIMIT,
                                                    batch_file=_bf_path)
                            _remaining = len(_batch_cache_ids) - _batch_start_idx
                            log(f"  Large channel ({len(_batch_cache_ids):,} videos). Downloading {len(_filtered_slice):,} new videos (batch {_batch_start_idx:,}-{_batch_end_idx:,}, {_remaining:,} remaining)...\n", "green")
                        elif not _all_cached_done:
                            _batch_cache_ids = None  # fall through to legacy

                    if not _batch_cache_ids and not _all_cached_done:
                        # Legacy fallback
                        _batch_pstart = _get_batch_playlist_start(ch)
                        cmd = build_channel_cmd(url, out_dir, min_dur, res, folder_ovr,
                                                break_on_existing=False,
                                                max_dur=ch.get("max_duration", 0),
                                                split_years=ch.get("split_years", False),
                                                split_months=ch.get("split_months", False),
                                                max_downloads=BATCH_LIMIT,
                                                playlist_start=_batch_pstart)
                        if _batch_pstart > 1:
                            log(f"  Large channel ({ch_total:,} videos). Resuming from index {_batch_pstart}, batch of {BATCH_LIMIT:,}...\n", "green")
                        else:
                            log(f"  Large channel detected ({ch_total:,} videos). Downloading batch of {BATCH_LIMIT:,}...\n", "green")

            # Build incremental compress callback if compress is enabled
            _sc_level = ch.get("compress_level", "")
            _sc_batch_cb = None
            _sc_bsize = ch.get("compress_batch_size", 20)
            if ch.get("compress_enabled", False) and _sc_level in _QUALITY_OPTIONS and ch.get("resolution", "") != "audio":
                _sc_folder = os.path.join(out_dir, sanitize_folder(ch.get("folder_override", "") or ch["name"]))
                _sc_prompt_shown = [False]
                def _sc_batch_cb(count, batch_paths, _ch=ch, _u=url, _f=_sc_folder, _lv=_sc_level, _bs=_sc_bsize):
                    _b = _get_next_compress_batch(_u)
                    _add_to_gpu_queue({
                        "type": "encode", "ch_name": _ch["name"], "ch_url": _ch["url"],
                        "folder": _f, "bitrate_mbhr": _get_compress_bitrate(_lv, _ch.get("compress_output_res", "")),
                        "output_res": _ch.get("compress_output_res", ""),
                        "split_years": _ch.get("split_years", False),
                        "split_months": _ch.get("split_months", False),
                        "batch_num": _b, "batch_size": _bs,
                        "target_paths": batch_paths,
                    }, _quiet=True)
                    if count >= 100 and not _sc_prompt_shown[0] and not _gpu_running:
                        _sc_prompt_shown[0] = True
                        if _ask_start_gpu_tasks(count):
                            _ui_queue.append(_gpu_start)

            c_dl = 0
            c_dur = 0
            if not cancel_event.is_set() and not _all_cached_done:
                c_dl = internal_run_cmd_blocking(cmd, channel_total=ch_total, live_ids=live_ids,
                                                 on_batch_ready=_sc_batch_cb,
                                                 compress_batch_size=_sc_bsize)
                c_dur = _last_run_counts.get("dur", 0)

                # Also check /streams tab for past livestreams
                _streams_url = _get_streams_url(url)
                if _streams_url and not cancel_event.is_set():
                    _streams_cmd = build_channel_cmd(_streams_url, out_dir, min_dur, res, folder_ovr,
                                                     break_on_existing=is_init and sync_complete,
                                                     max_dur=ch.get("max_duration", 0),
                                                     split_years=ch.get("split_years", False),
                                                     split_months=ch.get("split_months", False))
                    _s_dl = internal_run_cmd_blocking(_streams_cmd, on_batch_ready=_sc_batch_cb,
                                                      compress_batch_size=_sc_bsize)
                    c_dur += _last_run_counts.get("dur", 0)
                    if _s_dl:
                        c_dl = (c_dl or 0) + _s_dl

                if _is_simple_mode:
                    _stop_simple_anim()
                    if not cancel_event.is_set():
                        if c_dl:
                            _v = f"Downloaded: {c_dl} video{'s' if c_dl != 1 else ''}"
                            if c_dur:
                                _v += f"  ·  {c_dur} filtered"
                        elif c_dur:
                            _v = f"Filtered {c_dur}"
                        else:
                            _v = "no new videos"
                        _tag = "simpleline_green" if c_dl else "simpleline"
                        _cn = ch['name'] if len(ch['name']) <= 34 else ch['name'][:31] + "..."
                        log(f"[{_pfx_i}/{_pfx_t}] {_cn:<34} —  {_v}\n", _tag)

            if deferred_streams and not cancel_event.is_set():
                log(f"\n\n" + "█" * 55 + "\n", "livestream")
                log(f"  ⚠  DOWNLOADING {len(deferred_streams)} DEFERRED LIVESTREAM(S)  ⚠\n", "livestream")
                log(f"█" * 55 + "\n\n", "livestream")
                for _ds_ch, _ds_url, _ds_id in deferred_streams:
                    if cancel_event.is_set(): break
                    _ds_name = _ds_ch.get("name", _ds_id)
                    log(f"--- LIVESTREAM: {_ds_name} ---\n", "header")
                    _ds_out = os.path.join(out_dir, sanitize_folder(_ds_ch.get("folder_override", "") or _ds_name))
                    _ds_cmd = build_video_cmd(_ds_url, _ds_out, _ds_ch.get("resolution", "720"))
                    _ds_dl = internal_run_cmd_blocking(_ds_cmd)
                    # Only archive the stream ID on successful download so failed ones retry next sync
                    if _ds_dl:
                        with io_lock:
                            try:
                                with open(ARCHIVE_FILE, "a", encoding="utf-8") as _af:
                                    _af.write(f"youtube {_ds_id}\n")
                            except OSError as _e:
                                log(f"  WARNING: Could not write to archive file: {_e}\n", "red")

            _cleanup_batch_file()

            if cancel_event.is_set():
                _stop_simple_anim()
                clear_transient_lines()
                if _skip_current.is_set():
                    pass  # "Skipping" message already logged by _skip_current_job()
                else:
                    log("\nSyncs cancelled by user.\n", "red")
                _cleanup_partial_files(out_dir)
                # Save batch resume if large channel and enough progress was made (but not on skip)
                if not _skip_current.is_set() and (ch_total > 200 or batch_limited):
                    _cancel_total = _last_run_counts["dl"] + _last_run_counts["skip"] + _last_run_counts["dur"] + _last_run_counts["err"]
                    if _cancel_total > 50:
                        if _batch_cache_ids:
                            # Stay at _batch_start_idx — pre-filter will skip archived on resume
                            _save_batch_resume(url, _batch_pstart, _last_run_counts,
                                               cache_resume_index=_batch_start_idx)
                        else:
                            _save_batch_resume(url, _batch_pstart, _last_run_counts)
                        log(f"  Batch progress saved — will resume from here next sync.\n", "dim")
            else:
                # --- Batch safety: handle batch completion ---
                _batch_more_remaining = False
                if batch_limited:
                    _total_processed = _last_run_counts["dl"] + _last_run_counts["skip"] + _last_run_counts["dur"] + _last_run_counts["err"]
                    if _batch_cache_ids:
                        # Advance to end of batch range — pre-filter handled archived IDs
                        _cache_pos = _batch_end_idx
                        _batch_all_done = (_cache_pos >= len(_batch_cache_ids))
                    else:
                        _batch_all_done = (_total_processed < BATCH_LIMIT)

                    if not _batch_all_done:
                        _batch_more_remaining = True
                        if _batch_cache_ids:
                            _save_batch_resume(url, _batch_pstart, _last_run_counts,
                                               cache_resume_index=_cache_pos)
                        else:
                            _save_batch_resume(url, _batch_pstart, _last_run_counts)
                        cooldown_dt = _set_batch_cooldown(url)
                        time_str = cooldown_dt.strftime("%I:%M%p").lstrip("0").lower()
                        date_str = cooldown_dt.strftime("%b %d")
                        log(f"\n  Batch complete — downloaded {c_dl:,} of ~{ch_total:,} videos.\n", "green")
                        log(f"  Next batch available after {time_str}, {date_str}\n", "green")
                        log(f"  Sync this channel again after cooldown to continue.\n", "dim")
                    else:
                        _clear_batch_state(url, mark_complete=True)
                        log(f"  Channel initialization complete — all videos downloaded.\n", "green")

                _ts = datetime.now().strftime("%Y-%m-%d %H:%M")
                with config_lock:
                    for cfg_ch in config.get("channels", []):
                        if cfg_ch["url"] == url:
                            if not _batch_more_remaining:
                                cfg_ch["sync_complete"] = True
                                cfg_ch["initialized"] = True
                            cfg_ch["last_sync"] = _ts
                    # Don't update global "Last Full Sync" for single channel syncs —
                    # that should only be set when a full sync-subbed run completes.
                save_config(config)
                _invalidate_channel_disk_cache(url)
                _ui_queue.append(refresh_channel_dropdowns)

                # New videos downloaded — track pending transcription count
                if c_dl > 0:
                    with config_lock:
                        for _tp_ch in config.get("channels", []):
                            if _tp_ch["url"] == url:
                                _tp_ch["transcription_pending"] = _tp_ch.get("transcription_pending", 0) + c_dl
                                break
                    save_config(config)

                # Auto-compress: if channel has compress enabled and new videos were downloaded
                # (handled via incremental _sc_batch_cb during download; nothing extra needed here)

                # Auto-transcribe: try YT captions inline right after download;
                # only queue a GPU task if some videos still need Whisper.
                if c_dl > 0 and ch.get("auto_transcribe", False) and not cancel_event.is_set():
                    _at_folder = os.path.join(out_dir, sanitize_folder(ch.get("folder_override", "") or ch["name"]))
                    _at_sy = ch.get("split_years", False)
                    _at_sm = ch.get("split_months", False)
                    _start_transcription(
                        ch["name"], url, _at_folder, _at_sy, _at_sm, combined=not _at_sy,
                        cancel_ev=cancel_event, pause_ev=pause_event,
                        skip_model_dialog=True, _sync_mode=True, captions_only=True
                    )

                # Auto-metadata: queue metadata download for this channel after sync
                if c_dl > 0 and ch.get("auto_metadata", False) and not cancel_event.is_set():
                    _am_folder = os.path.join(out_dir, sanitize_folder(ch.get("folder_override", "") or ch["name"]))
                    _am_sy = ch.get("split_years", False)
                    _am_sm = ch.get("split_months", False)
                    _add_to_metadata_queue(ch["name"], url, _am_folder, _am_sy, _am_sm,
                                           None, None, ch["name"])

                if _queue_batch_total > 1:
                    # Queue batch mode: accumulate totals; defer summary/notification to end
                    _queue_batch_dl += session_totals["dl"]
                    _queue_batch_err += session_totals["err"]
                    _queue_batch_skip += session_totals["dur"]
                else:
                    _dl = session_totals["dl"]
                    _plural = "s" if _dl != 1 else ""
                    _notif_msg = f"Downloaded {_dl} video{_plural}. Errors: {session_totals['err']}"
                    if _batch_more_remaining:
                        _notif_msg += " (batch — more remaining)"
                    show_notification("YT Archiver — Sync complete", _notif_msg)

                    _skipped_list = _last_run_counts.get("skipped_titles", [])
                    _skip_n = len(_skipped_list)
                    log("\n" + "=" * 45 + "\n", "summary")
                    log(f"CHANNEL SUMMARY:\n", "summary")
                    _sum_parts = [f"Downloaded: {session_totals['dl']}", f"Skipped: {_skip_n}"]
                    if session_totals['dur'] > 0:
                        _sum_parts.append(f"Filtered: {session_totals['dur']}")
                    if session_totals['err'] > 0:
                        _sum_parts.append(f"Errors: {session_totals['err']}")
                    log(f"{', '.join(_sum_parts)}\n", "summary")
                    log("=" * 45 + "\n", "summary")
                if _queue_batch_total <= 1:
                    log("\n=== CHANNEL SYNC COMPLETE ===\n", "header")
        finally:
            elapsed_single = (datetime.now() - t_start_single).total_seconds()
            # Only record individual entry for true single-channel syncs, not queue batches.
            # Batches (Sync Subbed queued while another sync was running) get one combined
            # entry recorded at the end so the activity log stays consolidated.
            if _queue_batch_total <= 1:
                _record_sync(session_totals["dl"], session_totals["err"], elapsed_single,
                             kind="Manual", channel_name=ch.get("name", ""),
                             skipped=session_totals["dur"])

            # If a newer job has taken over (user cancelled + started new sync),
            # don't touch any shared state — the new job owns it now.
            if _job_generation == _my_gen:
                # Check for queued syncs, reorg, or transcription jobs before fully finishing.
                # Keep _sync_running=True until we confirm nothing else is queued,
                # to prevent a race where another sync starts in the gap.
                _queue_started = False
                if _skip_current.is_set():
                    _skip_current.clear()
                    cancel_event.clear()
                    _queue_started = _process_next_queued()
                elif not cancel_event.is_set():
                    _queue_started = _process_next_queued()

                if not _queue_started:
                    # End of queue batch (or single-channel sync) — fire final summary if batch
                    if _queue_batch_total > 1 and not cancel_event.is_set():
                        _b_dl = _queue_batch_dl
                        _b_err = _queue_batch_err
                        _b_skip = _queue_batch_skip
                        _b_plural = "s" if _b_dl != 1 else ""
                        log("\n" + "=" * 45 + "\n", "summary")
                        log(f"TOTAL SYNC SUMMARY:\n", "summary")
                        _sum_parts = [f"Downloaded: {_b_dl}", f"Channels synced: {_queue_batch_total}"]
                        if _b_skip > 0:
                            _sum_parts.append(f"Filtered: {_b_skip}")
                        if _b_err > 0:
                            _sum_parts.append(f"Errors: {_b_err}")
                        log(f"{', '.join(_sum_parts)}\n", "summary")
                        log("=" * 45 + "\n", "summary")
                        show_notification(
                            "YT Archiver — Sync complete",
                            f"Downloaded {_b_dl} video{_b_plural} across {_queue_batch_total} channels. Errors: {_b_err}"
                        )
                        # Record one combined activity-log entry for the whole batch
                        _b_elapsed = (datetime.now() - _queue_batch_t_start).total_seconds() if _queue_batch_t_start else elapsed_single
                        _record_sync(_b_dl, _b_err, _b_elapsed, kind="Manual", channel_name="Sync-Subbed", skipped=_b_skip)
                    # Capture for tray tooltip before resetting
                    _final_dl = _queue_batch_dl if _queue_batch_total > 1 else session_totals["dl"]
                    # Reset batch tracking whenever queue drains
                    _queue_batch_idx = 0
                    _queue_batch_total = 0
                    _queue_batch_dl = 0
                    _queue_batch_err = 0
                    _queue_batch_skip = 0
                    _queue_batch_t_start = None
                    _sync_running = False
                    _current_sync_ch = None
                    _clear_sync_progress()
                    if _root_alive:
                        def _on_single_sync_done(_fdl=_final_dl):
                            _validate_download_btn()
                            sync_btn.config(state="normal")
                            sync_single_btn.config(state="normal", text="▶ Sync this channel")
                            _sync_task_finished()
                            _tray_stop_spin()
                            if _fdl > 0:
                                _update_tray_tooltip(f"YT Archiver — {_fdl} new video{'s' if _fdl != 1 else ''} downloaded")
                            else:
                                _update_tray_tooltip("YT Archiver — Idle")

                            _iv = AUTORUN_OPTIONS.get(_cached_autorun_label, 0)
                            if _iv:
                                _schedule_autorun(_iv)

                        _ui_queue.append(_on_single_sync_done)

                # Process any videos queued during the sync (only if no queued sync took over)
                if not cancel_event.is_set() and not _queue_started:
                    _process_video_dl_queue()

    # Don't switch to Download tab — mini-logs on every tab show progress,
    # and the user may want to stay on the Subs tab to queue more channels.
    t_start_single = datetime.now()

    def _safe_single_worker():
        """Wrapper that guarantees _sync_running is cleared even on unhandled exceptions."""
        global _sync_running, _current_sync_ch
        try:
            _single_worker()
        except Exception as _unhandled:
            log(f"\n  ⚠ Unexpected sync error: {_unhandled}\n", "red")
            try:
                log(f"  {traceback.format_exc()}\n", "red")
            except Exception:
                pass
        finally:
            # Safety net: if _single_worker didn't clear these, do it here
            if _sync_running and _job_generation == _my_gen:
                _sync_running = False
                _current_sync_ch = None
                _clear_sync_progress()
                _current_job["label"] = None
                _current_job["url"] = None
                _tray_stop_spin()
                if _root_alive:
                    def _reset_ui():
                        try:
                            sync_btn.config(state="normal")
                            sync_single_btn.config(state="normal", text="▶ Sync this channel")
                            _validate_download_btn()
                            _sync_task_finished()
                        except Exception:
                            pass
                    _ui_queue.append(_reset_ui)
    threading.Thread(target=_safe_single_worker, daemon=True).start()


def _process_sync_queue():
    """Process next queued sync if any. Returns True if a sync was started."""
    global _queue_batch_idx, _queue_batch_total, _queue_batch_dl, _queue_batch_err, _queue_batch_skip, _queue_batch_t_start
    with _sync_queue_lock:
        if not _sync_queue:
            return False
        next_ch = _sync_queue.pop(0)
        remaining = len(_sync_queue)
    with _queue_order_lock:
        try:
            _queue_order.remove(("sync", next_ch["url"]))
        except ValueError:
            pass

    # Track position in queue batch so _single_worker shows correct [i/total] counter
    if _queue_batch_idx == 0:
        _queue_batch_dl = 0
        _queue_batch_err = 0
        _queue_batch_skip = 0
        _queue_batch_t_start = datetime.now()
    _queue_batch_idx += 1
    _queue_batch_total = _queue_batch_idx + remaining
    _write_sync_progress()

    if next_ch.get("initialized", False):
        _current_job["label"] = f"Sync {next_ch['name']}"
    else:
        _current_job["label"] = f"Initialize {next_ch['name']}"
    _update_queue_btn()

    # Find and select the channel in the tree, then sync it
    def _start_queued():
        global _sync_running, _current_sync_ch
        try:
            _found = False
            for item in settings_chan_tree.get_children():
                if settings_chan_tree.set(item, "url") == next_ch["url"]:
                    settings_chan_tree.selection_set(item)
                    on_chan_list_select(None)
                    _found = True
                    break
            # Keep _sync_running True to prevent races — sync_single_channel
            # will take ownership via _from_queue=True.
            if _found:
                sync_single_channel(_from_queue=True)
            else:
                log(f"  ⚠ Could not find {next_ch.get('name', '?')} in channel list — skipping.\n", "red")
                # Try next queued item instead of getting stuck
                _process_next_queued()
        except Exception as e:
            with _sync_queue_lock:
                _sync_running = False
            _current_sync_ch = None
            _clear_sync_progress()
            _current_job["label"] = None
            _current_job["url"] = None
            _tray_stop_spin()
            _update_tray_tooltip("YT Archiver — Idle")
            _sync_task_finished()
            _update_queue_btn()
            log(f"  ⚠ Error starting queued sync: {e}\n", "red")

    if _root_alive:
        _ui_queue.append(_start_queued)
    return True


def _process_next_queued():
    """Process the next queued item in insertion order. Returns True if something was started."""
    with _queue_order_lock:
        order_copy = list(_queue_order)
    for source, key in order_copy:
        if source == "sync":
            with _sync_queue_lock:
                has_items = bool(_sync_queue)
            if has_items:
                return _process_sync_queue()
        elif source == "reorg":
            with _reorg_queue_lock:
                has_items = bool(_reorg_queue)
            if has_items:
                return _process_reorg_queue()
        elif source == "transcribe":
            with _transcribe_queue_lock:
                has_items = bool(_transcribe_queue)
            if has_items:
                return _process_transcribe_queue()
        elif source == "mt":
            with _mt_queue_lock:
                has_items = bool(_mt_queue)
            if has_items:
                return _process_mt_queue()
        elif source == "redownload":
            with _redownload_queue_lock:
                has_items = bool(_redownload_queue)
            if has_items:
                return _process_redownload_queue()
        elif source == "metadata":
            with _metadata_queue_lock:
                has_items = bool(_metadata_queue)
            if has_items:
                return _process_metadata_queue()
    # Fallback: try each queue in case _queue_order is out of sync
    return _process_sync_queue() or _process_reorg_queue() or _process_transcribe_queue() or _process_mt_queue() or _process_redownload_queue() or _process_metadata_queue()


def _process_video_dl_queue():
    """Process queued single-video downloads sequentially after sync finishes.

    Must be called from a worker thread (not the main thread) since it blocks
    on each download. All UI updates are dispatched to the main thread via
    root.after().
    """
    with _video_dl_queue_lock:
        queued = list(_video_dl_queue)
        _video_dl_queue.clear()
    if not queued:
        return
    _update_queue_btn()
    log(f"\n--- Processing {len(queued)} queued download{'s' if len(queued) != 1 else ''} ---\n", "header")

    # Update UI from main thread
    def _show_dl_ui():
        sync_btn.config(state="disabled")
        sync_single_btn.config(state="disabled")
        _update_queue_btn()

    _ui_queue.append(_show_dl_ui)

    cancel_event.clear()
    for cmd, is_single in queued:
        if cancel_event.is_set():
            break
        internal_run_cmd_blocking(cmd)
        if cancel_event.is_set():
            try:
                out_idx = cmd.index("--output")
                out_path = cmd[out_idx + 1]
                _cleanup_partial_files(os.path.dirname(out_path))
            except (ValueError, IndexError):
                pass
            break
        if is_single:
            def _clear_url():
                url_var.set("")
                url_entry.event_generate("<FocusOut>")
                vid_custom_name_var.set("")
            _ui_queue.append(_clear_url)

    # Reset UI from main thread
    def _done_dl_ui():
        _validate_download_btn()
        if not _sync_running:
            sync_btn.config(state="normal")
        sync_single_btn.config(state="normal", text="▶ Sync this channel")
        _sync_task_finished()
        on_chan_list_select(None)

    _ui_queue.append(_done_dl_ui)


def remove_channel():
    sel = settings_chan_tree.selection()
    if not sel: return
    target_url = settings_chan_tree.set(sel[0], "url")

    with config_lock:
        channels = config.setdefault("channels", [])
        ch_to_remove = next((c for c in channels if c["url"] == target_url), None)
        if not ch_to_remove: return
        removed_name = ch_to_remove["name"]
        removed_url = ch_to_remove.get("url", "")

    if not _dark_askquestion(
        "Remove Channel",
        f"Are you sure you want to remove \"{removed_name}\" from your subscriptions?",
        yes_text="Remove", no_text="Cancel"
    ):
        return

    delete_ids = _dark_askquestion(
        "Remove Channel",
        f"Remove \"{removed_name}\" from your subscription list.\n\n"
        "Delete this channel's video IDs from the blocklist?\n\n"
        "• Yes — IDs are removed, so they could be re-downloaded if re-added\n"
        "• No  — videos already archived stay skipped on future syncs",
        yes_text="Yes", no_text="No"
    )

    if delete_ids and removed_url:
        def _purge_ids():
            log(f"  Fetching IDs for \"{removed_name}\" to remove from blocklist...\n", "dim")
            proc = None
            try:
                probe_cmd = [
                    "yt-dlp", "--flat-playlist", "--no-warnings",
                    "--print", "%(id)s",
                    "--cookies-from-browser", "firefox",
                    removed_url
                ]
                proc = spawn_yt_dlp(probe_cmd)
                if not proc:
                    return
                channel_ids = set()
                for line in proc.stdout:
                    line = line.strip()
                    if re.fullmatch(r'[\w-]{11}', line):
                        channel_ids.add(line)
                try:
                    proc.wait(timeout=300)
                except subprocess.TimeoutExpired:
                    proc.kill()
                    proc.wait()

                if not channel_ids:
                    log(f"  ⚠ No IDs found for \"{removed_name}\" — blocklist unchanged.\n", "red")
                    return

                with io_lock:
                    if os.path.exists(ARCHIVE_FILE):
                        with open(ARCHIVE_FILE, encoding="utf-8") as f_:
                            lines = f_.readlines()
                        kept = []
                        for l in lines:
                            parts = l.strip().split()
                            if parts and parts[-1] in channel_ids:
                                continue
                            kept.append(l)
                        removed_count = len(lines) - len(kept)
                        _tmp = ARCHIVE_FILE + ".tmp"
                        with open(_tmp, "w", encoding="utf-8") as f_:
                            f_.writelines(kept)
                        os.replace(_tmp, ARCHIVE_FILE)
                        log(f"  ✓ Removed {removed_count:,} IDs for \"{removed_name}\" from blocklist.\n", "green")
                    else:
                        log("  ⚠ Archive file not found — nothing to purge.\n", "red")
            except Exception as e:
                log(f"ERROR purging IDs for \"{removed_name}\": {e}\n", "red")
            finally:
                cleanup_process(proc)

        threading.Thread(target=_purge_ids, daemon=True).start()

    # Determine channel folder path before removing from config
    with config_lock:
        _folder_ovr = ch_to_remove.get("folder_override", "").strip()
        _ch_folder_name = sanitize_folder(_folder_ovr or removed_name)
        _base = config.get("output_dir", "").strip() or BASE_DIR
    _ch_folder_path = os.path.join(_base, _ch_folder_name)

    with config_lock:
        config["channels"] = [c for c in config.get("channels", []) if c.get("url") != target_url]
        if chan_var.get() == removed_name:
            chan_var.set("")
            url_var.set("")
            save_prefs_btn.config(state="disabled")
        if _editing_channel.get("name") == removed_name:
            _clear_edit_mode()
        save_config(config)

    refresh_channel_dropdowns()
    remove_channel_btn.pack_forget()
    with _disk_cache_lock:
        _disk_cache.pop(removed_url, None)
    _save_disk_cache()

    # Remove from sync queue (channel was queued but not yet running)
    with _sync_queue_lock:
        _before_sync = len(_sync_queue)
        _sync_queue[:] = [q for q in _sync_queue if q.get("url") != removed_url]
        _removed_sync = _before_sync - len(_sync_queue)
    with _queue_order_lock:
        try:
            _queue_order.remove(("sync", removed_url))
        except ValueError:
            pass
    if _removed_sync:
        log(f"  Removed \"{removed_name}\" from sync queue.\n", "dim")
        _update_queue_btn()

    # Remove from transcribe queue
    with _transcribe_queue_lock:
        _before_tr = len(_transcribe_queue)
        _transcribe_queue[:] = [q for q in _transcribe_queue if q[1] != removed_url]
        _removed_tr = _before_tr - len(_transcribe_queue)
    with _queue_order_lock:
        try:
            _queue_order.remove(("transcribe", removed_url))
        except ValueError:
            pass

    # Remove from redownload queue
    with _redownload_queue_lock:
        _before_rd = len(_redownload_queue)
        _redownload_queue[:] = [q for q in _redownload_queue if q.get("ch_url") != removed_url]
        _removed_rd = _before_rd - len(_redownload_queue)
    with _queue_order_lock:
        try:
            _queue_order.remove(("redownload", removed_url))
        except ValueError:
            pass

    # Remove any queued GPU tasks for this channel
    with _gpu_queue_lock:
        _before = len(_gpu_queue)
        _gpu_queue[:] = [q for q in _gpu_queue if q.get("ch_url") != removed_url]
        _removed_gpu = _before - len(_gpu_queue)
    if _removed_gpu:
        log(f"  Removed {_removed_gpu} GPU task(s) for \"{removed_name}\" from queue.\n", "dim")
        _update_gpu_btn()
        _save_queue_state()

    # Offer to delete the channel's folder if it exists
    if os.path.isdir(_ch_folder_path):
        try:
            # Use cached disk size if available (avoid blocking UI with os.walk)
            _cached = _disk_cache.get(removed_url, {})
            _total_bytes = _cached.get("size_bytes", 0)
            if _total_bytes:
                _size_disp = _fmt_size(str(_total_bytes))
            else:
                _size_disp = "unknown size"
        except Exception:
            _size_disp = "unknown size"

        if _dark_askquestion(
            "Delete channel folder?",
            f"Would you like to delete this channel's folder as well?\n\n"
            f"{_ch_folder_path}\n\n"
            f"({_size_disp})"
        ):
            try:
                shutil.rmtree(_ch_folder_path)
                log(f"  ✓ Deleted folder: {_ch_folder_path}\n", "green")
            except Exception as e:
                log(f"ERROR: Could not delete folder: {e}\n", "red")


split_row = ttk.Frame(add_outer, style="Raised.TFrame")
split_row.grid(row=4, column=0, columnspan=9, sticky="w", padx=(4, 8), pady=(2, 4))

new_folder_org_var = tk.StringVar(value="None")
new_auto_transcribe_var = tk.BooleanVar(value=False)
new_auto_metadata_var = tk.BooleanVar(value=False)

# Computed BooleanVars kept in sync with the dropdown so all existing code that
# reads new_split_years_var / new_split_months_var continues to work unchanged.
new_split_years_var = tk.BooleanVar(value=False)
new_split_months_var = tk.BooleanVar(value=False)

def _on_folder_org_changed(*_):
    val = new_folder_org_var.get()
    new_split_years_var.set(val in ("Years", "Years/Months"))
    new_split_months_var.set(val == "Years/Months")

new_folder_org_var.trace_add("write", _on_folder_org_changed)

ttk.Label(split_row, text="Folder Org:").pack(side="left", padx=(4, 4))
folder_org_combo = _combo(split_row, textvariable=new_folder_org_var,
                          values=["None", "Years", "Years/Months"],
                          state="readonly", width=13)
folder_org_combo.pack(side="left", padx=(0, 16))

auto_metadata_cb = ttk.Checkbutton(split_row, text="Auto-download metadata",
                                    variable=new_auto_metadata_var)
auto_metadata_cb.pack(side="right", padx=(8, 4))
auto_transcribe_cb = ttk.Checkbutton(split_row, text="Auto-transcribe",
                                      variable=new_auto_transcribe_var)
auto_transcribe_cb.pack(side="right", padx=(16, 4))

reorg_done_label = ttk.Label(split_row, text="Done!", style="Green.TLabel")
_reorg_done_job = {"id": None}


MONTH_NAMES = {
    1: "01 January", 2: "02 February", 3: "03 March", 4: "04 April",
    5: "05 May", 6: "06 June", 7: "07 July", 8: "08 August",
    9: "09 September", 10: "10 October", 11: "11 November", 12: "12 December"
}

# Reverse lookup: match existing month folders to month numbers
_MONTH_FOLDER_LOOKUP = {}
for _mn, _mname in MONTH_NAMES.items():
    _MONTH_FOLDER_LOOKUP[_mname.lower()] = _mn                     # "01 january"
    _MONTH_FOLDER_LOOKUP[_mname.split(" ", 1)[1].lower()] = _mn    # "january"
    _MONTH_FOLDER_LOOKUP[str(_mn).zfill(2)] = _mn                  # "01"
    _MONTH_FOLDER_LOOKUP[str(_mn)] = _mn                           # "1"

# Also handle old format like "1 January", "2 February", etc.
for _mn in range(1, 13):
    _old_fmt = f"{_mn} {MONTH_NAMES[_mn].split(' ', 1)[1]}"
    _MONTH_FOLDER_LOOKUP[_old_fmt.lower()] = _mn


def _is_year_folder(name):
    return bool(re.fullmatch(r'\d{4}', name))


def _is_month_folder(name):
    return name.lower() in _MONTH_FOLDER_LOOKUP


VIDEO_EXTS = _VIDEO_EXTS


def _reorganize_channel_folder(channel_name, folder_path, target_years, target_months,
                               trust_mtime=False):
    """Reorganize a channel's download folder based on split settings.

    target_years=True, target_months=True  → year/month subfolders
    target_years=True, target_months=False → year subfolders only
    target_years=False                      → flat (everything in root)

    trust_mtime: if True, always use file mtime for date sorting (use after
                 dates have been verified/fixed). If False, prefer existing
                 folder names over mtime.
    """
    if not os.path.isdir(folder_path):
        log(f"  ⚠ Folder not found: {folder_path}\n", "red")
        return

    log(f"\n--- Reorganizing: {channel_name} ---\n", "header")

    if target_years:
        if target_months:
            log(f"  Target structure: Year → Month subfolders\n", "dim")
        else:
            log(f"  Target structure: Year subfolders\n", "dim")
    else:
        log(f"  Target structure: Flat (all files in one folder)\n", "dim")

    moved_count = 0
    error_count = 0
    skipped_count = 0

    # Phase 1: Collect all video files from ALL locations (root, year folders, month folders)
    # Each entry: (current_path, mtime_datetime, folder_year, folder_month)
    # folder_year/folder_month come from the existing folder structure and are trusted
    # over mtime (which may reflect HTTP Last-Modified rather than actual upload date).
    all_files = []

    # Single pass over root folder — collect video files AND year subdirectories
    _year_dirs = []  # (path, year_int)
    try:
        for entry in os.scandir(folder_path):
            if entry.is_file() and os.path.splitext(entry.name)[1].lower() in VIDEO_EXTS:
                try:
                    mtime = datetime.fromtimestamp(entry.stat().st_mtime)
                    all_files.append((entry.path, mtime, None, None))
                except OSError:
                    all_files.append((entry.path, None, None, None))
            elif entry.is_dir() and _is_year_folder(entry.name):
                _year_dirs.append((entry.path, int(entry.name)))
    except OSError as e:
        log(f"  ERROR scanning root: {e}\n", "red")
        return

    # Scan year subfolders — trust year from folder name
    for _yd_path, f_year in _year_dirs:
        # Scan files directly in year folder
        try:
            for vid in os.scandir(_yd_path):
                if vid.is_file() and os.path.splitext(vid.name)[1].lower() in VIDEO_EXTS:
                    try:
                        mtime = datetime.fromtimestamp(vid.stat().st_mtime)
                        all_files.append((vid.path, mtime, f_year, None))
                    except OSError:
                        all_files.append((vid.path, None, f_year, None))
                elif vid.is_dir() and _is_month_folder(vid.name):
                    # Scan month subfolders within year folders — trust both year and month
                    f_month = _MONTH_FOLDER_LOOKUP[vid.name.lower()]
                    try:
                        for mv in os.scandir(vid.path):
                            if mv.is_file() and os.path.splitext(mv.name)[1].lower() in VIDEO_EXTS:
                                try:
                                    mtime = datetime.fromtimestamp(mv.stat().st_mtime)
                                    all_files.append((mv.path, mtime, f_year, f_month))
                                except OSError:
                                    all_files.append((mv.path, None, f_year, f_month))
                    except OSError:
                        pass
        except OSError:
            pass

    total = len(all_files)
    if total == 0:
        log(f"  No video files found in {folder_path}\n", "dim")
        log(f"--- Reorganization complete ---\n", "header")
        return

    log(f"  Found {total:,} video file(s) to process...\n", "dim")

    # Phase 2: Determine target path for each file and move if needed
    is_simple = _is_simple_mode
    _reorg_dots = [0]
    _reorg_anim_job = [None]
    _reorg_anim_active = [False]

    def _reorg_anim_tick():
        try:
            if not _reorg_anim_active[0] or not root.winfo_exists():
                return
            d = _DOTS[_reorg_dots[0] % 3]
            _reorg_dots[0] += 1
            log_simple_status(f"  → Moving {total:,} files{d}\n")
        except Exception:
            pass
        finally:
            if _reorg_anim_active[0] and root.winfo_exists():
                _reorg_anim_job[0] = root.after(500, _reorg_anim_tick)

    if is_simple:
        _reorg_anim_active[0] = True
        def _start_reorg_anim():
            if root.winfo_exists():
                _reorg_anim_job[0] = root.after(500, _reorg_anim_tick)
        _ui_queue.append(_start_reorg_anim)

    for i, (filepath, mtime, folder_year, folder_month) in enumerate(all_files):
        if cancel_event.is_set():
            log(f"  ⚠ Reorganization cancelled.\n", "red")
            # Stop the animation
            _reorg_anim_active[0] = False
            _old_rj = _reorg_anim_job[0]
            _reorg_anim_job[0] = None
            if _old_rj:
                _ui_queue.append(lambda j=_old_rj: root.after_cancel(j) if root.winfo_exists() else None)
            if is_simple:
                log_simple_status("")
            return False

        filename = os.path.basename(filepath)

        # Determine target directory
        # When trust_mtime is True (dates were just re-checked from YouTube), always
        # use mtime. Otherwise prefer folder names over mtime (mtime may reflect
        # HTTP Last-Modified rather than actual upload date) — BUT if the file's
        # mtime year disagrees with the folder year, trust mtime instead (the file
        # was likely placed in the wrong folder and its mtime has since been corrected).
        use_folder = not trust_mtime
        if use_folder and folder_year and mtime and mtime.year != folder_year:
            use_folder = False

        if not target_years:
            # Flat: everything goes to root
            target_dir = folder_path
        elif target_years and not target_months:
            # Year only
            if use_folder and folder_year:
                year_str = str(folder_year)
            elif mtime:
                year_str = str(mtime.year)
            else:
                year_str = "Unknown Year"
            target_dir = os.path.join(folder_path, year_str)
        else:
            # Year + month
            if use_folder and folder_year and folder_month:
                year_str = str(folder_year)
                month_str = MONTH_NAMES.get(folder_month, f"{folder_month:02d} Unknown")
            elif use_folder and folder_year:
                year_str = str(folder_year)
                # Have year from folder but no month — use mtime month as best guess
                if mtime:
                    month_str = MONTH_NAMES.get(mtime.month, f"{mtime.month:02d} Unknown")
                else:
                    month_str = "Unknown Month"
            elif mtime:
                year_str = str(mtime.year)
                month_str = MONTH_NAMES.get(mtime.month, f"{mtime.month:02d} Unknown")
            else:
                year_str = "Unknown Year"
                month_str = "Unknown Month"
            target_dir = os.path.join(folder_path, year_str, month_str)

        target_path = os.path.join(target_dir, filename)

        # Skip if already in the right place
        if os.path.normpath(filepath) == os.path.normpath(target_path):
            skipped_count += 1
            continue

        # Handle filename collision at target
        if os.path.exists(target_path):
            base, ext = os.path.splitext(filename)
            counter = 1
            while os.path.exists(target_path):
                target_path = os.path.join(target_dir, f"{base} ({counter}){ext}")
                counter += 1

        try:
            os.makedirs(target_dir, exist_ok=True)
            shutil.move(filepath, target_path)
            moved_count += 1
            if not is_simple:
                rel_target = os.path.relpath(target_dir, folder_path)
                log(f"  [{moved_count}/{total}] → {filename}  →  {rel_target}\n", "green")
            # Move companion files (thumbnail, subtitle, metadata) alongside the video
            _src_dir = os.path.dirname(filepath)
            _base_no_ext = os.path.splitext(filename)[0]
            _companion_exts = (".jpg", ".jpeg", ".png", ".webp", ".nfo", ".srt", ".vtt", ".ass", ".description", ".info.json")
            try:
                for _ce in os.scandir(_src_dir):
                    if _ce.is_file() and _ce.name.startswith(_base_no_ext) and _ce.name != filename:
                        # Verify the character after the base name is a dot to avoid
                        # matching "My Video Part 2.jpg" when base is "My Video"
                        if len(_ce.name) > len(_base_no_ext) and _ce.name[len(_base_no_ext)] != '.':
                            continue
                        _ce_ext_lower = _ce.name[len(_base_no_ext):].lower()
                        if _ce_ext_lower in _companion_exts:
                            _ce_target = os.path.join(target_dir, _ce.name)
                            if not os.path.exists(_ce_target):
                                shutil.move(_ce.path, _ce_target)
            except OSError:
                pass  # best-effort companion move
        except (OSError, shutil.Error) as e:
            log(f"  ⚠ Failed to move: {filename} — {e}\n", "red")
            error_count += 1

    # Stop the animation
    _reorg_anim_active[0] = False
    _old_rj = _reorg_anim_job[0]
    _reorg_anim_job[0] = None
    if _old_rj:
        _ui_queue.append(lambda j=_old_rj: root.after_cancel(j) if root.winfo_exists() else None)
    # Clear the animated status line
    if is_simple:
        log_simple_status("")

    # Phase 3: Clean up empty directories
    cleaned = 0
    for dirpath, dirnames, filenames in os.walk(folder_path, topdown=False):
        if dirpath == folder_path:
            continue
        rel = os.path.relpath(dirpath, folder_path)
        parts = rel.replace("\\", "/").split("/")
        # Only clean up year/month folders we manage
        if len(parts) <= 2 and (_is_year_folder(parts[0]) or parts[0] in ("Unknown Year",)):
            try:
                if not os.listdir(dirpath):
                    os.rmdir(dirpath)
                    cleaned += 1
            except OSError:
                pass

    summary_parts = []
    if moved_count: summary_parts.append(f"{moved_count:,} moved")
    if skipped_count: summary_parts.append(f"{skipped_count:,} already in place")
    if error_count: summary_parts.append(f"{error_count:,} errors")
    if cleaned: summary_parts.append(f"{cleaned:,} empty folders removed")

    log(f"  ✓ Done: {', '.join(summary_parts)}\n", "simpleline_green")
    log(f"--- Reorganization complete ---\n", "summary")
    return True


def _norm_ascii(text):
    """Normalize text to ASCII-only lowercase alphanumeric for fuzzy matching."""
    # NFKD decomposition turns é->e, ñ->n, etc.
    decomposed = unicodedata.normalize('NFKD', text.lower())
    # Keep only ASCII alphanumeric
    return re.sub(r'[^a-z0-9]', '', decomposed)


def _fix_file_dates(channel_url, folder_path):
    """Fetch upload dates from YouTube and fix file mtimes for accurate date sorting."""
    proc = None
    try:
        log(f"\n--- Fetching exact upload dates from YouTube (this may take a while)... ---\n", "header")

        # Use --skip-download (no --flat-playlist) to fetch exact upload dates
        # from each video's page. Slower than approximate_date but accurate.
        proc = spawn_yt_dlp([
            "yt-dlp", "--skip-download", "--no-warnings", "--ignore-errors",
            "--ignore-no-formats-error",
            "--sleep-requests", "1.0",
            "--print", "%(upload_date)s|||%(title)s",
            "--cookies-from-browser", "firefox",
            channel_url
        ])
        if not proc:
            log(f"  ⚠ Could not start yt-dlp to fetch dates.\n", "red")
            return

        # Build lookup: normalized title -> upload_date
        date_lookup = {}
        date_words = []  # [(upload_date, word_set), ...] for word-overlap fallback
        count = 0
        _last_progress_log = time.monotonic()

        # Animated dots for Simple mode (runs on main thread via root.after)
        _fetch_anim = {"active": True, "count": 0, "dot_i": 0, "job": None}
        _dot_cycle = [".  ", ".. ", "..."]

        def _animate_fetch_dots():
            if not _fetch_anim["active"] or not root.winfo_exists():
                return
            try:
                if _is_simple_mode and _fetch_anim["count"] > 0:
                    _fetch_anim["dot_i"] = (_fetch_anim["dot_i"] + 1) % 3
                    log_simple_status(f"  Fetched dates for {_fetch_anim['count']:,} videos so far{_dot_cycle[_fetch_anim['dot_i']]}\n")
                _fetch_anim["job"] = root.after(500, _animate_fetch_dots)
            except Exception:
                pass

        if root.winfo_exists():
            _ui_queue.append(lambda: _animate_fetch_dots())

        for line in proc.stdout:
            if cancel_event.is_set():
                break
            parts = line.strip().split("|||", 1)
            if len(parts) == 2:
                upload_date = parts[0].strip()
                title = parts[1].strip()
                if len(upload_date) == 8 and upload_date.isdigit():
                    # NFC-normalize to handle precomposed vs decomposed Unicode
                    title_nfc = unicodedata.normalize('NFC', title)
                    norm = re.sub(r'[^\w]', '', title_nfc.lower())
                    if norm:
                        date_lookup[norm] = upload_date
                    # Also store with pipe replaced (--replace-in-metadata swaps | to -)
                    norm_pipe = re.sub(r'[^\w]', '', title_nfc.replace('|', '-').lower())
                    if norm_pipe and norm_pipe != norm:
                        date_lookup[norm_pipe] = upload_date
                    # Also store ASCII-only normalized version (handles é, ñ, superscripts, etc.)
                    norm_ascii = _norm_ascii(title_nfc)
                    if norm_ascii and norm_ascii != norm:
                        date_lookup[norm_ascii] = upload_date
                    # Also store with yt-dlp filename sanitization applied (: → ：, etc.)
                    sanitized = title_nfc.replace(':', '：').replace('|', '｜').replace('"', '"').replace('?', '？').replace('*', '＊')
                    norm_sanitized = re.sub(r'[^\w]', '', sanitized.lower())
                    if norm_sanitized and norm_sanitized != norm:
                        date_lookup[norm_sanitized] = upload_date
                    # Build word set for word-overlap fallback (extract words from original title)
                    _words = set()
                    for _w in re.findall(r'\S+', title_nfc.lower()):
                        _aw = _norm_ascii(_w)
                        if len(_aw) >= 2:
                            _words.add(_aw)
                    if len(_words) >= 2:
                        date_words.append((upload_date, _words, norm_ascii or norm))
                    count += 1
                    _fetch_anim["count"] = count
                    is_simple = _is_simple_mode
                    if not is_simple:
                        # Verbose mode: log each video individually (use explicit "dim" tag
                        # to prevent auto-tag detection from coloring titles containing
                        # keywords like "failed" or "100%")
                        date_str = f"{upload_date[:4]}-{upload_date[4:6]}-{upload_date[6:]}"
                        log(f"  [{count:,}] {date_str}  {title_nfc}\n", "dim")
                    else:
                        # Simple mode: periodic summary (handled by dot animation)
                        pass

        # Stop the dot animation
        _fetch_anim["active"] = False
        _old_fetch_job = _fetch_anim.get("job")
        _fetch_anim["job"] = None
        if _old_fetch_job:
            _ui_queue.append(lambda j=_old_fetch_job: root.after_cancel(j) if root.winfo_exists() else None)

        if cancel_event.is_set():
            proc.terminate()
        try:
            proc.wait(timeout=10)
        except subprocess.TimeoutExpired:
            proc.kill()
            try:
                proc.wait(timeout=5)
            except Exception:
                pass
        cleanup_process(proc)
        proc = None

        clear_transient_lines()
        if cancel_event.is_set():
            log("⛔ Date check cancelled.\n", "red")
            return
        if not date_lookup:
            log(f"  ⚠ Could not fetch any dates from YouTube.\n", "red")
            return

        log(f"  Fetched dates for {count:,} videos. Matching to files...\n", "dim")

        # Pre-sort keys for binary-search prefix matching (avoids O(N*M) scans)
        _sorted_keys = sorted(date_lookup.keys())

        # Walk all video files and fix mtimes
        fixed = 0
        unmatched = 0
        already_correct = 0
        unmatched_files = []

        for dirpath, dirnames, filenames in os.walk(folder_path):
            for fname in filenames:
                if cancel_event.is_set():
                    return
                base, ext = os.path.splitext(fname)
                if ext.lower() not in VIDEO_EXTS:
                    continue

                filepath = os.path.join(dirpath, fname)
                # NFC-normalize filename to match NFC-normalized titles
                base_nfc = unicodedata.normalize('NFC', base)
                norm_fname = re.sub(r'[^\w]', '', base_nfc.lower())
                norm_fname_ascii = _norm_ascii(base_nfc)

                # Try exact normalized match
                upload_date = date_lookup.get(norm_fname)

                # Try ASCII-only normalized match (handles special chars stripped by filesystem)
                if not upload_date and norm_fname_ascii != norm_fname:
                    upload_date = date_lookup.get(norm_fname_ascii)

                # Try prefix match (--trim-filenames truncates long titles)
                # Uses binary search on sorted keys for O(log N) instead of O(N)
                if not upload_date and len(norm_fname) >= 15:
                    _idx = bisect.bisect_left(_sorted_keys, norm_fname)
                    # Check if a key at or near this position is a prefix match
                    for _bi in range(max(0, _idx - 1), min(len(_sorted_keys), _idx + 2)):
                        _sk = _sorted_keys[_bi]
                        if len(_sk) < 15:
                            continue
                        _min_l = min(len(_sk), len(norm_fname))
                        _max_l = max(len(_sk), len(norm_fname))
                        if _min_l / _max_l < 0.8:
                            continue
                        if _sk.startswith(norm_fname) or norm_fname.startswith(_sk):
                            upload_date = date_lookup[_sk]
                            break

                # Try ASCII prefix match using binary search
                if not upload_date and len(norm_fname_ascii) >= 10:
                    _idx = bisect.bisect_left(_sorted_keys, norm_fname_ascii)
                    for _bi in range(max(0, _idx - 1), min(len(_sorted_keys), _idx + 2)):
                        _sk = _sorted_keys[_bi]
                        if len(_sk) >= 10 and (_sk.startswith(norm_fname_ascii) or norm_fname_ascii.startswith(_sk)):
                            upload_date = date_lookup[_sk]
                            break

                # Word-overlap fallback: extract real words from original strings
                # Skip for very large channels (>5000 videos) to avoid O(N*M) stall
                if not upload_date and date_words and len(date_words) <= 5000:
                    fname_words = set()
                    for _w in re.findall(r'\S+', base_nfc.lower()):
                        _aw = _norm_ascii(_w)
                        if len(_aw) >= 2:
                            fname_words.add(_aw)
                    if len(fname_words) >= 4:
                        best_overlap = 0
                        best_date = None
                        for date_val, title_words, _ in date_words:
                            if len(title_words) < 4:
                                continue
                            overlap = len(fname_words & title_words) / max(len(fname_words), len(title_words))
                            if overlap > best_overlap and overlap >= 0.80:
                                best_overlap = overlap
                                best_date = date_val
                        if best_date:
                            upload_date = best_date

                # Substring containment fallback: catch near-matches from encoding/sanitization diffs
                # Uses bidirectional substring check instead of O(N^2) SequenceMatcher
                if not upload_date and norm_fname_ascii and len(norm_fname_ascii) >= 10 and len(date_words) <= 5000:
                    best_len = 0
                    best_date = None
                    _bi_a = {norm_fname_ascii[j:j+2] for j in range(len(norm_fname_ascii) - 1)}
                    for date_val, _, t_ascii in date_words:
                        if not t_ascii:
                            continue
                        # Check if one string contains most of the other (handles truncation/sanitization)
                        _shorter, _longer = (norm_fname_ascii, t_ascii) if len(norm_fname_ascii) <= len(t_ascii) else (t_ascii, norm_fname_ascii)
                        if len(_shorter) >= 10 and _shorter in _longer:
                            if len(_shorter) > best_len:
                                best_len = len(_shorter)
                                best_date = date_val
                        elif len(_shorter) >= 10:
                            # Check overlap ratio using set intersection of character bigrams
                            _bi_b = {t_ascii[j:j+2] for j in range(len(t_ascii) - 1)}
                            if _bi_a and _bi_b:
                                _overlap = len(_bi_a & _bi_b) / max(len(_bi_a), len(_bi_b))
                                if _overlap >= 0.80 and len(t_ascii) > best_len:
                                    best_len = len(t_ascii)
                                    best_date = date_val
                    if best_date:
                        upload_date = best_date

                if upload_date:
                    try:
                        ud = datetime.strptime(upload_date, "%Y%m%d")
                        ud_ts = ud.replace(hour=12).timestamp()
                        current_mtime = os.path.getmtime(filepath)
                        current_date = datetime.fromtimestamp(current_mtime).strftime("%Y%m%d")
                        if current_date != upload_date:
                            os.utime(filepath, (ud_ts, ud_ts))
                            fixed += 1
                        else:
                            already_correct += 1
                    except (ValueError, OSError):
                        unmatched += 1
                else:
                    unmatched += 1
                    unmatched_files.append(fname)

        # Log unmatched files for debugging
        if unmatched_files and not (_is_simple_mode):
            log(f"  Unmatched files ({len(unmatched_files)}):\n", "dim")
            for uf in unmatched_files[:20]:
                log(f"    - {uf}\n", "dim")
            if len(unmatched_files) > 20:
                log(f"    ... and {len(unmatched_files) - 20} more\n", "dim")

        parts = []
        if fixed:
            parts.append(f"{fixed:,} fixed")
        if already_correct:
            parts.append(f"{already_correct:,} already correct")
        if unmatched:
            parts.append(f"{unmatched:,} unmatched")
        log(f"  ✓ Date check complete: {', '.join(parts)}.\n", "simpleline_green")

    except Exception as e:
        log(f"  ⚠ Error fixing dates: {e}\n", "red")
    finally:
        if proc:
            cleanup_process(proc)


def _process_reorg_queue():
    """Process next queued reorganize if any. Returns True if one was started."""
    with _reorg_queue_lock:
        if not _reorg_queue:
            return False
        args = _reorg_queue.pop(0)
        remaining = len(_reorg_queue)

    ch_name, folder, t_years, t_months, ch_url, recheck = args
    with _queue_order_lock:
        try:
            _queue_order.remove(("reorg", ch_url or ch_name))
        except ValueError:
            pass
    if recheck:
        _current_job["label"] = f"Re-date & Organize {ch_name}"
    elif t_years:
        _current_job["label"] = f"Re-Organize {ch_name}"
    else:
        _current_job["label"] = f"Un-Organize {ch_name}"
    _update_queue_btn()
    log(f"\n=== Processing queued reorganize: {ch_name}", "header")
    if remaining:
        log(f" ({remaining} more in queue)", "header")
    log(f" ===\n", "header")
    _run_reorganize_auto(ch_name, folder, t_years, t_months, ch_url=ch_url, recheck_dates=recheck)
    return True


def _run_reorganize_auto(channel_name, folder_path, target_years, target_months, ch_url=None,
                         recheck_dates=False):
    """Trigger reorganization automatically after updating channel split settings."""
    global _reorg_running

    # If a reorg or sync is already running, queue this request.
    # Note: _already_running check is not fully atomic (flags read under different locks),
    # but this is benign — worst case we queue a redundant entry or start when another
    # task finishes between the check and start, which resolves harmlessly.
    with _reorg_queue_lock:
        _already_running = _reorg_running or _sync_running or _redownload_running
    if _already_running:
        with _reorg_queue_lock:
            if not any(q[0] == channel_name for q in _reorg_queue):
                _reorg_queue.append((channel_name, folder_path, target_years, target_months, ch_url, recheck_dates))
                with _queue_order_lock:
                    _queue_order.append(("reorg", ch_url or channel_name))
                log(f"\n=== Added {channel_name} reorganize to Sync List ===\n", "header")
            else:
                log(f"  ⚠ {channel_name} is already in the reorganize queue.\n", "simpleline")
        _update_queue_btn()
        return

    def _worker():
        global _reorg_running
        with _reorg_queue_lock:
            _reorg_running = True
        _update_global_pause_btn_sync()
        try:
            # If a cancel is already in-flight, respect it and bail out
            # instead of clearing it (which would erase user cancel intent).
            if cancel_event.is_set():
                return
            _ui_queue.append(lambda: _update_queue_btn())
            if recheck_dates and ch_url:
                _fix_file_dates(ch_url, folder_path)
                if cancel_event.is_set():
                    return
            success = _reorganize_channel_folder(channel_name, folder_path, target_years, target_months,
                                                   trust_mtime=recheck_dates)
            if success and ch_url:
                _chan_ctx_update_split(ch_url, target_years, target_months)
                # Update browse DB: delete stale rows for this channel, then rescan
                # so filepaths reflect the new directory structure.
                tp = _tp_panel_ref[0]
                if tp:
                    if not tp._conn:
                        try:
                            tp._conn = _tp_open_db(_TP_DB_PATH)
                        except Exception:
                            pass
                    if tp._conn:
                        try:
                            tp._db_execute("DELETE FROM videos WHERE channel=?", (channel_name,))
                            tp._db_commit()
                        except Exception:
                            pass
                # Rescan disk — re-registers videos at their new paths
                with config_lock:
                    _ch_cfg = None
                    for _c in config.get("channels", []):
                        if _c.get("url") == ch_url:
                            _ch_cfg = _c
                            break
                if _ch_cfg:
                    _update_disk_cache_for_channel(_ch_cfg)
                # Refresh browse tree on the UI thread
                if tp:
                    _ui_queue.append(lambda: tp._refresh_browse())
        finally:
            with _reorg_queue_lock:
                _reorg_running = False
            def _reorg_done():
                _sync_task_finished()
                if _reorg_done_job["id"]:
                    try:
                        root.after_cancel(_reorg_done_job["id"])
                    except Exception:
                        pass
                reorg_done_label.pack(side="left", padx=(4, 0))
                _reorg_done_job["id"] = root.after(5000, lambda: reorg_done_label.pack_forget())
            _ui_queue.append(_reorg_done)
            # Process any queued jobs in insertion order
            if _skip_current.is_set():
                _skip_current.clear()
                cancel_event.clear()
                _process_next_queued()
            elif not cancel_event.is_set():
                _process_next_queued()

    threading.Thread(target=_worker, daemon=True).start()


# ─── Transcription Feature ──────────────────────────────────────────────────────

def _parse_vtt_to_text(vtt_path):
    """Parse a .vtt subtitle file into clean plain text."""
    import html as _html_mod
    try:
        with open(vtt_path, "r", encoding="utf-8", errors="replace") as f:
            raw = f.read()
    except Exception:
        log(f"  {traceback.format_exc()}\n", "dim")
        return ""

    lines = raw.split("\n")
    clean = []
    prev = ""
    for line in lines:
        line = line.strip()
        # Skip WEBVTT header, NOTE lines, blank lines
        if not line or line.startswith("WEBVTT") or line.startswith("NOTE") or line.startswith("Kind:") or line.startswith("Language:"):
            continue
        # Skip timestamp lines (00:00:01.234 --> 00:00:04.567)
        if re.match(r'\d{2}:\d{2}', line) and '-->' in line:
            continue
        # Skip cue position markers
        if re.match(r'^\d+$', line):  # numeric cue IDs
            continue
        if 'align:' in line or 'position:' in line:
            continue
        # Strip HTML tags
        line = re.sub(r'<[^>]+>', '', line)
        # Decode HTML entities (&nbsp; &amp; &lt; etc.) to plain text
        line = _html_mod.unescape(line)
        # Normalize whitespace (non-breaking spaces, multiple spaces, etc.)
        line = re.sub(r'\s+', ' ', line).strip()
        if not line:
            continue
        # Collapse rolling YouTube caption overlaps: if the new line starts
        # with the previous line's text, it's a rolling cue extension — replace
        # the previous entry with this longer version instead of appending.
        if line == prev:
            continue  # exact duplicate — skip
        if prev and line.startswith(prev):
            # Rolling extension — replace previous with the longer version
            clean[-1] = line
            prev = line
        else:
            clean.append(line)
            prev = line

    return " ".join(clean)


def _parse_vtt_to_segments(vtt_path):
    """Parse a .vtt subtitle file into merged, deduplicated timestamped segments.

    YouTube VTT uses rolling captions where each cue repeats previous text and
    adds a few words.  This parser merges overlapping cues so the output has one
    clean segment per actual phrase with no duplication.

    YouTube auto-generated VTT embeds per-word timestamps via <c> tags, e.g.:
      hey<00:00:00.480><c> guys</c><00:00:00.720><c> this</c>
    These are extracted so each segment includes a "words" list with accurate
    per-word seek times (format: {"w": word, "s": start, "e": end}).

    Returns list of {"start", "end", "text", "words"} dicts.
    """
    import html as _html_mod
    try:
        with open(vtt_path, "r", encoding="utf-8", errors="replace") as f:
            raw = f.read()
    except Exception:
        log(f"  {traceback.format_exc()}\n", "dim")
        return []

    def _ts_to_secs(ts_str):
        """Convert 'HH:MM:SS.mmm' or 'MM:SS.mmm' to float seconds."""
        parts = ts_str.strip().split(":")
        if len(parts) == 3:
            return int(parts[0]) * 3600 + int(parts[1]) * 60 + float(parts[2])
        elif len(parts) == 2:
            return int(parts[0]) * 60 + float(parts[1])
        return 0.0

    # ── Step 1: Parse raw cues from VTT ──
    # Keep both cleaned text (for merge) and raw lines (for word extraction).
    raw_cues = []  # list of (start, end, text, raw_content_lines)
    lines = raw.split("\n")
    current_start = None
    current_end = None
    current_text = []
    current_raw = []

    for line in lines:
        line = line.strip()
        ts_match = re.match(r'(\d[\d:.]+)\s*-->\s*(\d[\d:.]+)', line)
        if ts_match:
            # Flush previous cue
            if current_text and current_start is not None:
                joined = " ".join(current_text)
                raw_cues.append((current_start, current_end, joined, list(current_raw)))
            current_start = _ts_to_secs(ts_match.group(1))
            current_end = _ts_to_secs(ts_match.group(2))
            current_text = []
            current_raw = []
            continue
        if not line or line.startswith("WEBVTT") or line.startswith("NOTE") or \
                line.startswith("Kind:") or line.startswith("Language:"):
            continue
        if re.match(r'^\d+$', line):
            continue
        if 'align:' in line or 'position:' in line:
            continue
        current_raw.append(line)
        cleaned = re.sub(r'<[^>]+>', '', line)
        cleaned = _html_mod.unescape(cleaned)
        cleaned = re.sub(r'\s+', ' ', cleaned).strip()
        if cleaned:
            current_text.append(cleaned)

    # Flush last cue
    if current_text and current_start is not None:
        joined = " ".join(current_text)
        raw_cues.append((current_start, current_end, joined, list(current_raw)))

    if not raw_cues:
        return []

    # ── Step 1b: Extract per-word timestamps from <c> tags ──
    # In YouTube rolling captions, each cue's NEW words have <timestamp><c> tags.
    # The prefix text (before any <c> tag) is repeated from the previous cue.
    # So: only extract tagged words (and the first cue's prefix).
    _ctag_re = re.compile(r'<(\d[\d:.]+)><c[^>]*>(.*?)</c>')
    _all_words = []
    _has_ctags = False

    for cue_idx, (cue_s, cue_e, _, raw_lines) in enumerate(raw_cues):
        for raw_line in raw_lines:
            tags = list(_ctag_re.finditer(raw_line))
            if tags:
                _has_ctags = True
                # First cue's untagged prefix is the genuine first word(s)
                if cue_idx == 0:
                    first_tag_pos = raw_line.find('<')
                    if first_tag_pos > 0:
                        prefix = _html_mod.unescape(raw_line[:first_tag_pos]).strip()
                        for pw in prefix.split():
                            pw = pw.strip()
                            if pw:
                                _all_words.append({"w": pw, "s": cue_s})
                # Extract each tagged word with its explicit timestamp
                for m in tags:
                    ts = _ts_to_secs(m.group(1))
                    word_text = _html_mod.unescape(m.group(2)).strip()
                    for w in word_text.split():
                        w = w.strip()
                        if w:
                            _all_words.append({"w": w, "s": ts})

    # If no <c> tags at all (manual subs), assign cue-start to each word.
    # Manual subs have short cues (~2-5 s) so this gives decent granularity
    # and — critically — populates the words field so the entry is not
    # mistakenly flagged as stale-whisper on future scans.
    if not _has_ctags:
        for cue_s, cue_e, text, _ in raw_cues:
            dur = cue_e - cue_s
            words_in_cue = text.strip().split()
            n = len(words_in_cue)
            for wi, w in enumerate(words_in_cue):
                # Distribute evenly across the cue duration
                _all_words.append({
                    "w": w,
                    "s": round(cue_s + dur * wi / max(n, 1), 3)
                })

    # Sort by timestamp and compute end times (each word ends when the next starts)
    _all_words.sort(key=lambda w: w["s"])
    for i in range(len(_all_words) - 1):
        _all_words[i]["e"] = round(_all_words[i + 1]["s"], 3)
    if _all_words:
        _all_words[-1]["e"] = round(raw_cues[-1][1], 3)
        for w in _all_words:
            w["s"] = round(w["s"], 3)

    # ── Step 2: Merge overlapping rolling cues ──
    # YouTube auto-subs emit cues where each new cue's text starts with the
    # tail of the previous cue's text plus new words.  We detect overlap by
    # checking if the new cue's text starts with a suffix of the current
    # accumulated text, and if so, only keep the new words.
    _MAX_SEG_SECS = 30.0   # flush a segment if it grows beyond this duration
    segments = []
    seg_start = raw_cues[0][0]
    seg_end = raw_cues[0][1]
    seg_text = raw_cues[0][2]

    for i in range(1, len(raw_cues)):
        _s, _e, _t, _ = raw_cues[i]

        # Check if this cue is a rolling continuation of the current segment.
        # A rolling cue's text typically starts with a suffix of seg_text.
        _is_overlap = False
        if seg_text and _t:
            # Check if the new cue text starts with the end of the accumulated text
            # Try matching the last N words of seg_text against the start of _t
            seg_words = seg_text.split()
            new_words = _t.split()
            # Try overlap lengths from large to small
            max_overlap = min(len(seg_words), len(new_words) - 1, 20)
            for ol in range(max_overlap, 0, -1):
                if seg_words[-ol:] == new_words[:ol]:
                    extra = " ".join(new_words[ol:])
                    _is_overlap = True
                    # Cap: if extending would push beyond the max duration,
                    # flush the current segment *before* adding new text so
                    # flushed segments stay ≤ _MAX_SEG_SECS.
                    if (_e - seg_start) > _MAX_SEG_SECS:
                        if seg_text.strip():
                            segments.append({"start": seg_start, "end": seg_end,
                                             "text": seg_text.strip()})
                        seg_start = _s
                        seg_end = _e
                        seg_text = _t
                    else:
                        if extra:
                            seg_text += " " + extra
                        seg_end = _e
                    break

            # Also catch near-zero-duration "echo" cues (e.g., 805.91→805.92)
            # that just repeat the tail without adding new words
            if not _is_overlap and (_e - _s) < 0.1:
                _is_overlap = True  # skip it
                seg_end = max(seg_end, _e)

        if not _is_overlap:
            # Flush current segment and start a new one
            if seg_text.strip():
                segments.append({"start": seg_start, "end": seg_end, "text": seg_text.strip()})
            seg_start = _s
            seg_end = _e
            seg_text = _t

    # Flush final segment
    if seg_text.strip():
        segments.append({"start": seg_start, "end": seg_end, "text": seg_text.strip()})

    # ── Step 2b: Split any segments that still exceed the cap ──
    # The overlap-merge cap only fires during rolling-cue merges.  Manual subs
    # (or any non-overlapping content) can produce segments well over the cap.
    # Split them here so downstream code never sees oversized segments.
    _capped = []
    for seg in segments:
        dur = seg["end"] - seg["start"]
        if dur <= _MAX_SEG_SECS:
            _capped.append(seg)
            continue
        words = seg["text"].split()
        n = max(2, int(dur / _MAX_SEG_SECS) + (1 if dur % _MAX_SEG_SECS > 1 else 0))
        cdur = dur / n
        wper = max(1, len(words) // n)
        for ci in range(n):
            w0 = ci * wper
            w1 = w0 + wper if ci < n - 1 else len(words)
            ct = " ".join(words[w0:w1])
            if not ct:
                continue
            cs = round(seg["start"] + ci * cdur, 2)
            ce = round(min(seg["end"], seg["start"] + (ci + 1) * cdur), 2)
            _capped.append({"start": cs, "end": ce, "text": ct})
    segments = _capped

    # ── Step 3: Attach per-word timestamps to merged segments ──
    if _all_words:
        _widx = 0
        for seg in segments:
            seg_words = []
            # Advance past words that ended before this segment
            # (reset _widx backward if a split sub-segment starts before current _widx)
            while _widx > 0 and _widx < len(_all_words) and _all_words[_widx]["s"] >= seg["start"] - 0.5:
                _widx -= 1
            while _widx < len(_all_words) and _all_words[_widx]["s"] < seg["start"] - 0.5:
                _widx += 1
            _scan = _widx
            while _scan < len(_all_words) and _all_words[_scan]["s"] <= seg["end"] + 0.5:
                seg_words.append(_all_words[_scan])
                _scan += 1
            if seg_words:
                seg["words"] = seg_words
            else:
                seg["words"] = _generate_distributed_words(
                    seg["text"], seg["start"], seg["end"])
            _widx = _scan
    else:
        # No word-level timestamps at all — generate distributed timestamps
        for seg in segments:
            seg["words"] = _generate_distributed_words(
                seg["text"], seg["start"], seg["end"])

    return segments


def _generate_distributed_words(text, start, end):
    """Generate evenly-distributed word timestamps from text and a time range.

    Used as a fallback when real word-level timestamps aren't available.
    Distributes words proportionally across the segment's duration so that
    clicking any word in the transcript viewer seeks to a reasonable position.
    """
    words = text.split()
    if not words:
        return []
    dur = max(end - start, 0.01)
    step = dur / len(words)
    return [{"w": w, "s": round(start + i * step, 3),
             "e": round(start + (i + 1) * step, 3)}
            for i, w in enumerate(words)]


def _get_jsonl_path(txt_path):
    """Get the hidden JSONL file path corresponding to a transcript .txt path."""
    dirname = os.path.dirname(txt_path)
    basename = os.path.basename(txt_path)
    root_name, _ = os.path.splitext(basename)
    jsonl_name = "." + root_name + ".jsonl"
    return os.path.join(dirname, jsonl_name)


def _hide_file_win(path):
    """Set the hidden attribute on a file (Windows only)."""
    if os.name == "nt":
        try:
            ctypes.windll.kernel32.SetFileAttributesW(path, 0x02)  # FILE_ATTRIBUTE_HIDDEN
        except Exception:
            pass


def _write_jsonl_entry(jsonl_path, video_id, title, segments):
    """Append JSONL lines for one video's timestamped segments.

    Builds the new lines in memory first, then appends in a single write so a
    partial disk failure cannot leave a half-written entry in the file.
    """
    try:
        _jsonl_dir = os.path.dirname(jsonl_path)
        if _jsonl_dir:
            os.makedirs(_jsonl_dir, exist_ok=True)
        # Build all lines in memory first
        new_lines = []
        for seg in segments:
            entry = {
                "video_id": video_id or "",
                "title": title,
                "start": round(seg["start"], 2),
                "end": round(seg["end"], 2),
                "text": seg["text"]
            }
            if "words" in seg and seg["words"]:
                entry["words"] = seg["words"]
            else:
                # Always include word timestamps — generate evenly-distributed
                # ones when real word-level data isn't available.
                entry["words"] = _generate_distributed_words(
                    seg["text"], seg["start"], seg["end"])
            new_lines.append(json.dumps(entry, ensure_ascii=False) + "\n")
        # Single write — reduces risk of partial entries on disk errors.
        # First, repair any truncated last line left by a previous crash:
        # if the file exists and its last line isn't valid JSON, remove it.
        if os.path.isfile(jsonl_path):
            try:
                with open(jsonl_path, "rb") as _chk:
                    _chk.seek(0, 2)
                    _fsize = _chk.tell()
                    if _fsize > 0:
                        # Read last 8KB to find the final newline
                        _read_back = min(_fsize, 8192)
                        _chk.seek(_fsize - _read_back)
                        _tail = _chk.read().decode("utf-8", errors="replace")
                        _last_nl = _tail.rfind("\n", 0, len(_tail) - 1)
                        _last_line = _tail[_last_nl + 1:].strip() if _last_nl >= 0 else _tail.strip()
                        if _last_line:
                            try:
                                json.loads(_last_line)
                            except (json.JSONDecodeError, ValueError):
                                # Truncated line — remove it by truncating the file
                                _trunc_pos = (_fsize - _read_back + _last_nl + 1) if _last_nl >= 0 else 0
                                if _trunc_pos <= 0 and _fsize > 0:
                                    pass  # No valid newline found — don't wipe the entire file
                                elif _trunc_pos > 0:
                                    with open(jsonl_path, "r+b") as _fix:
                                        _fix.seek(_trunc_pos)
                                        _fix.truncate()
            except Exception:
                pass  # best-effort repair; don't block the write
        with open(jsonl_path, "a", encoding="utf-8") as f:
            f.writelines(new_lines)
            f.flush()
            os.fsync(f.fileno())
        _hide_file_win(jsonl_path)
    except Exception as _jsonl_err:
        try:
            log(f"  ⚠ JSONL write failed for {video_id}: {_jsonl_err}\n", "red")
        except Exception:
            pass


def _scan_existing_jsonl(folder_path, ch_name):
    """Scan JSONL transcript files under folder_path.

    Returns a set of video titles that already have JSONL entries.
    """
    existing = set()
    for dirpath, _dirs, files in os.walk(folder_path):
        for f in files:
            if f.startswith("." + ch_name + " ") and f.endswith("Transcript.jsonl"):
                _jsonl_full = os.path.join(dirpath, f)
                try:
                    _corrupt_lines = 0
                    with open(_jsonl_full, "r", encoding="utf-8") as fh:
                        for line in fh:
                            line = line.strip()
                            if line:
                                try:
                                    entry = json.loads(line)
                                    title = entry.get("title", "")
                                    if title:
                                        existing.add(title)
                                except (json.JSONDecodeError, ValueError):
                                    _corrupt_lines += 1
                    if _corrupt_lines and not _is_simple_mode:
                        try:
                            log(f"  ⚠ {_corrupt_lines} corrupt line(s) in {f} — skipped.\n", "red")
                        except Exception:
                            pass
                except Exception as _scan_err:
                    try:
                        log(f"  ⚠ Error reading JSONL {f}: {_scan_err}\n", "dim")
                    except Exception:
                        pass
    return existing


def _remove_jsonl_entries_for_title(jsonl_path, title):
    """Rewrite a JSONL file, dropping every line whose title matches *title*.
    Called before re-writing corrected segments so old bad entries are replaced.
    Uses atomic write-to-tmp + os.replace to avoid data loss on crash.
    """
    try:
        with open(jsonl_path, "r", encoding="utf-8") as fh:
            lines = fh.readlines()
        kept = []
        for line in lines:
            stripped = line.strip()
            if stripped:
                try:
                    if json.loads(stripped).get("title", "") != title:
                        kept.append(line)
                except Exception:
                    kept.append(line)   # keep malformed lines untouched
            else:
                kept.append(line)
        tmp_path = jsonl_path + ".tmp"
        with open(tmp_path, "w", encoding="utf-8") as fh:
            fh.writelines(kept)
        os.replace(tmp_path, jsonl_path)
        _hide_file_win(jsonl_path)
    except Exception:
        log(f"  {traceback.format_exc()}\n", "dim")


def _remove_jsonl_entries_for_title_all_files(folder_path, ch_name, title):
    """Walk all JSONL files for *ch_name* under *folder_path* and remove entries
    whose title matches *title*.  Needed because year-split routing may differ
    between initial transcription (upload date) and backfill (file mtime)."""
    for dirpath, _dirs, files in os.walk(folder_path):
        for f in files:
            if f.startswith("." + ch_name + " ") and f.endswith("Transcript.jsonl"):
                _remove_jsonl_entries_for_title(os.path.join(dirpath, f), title)


# Path to Python 3.11 with CUDA PyTorch + Whisper installed
# Auto-detect: check common install locations, fall back to PATH
def _find_python311():
    # Check standard Windows install locations
    import glob as _glob_mod
    _candidates = []
    for _base in [os.path.expandvars(r"%LOCALAPPDATA%\Programs\Python"),
                  r"C:\Python311", r"C:\Python310",
                  os.path.expandvars(r"%PROGRAMFILES%\Python311"),
                  os.path.expandvars(r"%PROGRAMFILES(X86)%\Python311")]:
        _candidates.extend(_glob_mod.glob(os.path.join(_base, "Python311*", "python.exe")))
        _p = os.path.join(_base, "python.exe")
        if os.path.isfile(_p):
            _candidates.append(_p)
    if _candidates:
        return _candidates[0]
    # Try PATH
    import shutil as _shutil_mod
    for _name in ("python3.11", "python"):
        _found = _shutil_mod.which(_name)
        if _found:
            return _found
    # Ultimate fallback — common location
    return os.path.expandvars(r"%LOCALAPPDATA%\Programs\Python\Python311\python.exe")

_WHISPER_PYTHON = _find_python311()
_whisper_proc = None  # persistent Whisper subprocess (model stays loaded)
_whisper_line_queue = None  # queue.Queue for subprocess stdout lines (module-level to avoid race)
_whisper_starting = False  # guard against concurrent startup attempts
_whisper_last_failed = False  # True when last whisper call was a stall/crash (not "no speech")
_whisper_model_choice = "large-v3"  # selected model — set via dialog before transcription
_whisper_model_lock = threading.Lock()  # protects _whisper_model_choice during re-transcription
_ffmpeg_proc = None  # ffmpeg encode subprocess (for compression feature)

# Whisper helper script — runs under Python 3.11 with CUDA, stays alive accepting JSON requests
# Uses faster-whisper (CTranslate2 backend) for ~4x speedup + built-in VAD to prevent hallucination loops
_WHISPER_SCRIPT = r'''
import sys, json, os, io

# Save real stdout for our JSON protocol, redirect stdout/stderr to suppress
# any prints from huggingface_hub downloads, tqdm bars, or import warnings
_out = sys.stdout
sys.stdout = io.StringIO()
sys.stderr = io.StringIO()

# faster-whisper uses CTranslate2 — no PyTorch needed for inference
from faster_whisper import WhisperModel

_model_name = os.environ.get("WHISPER_MODEL", "large-v3")
_device = os.environ.get("WHISPER_DEVICE", "cuda")
_compute = os.environ.get("WHISPER_COMPUTE", "float16")

try:
    model = WhisperModel(_model_name, device=_device, compute_type=_compute)
except Exception:
    _device = "cpu"
    _compute = "default"
    model = WhisperModel(_model_name, device=_device, compute_type=_compute)

# Restore stderr for real errors during transcription, keep stdout suppressed
sys.stderr = sys.__stderr__

_out.write(json.dumps({"status": "ready", "device": _device}) + "\n")
_out.flush()

for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        req = json.loads(line)
        path = req.get("path", "")
        duration = req.get("duration", 0)
    except json.JSONDecodeError:
        path = line
        duration = 0
    if not path:
        continue
    try:
        # Notify the host immediately so it knows the subprocess is alive.
        # model.transcribe() with vad_filter=True can block for many minutes
        # during VAD pre-processing before returning, so this heartbeat must
        # come BEFORE the call — not after.
        _out.write(json.dumps({"status": "starting"}) + "\n")
        _out.flush()
        segments_gen, info = model.transcribe(
            path,
            language="en",
            beam_size=5,
            vad_filter=True,
            vad_parameters=dict(min_silence_duration_ms=500),
            condition_on_previous_text=False,
            no_speech_threshold=0.6,
            word_timestamps=True,
        )
        # info.duration is the total audio length in seconds
        total_dur = info.duration if info.duration and info.duration > 0 else duration
        all_segments = []
        last_pct = -1
        for seg in segments_gen:
            all_segments.append(seg)
            if total_dur > 0:
                pct = min(99, int(seg.end / total_dur * 100))
                if pct > last_pct:
                    last_pct = pct
                    _out.write(json.dumps({"status": "progress", "pct": pct}) + "\n")
                    _out.flush()

        text = " ".join(seg.text.strip() for seg in all_segments if seg.text.strip())

        # Split any segment longer than 30 s into sub-segments using actual word
        # timestamps where available, falling back to proportional split otherwise.
        _MAX_SEG = 30.0
        seg_data = []
        for seg in all_segments:
            t = seg.text.strip()
            if not t:
                continue
            dur = seg.end - seg.start
            # Collect word-level timestamps for this segment
            raw_words = [w for w in (seg.words or []) if w.word.strip()]
            if dur <= _MAX_SEG:
                w_data = [{"w": w.word.strip(), "s": round(w.start, 3), "e": round(w.end, 3)}
                          for w in raw_words]
                seg_data.append({"s": round(seg.start, 2), "e": round(seg.end, 2),
                                 "t": t, "w": w_data})
            elif raw_words:
                # Split at actual word boundaries using real timestamps
                n_chunks = max(2, int(dur / _MAX_SEG) + (1 if dur % _MAX_SEG > 1 else 0))
                wpc = max(1, len(raw_words) // n_chunks)
                for ci in range(n_chunks):
                    wi0 = ci * wpc
                    wi1 = wi0 + wpc if ci < n_chunks - 1 else len(raw_words)
                    chunk_ws = raw_words[wi0:wi1]
                    if not chunk_ws:
                        continue
                    chunk_text = " ".join(w.word.strip() for w in chunk_ws)
                    w_data = [{"w": w.word.strip(), "s": round(w.start, 3), "e": round(w.end, 3)}
                              for w in chunk_ws]
                    seg_data.append({"s": round(chunk_ws[0].start, 2),
                                     "e": round(chunk_ws[-1].end, 2),
                                     "t": chunk_text, "w": w_data})
            else:
                # Fallback: proportional split (no word timestamps available)
                words = t.split()
                n_chunks = max(2, int(dur / _MAX_SEG) + (1 if dur % _MAX_SEG > 1 else 0))
                chunk_dur = dur / n_chunks
                wpc = max(1, len(words) // n_chunks)
                for ci in range(n_chunks):
                    wi0 = ci * wpc
                    wi1 = wi0 + wpc if ci < n_chunks - 1 else len(words)
                    chunk_text = " ".join(words[wi0:wi1])
                    if not chunk_text:
                        continue
                    cs = round(seg.start + ci * chunk_dur, 2)
                    ce = round(min(seg.end, seg.start + (ci + 1) * chunk_dur), 2)
                    seg_data.append({"s": cs, "e": ce, "t": chunk_text, "w": []})

        _out.write(json.dumps({"status": "ok", "text": text, "segments": seg_data}) + "\n")
        _out.flush()
    except Exception as e:
        _out.write(json.dumps({"status": "error", "text": str(e)}) + "\n")
        _out.flush()
'''


# Punctuation helper script — runs under Python 3.11 with CUDA, stays alive accepting JSON requests
_PUNCT_SCRIPT = r'''
import sys, json, io, re, os, logging

_out = sys.stdout
sys.stdout = io.StringIO()
sys.stderr = io.StringIO()

os.environ["HF_HUB_DISABLE_SYMLINKS_WARNING"] = "1"
os.environ["TRANSFORMERS_NO_ADVISORY_WARNINGS"] = "1"
os.environ["HF_HUB_DISABLE_TELEMETRY"] = "1"
os.environ["TOKENIZERS_PARALLELISM"] = "false"

for _name in ("transformers", "huggingface_hub", "safetensors", "transformers.modeling_utils"):
    logging.getLogger(_name).setLevel(logging.ERROR)

try:
    from transformers import pipeline as tf_pipeline
    import torch

    device_str = "cuda" if torch.cuda.is_available() else "cpu"
    pipe = tf_pipeline("ner", "oliverguhr/fullstop-punctuation-multilang-large",
                       aggregation_strategy="none",
                       device=0 if device_str == "cuda" else -1)

    _out.write(json.dumps({"status": "ready", "device": device_str}) + "\n")
    _out.flush()
except Exception as e:
    _out.write(json.dumps({"status": "error", "text": str(e)}) + "\n")
    _out.flush()
    sys.exit(1)

for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        req = json.loads(line)
        text = req.get("text", "")
    except json.JSONDecodeError:
        continue
    if not text:
        _out.write(json.dumps({"status": "ok", "text": ""}) + "\n")
        _out.flush()
        continue

    try:
        cleaned = re.sub(r"(?<!\d)[.,;:!?](?!\d)", "", text)
        words = cleaned.split()
        if not words:
            _out.write(json.dumps({"status": "ok", "text": text}) + "\n")
            _out.flush()
            continue

        chunk_size = 230
        overlap = 5 if len(words) > chunk_size else 0

        def _chunk(lst, n, stride):
            for i in range(0, len(lst), n - stride):
                yield lst[i:i + n]

        batches = list(_chunk(words, chunk_size, overlap))
        if len(batches) > 1 and len(batches[-1]) <= overlap:
            batches.pop()

        tagged = []
        for batch in batches:
            ov = 0 if batch is batches[-1] else overlap
            text_chunk = " ".join(batch)
            result = pipe(text_chunk)
            char_index = 0
            result_index = 0
            for word in batch[:len(batch) - ov]:
                char_index += len(word) + 1
                label = "0"
                while result_index < len(result) and char_index > result[result_index]["end"]:
                    label = result[result_index]["entity"]
                    result_index += 1
                tagged.append((word, label))

        out = ""
        for word, label in tagged:
            out += word
            if label == "0":
                out += " "
            elif label in ".,?-:":
                out += label + " "
        out = out.strip()

        out = re.sub(r"([.!?]\s+)(\w)", lambda m: m.group(1) + m.group(2).upper(), out)
        if out:
            out = out[0].upper() + out[1:]

        _out.write(json.dumps({"status": "ok", "text": out}) + "\n")
        _out.flush()
    except Exception as e:
        _out.write(json.dumps({"status": "error", "text": str(e)}) + "\n")
        _out.flush()
'''


def _check_punct_installed():
    """Check if transformers is installed under Python 3.11."""
    if not os.path.exists(_WHISPER_PYTHON):
        return False
    try:
        result = subprocess.run(
            [_WHISPER_PYTHON, "-c", "from transformers import pipeline; print('ok')"],
            capture_output=True, text=True, timeout=30, startupinfo=startupinfo
        )
        return result.returncode == 0 and "ok" in result.stdout
    except Exception:
        return False


def _install_punct_blocking():
    """Install transformers under Python 3.11. Returns True on success."""
    if not os.path.exists(_WHISPER_PYTHON):
        log(f"  ⚠ Python 3.11 not found at {_WHISPER_PYTHON}\n", "red")
        return False
    try:
        log("  Installing transformers library for punctuation...\n", "simpleline")
        result = subprocess.run(
            [_WHISPER_PYTHON, "-m", "pip", "install", "transformers"],
            capture_output=True, text=True, timeout=600, startupinfo=startupinfo
        )
        if result.returncode == 0:
            log("  ✓ Punctuation library installed.\n", "simpleline_green")
            return True
        else:
            log(f"  ⚠ Punctuation library install failed: {result.stderr[:300]}\n", "red")
            return False
    except Exception as e:
        log(f"  ⚠ Punctuation library install error: {e}\n", "red")
        return False


def _start_punct_process():
    """Start the persistent punctuation subprocess under Python 3.11. Returns True if ready."""
    global _punct_proc
    with _punct_lock:
        if _punct_proc is not None and _punct_proc.poll() is None:
            return True  # Already running

        try:
            log("  Loading punctuation model...\n", "simpleline_blue")
            _punct_proc = subprocess.Popen(
                [_WHISPER_PYTHON, "-c", _PUNCT_SCRIPT],
                stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                text=True, bufsize=1, startupinfo=startupinfo
            )
            # Use thread+join pattern to avoid indefinite readline block
            _ready_result = [None]
            def _read_punct_ready():
                try:
                    _ready_result[0] = _punct_proc.stdout.readline().strip()
                except Exception:
                    pass
            _rt = threading.Thread(target=_read_punct_ready, daemon=True)
            _rt.start()
            _rt.join(timeout=120)  # 2 minutes max for model loading
            ready_line = _ready_result[0] if not _rt.is_alive() else None
            if _rt.is_alive():
                log("  ⚠ Punctuation process timed out during startup.\n", "red")
                _stop_punct_process()
                return False
            if ready_line:
                try:
                    info = json.loads(ready_line)
                except (json.JSONDecodeError, ValueError):
                    log(f"  ⚠ Punctuation process sent non-JSON: {ready_line[:200]}\n", "red")
                    _stop_punct_process()
                    return False
                if info.get("status") == "ready":
                    log(f"  — ✓ Punctuation model loaded ({info.get('device', '?').upper()}).\n", "simpleline_green")
                    return True
                elif info.get("status") == "error":
                    log(f"  ⚠ Punctuation model failed: {info.get('text', 'unknown')}\n", "red")
                    _stop_punct_process()
                    return False
            log("  ⚠ Punctuation process did not start correctly.\n", "red")
            _stop_punct_process()
            return False
        except Exception as e:
            log(f"  ⚠ Failed to start punctuation process: {e}\n", "red")
            _stop_punct_process()
            return False


def _stop_punct_process():
    """Stop the persistent punctuation subprocess."""
    global _punct_proc
    with _punct_lock:
        if _punct_proc is not None:
            try:
                _punct_proc.stdin.close()
                _punct_proc.terminate()
                _punct_proc.wait(timeout=10)
            except Exception:
                try:
                    _punct_proc.kill()
                except Exception:
                    pass
            _punct_proc = None


def _check_whisper_installed():
    """Check if faster-whisper + CUDA CTranslate2 is installed under Python 3.11."""
    if not os.path.exists(_WHISPER_PYTHON):
        return False
    try:
        result = subprocess.run(
            [_WHISPER_PYTHON, "-c",
             "from faster_whisper import WhisperModel; import ctranslate2; print(ctranslate2.get_cuda_device_count() > 0)"],
            capture_output=True, text=True, timeout=30, startupinfo=startupinfo
        )
        return result.returncode == 0 and "True" in result.stdout
    except Exception:
        return False


def _install_whisper_blocking():
    """Install faster-whisper + CUDA PyTorch (for punctuation) under Python 3.11. Returns True on success."""
    if not os.path.exists(_WHISPER_PYTHON):
        log(f"  ⚠ Python 3.11 not found at {_WHISPER_PYTHON}\n", "red")
        return False
    try:
        # Step 0: Remove old openai-whisper if installed (cleanup, saves disk space)
        subprocess.run(
            [_WHISPER_PYTHON, "-m", "pip", "uninstall", "-y", "openai-whisper"],
            capture_output=True, text=True, timeout=120, startupinfo=startupinfo
        )

        # Step 1: Install CUDA PyTorch (still needed for punctuation subprocess)
        log("  Installing CUDA PyTorch under Python 3.11...\n", "simpleline")
        torch_result = subprocess.run(
            [_WHISPER_PYTHON, "-m", "pip", "install",
             "torch", "torchvision", "torchaudio",
             "--index-url", "https://download.pytorch.org/whl/cu121"],
            capture_output=True, text=True, timeout=900, startupinfo=startupinfo
        )
        if torch_result.returncode == 0:
            log("  ✓ CUDA PyTorch installed.\n", "simpleline_green")
        else:
            log(f"  ⚠ CUDA PyTorch install failed: {torch_result.stderr[:300]}\n", "red")
            return False

        # Step 2: Install faster-whisper (CTranslate2 backend — ~4x faster than openai-whisper)
        log("  Installing faster-whisper...\n", "simpleline")
        result = subprocess.run(
            [_WHISPER_PYTHON, "-m", "pip", "install", "faster-whisper"],
            capture_output=True, text=True, timeout=600, startupinfo=startupinfo
        )
        if result.returncode == 0:
            log("  ✓ faster-whisper installed successfully.\n", "simpleline_green")
            return True
        else:
            log(f"  ⚠ faster-whisper install failed: {result.stderr[:500]}\n", "red")
            return False
    except Exception as e:
        log(f"  ⚠ Whisper install error: {e}\n", "red")
        return False


def _start_whisper_process():
    """Start the persistent Whisper subprocess under Python 3.11. Returns True if ready."""
    global _whisper_proc, _whisper_line_queue, _whisper_starting
    with _whisper_lock:
        if _whisper_proc is not None and _whisper_proc.poll() is None:
            return True  # Already running
        if _whisper_starting:
            return False  # Another thread is already starting the process
        _whisper_starting = True
        _whisper_proc = None  # ensure clean state

    try:
        _model = _whisper_model_choice
        _hf_cache = os.path.join(os.environ.get("HF_HOME", os.path.join(os.path.expanduser("~"), ".cache", "huggingface")), "hub")
        _model_cached = os.path.isdir(os.path.join(_hf_cache, f"models--Systran--faster-whisper-{_model}"))
        _dl_hint = "" if _model_cached else " (first run downloads model)"
        log(f"  Transcribing - Loading Whisper model ({_model}) on GPU...{_dl_hint}\n", "transcribe_using")
        _env = os.environ.copy()
        _env["WHISPER_MODEL"] = _model
        _env["WHISPER_DEVICE"] = "cuda"
        _env["WHISPER_COMPUTE"] = "float16"
        # stderr=DEVNULL prevents a classic pipe-deadlock: CTranslate2's C++ layer
        # writes warnings/logs to fd 2, and if the pipe buffer fills (nobody reads it)
        # the subprocess blocks — freezing transcription at 0%.
        _whisper_proc = subprocess.Popen(
            [_WHISPER_PYTHON, "-c", _WHISPER_SCRIPT],
            stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.DEVNULL,
            text=True, bufsize=1, startupinfo=startupinfo, env=_env
        )
        # Wait for "ready" message (model loading) with timeout to avoid indefinite block
        _ready_result = [None]
        def _read_whisper_ready():
            try:
                _ready_result[0] = _whisper_proc.stdout.readline().strip()
            except Exception:
                pass
        _wrt = threading.Thread(target=_read_whisper_ready, daemon=True)
        _wrt.start()
        _wrt.join(timeout=300)  # 5 minutes max for model download + loading
        ready_line = _ready_result[0] if not _wrt.is_alive() else None
        if _wrt.is_alive():
            log("  ⚠ Whisper process timed out during model loading.\n", "red")
            _stop_whisper_process()
            return False
        if ready_line:
            try:
                info = json.loads(ready_line)
            except (json.JSONDecodeError, ValueError):
                log(f"  ⚠ Whisper process sent non-JSON: {ready_line[:200]}\n", "red")
                _stop_whisper_process()
                return False
            if info.get("status") == "ready":
                log(f"  — ✓ Whisper model loaded ({_model}, {info.get('device', '?').upper()}).\n", "simpleline_green")
                # Start a single reader thread for the lifetime of this subprocess.
                # Previous code created a new reader thread per _whisper_transcribe()
                # call — but old threads kept blocking on readline(), racing with new
                # threads and "stealing" response lines, causing lost output and stalls.
                _whisper_line_queue = queue.Queue()
                _proc_ref = _whisper_proc  # local ref so the closure reads from THIS
                                           # process even after _whisper_proc is reset to None
                def _reader(_q=_whisper_line_queue):
                    # _q is captured by default-arg at definition time, so even
                    # if the global _whisper_line_queue is set to None later,
                    # this thread still holds a valid reference and can exit.
                    try:
                        for _ln in iter(_proc_ref.stdout.readline, ""):
                            try:
                                _q.put(_ln)
                            except Exception:
                                break  # queue no longer usable — exit
                    except Exception:
                        pass
                    try:
                        _q.put(None)  # sentinel — stream closed
                    except Exception:
                        pass
                threading.Thread(target=_reader, daemon=True).start()
                return True
        log("  ⚠ Whisper process did not start correctly.\n", "red")
        _stop_whisper_process()
        return False
    except Exception as e:
        log(f"  ⚠ Failed to start Whisper process: {e}\n", "red")
        _stop_whisper_process()
        return False
    finally:
        with _whisper_lock:
            _whisper_starting = False


def _check_cuda_available():
    """Check if CUDA GPU is available for Whisper. Returns True/False."""
    try:
        result = subprocess.run(
            [_WHISPER_PYTHON, "-c", "import torch; print(torch.cuda.is_available())"],
            capture_output=True, text=True, timeout=30, startupinfo=startupinfo
        ) if os.path.exists(_WHISPER_PYTHON) else None
        return result is not None and "True" in result.stdout
    except Exception:
        return False


def _stop_whisper_process(force=False):
    """Stop the persistent Whisper subprocess.

    If force=True (used after stalls), skip terminate() and go straight to kill(),
    and also kill the entire process tree to ensure CUDA memory is freed.
    """
    global _whisper_proc, _whisper_line_queue
    with _whisper_lock:
        _proc = _whisper_proc
        _whisper_proc = None
        _whisper_line_queue = None
    if _proc is not None:
        _pid = _proc.pid
        try:
            _proc.stdin.close()
        except Exception:
            pass
        if force:
            # Kill the entire process tree (CTranslate2 may spawn child processes)
            try:
                import psutil
                _parent = psutil.Process(_pid)
                for _child in _parent.children(recursive=True):
                    try:
                        _child.kill()
                    except Exception:
                        pass
                _parent.kill()
                _parent.wait(timeout=10)
            except Exception:
                # psutil not available or process already gone — fall back to direct kill
                try:
                    _proc.kill()
                    _proc.wait(timeout=10)
                except Exception:
                    pass
        else:
            try:
                _proc.terminate()
                _proc.wait(timeout=10)
            except Exception:
                try:
                    _proc.kill()
                    _proc.wait(timeout=10)
                except Exception:
                    pass


def _stop_ffmpeg_process():
    """Stop the ffmpeg encode subprocess if running."""
    global _ffmpeg_proc, _gpu_actively_encoding
    with _ffmpeg_lock:
        _proc = _ffmpeg_proc
        _ffmpeg_proc = None
        _gpu_actively_encoding = False
    if _proc is not None:
        try:
            _proc.terminate()
            _proc.wait(timeout=10)
        except Exception:
            try:
                _proc.kill()
                _proc.wait(timeout=10)
            except Exception:
                pass


def _ffprobe_duration(file_path):
    """Get video duration in seconds via ffprobe. Returns float or 0 on error."""
    try:
        result = subprocess.run(
            ["ffprobe", "-v", "error", "-show_entries", "format=duration",
             "-of", "csv=p=0", file_path],
            stdout=subprocess.PIPE, stderr=subprocess.PIPE,
            encoding="utf-8", errors="replace", startupinfo=startupinfo, timeout=30
        )
        return float(result.stdout.strip())
    except Exception:
        return 0


def _fmt_enc_size(mb):
    """Format a compressed file size in MB, showing GB (2 decimal places) if ≥ 1024 MB."""
    if mb is None or mb < 0:
        return "?"
    if mb >= 1024:
        return f"{mb / 1024:.2f} GB"
    return f"{mb:.1f} MB"


def _ffprobe_height(file_path):
    """Get video height in pixels via ffprobe. Returns int or 0 on error."""
    try:
        result = subprocess.run(
            ["ffprobe", "-v", "error", "-select_streams", "v:0",
             "-show_entries", "stream=height",
             "-of", "csv=p=0", file_path],
            stdout=subprocess.PIPE, stderr=subprocess.PIPE,
            encoding="utf-8", errors="replace", startupinfo=startupinfo, timeout=30
        )
        return int(result.stdout.strip())
    except Exception:
        return 0


def _ffprobe_is_compressed(file_path):
    """Check if a file has the ytarchiver_compressed metadata marker."""
    try:
        result = subprocess.run(
            ["ffprobe", "-v", "error", "-show_entries", "format_tags=comment",
             "-of", "csv=p=0", file_path],
            stdout=subprocess.PIPE, stderr=subprocess.PIPE,
            encoding="utf-8", errors="replace", startupinfo=startupinfo, timeout=30
        )
        return "ytarchiver_compressed=1" in result.stdout
    except Exception:
        return False


def _compress_channel(ch_name, ch_url, folder, bitrate_mbhr, split_years, split_months,
                      output_res="", cancel_ev=None, pause_ev=None, _sync_mode=False,
                      target_paths=None, batch_num=None):
    """Compress all un-compressed video files in a channel folder using ffmpeg AV1 NVENC.

    bitrate_mbhr: target file size in MB per hour of video.
    output_res: optional target height (e.g. "360", "720"). Empty = keep original.
    cancel_ev/pause_ev: optional threading.Events.
    _sync_mode: if True, run directly (blocking) instead of spawning a thread.
    """
    global _ffmpeg_proc, _gpu_actively_encoding

    _VIDEO_EXTS_COMPRESS = _VIDEO_EXTS

    def _worker():
        global _ffmpeg_proc, _gpu_actively_encoding
        _ce = cancel_ev or cancel_event
        _pe = pause_ev or pause_event

        if not _is_simple_mode:
            log(f"\n=== Compressing: {ch_name} ===\n", "header")
            _res_label = f"{output_res}p" if output_res else "Original"
            log(f"  Target: {bitrate_mbhr} MB/hr  |  Output: {_res_label}\n", "simpleline")

        # ── Step 1: Scan for video files ──
        if target_paths:
            local_files = {}
            for tp in target_paths:
                if os.path.exists(tp) and any(tp.lower().endswith(ext) for ext in _VIDEO_EXTS_COMPRESS):
                    if "_TEMP_COMPRESS" not in tp and ".temp." not in tp.lower() and ".part" not in tp.lower():
                        local_files[os.path.basename(tp)] = tp
            if not local_files:
                log("  No target video files found for this batch.\n", "simpleline")
                return
        else:
            local_files = {}
            for dirpath, _, files in os.walk(folder):
                for f in files:
                    if f.lower().endswith(_VIDEO_EXTS_COMPRESS):
                        # Skip temp files from previous interrupted runs or partial downloads
                        if "_TEMP_COMPRESS" in f or ".temp." in f.lower() or ".part" in f.lower():
                            continue
                        fpath = os.path.join(dirpath, f)
                        local_files[f] = fpath

            if not local_files:
                log("  No video files found to compress.\n", "simpleline")
                return

        if not _is_simple_mode:
            log(f"  Found {len(local_files)} video file(s).\n", "simpleline")

        # ── Step 2: Filter out already-compressed files ──
        files_to_compress = {}
        skipped = 0
        for fname, fpath in local_files.items():
            if _ce.is_set():
                log(f"\n  ⛔ Compression cancelled.\n", "red")
                return
            if _ffprobe_is_compressed(fpath):
                skipped += 1
            else:
                files_to_compress[fname] = fpath

        if not _is_simple_mode:
            if skipped:
                log(f"  {skipped} file(s) already compressed — skipping.\n", "simpleline")
        if not files_to_compress:
            log(f"  ✓ All videos already compressed!\n", "simpleline_green")
            return

        if _is_simple_mode:
            log(f"\n=== Compressing: {ch_name}, {len(files_to_compress)} files ===\n", "header")
        else:
            log(f"  {len(files_to_compress)} file(s) to compress.\n", "simpleline")

        # ── Step 3: Calculate target bitrate ──
        # Convert MB/hr to kbps: MB/hr * 1024 * 8 / 3600
        target_total_kbps = (bitrate_mbhr * 1024 * 8) / 3600
        audio_kbps = 128  # fixed AAC audio bitrate
        video_kbps = max(int(target_total_kbps - audio_kbps), 50)  # minimum 50 kbps video

        if not _is_simple_mode:
            log(f"  Video bitrate: ~{video_kbps} kbps (VBR), Audio: {audio_kbps} kbps\n", "simpleline")

        # ── Step 4: Process each file ──
        done_count = 0
        err_count = 0
        total = len(files_to_compress)
        t_start = time.time()

        for idx, (fname, fpath) in enumerate(files_to_compress.items(), 1):
            # Pause check
            if _pe.is_set() and not _ce.is_set():
                log(f"\n  ⏸ Compression paused.\n", "pauselog")
                while _pe.is_set() and not _ce.is_set():
                    time.sleep(0.25)
                if not _ce.is_set():
                    log(f"  ▶ Compression resuming...\n", "pauselog")

            if _ce.is_set():
                log(f"\n  ⛔ Compression cancelled.\n", "red")
                break

            # Get duration for progress reporting
            duration = _ffprobe_duration(fpath)
            if duration:
                _d_tot_min = int(duration // 60)
                if _d_tot_min >= 60:
                    dur_str = f"{_d_tot_min // 60}h{_d_tot_min % 60:02d}m"
                else:
                    dur_str = f"{_d_tot_min}m{int(duration % 60):02d}s"
            else:
                dur_str = "?"

            fname_short = fname if len(fname) <= 50 else fname[:47] + "..."
            if not _is_simple_mode:
                log(f"\n  [{idx}/{total}] {fname} ({dur_str})\n", "simpleline")

            # Pre-flight disk space check: need ~2x file size for temp + original
            try:
                _orig_sz = os.path.getsize(fpath)
                if not _check_disk_space(fpath, _orig_sz * 2):
                    log(f"  ⚠ Skipping {fname} — insufficient disk space (need ~{_orig_sz * 2 // (1024*1024)} MB free)\n", "red")
                    continue
            except OSError:
                pass

            # Build temp output path (keep original extension so os.replace
            # doesn't leave a container/extension mismatch, e.g. .mkv with MP4 data)
            base, ext = os.path.splitext(fpath)
            temp_path = base + "_TEMP_COMPRESS" + ext

            # Build ffmpeg command
            cmd = [
                "ffmpeg", "-y", "-i", fpath,
            ]
            if output_res:
                cmd += ["-vf", f"scale=-2:{output_res}"]
            cmd += [
                "-c:v", "av1_nvenc",
                "-rc", "vbr",
                "-cq", "32",
                "-b:v", f"{video_kbps}k",
                "-maxrate", f"{int(video_kbps * 1.5)}k",
                "-preset", "p6",
                "-multipass", "2",
                "-c:a", "aac", "-b:a", f"{audio_kbps}k",
                "-movflags", "+faststart",
                "-metadata", "comment=ytarchiver_compressed=1",
                temp_path
            ]

            try:
                proc = subprocess.Popen(
                    cmd, stdout=subprocess.DEVNULL, stderr=subprocess.PIPE,
                    startupinfo=startupinfo, encoding="utf-8", errors="replace"
                )
                with _ffmpeg_lock:
                    _ffmpeg_proc = proc
                    _gpu_actively_encoding = True
                _encode_t0 = time.time()

                # Show a loading state while ffmpeg initializes (can take several minutes)
                if _is_simple_mode:
                    _load_info = f"[{idx}/{total}] ENCODING: {fname_short} ({dur_str}) - " if duration > 0 else f"[{idx}/{total}] ENCODING: {fname_short} - "
                    _update_encode_progress(f"{_load_info}loading\n")

                # Parse progress from stderr
                _time_re = _FFMPEG_TIME_RE
                last_pct = -1
                _dot_idx = 0
                _EDOTS = [".", "..", "..."]
                for line in proc.stderr:
                    if _ce.is_set():
                        proc.terminate()
                        try:
                            proc.wait(timeout=5)
                        except Exception:
                            proc.kill()
                        break

                    m = _time_re.search(line)
                    if m and duration > 0:
                        h, mi, s, cs = int(m.group(1)), int(m.group(2)), int(m.group(3)), int(m.group(4))
                        elapsed = h * 3600 + mi * 60 + s + cs / 100
                        pct = min(int(elapsed / duration * 100), 100)
                        if pct != last_pct:
                            last_pct = pct
                            _dot_idx += 1
                            _d = _EDOTS[_dot_idx % 3]
                            _vid_info = f"[{idx}/{total}] ENCODING: {fname_short} ({dur_str}) - " if _is_simple_mode else ""
                            if _pe.is_set():
                                _update_encode_progress(f"{_vid_info}{pct}% — will pause after this video{_d}\n")
                            else:
                                _update_encode_progress(f"{_vid_info}{pct}%{_d}\n")
                    elif duration <= 0:
                        _dot_idx += 1
                        _d = _EDOTS[_dot_idx % 3]
                        _vid_info = f"[{idx}/{total}] ENCODING: {fname_short} - " if _is_simple_mode else ""
                        if _pe.is_set():
                            _update_encode_progress(f"{_vid_info}— will pause after this video{_d}\n")
                        else:
                            _update_encode_progress(f"{_vid_info}{_d}\n")

                try:
                    proc.wait(timeout=600)
                except subprocess.TimeoutExpired:
                    proc.kill()
                    try:
                        proc.wait(timeout=10)
                    except subprocess.TimeoutExpired:
                        pass  # process is a zombie; nothing more we can do
                with _ffmpeg_lock:
                    _ffmpeg_proc = None
                    _gpu_actively_encoding = False
                _clear_encode_progress()
                _encode_elapsed = time.time() - _encode_t0

                if _ce.is_set():
                    # Clean up temp file on cancel
                    try:
                        if os.path.exists(temp_path):
                            os.remove(temp_path)
                    except Exception:
                        pass
                    break

                # Format elapsed time
                _em = int(_encode_elapsed) // 60
                _es = int(_encode_elapsed) % 60
                _elapsed_str = f"{_em}m{_es:02d}s" if _em > 0 else f"{_es}s"

                if proc.returncode == 0 and os.path.exists(temp_path):
                    # Get sizes for logging
                    orig_size = os.path.getsize(fpath)
                    new_size = os.path.getsize(temp_path)
                    ratio = (1 - new_size / orig_size) * 100 if orig_size > 0 else 0

                    # Safety check: skip replacement if output is suspiciously small
                    if new_size < 10240 or (orig_size > 0 and new_size < orig_size * 0.01):
                        log(f"    ⚠ Compressed output too small ({new_size:,} bytes vs {orig_size:,} original) — skipping replacement.\n", "red")
                        try:
                            os.remove(temp_path)
                        except Exception:
                            pass
                        err_count += 1
                        continue

                    # Atomic replace; preserve original upload-date mtime (ffmpeg creates a
                    # new file with today's timestamp, which would lose the YT upload date)
                    try:
                        orig_stat = os.stat(fpath)
                        _safe_replace(temp_path, fpath)
                        try:
                            os.utime(fpath, (orig_stat.st_atime, orig_stat.st_mtime))
                        except OSError:
                            pass
                        done_count += 1
                        orig_mb = orig_size / (1024 * 1024)
                        new_mb = new_size / (1024 * 1024)
                        _rt_str = f", {duration / _encode_elapsed:.1f}x realtime" if duration > 0 and _encode_elapsed > 0 else ""
                        if _is_simple_mode:
                            log(f"    [{idx}/{total}] {fname_short} ({dur_str})\n", "simpleline_blue")
                        log(f"    ✓ {_fmt_enc_size(orig_mb)} → {_fmt_enc_size(new_mb)} ({ratio:.0f}% smaller, took {_elapsed_str}{_rt_str})\n", "simpleline_blue")
                    except Exception as e:
                        err_count += 1
                        log(f"    ⚠ Replace failed: {e}\n", "red")
                        try:
                            os.remove(temp_path)
                        except Exception:
                            pass
                else:
                    err_count += 1
                    log(f"    ⚠ ffmpeg failed (exit code {proc.returncode}, took {_elapsed_str})\n", "red")
                    try:
                        if os.path.exists(temp_path):
                            os.remove(temp_path)
                    except Exception:
                        pass

            except FileNotFoundError:
                err_count += 1
                log(f"    ⚠ ffmpeg not found — cannot compress.\n", "red")
                break
            except Exception as e:
                err_count += 1
                with _ffmpeg_lock:
                    _ffmpeg_proc = None
                    _gpu_actively_encoding = False
                log(f"    ⚠ Compression error: {e}\n", "red")
                try:
                    if os.path.exists(temp_path):
                        os.remove(temp_path)
                except Exception:
                    pass

        # ── Summary ──
        elapsed = time.time() - t_start
        if not _ce.is_set():
            _e_hrs, _e_rem = divmod(int(elapsed), 3600)
            _e_mins, _e_secs = divmod(_e_rem, 60)
            if _e_hrs:
                _t_str = f"{_e_hrs}h {_e_mins}m {_e_secs}s"
            elif _e_mins:
                _t_str = f"{_e_mins}m {_e_secs}s"
            else:
                _t_str = f"{_e_secs}s"
            log(f"\n  ✓ Compression complete: {done_count} done", "simpleline_green")
            if err_count:
                log(f", {err_count} errors", "simpleline_green")
            log(f" ({_t_str})\n", "simpleline_green")
            _record_compression(ch_name, done_count, err_count, elapsed, batch_num)
            _invalidate_channel_disk_cache(ch_url)

    if _sync_mode:
        _worker()
    else:
        threading.Thread(target=_worker, daemon=True).start()


def _backlog_compress_channel(ch_name, ch_url, folder, resolution, bitrate_mbhr, output_res,
                              split_years, split_months, batch_size=20,
                              cancel_ev=None, pause_ev=None, _sync_mode=False):
    """Re-download and compress existing videos in a channel folder.

    Fetches the YouTube video list, matches local files by title→video ID,
    then processes in batches: download at new quality → ffmpeg AV1 NVENC → replace.
    Shows batch size stats and prompts user to confirm after first batch.
    """
    global _ffmpeg_proc, _gpu_actively_encoding



    def _worker():
        global _ffmpeg_proc, _gpu_actively_encoding
        _ce = cancel_ev or cancel_event
        _pe = pause_ev or pause_event
        _current_bitrate = bitrate_mbhr
        _current_output_res = output_res

        log(f"\n=== Backlog Compress: {ch_name} ===\n", "header")
        _res_key = _current_output_res if _current_output_res in _COMPRESS_PRESETS else "1080"
        _presets_for_res = _COMPRESS_PRESETS.get(_res_key, _COMPRESS_PRESETS["1080"])
        _lvl_name = next((k for k, v in _presets_for_res.items() if v == _current_bitrate), f"{_current_bitrate} MB/hr")
        _res_label = f"{_current_output_res}p" if _current_output_res else "Original"
        log(f"  Quality: {_lvl_name} ({_current_bitrate} MB/hr)  |  Output: {_res_label}  |  Download: {resolution}\n", "simpleline")

        # ── Step 1: Scan local video files ──
        local_files = {}
        for dirpath, dirnames, files in os.walk(folder):
            dirnames[:] = [d for d in dirnames if d != "_BACKLOG_TEMP"]
            for f in files:
                if f.lower().endswith(_VIDEO_EXTS):
                    if "_TEMP_COMPRESS" in f or "_BACKLOG_TEMP" in f or ".temp." in f.lower() or ".part" in f.lower():
                        continue
                    fpath = os.path.join(dirpath, f)
                    local_files[f] = fpath

        if not local_files:
            log("  No video files found.\n", "simpleline")
            return

        log(f"  Found {len(local_files)} local video file(s).\n", "simpleline")

        # ── Step 2: Filter already-compressed ──
        files_to_process = {}
        skipped_compressed = 0
        for fname, fpath in local_files.items():
            if _ce.is_set():
                return
            if _ffprobe_is_compressed(fpath):
                skipped_compressed += 1
            else:
                files_to_process[fname] = fpath

        if skipped_compressed:
            log(f"  {skipped_compressed} file(s) already compressed — skipping.\n", "simpleline")
        if not files_to_process:
            log(f"  ✓ All videos already compressed!\n", "simpleline_green")
            return

        log(f"  {len(files_to_process)} file(s) to re-download and compress.\n", "simpleline")

        if _ce.is_set():
            return

        # ── Step 3: Fetch YouTube video list for ID matching ──
        log("  Fetching YouTube video list for ID matching...\n", "simpleline")
        yt_title_to_id = {}
        try:
            enum_cmd = [
                "yt-dlp", "--flat-playlist",
                "--print", "%(id)s|||%(title)s",
                "--no-warnings", "--verbose",
                "--cookies-from-browser", "firefox",
                ch_url
            ]
            _enum_proc = subprocess.Popen(
                enum_cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                text=True, startupinfo=startupinfo
            )
            # Read both streams via background threads — yt-dlp buffers all --print
            # output until the entire playlist is enumerated, so stderr page progress
            # is the only real-time signal.
            _stdout_q = queue.Queue()
            _stderr_q = queue.Queue()
            _so_done = threading.Event()
            _se_done = threading.Event()
            def _rd_so():
                try:
                    for _ln in _enum_proc.stdout:
                        _stdout_q.put(_ln)
                except ValueError:
                    pass
                finally:
                    _so_done.set()
            def _rd_se():
                try:
                    for _ln in _enum_proc.stderr:
                        _stderr_q.put(_ln)
                except ValueError:
                    pass
                finally:
                    _se_done.set()
            threading.Thread(target=_rd_so, daemon=True).start()
            threading.Thread(target=_rd_se, daemon=True).start()
            _deadline = time.time() + 600
            _last_page = 0
            _page_re = re.compile(r'page (\d+)')
            while True:
                while not _stdout_q.empty():
                    try:
                        line = _stdout_q.get_nowait().strip()
                        if "|||" in line:
                            vid_id, yt_title = line.split("|||", 1)
                            yt_title_to_id[yt_title.strip()] = vid_id.strip()
                    except queue.Empty:
                        break
                while not _stderr_q.empty():
                    try:
                        _se = _stderr_q.get_nowait()
                        _pm = _page_re.search(_se)
                        if _pm:
                            _pg = int(_pm.group(1))
                            if _pg >= _last_page + 10:
                                _last_page = _pg
                                log(f"  — Scanning YouTube catalog (page {_pg})...\n", "simpleline")
                    except queue.Empty:
                        break
                if _so_done.is_set() and _se_done.is_set() and _stdout_q.empty():
                    break
                if _ce.is_set():
                    _enum_proc.terminate()
                    break
                if time.time() > _deadline:
                    _enum_proc.terminate()
                    log("  ⚠ YouTube list fetch timed out.\n", "red")
                    break
                time.sleep(0.5)
            try:
                _enum_proc.wait(timeout=10)
            except subprocess.TimeoutExpired:
                _enum_proc.kill()
            log(f"  Found {len(yt_title_to_id)} video(s) on YouTube.\n", "simpleline")
        except Exception as e:
            log(f"  ⚠ Could not fetch YouTube list: {e}\n", "red")
            return

        if _ce.is_set():
            return

        # Build normalized lookup: norm_title -> (video_id, yt_title)
        norm_lookup = {}
        for yt_title, vid_id in yt_title_to_id.items():
            norm = re.sub(r'[^\w]', '', unicodedata.normalize('NFC', yt_title.lower()))
            norm_lookup[norm] = (vid_id, yt_title)
            norm_a = _norm_ascii(yt_title)
            if norm_a != norm and norm_a not in norm_lookup:
                norm_lookup[norm_a] = (vid_id, yt_title)

        # ── Step 4: Match local files to video IDs ──
        work_list = []  # list of (video_id, original_path, original_size)
        skipped_no_match = 0
        for fname, fpath in files_to_process.items():
            base = os.path.splitext(fname)[0]
            base_nfc = unicodedata.normalize('NFC', base)
            norm_fname = re.sub(r'[^\w]', '', base_nfc.lower())
            norm_fname_ascii = _norm_ascii(base_nfc)

            match = norm_lookup.get(norm_fname)
            if not match and norm_fname_ascii != norm_fname:
                match = norm_lookup.get(norm_fname_ascii)
            # Prefix match for truncated filenames (--trim-filenames)
            if not match and len(norm_fname) >= 15:
                for norm_title, val in norm_lookup.items():
                    if len(norm_title) < 15:
                        continue
                    _min_l = min(len(norm_title), len(norm_fname))
                    _max_l = max(len(norm_title), len(norm_fname))
                    if _min_l / _max_l < 0.8:
                        continue
                    if norm_title.startswith(norm_fname) or norm_fname.startswith(norm_title):
                        match = val
                        break
            if not match and len(norm_fname_ascii) >= 10:
                for norm_title, val in norm_lookup.items():
                    if norm_title.startswith(norm_fname_ascii) or norm_fname_ascii.startswith(norm_title[:len(norm_fname_ascii)]):
                        match = val
                        break

            if match:
                orig_size = os.path.getsize(fpath)
                work_list.append((match[0], fpath, orig_size))
            else:
                skipped_no_match += 1

        if skipped_no_match:
            log(f"  ⚠ {skipped_no_match} file(s) could not be matched to YouTube videos.\n", "red")
        if not work_list:
            log(f"  No files to process after matching.\n", "simpleline")
            return

        log(f"  Matched {len(work_list)} file(s) for backlog processing.\n", "simpleline")

        # ── Step 5: Process in batches ──
        temp_dir = os.path.join(folder, "_BACKLOG_TEMP")
        total_batches = (len(work_list) + batch_size - 1) // batch_size
        total_orig_bytes = 0
        total_new_bytes = 0
        total_done = 0
        total_errors = 0
        fmt = build_format_string(resolution)
        first_batch = True
        t_start = time.time()

        for batch_num in range(total_batches):
            if _ce.is_set():
                log(f"\n  ⛔ Backlog cancelled.\n", "red")
                break

            # Pause check
            if _pe.is_set() and not _ce.is_set():
                log(f"\n  ⏸ Backlog paused.\n", "pauselog")
                while _pe.is_set() and not _ce.is_set():
                    time.sleep(0.25)
                if not _ce.is_set():
                    log(f"  ▶ Backlog resuming...\n", "pauselog")

            batch_start = batch_num * batch_size
            batch_end = min(batch_start + batch_size, len(work_list))
            batch = work_list[batch_start:batch_end]

            _process_batch_result = [None]  # [True=continue, False=redo, None=pending]

            # Store original sizes before first pass so redo uses pre-compression sizes
            _orig_sizes = {}
            for _bi, (_vid_id_m, _orig_path_m, _orig_sz) in enumerate(batch):
                _orig_sizes[_vid_id_m] = _orig_sz

            def _process_batch(_bitrate, _out_res, batch=batch):
                """Download, compress, replace one batch. Returns (batch_orig, batch_new, errors)."""
                os.makedirs(temp_dir, exist_ok=True)
                # Use stored original sizes so redo safety checks compare against
                # pre-compression sizes, not post-compression sizes
                batch_orig = 0
                for _bi, (_vid_id_m, _orig_path_m, _) in enumerate(batch):
                    _stored_size = _orig_sizes.get(_vid_id_m, 0)
                    if _stored_size == 0:
                        try:
                            _stored_size = os.path.getsize(_orig_path_m)
                        except OSError:
                            _stored_size = 0
                    batch[_bi] = (_vid_id_m, _orig_path_m, _stored_size)
                    batch_orig += _stored_size
                batch_new = 0
                batch_errors = 0

                # Calculate target bitrate
                target_total_kbps = (_bitrate * 1024 * 8) / 3600
                audio_kbps = 128
                video_kbps = max(int(target_total_kbps - audio_kbps), 50)

                for idx, (vid_id, orig_path, orig_size) in enumerate(batch):
                    if _ce.is_set():
                        break

                    if _pe.is_set() and not _ce.is_set():
                        log(f"\n  ⏸ Backlog paused.\n", "pauselog")
                        while _pe.is_set() and not _ce.is_set():
                            time.sleep(0.25)
                        if not _ce.is_set():
                            log(f"  ▶ Backlog resuming...\n", "pauselog")

                    orig_fname = os.path.basename(orig_path)
                    fname_short = orig_fname if len(orig_fname) <= 50 else orig_fname[:47] + "..."
                    if not _is_simple_mode:
                        log(f"\n  [{batch_start + idx + 1}/{len(work_list)}] {fname_short}\n", "simpleline")

                    # Download at new quality
                    dl_path = os.path.join(temp_dir, f"{vid_id}.mp4")
                    vid_url = f"https://www.youtube.com/watch?v={vid_id}"
                    if not _is_simple_mode:
                        log(f"    URL:  {vid_url}\n", "dim")
                    dl_cmd = [
                        "yt-dlp", "--newline", "--no-quiet",
                        "--trim-filenames", "200",
                        "--format", fmt, "--merge-output-format", "mp4",
                        "--ppa", "Merger:-c copy",
                        "--output", dl_path,
                        "--cookies-from-browser", "firefox",
                        "--no-download-archive",
                        vid_url
                    ]

                    if not _is_simple_mode:
                        log(f"    Downloading ({resolution})...\n", "simpleline")
                    try:
                        dl_proc = spawn_yt_dlp(dl_cmd)
                        if dl_proc is None:
                            log(f"    ⚠ Could not launch yt-dlp for redownload.\n", "red")
                            batch_errors += 1
                            continue
                        for line in dl_proc.stdout:
                            if _ce.is_set():
                                dl_proc.terminate()
                                break
                            if not _is_simple_mode:
                                log(f"  {line.rstrip()}\n", "dim")
                        try:
                            dl_proc.wait(timeout=300)
                        except subprocess.TimeoutExpired:
                            dl_proc.kill()
                            dl_proc.wait()
                        with proc_lock:
                            if dl_proc in active_processes:
                                active_processes.remove(dl_proc)
                        if _ce.is_set():
                            break
                        if dl_proc.returncode != 0 or not os.path.exists(dl_path):
                            # yt-dlp may produce a file with different extension after merge
                            found_dl = None
                            for f_temp in os.listdir(temp_dir):
                                if f_temp.startswith(vid_id) and "_compressed" not in f_temp:
                                    found_dl = os.path.join(temp_dir, f_temp)
                                    break
                            if found_dl:
                                dl_path = found_dl
                            else:
                                log(f"    ⚠ Download failed.\n", "red")
                                batch_errors += 1
                                continue
                    except Exception as e:
                        log(f"    ⚠ Download error: {e}\n", "red")
                        batch_errors += 1
                        continue

                    # Compress with ffmpeg (use original extension to avoid container mismatch)
                    _orig_ext = os.path.splitext(orig_path)[1] or ".mp4"
                    compressed_path = os.path.join(temp_dir, f"{vid_id}_compressed{_orig_ext}")

                    # Get duration for progress reporting
                    _bl_duration = _ffprobe_duration(dl_path)

                    ffmpeg_cmd = ["ffmpeg", "-y", "-i", dl_path]
                    if _out_res:
                        ffmpeg_cmd += ["-vf", f"scale=-2:{_out_res}"]
                    ffmpeg_cmd += [
                        "-c:v", "av1_nvenc",
                        "-rc", "vbr",
                        "-cq", "32",
                        "-b:v", f"{video_kbps}k",
                        "-maxrate", f"{int(video_kbps * 1.5)}k",
                        "-preset", "p6",
                        "-multipass", "2",
                        "-c:a", "aac", "-b:a", f"{audio_kbps}k",
                        "-movflags", "+faststart",
                        "-metadata", "comment=ytarchiver_compressed=1",
                        compressed_path
                    ]

                    try:
                        proc = subprocess.Popen(
                            ffmpeg_cmd, stdout=subprocess.DEVNULL, stderr=subprocess.PIPE,
                            startupinfo=startupinfo, encoding="utf-8", errors="replace"
                        )
                        with _ffmpeg_lock:
                            _ffmpeg_proc = proc
                            _gpu_actively_encoding = True
                        _bl_encode_t0 = time.time()

                        # Compute vid info strings for progress display and loading state
                        if _is_simple_mode:
                            _bl_total = len(work_list)
                            _bl_idx = batch_start + idx + 1
                            _bl_dur_short = f"{int(_bl_duration // 60)}m{int(_bl_duration % 60):02d}s" if _bl_duration > 0 else "?"
                            _bl_vid_info_dur = f"[{_bl_idx}/{_bl_total}] ENCODING: {fname_short} ({_bl_dur_short}) - "
                            _bl_vid_info_nodur = f"[{_bl_idx}/{_bl_total}] ENCODING: {fname_short} - "
                            # Show loading state while ffmpeg initializes (issue #50)
                            _bl_load_info = _bl_vid_info_dur if _bl_duration > 0 else _bl_vid_info_nodur
                            _update_encode_progress(f"{_bl_load_info}loading\n")
                        else:
                            _bl_dur_short = f"{int(_bl_duration // 60)}m{int(_bl_duration % 60):02d}s" if _bl_duration > 0 else "?"
                            log(f"    Encoding ({_bl_dur_short})...\n", "simpleline")
                            _bl_vid_info_dur = ""
                            _bl_vid_info_nodur = ""

                        _bl_time_re = _FFMPEG_TIME_RE
                        _bl_last_pct = -1
                        _bl_dot_idx = 0
                        _EDOTS = [".", "..", "..."]
                        for line in proc.stderr:
                            if _ce.is_set():
                                proc.terminate()
                                try:
                                    proc.wait(timeout=5)
                                except Exception:
                                    proc.kill()
                                break

                            _bl_m = _bl_time_re.search(line)
                            if _bl_m and _bl_duration > 0:
                                _bl_h, _bl_mi, _bl_s, _bl_cs = int(_bl_m.group(1)), int(_bl_m.group(2)), int(_bl_m.group(3)), int(_bl_m.group(4))
                                _bl_elapsed = _bl_h * 3600 + _bl_mi * 60 + _bl_s + _bl_cs / 100
                                _bl_pct = min(int(_bl_elapsed / _bl_duration * 100), 100)
                                if _bl_pct != _bl_last_pct:
                                    _bl_last_pct = _bl_pct
                                    _bl_dot_idx += 1
                                    _d = _EDOTS[_bl_dot_idx % 3]
                                    if _pe.is_set():
                                        _update_encode_progress(f"{_bl_vid_info_dur}{_bl_pct}% — will pause after this video{_d}\n")
                                    else:
                                        _update_encode_progress(f"{_bl_vid_info_dur}{_bl_pct}%{_d}\n")
                            elif _bl_duration <= 0:
                                _bl_dot_idx += 1
                                _d = _EDOTS[_bl_dot_idx % 3]
                                if _pe.is_set():
                                    _update_encode_progress(f"{_bl_vid_info_nodur}— will pause after this video{_d}\n")
                                else:
                                    _update_encode_progress(f"{_bl_vid_info_nodur}{_d}\n")

                        if not _ce.is_set():
                            try:
                                proc.wait(timeout=300)
                            except subprocess.TimeoutExpired:
                                proc.kill()
                                try:
                                    proc.wait(timeout=10)
                                except subprocess.TimeoutExpired:
                                    pass
                        with _ffmpeg_lock:
                            _ffmpeg_proc = None
                            _gpu_actively_encoding = False
                        _clear_encode_progress()
                        _bl_encode_elapsed = time.time() - _bl_encode_t0

                        if _ce.is_set():
                            break

                        # Format elapsed time
                        _bl_em = int(_bl_encode_elapsed) // 60
                        _bl_es = int(_bl_encode_elapsed) % 60
                        _bl_elapsed_str = f"{_bl_em}m{_bl_es:02d}s" if _bl_em > 0 else f"{_bl_es}s"

                        if proc.returncode == 0 and os.path.exists(compressed_path):
                            new_size = os.path.getsize(compressed_path)
                            # Safety check: skip replacement if output is suspiciously small
                            if new_size < 10240 or (orig_size > 0 and new_size < orig_size * 0.01):
                                log(f"    ⚠ Compressed output too small ({new_size:,} bytes vs {orig_size:,} original) — skipping replacement.\n", "red")
                                try:
                                    os.remove(compressed_path)
                                except Exception:
                                    pass
                                batch_errors += 1
                                continue
                            # Replace original file (preserve mtime = YouTube upload date)
                            try:
                                _bl_orig_stat = os.stat(orig_path)
                                _safe_replace(compressed_path, orig_path)
                                try:
                                    os.utime(orig_path, (_bl_orig_stat.st_atime, _bl_orig_stat.st_mtime))
                                except Exception:
                                    pass
                                batch_new += new_size
                                o_mb = orig_size / (1024 * 1024)
                                n_mb = new_size / (1024 * 1024)
                                _bl_ratio = (1 - new_size / orig_size) * 100 if orig_size > 0 else 0
                                _bl_dur_str = f"{int(_bl_duration // 60)}m{int(_bl_duration % 60):02d}s" if _bl_duration > 0 else "?"
                                _bl_rt_str = f", {_bl_duration / _bl_encode_elapsed:.1f}x realtime" if _bl_duration > 0 and _bl_encode_elapsed > 0 else ""
                                if _is_simple_mode:
                                    log(f"    [{batch_start + idx + 1}/{len(work_list)}] {fname_short} ({_bl_dur_str})\n", "simpleline_blue")
                                log(f"    ✓ {_fmt_enc_size(o_mb)} → {_fmt_enc_size(n_mb)} ({_bl_ratio:.0f}% smaller, took {_bl_elapsed_str}{_bl_rt_str})\n", "simpleline_blue")
                            except Exception as e:
                                log(f"    ⚠ Replace failed: {e}\n", "red")
                                batch_errors += 1
                        else:
                            log(f"    ⚠ Encode failed (took {_bl_elapsed_str}).\n", "red")
                            batch_errors += 1
                    except FileNotFoundError:
                        log(f"    ⚠ ffmpeg not found.\n", "red")
                        batch_errors += 1
                        break
                    except Exception as e:
                        with _ffmpeg_lock:
                            _ffmpeg_proc = None
                            _gpu_actively_encoding = False
                        log(f"    ⚠ Encode error: {e}\n", "red")
                        batch_errors += 1
                    finally:
                        # Clean up downloaded temp file
                        try:
                            if os.path.exists(dl_path):
                                os.remove(dl_path)
                        except Exception:
                            pass
                        try:
                            if os.path.exists(compressed_path):
                                os.remove(compressed_path)
                        except Exception:
                            pass

                return batch_orig, batch_new, batch_errors

            # Process the batch (may loop if user wants to redo with new settings)
            while True:
                if _ce.is_set():
                    break

                batch_orig, batch_new, batch_errors = _process_batch(_current_bitrate, _current_output_res)

                if _ce.is_set():
                    break

                # Log batch stats
                batch_done = len(batch) - batch_errors
                total_done += batch_done
                total_errors += batch_errors
                total_orig_bytes += batch_orig
                total_new_bytes += batch_new

                if batch_orig > 0 and batch_new > 0:
                    orig_mb = batch_orig / (1024 * 1024)
                    new_mb = batch_new / (1024 * 1024)
                    reduction = ((batch_orig - batch_new) / batch_orig) * 100 if batch_orig > 0 else 0
                    log(f"\n  Batch {batch_num + 1}/{total_batches}: {orig_mb:.0f} MB → {new_mb:.0f} MB ({reduction:.0f}% reduction)\n", "header")

                # After first batch, ask user to confirm
                if first_batch and total_batches > 1 and not _ce.is_set():
                    first_batch = False
                    _confirm_result = [None]  # None=pending, True=continue, "redo"=redo

                    def _ask_confirm(batch_orig=batch_orig, batch_new=batch_new, batch_errors=batch_errors):
                        if batch_orig > 0 and batch_new > 0:
                            o_mb = batch_orig / (1024 * 1024)
                            n_mb = batch_new / (1024 * 1024)
                            pct = ((batch_orig - batch_new) / batch_orig) * 100
                            msg = (f"Batch 1 complete: {o_mb:.0f} MB → {n_mb:.0f} MB "
                                   f"({pct:.0f}% reduction)\n\n"
                                   f"Continue with these settings for the remaining "
                                   f"{len(work_list) - batch_size} videos?")
                        else:
                            msg = (f"Batch 1 complete with {batch_errors} error(s).\n\n"
                                   f"Continue for the remaining {len(work_list) - batch_size} videos?")
                        result = _dark_askquestion("Backlog Compression", msg,
                                                      yes_text="Continue", no_text="Adjust Settings")
                        _confirm_result[0] = True if result else "redo"

                    _ui_queue.append(_ask_confirm)
                    while _confirm_result[0] is None and not _ce.is_set():
                        time.sleep(0.25)

                    if _ce.is_set():
                        break

                    if _confirm_result[0] == "redo":
                        # Ask for new settings
                        _new_settings = [None]  # (bitrate, output_res) or None

                        def _ask_new_settings():
                            dlg = tk.Toplevel(root)
                            dlg.title("Adjust Compression Settings")
                            dlg.configure(bg=C_BG)
                            dlg.resizable(False, False)
                            dlg.grab_set()
                            dlg.update_idletasks()
                            _apply_dark_title_bar(dlg)

                            tk.Label(dlg, text="Adjust settings and try batch 1 again:",
                                     bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10)).pack(padx=16, pady=(12, 8))

                            row = tk.Frame(dlg, bg=C_BG)
                            row.pack(padx=16, pady=4)
                            # Res dropdown (first)
                            tk.Label(row, text="Res:", bg=C_BG, fg=C_DIM, font=("Segoe UI", 9)).pack(side="left", padx=(0, 4))
                            _rv = tk.StringVar(value=f"{_current_output_res}p" if _current_output_res else "Original")
                            _rv_combo = _combo(row, textvariable=_rv, values=["Original", "144p", "240p", "360p", "480p", "720p", "1080p"],
                                               state="readonly", width=10)
                            _rv_combo.pack(side="left", padx=(0, 12))
                            # Quality dropdown (second, depends on Res)
                            tk.Label(row, text="Quality:", bg=C_BG, fg=C_DIM, font=("Segoe UI", 9)).pack(side="left", padx=(0, 4))
                            _dlg_res_key = _current_output_res if _current_output_res in _COMPRESS_PRESETS else "1080"
                            _dlg_presets = _COMPRESS_PRESETS.get(_dlg_res_key, _COMPRESS_PRESETS["1080"])
                            _init_quality = next((k for k, v in _dlg_presets.items() if v == _current_bitrate), "Average")
                            _lv = tk.StringVar(value=_init_quality)
                            _lv_combo = _combo(row, textvariable=_lv, values=_QUALITY_OPTIONS, state="readonly", width=14)
                            _lv_combo.pack(side="left")

                            def _on_dlg_res_change(*_):
                                rv_raw = _rv.get()
                                rk = rv_raw.replace("p", "") if rv_raw != "Original" else "1080"
                                _lv_combo.config(values=_QUALITY_OPTIONS)
                                cur_q = _lv.get()
                                if cur_q not in _COMPRESS_PRESETS.get(rk, _COMPRESS_PRESETS["1080"]):
                                    _lv.set("Average")
                            _rv.trace_add("write", _on_dlg_res_change)

                            def _ok():
                                lv = _lv.get()
                                rv = _rv.get()
                                new_or = rv.replace("p", "") if rv != "Original" else ""
                                new_br = _get_compress_bitrate(lv, new_or)
                                _new_settings[0] = (new_br, new_or)
                                dlg.destroy()

                            def _cancel():
                                _new_settings[0] = "cancel"
                                dlg.destroy()

                            btn_row = tk.Frame(dlg, bg=C_BG)
                            btn_row.pack(padx=16, pady=(8, 12))
                            tk.Button(btn_row, text="Retry Batch 1", bg="#3a6a3a", fg="#cccccc",
                                      relief="flat", font=("Segoe UI", 9, "bold"),
                                      cursor="hand2", command=_ok).pack(side="left", padx=(0, 8))
                            tk.Button(btn_row, text="Cancel Backlog", bg="#8b1a1a", fg="#ffffff",
                                      relief="flat", font=("Segoe UI", 9, "bold"),
                                      cursor="hand2", command=_cancel).pack(side="left")

                            dlg.protocol("WM_DELETE_WINDOW", _cancel)
                            dlg.update_idletasks()
                            dlg.geometry(f"+{root.winfo_x() + 200}+{root.winfo_y() + 200}")

                        _ui_queue.append(_ask_new_settings)
                        while _new_settings[0] is None and not _ce.is_set():
                            time.sleep(0.25)

                        if _ce.is_set() or _new_settings[0] == "cancel":
                            log(f"\n  ⛔ Backlog cancelled by user.\n", "red")
                            break

                        # Apply new settings and redo batch 1
                        _current_bitrate, _current_output_res = _new_settings[0]
                        # Undo batch 1 stats
                        total_done -= batch_done
                        total_errors -= batch_errors
                        total_orig_bytes -= batch_orig
                        total_new_bytes -= batch_new
                        _res_key = _current_output_res if _current_output_res in _COMPRESS_PRESETS else "1080"
                        _presets_for_res = _COMPRESS_PRESETS.get(_res_key, _COMPRESS_PRESETS["1080"])
                        _lvl_name = next((k for k, v in _presets_for_res.items() if v == _current_bitrate), f"{_current_bitrate} MB/hr")
                        _res_label = f"{_current_output_res}p" if _current_output_res else "Original"
                        log(f"\n  Retrying batch 1 with: {_lvl_name} ({_current_bitrate} MB/hr), {_res_label}\n", "header")
                        continue  # Redo the while loop with new settings
                    # User confirmed — break inner loop, proceed to next batch
                    break
                else:
                    first_batch = False
                    break  # Not first batch or only one batch, proceed

        # Clean up temp dir
        try:
            if os.path.exists(temp_dir):
                shutil.rmtree(temp_dir, ignore_errors=True)
        except Exception:
            pass

        # ── Summary ──
        if not _ce.is_set() and total_done > 0:
            elapsed = time.time() - t_start
            _e_hrs, _e_rem = divmod(int(elapsed), 3600)
            _e_mins, _e_secs = divmod(_e_rem, 60)
            if _e_hrs:
                _t_str = f"{_e_hrs}h {_e_mins}m {_e_secs}s"
            elif _e_mins:
                _t_str = f"{_e_mins}m {_e_secs}s"
            else:
                _t_str = f"{_e_secs}s"
            orig_gb = total_orig_bytes / (1024 ** 3)
            new_gb = total_new_bytes / (1024 ** 3)
            pct = ((total_orig_bytes - total_new_bytes) / total_orig_bytes * 100) if total_orig_bytes > 0 else 0
            log(f"\n=== Backlog Complete: {ch_name} ===\n", "header")
            log(f"  Total: {total_done} video(s) processed ({_t_str})\n", "simpleline_green")
            log(f"  Before: {orig_gb:.1f} GB → After: {new_gb:.1f} GB ({pct:.0f}% reduction)\n", "simpleline_green")
            if skipped_compressed:
                log(f"  Skipped: {skipped_compressed} (already compressed)", "simpleline")
            if skipped_no_match:
                log(f"  Unmatched: {skipped_no_match} (no YouTube match)", "simpleline")
            if total_errors:
                log(f"  Errors: {total_errors}\n", "red")
            log("\n", "simpleline")
            _invalidate_channel_disk_cache(ch_url)

    if _sync_mode:
        _worker()
    else:
        threading.Thread(target=_worker, daemon=True).start()


def _backlog_redownload_channel(ch_name, ch_url, folder, new_res,
                                cancel_ev=None, pause_ev=None, _sync_mode=False):
    """Re-download existing channel videos at a new resolution and replace the old files.

    Scans local video files, matches them to YouTube video IDs, downloads each
    at the new resolution, and replaces the original.  No compression step —
    intended for resolution-only upgrades that are not GPU-taxing.

    Progress is persisted so a cancelled redownload can resume from where it
    left off (completed video IDs are stored in a progress file).

    _sync_mode: if True, run the worker body directly (blocking) instead of spawning a thread.
    """

    _PROGRESS_FILE = os.path.join(folder, "_redownload_progress.json")

    def _load_progress():
        """Load set of already-redownloaded video IDs from progress file."""
        try:
            if os.path.exists(_PROGRESS_FILE):
                with open(_PROGRESS_FILE, "r", encoding="utf-8") as f:
                    data = json.load(f)
                if data.get("resolution") == new_res and data.get("ch_url") == ch_url:
                    return set(data.get("done_ids", []))
        except Exception:
            pass
        return set()

    def _save_progress(done_ids):
        """Persist completed video IDs so a cancelled redownload can resume."""
        try:
            os.makedirs(folder, exist_ok=True)
            _tmp = _PROGRESS_FILE + ".tmp"
            with open(_tmp, "w", encoding="utf-8") as f:
                json.dump({"ch_url": ch_url, "resolution": new_res,
                           "done_ids": list(done_ids)}, f)
            os.replace(_tmp, _PROGRESS_FILE)
        except Exception:
            pass

    def _clear_progress():
        """Remove progress file after a complete run."""
        try:
            if os.path.exists(_PROGRESS_FILE):
                os.remove(_PROGRESS_FILE)
        except Exception:
            pass

    def _fetch_yt_list(use_cookies):
        """Fetch YouTube video list (id→title) using spawn_yt_dlp with cancel support.
        Uses --verbose so stderr (merged into stdout) shows page progress — yt-dlp
        buffers all --print output until the entire playlist is enumerated."""
        enum_cmd = [
            "yt-dlp", "--flat-playlist",
            "--print", "%(id)s|||%(title)s",
            "--no-warnings", "--verbose",
        ]
        if use_cookies:
            enum_cmd += ["--cookies-from-browser", "firefox"]
        enum_cmd.append(ch_url)
        proc = spawn_yt_dlp(enum_cmd)
        if proc is None:
            return None
        result = {}
        _last_page = 0
        _page_re = re.compile(r'page (\d+)')
        try:
            for line in proc.stdout:
                if (cancel_ev or cancel_event).is_set():
                    proc.terminate()
                    break
                line = line.strip()
                if "|||" in line:
                    vid_id, yt_title = line.split("|||", 1)
                    vid_id = vid_id.strip()
                    yt_title = yt_title.strip()
                    if re.fullmatch(r'[\w-]{11}', vid_id):  # YouTube IDs are exactly 11 chars
                        result[yt_title] = vid_id
                else:
                    # Check for page progress from verbose stderr (merged into stdout)
                    _pm = _page_re.search(line)
                    if _pm:
                        _pg = int(_pm.group(1))
                        if _pg >= _last_page + 10:
                            _last_page = _pg
                            log(f"  — Scanning YouTube catalog (page {_pg})...\n", "simpleline")
        finally:
            try:
                proc.wait(timeout=300)
            except subprocess.TimeoutExpired:
                proc.kill()
                proc.wait()
            with proc_lock:
                if proc in active_processes:
                    active_processes.remove(proc)
        return result

    def _worker():
        _ce = cancel_ev or cancel_event
        _pe = pause_ev or pause_event
        _res_label = "Best" if new_res == "best" else f"{new_res}p"
        log(f"\n=== Resolution Redownload: {ch_name} ({_res_label}) ===\n", "header")

        # ── Step 1: Scan local video files ──
        # Key: filename (without path), Value: full path.  Use the LAST path seen for
        # any given filename so duplicates across split_year sub-folders are handled.
        local_files = {}
        for dirpath, dirnames, files in os.walk(folder):
            dirnames[:] = [d for d in dirnames if d not in ("_BACKLOG_TEMP", "_TEMP_COMPRESS")]
            for f in files:
                if f.lower().endswith(_VIDEO_EXTS) and not f.lower().endswith(".part"):
                    fpath = os.path.join(dirpath, f)
                    local_files[f] = fpath

        if not local_files:
            log("  No video files found.\n", "simpleline")
            return

        log(f"  Found {len(local_files)} local file(s).\n", "simpleline")

        if _ce.is_set():
            log("  Redownload cancelled before YouTube fetch.\n", "simpleline")
            return

        # ── Step 2: Fetch YouTube video list for ID matching ──
        # Try with cookies first; fall back to without cookies for public channels.
        # Protected by internet monitor: if internet drops mid-fetch, wait and retry.
        log("  Fetching YouTube video list for ID matching...\n", "simpleline")
        while not _ce.is_set():
            _internet_went_down_during.clear()  # arm the dirty flag
            if not _block_if_no_internet(cancel_ev=_ce):
                break  # cancelled
            yt_title_to_id = _fetch_yt_list(use_cookies=True)

            if _ce.is_set():
                break

            if yt_title_to_id is None:
                log("  ⚠ Could not start yt-dlp (not installed or not on PATH).\n", "red")
                return

            if not yt_title_to_id:
                # Retry without cookies — useful for public channels where Firefox
                # cookies are not configured or cause authentication errors.
                log("  No videos returned with cookies — retrying without cookies...\n", "simpleline")
                yt_title_to_id = _fetch_yt_list(use_cookies=False) or {}
                if _ce.is_set():
                    break

            # Check if internet dropped during the fetch — list may be incomplete
            if _internet_went_down_during.is_set() and not _ce.is_set():
                log("  ⚠ Internet dropped during playlist fetch — will re-fetch after restore.\n", "red")
                if not _block_if_no_internet(cancel_ev=_ce):
                    break  # cancelled
                log("  Retrying YouTube video list fetch...\n", "simpleline")
                continue  # retry from the top
            break  # clean fetch — proceed

        if _ce.is_set():
            log("  Redownload cancelled during YouTube fetch.\n", "simpleline")
            return

        if not yt_title_to_id:
            log("  ⚠ Could not retrieve video list from YouTube. Check the channel URL and your internet connection.\n", "red")
            return

        log(f"  Found {len(yt_title_to_id)} video(s) on YouTube.\n", "simpleline")

        if _ce.is_set():
            log("  Redownload cancelled after YouTube fetch.\n", "simpleline")
            return

        # ── Step 3: Build normalized lookup and match local files ──
        # Fuzzy-match cutoff for difflib: 0.92 = high confidence (avoids false positives
        # on short or similar-sounding titles while still catching minor Unicode/OS
        # filename-sanitisation differences).
        _FUZZY_CUTOFF = 0.92

        norm_lookup = {}
        for yt_title, vid_id in yt_title_to_id.items():
            norm = re.sub(r'[^\w]', '', unicodedata.normalize('NFC', yt_title.lower()))
            norm_lookup[norm] = (vid_id, yt_title)
            norm_a = _norm_ascii(yt_title)
            if norm_a != norm and norm_a not in norm_lookup:
                norm_lookup[norm_a] = (vid_id, yt_title)

        # Pre-build sorted list of norm_lookup keys for difflib matching
        _norm_keys = list(norm_lookup.keys())

        work_list = []
        skipped_no_match = 0
        for fname, fpath in local_files.items():
            base = os.path.splitext(fname)[0]
            base_nfc = unicodedata.normalize('NFC', base)
            norm_fname = re.sub(r'[^\w]', '', base_nfc.lower())
            norm_fname_ascii = _norm_ascii(base_nfc)

            match = norm_lookup.get(norm_fname)
            if not match and norm_fname_ascii != norm_fname:
                match = norm_lookup.get(norm_fname_ascii)
            # Prefix matching for truncated filenames (--trim-filenames 200)
            if not match and len(norm_fname) >= 15:
                for norm_title, val in norm_lookup.items():
                    if len(norm_title) < 15:
                        continue
                    _min_l = min(len(norm_title), len(norm_fname))
                    _max_l = max(len(norm_title), len(norm_fname))
                    if _min_l / _max_l < 0.8:
                        continue
                    if norm_title.startswith(norm_fname) or norm_fname.startswith(norm_title):
                        match = val
                        break
            if not match and len(norm_fname_ascii) >= 10:
                for norm_title, val in norm_lookup.items():
                    if norm_title.startswith(norm_fname_ascii) or norm_fname_ascii.startswith(norm_title[:len(norm_fname_ascii)]):
                        match = val
                        break
            # Fuzzy fallback via difflib — catches minor Unicode/sanitisation differences
            if not match and len(norm_fname) >= 10 and _norm_keys:
                _close = difflib.get_close_matches(norm_fname, _norm_keys, n=1, cutoff=_FUZZY_CUTOFF)
                if not _close:
                    _close = difflib.get_close_matches(norm_fname_ascii, _norm_keys, n=1, cutoff=_FUZZY_CUTOFF)
                if _close:
                    match = norm_lookup[_close[0]]

            if match:
                work_list.append((match[0], fpath))
            else:
                skipped_no_match += 1

        if skipped_no_match:
            log(f"  ⚠ {skipped_no_match} file(s) could not be matched to YouTube videos.\n", "red")
        if not work_list:
            log("  No files to process after matching.\n", "simpleline")
            return

        # ── Resume: skip videos already completed in a previous run ──
        done_ids = _load_progress()
        if done_ids:
            before = len(work_list)
            work_list = [(vid_id, fp) for vid_id, fp in work_list if vid_id not in done_ids]
            skipped_prev = before - len(work_list)
            if skipped_prev:
                log(f"  Resuming — {skipped_prev} video(s) already redownloaded, {len(work_list)} remaining.\n", "simpleline_green")
        if not work_list:
            log("  All files already redownloaded.\n", "simpleline_green")
            _clear_progress()
            return

        total_to_do = len(work_list)
        log(f"  Matched {total_to_do} file(s). Starting redownload at {_res_label}...\n", "simpleline")
        _record_redownload_start(ch_name, _res_label, total_to_do)
        _rd_start_time = time.time()

        # Start simple mode animation for redownload
        if _is_simple_mode:
            _start_simple_anim(ch_name, 1, total_to_do, mode="redownload")

        # ── Step 4: Download each video at new resolution and replace ──
        fmt = build_format_string(new_res)
        temp_dir = os.path.join(folder, "_BACKLOG_TEMP")
        done = 0
        errors = 0
        skipped_quality = 0  # videos already at target quality

        # Parse numeric target height once (0 if "best")
        try:
            _target_height = int(new_res) if new_res != "best" else 0
        except (ValueError, TypeError):
            _target_height = 0

        def _probe_height(path):
            """Return video height of a file via ffprobe, or 0 on failure."""
            try:
                _pr = subprocess.run(
                    ["ffprobe", "-v", "quiet", "-select_streams", "v:0",
                     "-show_entries", "stream=height", "-of", "csv=p=0", path],
                    capture_output=True, text=True, timeout=15, startupinfo=startupinfo
                )
                return int(_pr.stdout.strip())
            except Exception:
                return 0

        for idx, (vid_id, orig_path) in enumerate(work_list):
            if _ce.is_set():
                break

            if _pe.is_set():
                log(f"\n  ⏸ Redownload paused.\n", "pauselog")
                while _pe.is_set() and not _ce.is_set():
                    time.sleep(0.25)
                if not _ce.is_set():
                    log(f"  ▶ Redownload resuming...\n", "pauselog")

            if _ce.is_set():
                break

            # Update simple mode status line
            if _is_simple_mode:
                _simple_anim_state["idx"] = idx + 1
                _simple_anim_state["total"] = total_to_do

            orig_fname = os.path.basename(orig_path)
            fname_short = orig_fname if len(orig_fname) <= 50 else orig_fname[:47] + "..."
            if not _is_simple_mode:
                log(f"\n  [{idx + 1}/{total_to_do}] {fname_short}\n", "simpleline")

            try:
                os.makedirs(temp_dir, exist_ok=True)
            except Exception:
                pass

            # ── Pre-download quality check (numeric targets only) ──────────────
            # For a specific resolution, probe the existing file. If it's already
            # at that height there's nothing to do — skip without downloading.
            if _target_height and os.path.exists(orig_path):
                _existing_h = _probe_height(orig_path)
                if _existing_h == _target_height:
                    if _is_simple_mode:
                        log(f"  [{idx + 1}/{total_to_do}] {fname_short}\n", "simpleline")
                    log(f"    ↔ Already at {_target_height}p, skipping.\n", "dim")
                    skipped_quality += 1
                    done_ids.add(vid_id)
                    _save_progress(done_ids)
                    continue

            orig_size = os.path.getsize(orig_path) if os.path.exists(orig_path) else 0
            dl_path = os.path.join(temp_dir, f"{vid_id}.mp4")
            vid_url = f"https://www.youtube.com/watch?v={vid_id}"
            dl_cmd = [
                "yt-dlp", "--newline", "--no-quiet",
                "--trim-filenames", "200",
                "--format", fmt, "--merge-output-format", "mp4",
                "--ppa", "Merger:-c copy",
                "--output", dl_path,
                "--cookies-from-browser", "firefox",
                "--no-download-archive",
                vid_url
            ]

            if not _is_simple_mode:
                log(f"    Downloading ({_res_label})...\n", "simpleline")
            try:
                dl_proc = spawn_yt_dlp(dl_cmd)
                if dl_proc is None:
                    log(f"    ⚠ Could not start yt-dlp.\n", "red")
                    errors += 1
                    continue
                for line in dl_proc.stdout:
                    if _ce.is_set():
                        dl_proc.terminate()
                        break
                try:
                    dl_proc.wait(timeout=300)
                except subprocess.TimeoutExpired:
                    dl_proc.kill()
                    dl_proc.wait()
                with proc_lock:
                    if dl_proc in active_processes:
                        active_processes.remove(dl_proc)

                if _ce.is_set():
                    break

                # yt-dlp may produce a file with a different name after merge
                if not os.path.exists(dl_path):
                    found_dl = None
                    try:
                        for f_temp in os.listdir(temp_dir):
                            if f_temp.startswith(vid_id) and not f_temp.endswith("_compressed.mp4"):
                                found_dl = os.path.join(temp_dir, f_temp)
                                break
                    except OSError:
                        pass
                    if found_dl:
                        dl_path = found_dl
                    else:
                        log(f"    ⚠ Download failed.\n", "red")
                        errors += 1
                        continue

                try:
                    new_size = os.path.getsize(dl_path)

                    # ── Post-download quality check ("best" target only) ────────
                    # Compare resolution of downloaded file vs original. If yt-dlp
                    # picked the same height (best available == what we already had),
                    # discard the download and skip replacement.
                    if not _target_height and os.path.exists(orig_path):
                        _dl_h = _probe_height(dl_path)
                        _orig_h = _probe_height(orig_path)
                        if _dl_h and _orig_h and _dl_h == _orig_h:
                            try:
                                os.remove(dl_path)
                            except Exception:
                                pass
                            if _is_simple_mode:
                                log(f"  [{idx + 1}/{total_to_do}] {fname_short}\n", "simpleline")
                            log(f"    ↔ Already at best quality ({_dl_h}p), skipping.\n", "dim")
                            skipped_quality += 1
                            done_ids.add(vid_id)
                            _save_progress(done_ids)
                            continue

                    # Safety check: skip replacement if output is suspiciously small
                    if new_size < 10240 or (orig_size > 0 and new_size < orig_size * 0.01):
                        log(f"    ⚠ Downloaded file too small ({new_size:,} bytes vs {orig_size:,} original) — skipping replacement.\n", "red")
                        try:
                            os.remove(dl_path)
                        except Exception:
                            pass
                        errors += 1
                        continue
                    # Preserve original mtime (YouTube upload date) before replacing
                    _orig_stat = os.stat(orig_path) if os.path.exists(orig_path) else None
                    _safe_replace(dl_path, orig_path)
                    if _orig_stat:
                        try:
                            os.utime(orig_path, (_orig_stat.st_atime, _orig_stat.st_mtime))
                        except Exception:
                            pass
                    o_mb = orig_size / (1024 * 1024)
                    n_mb = new_size / (1024 * 1024)
                    if _is_simple_mode:
                        log(f"  [{idx + 1}/{total_to_do}] {fname_short}\n", "simpleline")
                    if orig_size > 0:
                        _sz_ratio = (new_size / orig_size - 1) * 100
                        _sz_dir = "larger" if _sz_ratio >= 0 else "smaller"
                        log(f"    ✓ {_fmt_enc_size(o_mb)} → {_fmt_enc_size(n_mb)} ({abs(_sz_ratio):.0f}% {_sz_dir})\n", "simpleline_green")
                    else:
                        log(f"    ✓ {_fmt_enc_size(n_mb)} (replaced at {_res_label})\n", "simpleline_green")
                    done += 1
                    done_ids.add(vid_id)
                    _save_progress(done_ids)
                except Exception as e:
                    log(f"    ⚠ Replace failed: {e}\n", "red")
                    errors += 1
            except Exception as e:
                log(f"    ⚠ Error: {e}\n", "red")
                errors += 1

        if _is_simple_mode:
            _stop_simple_anim()
            clear_simple_status()

        # Cleanup temp dir
        try:
            if os.path.isdir(temp_dir):
                import shutil as _shutil
                _shutil.rmtree(temp_dir, ignore_errors=True)
        except Exception:
            pass

        # Clear progress file if all videos were processed (not cancelled)
        if not _ce.is_set():
            _clear_progress()

        _skip_part = f", {skipped_quality} already at quality" if skipped_quality else ""
        log(f"\n=== Redownload Complete: {ch_name} — {done} done{_skip_part}, {errors} error(s) ===\n", "header")
        _record_redownload_finish(ch_name, done, errors, time.time() - _rd_start_time, _res_label, skipped_quality)

    if _sync_mode:
        _worker()
    else:
        threading.Thread(target=_worker, daemon=True).start()


def _whisper_transcribe_chunked(audio_path, total_duration, title="", cancel_ev=None, pause_ev=None, progress_cb=None):
    """Transcribe a long audio file by splitting it into chunks with ffmpeg.

    Each chunk is extracted as a temporary WAV file, transcribed individually,
    then timestamps are offset so the final result is seamless.  This avoids
    loading the entire waveform into RAM at once.

    Chunks overlap by 30 seconds so Whisper's VAD doesn't cut off speech at
    boundaries.  Duplicate segments in the overlap zone are removed when merging.
    """
    import tempfile as _tf
    _ce = cancel_ev or cancel_event
    _CHUNK_LEN = 7200  # 2 hours per chunk
    _OVERLAP = 30      # seconds of overlap between chunks

    _hrs = total_duration / 3600
    _n_chunks = max(1, int(total_duration / _CHUNK_LEN) + (1 if total_duration % _CHUNK_LEN > 0 else 0))

    # Log the main [X/X] line for this video, then sections will appear indented below it
    _wp = f"[{_whisper_counter['idx']}/{_whisper_counter['total']}] " if _is_simple_mode and _whisper_counter['total'] else "    "
    _title_disp = title
    if _title_disp:
        _title_disp = _trunc_pad_title(_title_disp, _MAX_TITLE_DISPLAY).rstrip()
    _title_part = f' "{_title_disp}"' if _title_disp else ""
    log(f"{_wp}Transcribing{_title_part} — {_hrs:.1f}h, {_n_chunks} sections\n", "simpleline")

    all_text_parts = []
    all_segments = []
    _chunk_tmp_dir = _tf.mkdtemp(prefix="yt_whisper_chunk_")

    _pe = pause_ev or pause_event

    try:
        for ci in range(_n_chunks):
            if _ce.is_set():
                break

            # Respect pause between chunks — wait here until resumed
            while _pe.is_set() and not _ce.is_set():
                time.sleep(0.5)

            if _ce.is_set():
                break

            _start_sec = ci * _CHUNK_LEN
            # Include overlap from previous chunk's end so we don't miss speech at boundaries
            if ci > 0:
                _start_sec -= _OVERLAP
            _end_sec = min(_start_sec + _CHUNK_LEN + (_OVERLAP if ci > 0 else 0), total_duration)
            _chunk_dur = _end_sec - _start_sec
            if _chunk_dur <= 0:
                break

            _chunk_path = os.path.join(_chunk_tmp_dir, f"chunk_{ci:03d}.wav")

            # Extract chunk with ffmpeg (WAV 16kHz mono — what Whisper expects)
            _ff_cmd = [
                "ffmpeg", "-y", "-hide_banner", "-loglevel", "error",
                "-ss", str(_start_sec),
                "-t", str(_chunk_dur),
                "-i", audio_path,
                "-vn", "-ac", "1", "-ar", "16000", "-acodec", "pcm_s16le",
                _chunk_path,
            ]
            try:
                subprocess.run(_ff_cmd, check=True, capture_output=True, timeout=600,
                               startupinfo=startupinfo)
            except Exception as e:
                log(f"  ⚠ Failed to extract chunk {ci+1}: {e}\n", "red")
                continue

            # Transcribe the chunk (duration fits within the normal limit)
            def _chunk_progress(pct, _ss=_start_sec, _cd=_chunk_dur):
                # Scale chunk progress to overall progress
                overall = int((_ss / total_duration + pct / 100 * _cd / total_duration) * 100)
                overall = min(99, overall)
                if progress_cb:
                    try:
                        progress_cb(overall)
                    except Exception:
                        pass
            _section_prefix = f"      Section {ci+1}/{_n_chunks},"
            _t_chunk_start = time.time()
            _text, _segs = _whisper_transcribe(
                _chunk_path, duration=_chunk_dur, title="",
                cancel_ev=cancel_ev, pause_ev=pause_ev, progress_cb=_chunk_progress,
                _log_prefix=_section_prefix)
            _t_chunk_elapsed = time.time() - _t_chunk_start
            _clear_whisper_progress()  # Remove "Section X/Y,Transcribing, 100%..." before logging done line

            # Log per-section summary (indented, stays in log)
            _ce_m, _ce_s = divmod(int(_t_chunk_elapsed), 60)
            _ce_str = f"{_ce_m}min {_ce_s:02d}sec" if _ce_m else f"{_ce_s}sec"
            _cd_m, _cd_s = divmod(int(_chunk_dur), 60)
            _cd_str = f"{_cd_m}m{_cd_s:02d}s"
            _rt = f"{_chunk_dur / _t_chunk_elapsed:.1f}x realtime" if _t_chunk_elapsed > 0 else ""
            if _text:
                log(f"      Section {ci+1}/{_n_chunks} done ({_cd_str}, {_ce_str}, {_rt})\n", "simpleline_blue")
            else:
                _reason = "failed" if _whisper_last_failed else "no speech"
                log(f"      Section {ci+1}/{_n_chunks} — {_reason} ({_cd_str}, {_ce_str})\n", "simpleline")

            # Clean up chunk file immediately to save disk space
            try:
                os.remove(_chunk_path)
            except Exception:
                pass

            if _text:
                all_text_parts.append(_text)

            if _segs:
                # Offset all segment timestamps by the chunk's start position.
                # _whisper_transcribe returns {"start", "end", "text", "words"} dicts
                # where words have {"w", "s", "e"} sub-dicts.
                _offset = _start_sec
                for seg in _segs:
                    seg["start"] = round(seg["start"] + _offset, 2)
                    seg["end"] = round(seg["end"] + _offset, 2)
                    for w in seg.get("words", []):
                        w["s"] = round(w["s"] + _offset, 3)
                        w["e"] = round(w["e"] + _offset, 3)

                if ci > 0 and all_segments and _segs:
                    # Remove duplicate segments from the overlap zone
                    _overlap_start = _start_sec + _OVERLAP
                    # Drop segments from this chunk that start before the overlap boundary
                    _segs = [s for s in _segs if s["start"] >= _overlap_start - 2]

                all_segments.extend(_segs)

        if _whisper_last_failed and not all_text_parts:
            return None, []

        _full_text = " ".join(all_text_parts) if all_text_parts else None
        return _full_text, all_segments

    finally:
        # Clean up temp directory
        try:
            import shutil as _shutil
            _shutil.rmtree(_chunk_tmp_dir, ignore_errors=True)
        except Exception:
            pass


def _whisper_transcribe(audio_path, duration=0, title="", cancel_ev=None, pause_ev=None, progress_cb=None, _log_prefix=None, _retrying=False):
    """Transcribe a file using the persistent Whisper subprocess.

    Returns (text, segments) where text is str or None, and segments is a list of
    {"start": float, "end": float, "text": str} dicts (empty list on failure).
    If duration (seconds) is provided, progress percentage is logged in real time.
    title is shown in the progress line so the user knows which video is being processed.
    cancel_ev/pause_ev default to the global cancel_event/pause_event if not provided.
    _log_prefix overrides the default [idx/total] prefix (used by chunked transcription).

    On process stalls or crashes, sets _whisper_last_failed = True so callers can
    distinguish a process failure from a legitimate "no speech" result.
    """
    global _gpu_actively_encoding, _whisper_last_failed
    _whisper_last_failed = False
    _ce = cancel_ev or cancel_event
    _pe = pause_ev or pause_event
    global _whisper_proc
    with _whisper_lock:
        _wp_alive = _whisper_proc is not None and _whisper_proc.poll() is None
    if not _wp_alive:
        if not _start_whisper_process():
            _whisper_last_failed = True
            return None, []

    # Guard: if audio exceeds _WHISPER_MAX_DURATION, split into chunks and transcribe
    # each one separately to avoid loading the entire waveform into RAM at once.
    # Skip this guard when already called from _whisper_transcribe_chunked (indicated
    # by _log_prefix being set) — chunk durations can slightly exceed the limit due
    # to overlap padding, and re-entering the chunker would cause recursive splitting.
    if _log_prefix is None:
        _check_dur = duration
        if not _check_dur and audio_path:
            _check_dur = _ffprobe_duration(audio_path)
        if _check_dur and _check_dur > _WHISPER_MAX_DURATION:
            return _whisper_transcribe_chunked(
                audio_path, _check_dur, title=title,
                cancel_ev=cancel_ev, pause_ev=pause_ev, progress_cb=progress_cb)

    try:
        # In simple mode, prefix with [idx/total] instead of spaces.
        # _log_prefix overrides this (used by chunked transcription for indented section lines).
        if _log_prefix is not None:
            _wp = _log_prefix
        elif _is_simple_mode and _whisper_counter['total']:
            _wp = f"[{_whisper_counter['idx']}/{_whisper_counter['total']}] "
        else:
            _wp = "    "
        _title_disp = title
        if _title_disp:
            _title_disp = _trunc_pad_title(_title_disp, _MAX_TITLE_DISPLAY).rstrip()
        _title_part = f' "{_title_disp}"' if _title_disp else ""
        with _ffmpeg_lock:
            _gpu_actively_encoding = True
        try:
            log(f"{_wp}Transcribing{_title_part}, 0%...\n", "whisper_progress")
            request = json.dumps({"path": audio_path, "duration": duration})
            with _whisper_lock:
                _whisper_proc.stdin.write(request + "\n")
                _whisper_proc.stdin.flush()

            # Use the module-level reader thread + queue (started in _start_whisper_process).
            if _whisper_line_queue is None:
                log("  ⚠ Internal error: Whisper reader not initialized.\n", "red")
                _whisper_last_failed = True
                _stop_whisper_process()
                return None, []

            # Drain any stale data left over from a previous call
            _stale = 0
            while True:
                try:
                    _whisper_line_queue.get_nowait()
                    _stale += 1
                except queue.Empty:
                    break
            if _stale:
                log(f"  ⚠ Drained {_stale} stale message(s) from previous Whisper call.\n", "red")

            # Read responses — may be progress updates before the final result
            while True:
                try:
                    response_line = _whisper_line_queue.get(timeout=_WHISPER_STALL_TIMEOUT)
                except queue.Empty:
                    _is_retry = _retrying
                    if _is_retry:
                        log(
                            f"  ⚠ Whisper stalled again on retry (no output for "
                            f"{_WHISPER_STALL_TIMEOUT // 60} min). Skipping this file.\n",
                            "red",
                        )
                        _stop_whisper_process(force=True)
                        time.sleep(3)
                        _whisper_last_failed = True
                        return None, []
                    log(
                        f"  ⚠ Whisper stalled (no output for {_WHISPER_STALL_TIMEOUT // 60} min). "
                        f"Restarting process and retrying...\n",
                        "red",
                    )
                    _stop_whisper_process(force=True)
                    time.sleep(3)
                    _retry_result = _whisper_transcribe(
                        audio_path, duration=duration, title=title,
                        cancel_ev=cancel_ev, pause_ev=pause_ev, progress_cb=progress_cb,
                        _retrying=True)
                    return _retry_result

                if response_line is None:
                    _whisper_last_failed = True
                    return None, []

                response_line = response_line.strip()
                if not response_line:
                    continue
                try:
                    result = json.loads(response_line)
                except (json.JSONDecodeError, ValueError):
                    continue
                if result.get("status") == "starting":
                    log(f"{_wp}Transcribing{_title_part}, 0% — loading...\n", "whisper_progress")
                    continue
                if result.get("status") == "progress":
                    pct = result.get("pct", 0)
                    if progress_cb:
                        try:
                            progress_cb(pct)
                        except Exception:
                            pass
                    if _ce.is_set():
                        log(f"{_wp}Transcribing{_title_part}, {pct}% — cancelling after this file...\n", "whisper_progress")
                    elif _pe.is_set():
                        log(f"{_wp}Transcribing{_title_part}, {pct}% — will pause after this file...\n", "whisper_progress")
                    else:
                        log(f"{_wp}Transcribing{_title_part}, {pct}%...\n", "whisper_progress")
                    continue
                elif result.get("status") == "ok":
                    log(f"{_wp}Transcribing{_title_part}, 100%...\n", "whisper_progress")
                    _text = result.get("text") or None
                    _raw_segs = result.get("segments", [])
                    _segments = [{"start": s["s"], "end": s["e"], "text": s["t"],
                                  "words": s.get("w", [])} for s in _raw_segs]
                    return _text, _segments
                else:
                    log(f"  ⚠ Whisper error: {result.get('text', 'unknown')}\n", "red")
                    _whisper_last_failed = True
                    return None, []
        finally:
            with _ffmpeg_lock:
                _gpu_actively_encoding = False
    except Exception as e:
        log(f"  ⚠ Whisper communication error: {e}\n", "red")
        with _ffmpeg_lock:
            _gpu_actively_encoding = False
        _whisper_last_failed = True
        _stop_whisper_process()
        return None, []


# ─── Punctuation restoration (for YouTube auto-captions) ─────────────────────
def _load_punctuation_model():
    """Start the punctuation restoration subprocess on GPU. Returns True if ready."""
    global _punct_proc
    with _punct_lock:
        if _punct_proc is not None and _punct_proc.poll() is None:
            return True

    if not os.path.exists(_WHISPER_PYTHON):
        log("  ⚠ Punctuation model unavailable (Python 3.11 not found).\n", "red")
        return False

    # Check / install transformers in the CUDA Python environment
    if not _check_punct_installed():
        if not _install_punct_blocking():
            return False

    return _start_punct_process()


def _punctuate_text(text):
    """Restore punctuation and capitalization via the GPU subprocess.

    Returns original text if subprocess is unavailable or errors.
    Serialized via _punct_lock to prevent concurrent stdin/stdout interleaving.
    """
    global _punct_proc
    with _punct_lock:
        if _punct_proc is None or _punct_proc.poll() is not None:
            return text
        _local_proc = _punct_proc  # capture local reference under lock
        try:
            request = json.dumps({"text": text})
            _local_proc.stdin.write(request + "\n")
            _local_proc.stdin.flush()

            # Read response with a 60-second timeout to avoid blocking forever
            # if the subprocess hangs.
            _resp_q = queue.Queue()
            def _read_response():
                try:
                    _resp_q.put(_local_proc.stdout.readline())
                except Exception as _e:
                    _resp_q.put(_e)
            _t = threading.Thread(target=_read_response, daemon=True)
            _t.start()
            _t.join(timeout=60)
            if _t.is_alive():
                # Subprocess hung — kill it and report
                log("    ⚠ Punctuation subprocess timed out (60 s), killing it.\n", "red")
                _stop_punct_process()
                return text

            _raw = _resp_q.get_nowait()
            if isinstance(_raw, Exception):
                raise _raw
            response_line = _raw.strip()
            if not response_line:
                return text
            result = json.loads(response_line)
            if result.get("status") == "ok":
                return result.get("text", text)
            else:
                log(f"    ⚠ Punctuation error: {result.get('text', 'unknown')}\n", "red")
                return text
        except Exception:
            _stop_punct_process()  # Kill broken process
            return text


def _whisper_punct_fixup(text):
    """Run punctuation model on Whisper output only if it lacks punctuation."""
    if not text:
        return text
    # Require meaningful punctuation density, not just a single stray comma.
    # At least 1 punctuation mark per ~200 chars (and at least 3 total).
    _p_count = sum(1 for ch in text if ch in ',.!?;')
    if _p_count >= max(3, len(text) // 200):
        return text
    with _punct_lock:
        _proc_dead = _punct_proc is None or _punct_proc.poll() is not None
    if _proc_dead:
        return text  # Punctuation model not loaded — skip
    try:
        return _punctuate_text(text)
    except Exception:
        return text


def _check_internet(timeout=5):
    """Quick connectivity check. Returns True if internet is reachable."""
    for host in ("https://www.google.com", "https://dns.google"):
        try:
            resp = urllib.request.urlopen(host, timeout=timeout)
            resp.close()
            return True
        except Exception:
            continue
    return False


def _wait_for_internet(cancel_ev, pause_ev, log_fn=None):
    """Block until internet is restored or cancel is set. Returns True if restored, False if cancelled."""
    if log_fn:
        log_fn(f"  ⚠ Internet connection lost — pausing until restored...\n", "red")
    while not cancel_ev.is_set():
        if _check_internet(timeout=5):
            if log_fn:
                log_fn(f"  ✓ Internet restored — resuming.\n", "simpleline_green")
            return True
        time.sleep(3)
    return False


# ─── Background Internet Monitor ─────────────────────────────────────────────

def _start_internet_monitor():
    """Start the background internet monitor if not already running.

    Pings every 5 seconds.  After 2 consecutive failures, sets _internet_down
    (pausing all internet-dependent operations) and _internet_went_down_during
    (dirty flag so playlist fetches know to retry).  On restoration, clears
    _internet_down and logs a green message.  The thread exits automatically
    when no operations (_sync_running, _transcribe_running, _redownload_running)
    are active.
    """
    global _internet_monitor_running
    if _internet_monitor_running:
        return  # already running
    _internet_monitor_running = True  # set before thread start to close race window

    def _monitor_loop():
        global _internet_monitor_running
        _consec_fails = 0
        _was_down = False
        try:
            while True:
                # Exit when nothing needs internet monitoring
                if (not _sync_running and not _transcribe_running
                        and not _redownload_running and not _gpu_running):
                    break
                # Also exit if everything has been cancelled
                if cancel_event.is_set() and _gpu_cancel.is_set():
                    break

                if _check_internet(timeout=5):
                    _consec_fails = 0
                    if _was_down:
                        # Internet just came back
                        _internet_down.clear()
                        _was_down = False
                        log("  ✓ Internet restored — resuming operations.\n", "simpleline_green")
                else:
                    _consec_fails += 1
                    if _consec_fails >= 2 and not _was_down:
                        # Confirmed outage — pause everything
                        _internet_down.set()
                        _internet_went_down_during.set()
                        _was_down = True
                        log("  ⚠ Internet connection lost — all operations paused until restored.\n", "red")

                time.sleep(5)
        finally:
            _internet_monitor_running = False
            # Ensure we leave in a clean state if exiting while still flagged down
            # (e.g. user cancelled everything while offline)
            _internet_down.clear()

    t = threading.Thread(target=_monitor_loop, daemon=True)
    t.start()


def _block_if_no_internet(cancel_ev=None, pause_ev=None):
    """Block until internet is available.  Returns True if OK, False if cancelled.

    Uses the background monitor's _internet_down event.  If internet is currently
    down, blocks (polling every 1 s) until the monitor clears the flag or cancel
    fires.  If internet is up, returns immediately.
    """
    _ce = cancel_ev or cancel_event
    if not _internet_down.is_set():
        return True  # fast path — internet is fine
    # Internet is down — wait for the monitor to clear it
    while _internet_down.is_set():
        if _ce.is_set():
            return False
        time.sleep(1)
    return True


def _fetch_auto_captions(video_id, temp_dir, cookies_forced=False):
    """Fetch YouTube captions (manual or auto-generated) for a video.

    Returns (text, segments, needed_cookies) where text is str or None, segments
    is a list of {"start": float, "end": float, "text": str} dicts (empty list
    on failure), and needed_cookies is True if the cookieless attempt failed but
    the cookies attempt succeeded (used for adaptive cookie forcing).

    By default tries WITHOUT cookies first (faster — skips Firefox DB read),
    then falls back to WITH cookies.  If cookies_forced=True, goes straight to
    cookies (skips the cookieless attempt).
    """
    temp_base = os.path.join(temp_dir, f"_transcript_{video_id}")
    url = f"https://www.youtube.com/watch?v={video_id}"
    _last_stderr = [""]  # capture stderr for diagnostics

    def _cleanup_temp_files():
        """Remove ALL temp files for this video_id (not just .vtt)."""
        try:
            for f in glob.glob(os.path.join(temp_dir, f"_transcript_{video_id}*")):
                os.remove(f)
        except Exception:
            log(f"  {traceback.format_exc()}\n", "dim")

    def _run_fetch(use_cookies, force_overwrites=False):
        cmd = [
            "yt-dlp", "--skip-download",
            "--write-sub", "--write-auto-sub", "--sub-lang", "en", "--sub-format", "vtt",
            "-o", temp_base + ".%(ext)s",
            "--no-playlist",
        ]
        if force_overwrites:
            cmd.append("--force-overwrites")
        if use_cookies:
            cmd += ["--cookies-from-browser", "firefox"]
        cmd.append(url)
        try:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=120, startupinfo=startupinfo)
            _last_stderr[0] = (result.stderr or "").strip()
            return True
        except Exception as e:
            log(f"    ⚠ yt-dlp caption fetch error: {e}\n", "red")
            return False

    def _try_parse_vtt():
        """Check for .vtt files and parse if found.  Returns (text, segments, vtt_files).
        Prefers auto-generated subs (contain <c> tags with real word timestamps)
        over manual subs (which only get interpolated timestamps)."""
        vtt_files = glob.glob(os.path.join(temp_dir, f"_transcript_{video_id}*.vtt"))
        if not vtt_files:
            return None, [], []
        # Prefer auto-generated VTT — it has <c> tags with real word timestamps.
        # Manual subs typically don't have .en-orig in the filename.
        vtt_path = vtt_files[0]
        if len(vtt_files) > 1:
            for vf in vtt_files:
                try:
                    with open(vf, "r", encoding="utf-8") as _vf:
                        _sample = _vf.read(2000)
                    if "<c>" in _sample or "<c " in _sample:
                        vtt_path = vf  # has <c> tags — real word timestamps
                        break
                except Exception:
                    pass
        text = _parse_vtt_to_text(vtt_path)
        segments = _parse_vtt_to_segments(vtt_path)
        return text, segments, vtt_files

    _needed_cookies = False

    if cookies_forced:
        # Adaptive mode: previous failures indicate cookies are required
        _run_fetch(use_cookies=True, force_overwrites=True)
        text, segments, vtt_files = _try_parse_vtt()
    else:
        # First attempt: WITHOUT cookies (faster — skips Firefox DB read)
        _run_fetch(use_cookies=False, force_overwrites=True)
        text, segments, vtt_files = _try_parse_vtt()

        # Fallback: retry WITH cookies if cookieless attempt produced no usable text
        if not text:
            _cleanup_temp_files()
            _run_fetch(use_cookies=True, force_overwrites=True)
            text, segments, vtt_files = _try_parse_vtt()
            if text:
                _needed_cookies = True  # signal to caller for adaptive tracking

    # Log yt-dlp's error output when both attempts fail (aids diagnostics)
    if not text and _last_stderr[0]:
        # Truncate very long stderr to avoid flooding the log
        _err_preview = _last_stderr[0][:200]
        if len(_last_stderr[0]) > 200:
            _err_preview += "..."
        log(f"    yt-dlp: {_err_preview}\n", "dim")

    # Cleanup temp files
    for vf in vtt_files:
        try:
            os.remove(vf)
        except Exception:
            pass
    return (text if text else None), segments, _needed_cookies


def _format_upload_date(date_str):
    """Convert YYYYMMDD to (MM.DD.YYYY) display format."""
    if len(date_str) == 8 and date_str.isdigit():
        return f"({date_str[4:6]}.{date_str[6:8]}.{date_str[:4]})"
    return f"({date_str})" if date_str else "(Unknown date)"


def _format_duration(dur_str):
    """Ensure duration is wrapped in parens."""
    if not dur_str:
        return "(Unknown length)"
    return f"({dur_str})"


def _get_transcript_filename(ch_name, folder_path, split_years, split_months, combined,
                              year=None, month=None):
    """Build the transcript .txt file path based on organization settings.

    Returns (file_path, subfolder_path) where subfolder_path is the target directory.
    """
    if combined or (not split_years):
        # Single file in channel root
        return os.path.join(folder_path, f"{ch_name} Transcript.txt"), folder_path

    if split_years and split_months and year and month:
        # Year/Month: e.g. "ChannelName January 24 Transcript.txt" in year/month folder
        month_num = int(month) if isinstance(month, str) and month.isdigit() else month
        month_name = MONTH_NAMES.get(month_num, f"{month_num:02d} Unknown").split(" ", 1)[1]  # "January"
        yr_short = str(year)[-2:]  # "24"
        subfolder = os.path.join(folder_path, str(year), MONTH_NAMES.get(month_num, f"{month_num:02d} Unknown"))
        fname = f"{ch_name} {month_name} {yr_short} Transcript.txt"
        return os.path.join(subfolder, fname), subfolder

    if split_years and year:
        # Year only: e.g. "ChannelName 2024 Transcript.txt" in year folder
        subfolder = os.path.join(folder_path, str(year))
        fname = f"{ch_name} {year} Transcript.txt"
        return os.path.join(subfolder, fname), subfolder

    # Fallback
    return os.path.join(folder_path, f"{ch_name} Transcript.txt"), folder_path


def _scan_existing_transcripts(folder_path, ch_name):
    """Scan all transcript .txt files under folder_path. Return set of video titles already transcribed."""
    existing = set()
    pattern = re.compile(r'^===\((.+?)\),\s*\(')
    for dirpath, _dirs, files in os.walk(folder_path):
        for f in files:
            if f.startswith(ch_name) and f.endswith("Transcript.txt"):
                try:
                    with open(os.path.join(dirpath, f), "r", encoding="utf-8") as fh:
                        for line in fh:
                            m = pattern.match(line.strip())
                            if m:
                                existing.add(m.group(1))
                except Exception:
                    pass
    return existing


def _sort_transcript_entries(txt_paths):
    """Sort transcript entries in each .txt file chronologically by date.

    Entry format: ===({title}), ({MM.DD.YYYY}), ({duration}), ({source})===
    Entries are separated by triple-newline.
    """
    _entry_re = re.compile(r'^===\((.+?)\),\s*\((\d{2})\.(\d{2})\.(\d{4})\)')
    for txt_path in txt_paths:
        try:
            with open(txt_path, "r", encoding="utf-8") as f:
                content = f.read()
            if not content.strip():
                continue

            # Split into entries (each starts with ===)
            raw_entries = re.split(r'(?=^===\()', content, flags=re.MULTILINE)
            raw_entries = [e for e in raw_entries if e.strip()]
            if len(raw_entries) <= 1:
                continue  # nothing to sort

            # Parse date from each entry for sorting
            dated_entries = []
            for entry in raw_entries:
                m = _entry_re.match(entry.strip())
                if m:
                    mm, dd, yyyy = m.group(2), m.group(3), m.group(4)
                    sort_key = f"{yyyy}{mm}{dd}"
                else:
                    sort_key = "00000000"  # unknown date → put first
                dated_entries.append((sort_key, entry))

            # Sort newest first (reverse chronological)
            dated_entries.sort(key=lambda x: x[0], reverse=True)

            # Rewrite file atomically (temp + replace) to avoid corruption on disk-full
            _sorted_parts = []
            for _, entry in dated_entries:
                # Ensure each entry ends with exactly triple-newline
                _sorted_parts.append(entry.rstrip("\n") + "\n\n\n")
            sorted_content = "".join(_sorted_parts)

            _tmp_sort = txt_path + ".tmp_sort"
            try:
                with open(_tmp_sort, "w", encoding="utf-8") as f:
                    f.write(sorted_content)
                os.replace(_tmp_sort, txt_path)
            except Exception:
                try:
                    os.remove(_tmp_sort)
                except OSError:
                    pass
                raise
        except Exception:
            log(f"  {traceback.format_exc()}\n", "dim")  # don't break transcription over a sort error


def _ask_whisper_model_dialog(prompt_text="Which Whisper model to use?",
                              subtitle_text="Manual file transcription",
                              cancel_ev=None):
    """Show model selection dialog for manual transcription.
    Returns (model_string, timed_out) tuple, or (None, False) if cancelled.
    Blocks the calling thread until the user picks.
    cancel_ev: optional threading.Event to poll for cancellation (defaults to global cancel_event).
    """
    _cancel = cancel_ev or cancel_event
    _model_result = [None]
    _model_timed_out = [False]

    def _ask():
        _dlg = tk.Toplevel(root)
        _dlg.title("Whisper Model Selection")
        _dlg.configure(bg=C_BG)
        _dlg.resizable(False, False)
        _dlg.transient(root)
        _dlg.grab_set()
        _dlg.update_idletasks()
        _apply_dark_title_bar(_dlg)
        _rx = root.winfo_rootx() + root.winfo_width() // 2
        _ry = root.winfo_rooty() + root.winfo_height() // 2
        _dlg.geometry(f"+{_rx - 160}+{_ry - 140}")

        tk.Label(_dlg, text=prompt_text,
                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10, "bold"),
                 pady=10, padx=20).pack(fill="x")
        tk.Label(_dlg, text=subtitle_text,
                 bg=C_BG, fg=C_DIM, font=("Segoe UI", 9),
                 padx=20).pack(fill="x")

        _btn_frame = tk.Frame(_dlg, bg=C_BG, pady=10)
        _btn_frame.pack(fill="x", padx=20)

        _models = [
            ("tiny",     "Fastest  (~30-50\u00d7 realtime)",  "tiny"),
            ("small",    "Fast  (~15-20\u00d7 realtime)",     "small"),
            ("medium",   "Balanced  (~7-10\u00d7 realtime)",  "medium"),
            ("large-v3", "Best quality  (~3-5\u00d7 realtime)", "large-v3"),
        ]
        _DEFAULT_MODEL = "small"
        _countdown = {"secs": 60, "job": None}

        def _pick(m, dlg=_dlg):
            if _countdown["job"]:
                try:
                    _dlg.after_cancel(_countdown["job"])
                except Exception:
                    pass
            _model_result[0] = m
            try:
                dlg.destroy()
            except Exception:
                pass

        _timer_lbl = tk.Label(_dlg, text=f"Auto-selecting {_DEFAULT_MODEL} in 60s...",
                              bg=C_BG, fg=C_DIM, font=("Segoe UI", 8),
                              padx=20)
        _timer_lbl.pack(fill="x", pady=(0, 4))

        def _tick():
            if _model_result[0] is not None:
                return  # user already picked — avoid double destroy race
            _countdown["secs"] -= 1
            if _countdown["secs"] <= 0:
                _model_timed_out[0] = True
                _pick(_DEFAULT_MODEL)
                return
            try:
                _timer_lbl.config(text=f"Auto-selecting {_DEFAULT_MODEL} in {_countdown['secs']}s...")
                _countdown["job"] = _dlg.after(1000, _tick)
            except Exception:
                pass

        _countdown["job"] = _dlg.after(1000, _tick)

        for label, desc, model_id in _models:
            _row = tk.Frame(_btn_frame, bg=C_BG)
            _row.pack(fill="x", pady=2)
            _b = tk.Button(_row, text=label, width=10,
                           bg="#3a3a3a", fg=C_TEXT, activebackground="#555555",
                           activeforeground=C_TEXT, relief="flat", bd=0,
                           font=("Segoe UI", 9, "bold"), cursor="hand2",
                           command=lambda m=model_id: _pick(m))
            _b.pack(side="left", padx=(0, 8))
            tk.Label(_row, text=desc, bg=C_BG, fg=C_DIM,
                     font=("Segoe UI", 9)).pack(side="left")
            if model_id == _DEFAULT_MODEL:
                tk.Label(_row, text="(default)", bg=C_BG, fg="#5a8a5a",
                         font=("Segoe UI", 8)).pack(side="left", padx=(4, 0))

        _dlg.protocol("WM_DELETE_WINDOW", lambda: _pick(_DEFAULT_MODEL))

    if _root_alive:
        _ui_queue.append(_ask)
        while _model_result[0] is None and not _cancel.is_set():
            time.sleep(0.1)

    return _model_result[0], _model_timed_out[0]


def _ask_start_gpu_tasks(count, cancel_ev=None, timeout=180):
    """Show a timed dialog asking the user to start GPU Tasks. Returns True if user clicks Yes.
    Auto-dismisses after timeout seconds (default 3 min), returning False.
    Thread-safe: creates dialog on main thread, waits from worker thread.
    """
    _result = [None]  # None=pending, True=yes, False=no/timeout

    def _show():
        dlg = tk.Toplevel(root)
        dlg.title("Start GPU Tasks?")
        dlg.configure(bg=C_BG)
        dlg.resizable(False, False)
        dlg.grab_set()
        dlg.update_idletasks()
        _apply_dark_title_bar(dlg)
        dlg.protocol("WM_DELETE_WINDOW", lambda: _dismiss(False))

        tk.Label(dlg, text=f"Downloaded {count} videos so far.",
                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10, "bold")).pack(padx=20, pady=(14, 4))
        tk.Label(dlg, text="It is recommended to start GPU Tasks now\nto save storage space.",
                 bg=C_BG, fg=C_DIM, font=("Segoe UI", 9)).pack(padx=20, pady=(0, 8))

        _secs = [timeout]
        _timer_lbl = tk.Label(dlg, text=f"Auto-dismissing in {_secs[0]}s...",
                              bg=C_BG, fg=C_DIM, font=("Segoe UI", 8))
        _timer_lbl.pack(padx=20, pady=(0, 4))
        _timer_job = [None]

        def _tick():
            _secs[0] -= 1
            if _secs[0] <= 0:
                _dismiss(False)
                return
            try:
                _timer_lbl.config(text=f"Auto-dismissing in {_secs[0]}s...")
                _timer_job[0] = dlg.after(1000, _tick)
            except Exception:
                pass

        def _dismiss(val):
            _result[0] = val
            if _timer_job[0]:
                try:
                    dlg.after_cancel(_timer_job[0])
                except Exception:
                    pass
            try:
                dlg.destroy()
            except Exception:
                pass

        btn_row = tk.Frame(dlg, bg=C_BG)
        btn_row.pack(padx=20, pady=(4, 14))
        tk.Button(btn_row, text="Start GPU Tasks", bg="#3a6a3a", fg="#cccccc",
                  relief="flat", font=("Segoe UI", 9, "bold"), cursor="hand2",
                  command=lambda: _dismiss(True)).pack(side="left", padx=(0, 10))
        tk.Button(btn_row, text="Not Now", bg=C_SURFACE, fg=C_DIM,
                  relief="flat", font=("Segoe UI", 9), cursor="hand2",
                  command=lambda: _dismiss(False)).pack(side="left")

        _timer_job[0] = dlg.after(1000, _tick)
        dlg.update_idletasks()
        dlg.geometry(f"+{root.winfo_x() + 200}+{root.winfo_y() + 200}")

    _ui_queue.append(_show)
    _ce = cancel_ev or cancel_event
    while _result[0] is None and not _ce.is_set():
        time.sleep(0.25)
    return _result[0] is True


def _count_gpu_encode_batches(ch_url):
    """Count unprocessed encode/backlog_encode batches for a channel in the GPU queue."""
    count = 0
    with _gpu_queue_lock:
        for q in _gpu_queue:
            if q.get("ch_url") == ch_url and q["type"] in ("encode", "backlog_encode"):
                count += 1
    # Also count the currently-running item if it's an encode for this channel
    if _gpu_running and _gpu_current_item:
        _ci = _gpu_current_item
        if _ci.get("ch_url") == ch_url and _ci.get("type") in ("encode", "backlog_encode"):
            count += 1
    return count


def _get_max_encode_batch(ch_url):
    """Return the highest batch_num already queued (or running) for a channel's encode tasks, or 0."""
    with _gpu_queue_lock:
        nums = [q.get("batch_num", 0) for q in _gpu_queue
                if q.get("ch_url") == ch_url and q.get("type") == "encode" and q.get("batch_num") is not None]
        _cur = _gpu_current_item
        if _cur and _cur.get("ch_url") == ch_url and _cur.get("type") == "encode" and _cur.get("batch_num") is not None:
            nums.append(_cur["batch_num"])
    return max(nums) if nums else 0


def _get_next_compress_batch(ch_url):
    """Increment and return the compression batch sequence number for a channel.

    Persisted in channel config so batch numbers survive app restarts.
    """
    seq = 1
    with config_lock:
        for ch in config.get("channels", []):
            if ch.get("url") == ch_url:
                seq = ch.get("compress_batch_seq", 0) + 1
                ch["compress_batch_seq"] = seq
                break
        save_config(config)
    return seq


def _add_to_gpu_queue(item, _quiet=False):
    """Add a task to the GPU Tasks queue and show the GPU button.
    _quiet: if True, suppress duplicate warning logs (used by incremental compress callback).
    """
    with _gpu_queue_lock:
        # Also check the currently-running item for dedup
        _cur = _gpu_current_item
        # Duplicate check
        if item["type"] == "transcribe":
            if any(q.get("ch_url") == item["ch_url"] and q["type"] == "transcribe" for q in _gpu_queue) or \
               (_cur and _cur.get("ch_url") == item.get("ch_url") and _cur.get("type") == "transcribe"):
                if not _quiet:
                    log(f"  ⚠ {item['ch_name']} is already in the GPU Tasks queue.\n", "simpleline")
                return
            label = f"Transcribe {item['ch_name']}"
        elif item["type"] == "encode":
            _bn = item.get("batch_num")
            if _bn is not None:
                # Batch-numbered: dedup by channel + batch number
                if any(q.get("ch_url") == item["ch_url"] and q["type"] == "encode" and q.get("batch_num") == _bn for q in _gpu_queue) or \
                   (_cur and _cur.get("ch_url") == item.get("ch_url") and _cur.get("type") == "encode" and _cur.get("batch_num") == _bn):
                    if not _quiet:
                        log(f"  ⚠ {item['ch_name']} Batch {_bn} compression is already in the GPU Tasks queue.\n", "simpleline")
                    return
                label = f"Compress {item['ch_name']}, Batch {_bn}"
            else:
                # Non-batch: dedup by channel URL (original behavior)
                if any(q.get("ch_url") == item["ch_url"] and q["type"] == "encode" for q in _gpu_queue) or \
                   (_cur and _cur.get("ch_url") == item.get("ch_url") and _cur.get("type") == "encode"):
                    if not _quiet:
                        log(f"  ⚠ {item['ch_name']} compression is already in the GPU Tasks queue.\n", "simpleline")
                    return
                label = f"Compress {item['ch_name']}"
        elif item["type"] == "backlog_encode":
            if any(q.get("ch_url") == item["ch_url"] and q["type"] == "backlog_encode" for q in _gpu_queue) or \
               (_cur and _cur.get("ch_url") == item.get("ch_url") and _cur.get("type") == "backlog_encode"):
                if not _quiet:
                    log(f"  ⚠ {item['ch_name']} backlog is already in the GPU Tasks queue.\n", "simpleline")
                return
            label = f"Backlog {item['ch_name']}"
        elif item["type"] == "mt":
            if item.get("folder_path"):
                # Folder-based manual transcription
                if any(q.get("folder_path") == item["folder_path"] and q["type"] == "mt" for q in _gpu_queue) or \
                   (_cur and _cur.get("folder_path") == item.get("folder_path") and _cur.get("type") == "mt"):
                    if not _quiet:
                        log(f"  Folder already in GPU Tasks queue.\n", "simpleline")
                    return
                label = f"M.T. {item['folder_name']} ({item['vid_count']} files)"
            else:
                # Single-file manual transcription
                if any(q.get("file_path") == item.get("file_path") and q["type"] == "mt" for q in _gpu_queue) or \
                   (_cur and _cur.get("file_path") == item.get("file_path") and _cur.get("type") == "mt"):
                    if not _quiet:
                        log(f"  File already in GPU Tasks queue.\n", "simpleline")
                    return
                fname = os.path.splitext(os.path.basename(item["file_path"]))[0]
                label = f"M.T. {fname}"
        else:
            label = "GPU Task"
        _gpu_queue.append(item)
    log(f"=== Added to GPU Tasks: {label} ===\n", "header")
    _update_gpu_btn()
    _save_queue_state()
    # Refresh channel list so Transcribed column shows "Queued" immediately.
    # Use root.after(0) instead of _ui_queue — immune to queue overflow drops.
    if item.get("type") in ("transcribe", "mt") and _root_alive:
        try:
            root.after(0, refresh_channel_dropdowns)
        except Exception:
            pass
    # Autorun: auto-start GPU processing if enabled and not already running
    if not _gpu_running and config.get("autorun_gpu", False):
        _ui_queue.append(_gpu_start)


def _process_transcribe_queue():
    """Process next queued transcription if any. Returns True if one was started."""
    with _transcribe_queue_lock:
        if not _transcribe_queue:
            return False
        args = _transcribe_queue.pop(0)
        remaining = len(_transcribe_queue)

    ch_name, ch_url, folder, sy, sm, combined = args
    with _queue_order_lock:
        try:
            _queue_order.remove(("transcribe", ch_url))
        except ValueError:
            pass
    _current_job["label"] = f"Transcribe {ch_name}"
    _update_queue_btn()
    log(f"\n=== Processing queued transcription: {ch_name}", "header")
    if remaining:
        log(f" ({remaining} more in queue)", "header")
    log(f" ===\n", "header")
    _start_transcription(ch_name, ch_url, folder, sy, sm, combined)
    return True


def _process_redownload_queue():
    """Process next queued redownload if any. Returns True if one was started."""
    with _redownload_queue_lock:
        if not _redownload_queue:
            return False
        item = _redownload_queue.pop(0)
        remaining = len(_redownload_queue)

    ch_url = item["ch_url"]
    ch_name = item["ch_name"]
    with _queue_order_lock:
        try:
            _queue_order.remove(("redownload", ch_url))
        except ValueError:
            pass
    _rr_res = item.get("resolution", "")
    _rr_disp = "Best" if _rr_res == "best" else f"{_rr_res}p"
    log(f"\n=== Processing queued redownload: {ch_name} ({_rr_disp})", "header")
    if remaining:
        log(f" ({remaining} more in queue)", "header")
    log(f" ===\n", "header")
    _start_redownload_task(ch_name, ch_url, item["folder"], item["resolution"])
    return True


def _add_to_redownload_queue(ch_name, ch_url, folder, resolution):
    """Add a redownload task to the Sync-Tasks queue (not GPU queue)."""
    with _redownload_queue_lock:
        if any(q["ch_url"] == ch_url for q in _redownload_queue):
            log(f"  ⚠ {ch_name} redownload is already in the queue.\n", "simpleline")
            return
        # Also check if it's the currently running redownload
        if _redownload_running and _current_job.get("url") == ch_url:
            log(f"  ⚠ {ch_name} redownload is already running.\n", "simpleline")
            return
        _redownload_queue.append({
            "ch_name": ch_name,
            "ch_url": ch_url,
            "folder": folder,
            "resolution": resolution,
        })
    _rr_disp = "Best" if resolution == "best" else f"{resolution}p"
    with _queue_order_lock:
        _queue_order.append(("redownload", ch_url))
    log(f"\n=== Added to Sync List: Redownload {ch_name} ({_rr_disp}) ===\n", "header")
    _update_queue_btn()
    _save_queue_state()

    # If nothing else is running, start processing immediately
    # GPU-driven transcription (_transcribe_sync_controlled=False) is independent and does not block redownload
    if not _sync_running and not _reorg_running and not (_transcribe_running and _transcribe_sync_controlled) and not _redownload_running:
        _process_redownload_queue()


def _start_redownload_task(ch_name, ch_url, folder, resolution):
    """Start a redownload task as a sync-pipeline job."""
    global _redownload_running

    if _sync_running or _reorg_running or (_transcribe_running and _transcribe_sync_controlled) or _redownload_running:
        _add_to_redownload_queue(ch_name, ch_url, folder, resolution)
        return

    # Set flag before starting thread to close the race window where a second
    # call could pass the check above before the thread sets it itself.
    _redownload_running = True
    _update_global_pause_btn_sync()
    _start_internet_monitor()

    def _worker():
        global _redownload_running, _current_redownload_item
        # Only clear stale cancel if no other operations are running
        if not _sync_running and not _reorg_running and not (_transcribe_running and _transcribe_sync_controlled):
            cancel_event.clear()

        _current_redownload_item = {"ch_name": ch_name, "ch_url": ch_url, "folder": folder, "resolution": resolution}
        _rr_disp = "Best" if resolution == "best" else f"{resolution}p"
        _current_job["label"] = f"Redownload {ch_name} ({_rr_disp})"
        _current_job["url"] = ch_url
        _update_queue_btn()
        _tray_start_spin()
        _update_tray_tooltip(f"YT Archiver — Redownloading {ch_name}")
        try:
            _backlog_redownload_channel(
                ch_name, ch_url, folder, resolution,
                cancel_ev=cancel_event, pause_ev=pause_event,
                _sync_mode=True
            )
        except Exception as e:
            log(f"\n  ⚠ Redownload error: {e}\n", "red")
        finally:
            _redownload_running = False
            _current_redownload_item = None
            _current_job["label"] = None
            _current_job["url"] = None
            _tray_stop_spin()
            _update_tray_tooltip("YT Archiver — Idle")
            _invalidate_channel_disk_cache(ch_url)

            # Process next queued item
            _queue_started = False
            if _skip_current.is_set():
                _skip_current.clear()
                cancel_event.clear()
                _queue_started = _process_next_queued()
            elif not cancel_event.is_set():
                _queue_started = _process_next_queued()
            if not _queue_started:
                try:
                    _ui_queue.append(_sync_task_finished)
                except Exception:
                    pass
            _save_queue_state()

    try:
        threading.Thread(target=_worker, daemon=True).start()
    except Exception:
        _redownload_running = False


def _add_to_metadata_queue(ch_name, ch_url, folder_path, split_years, split_months, year, month, scope_label, refresh=False):
    """Add a metadata download task to the Sync-Tasks queue."""
    _key = f"metadata:{ch_name}:{year}:{month}"
    with _metadata_queue_lock:
        if any(q["_key"] == _key for q in _metadata_queue):
            log(f"  ⚠ {scope_label} metadata is already in the queue.\n", "simpleline")
            return
        if _metadata_running and _current_job.get("_metadata_key") == _key:
            log(f"  ⚠ {scope_label} metadata is already running.\n", "simpleline")
            return
        _metadata_queue.append({
            "ch_name": ch_name,
            "ch_url": ch_url,
            "folder_path": folder_path,
            "split_years": split_years,
            "split_months": split_months,
            "year": year,
            "month": month,
            "scope_label": scope_label,
            "refresh": refresh,
            "_key": _key,
        })
    with _queue_order_lock:
        _queue_order.append(("metadata", _key))
    log(f"\n=== Added to Sync List: Download {scope_label} Metadata ===\n", "header")
    _update_queue_btn()
    _save_queue_state()

    # If nothing else is running, start processing immediately
    if not _sync_running and not _reorg_running and not (_transcribe_running and _transcribe_sync_controlled) and not _redownload_running and not _metadata_running:
        _process_metadata_queue()


def _process_metadata_queue():
    """Pop the next metadata task from the queue and start it."""
    with _metadata_queue_lock:
        if not _metadata_queue:
            return False
        item = _metadata_queue.pop(0)
    with _queue_order_lock:
        try:
            _queue_order.remove(("metadata", item["_key"]))
        except ValueError:
            pass
    _start_metadata_task(item)
    return True


def _start_metadata_task(item):
    """Start a metadata download task as a sync-pipeline job."""
    global _metadata_running

    if _sync_running or _reorg_running or (_transcribe_running and _transcribe_sync_controlled) or _redownload_running or _metadata_running:
        with _metadata_queue_lock:
            _metadata_queue.insert(0, item)
        with _queue_order_lock:
            _queue_order.insert(0, ("metadata", item["_key"]))
        return

    _metadata_running = True
    _update_global_pause_btn_sync()
    _start_internet_monitor()

    def _worker():
        global _metadata_running
        if not _sync_running and not _reorg_running and not (_transcribe_running and _transcribe_sync_controlled):
            cancel_event.clear()

        _current_job["label"] = f"Download {item['scope_label']} Metadata"
        _current_job["url"] = None
        _current_job["_metadata_key"] = item["_key"]
        _update_queue_btn()
        _tray_start_spin()
        _update_tray_tooltip(f"YT Archiver — Downloading {item['scope_label']} metadata")
        try:
            _run_metadata_download(item)
        except Exception as e:
            log(f"\n  ⚠ Metadata error: {e}\n", "red")
        finally:
            _metadata_running = False
            _current_job["label"] = None
            _current_job["url"] = None
            _current_job.pop("_metadata_key", None)
            _tray_stop_spin()
            _update_tray_tooltip("YT Archiver — Idle")

            _queue_started = False
            if _skip_current.is_set():
                _skip_current.clear()
                cancel_event.clear()
                _queue_started = _process_next_queued()
            elif not cancel_event.is_set():
                _queue_started = _process_next_queued()
            if not _queue_started:
                try:
                    _ui_queue.append(_sync_task_finished)
                except Exception:
                    pass
            _save_queue_state()

    try:
        threading.Thread(target=_worker, daemon=True).start()
    except Exception:
        _metadata_running = False


def _run_metadata_download(item):
    """Worker: fetch metadata for all videos in the given scope.
    Uses the TranscriptionParser instance methods via the global reference."""
    ch_name = item["ch_name"]
    ch_url = item.get("ch_url", "")
    folder_path = item["folder_path"]
    split_years = item["split_years"]
    split_months = item["split_months"]
    year = item["year"]
    month = item["month"]
    scope_label = item["scope_label"]
    refresh = item.get("refresh", False)

    log(f"Metadata: preparing {scope_label}...\n", "simpleline")

    # Get the TP instance (Browse tab) for DB access and metadata helpers
    tp = _tp_panel_ref[0]
    if not tp or not tp._conn:
        log("Metadata: no database connection.\n", "red")
        return

    # Try videos table first, fall back to scanning the filesystem
    sql = "SELECT video_id, title, year, month, filepath FROM videos WHERE channel=?"
    params = [ch_name]
    if year is not None:
        sql += " AND year=?"
        params.append(year)
    if month is not None:
        sql += " AND month=?"
        params.append(month)

    rows = []
    try:
        rows = tp._db_execute(sql, params).fetchall()
    except Exception:
        pass

    if not rows:
        # Fallback: scan the filesystem for video files in the channel folder
        log(f"  No videos in DB for {scope_label} — scanning folder...\n", "dim")
        scan_path = folder_path
        if year is not None:
            scan_path = os.path.join(scan_path, str(year))
        if month is not None and 1 <= (month or 0) <= 12:
            scan_path = os.path.join(scan_path, MONTH_NAMES.get(month, f"{month:02d} Unknown"))
        if os.path.isdir(scan_path):
            for dirpath, _, filenames in os.walk(scan_path):
                for fn in filenames:
                    fn_lower = fn.lower()
                    if not any(fn_lower.endswith(ext) for ext in _VIDEO_EXTS):
                        continue
                    if ".temp." in fn_lower or fn_lower.endswith(".part"):
                        continue
                    fp = os.path.join(dirpath, fn)
                    title = os.path.splitext(fn)[0]
                    _vid_id = None
                    _bracket = title.rfind(" [")
                    if _bracket >= 0 and title.endswith("]"):
                        _candidate = title[_bracket + 2:-1]
                        if 10 <= len(_candidate) <= 12 and re.match(r'^[\w-]+$', _candidate):
                            _vid_id = _candidate
                    # Derive year/month from path
                    _, v_year, v_month = _tp_parse_path_meta(fp, [folder_path])
                    rows.append((_vid_id, title, v_year, v_month, fp))

    if not rows:
        log(f"Metadata: {scope_label} — no videos found.\n"
            f"  Check that video files exist in the channel folder.\n", "red")
        return

    log(f"  Found {len(rows)} video(s) — resolving video IDs...\n", "dim")

    # Resolve missing video_ids from segments table or JSONL files on disk
    _resolved_rows = []
    _no_id_count = 0
    _seg_id_map = {}
    # Try segments table first
    try:
        for _st, _sv in tp._db_execute(
                "SELECT DISTINCT title, video_id FROM segments "
                "WHERE channel=? AND video_id != ''",
                (ch_name,)).fetchall():
            if _sv:
                _seg_id_map[_st] = _sv
    except Exception:
        pass
    # If segments had nothing, read JSONL files from the channel folder
    if not _seg_id_map:
        log(f"  Scanning transcript files for video IDs...\n", "dim")
        for dirpath, _, filenames in os.walk(folder_path):
            try:
                for _fn in filenames:
                    if _fn.endswith('.jsonl') and _fn.startswith('.'):
                        _jf = os.path.join(dirpath, _fn)
                        with open(_jf, 'r', encoding='utf-8', errors='replace') as _fh:
                            for _jline in _fh:
                                _jline = _jline.strip()
                                if not _jline:
                                    continue
                                try:
                                    _jd = json.loads(_jline)
                                    _jvid = _jd.get("video_id", "")
                                    _jtitle = _jd.get("title", "")
                                    if _jvid and _jtitle and _jtitle not in _seg_id_map:
                                        _seg_id_map[_jtitle] = _jvid
                                except (json.JSONDecodeError, Exception):
                                    continue
            except (OSError, PermissionError):
                continue

    _need_search = []  # (index, title, v_year, v_month, filepath) for yt-dlp search
    for vid_id, title, v_year, v_month, filepath in rows:
        if not vid_id:
            # Try segments table lookup
            vid_id = _seg_id_map.get(title)
        if not vid_id and filepath:
            # Try filename pattern: "Title [VIDEO_ID].ext"
            _base = os.path.splitext(os.path.basename(filepath))[0]
            _bracket = _base.rfind(" [")
            if _bracket >= 0 and _base.endswith("]"):
                _candidate = _base[_bracket + 2:-1]
                if 10 <= len(_candidate) <= 12 and re.match(r'^[\w-]+$', _candidate):
                    vid_id = _candidate
        if vid_id:
            # Backfill into videos table if it was missing
            if filepath:
                try:
                    tp._db_execute(
                        "UPDATE videos SET video_id=? WHERE filepath=? AND video_id IS NULL",
                        (vid_id, filepath))
                except Exception:
                    pass
            _resolved_rows.append((vid_id, title, v_year, v_month, filepath))
        else:
            _need_search.append((title, v_year, v_month, filepath))
            _no_id_count += 1

    # For videos with no video_id, try searching YouTube by title + channel name
    if _need_search and ch_url:
        log(f"  Searching YouTube for {len(_need_search)} video(s) with no ID...\n", "dim")
        _search_found = 0
        _search_i = 0
        # Track all known video_ids to avoid assigning the same ID to multiple videos
        _known_vids = set(vid for vid, *_ in _resolved_rows)
        try:
            for _db_vid, in tp._db_execute(
                    "SELECT DISTINCT video_id FROM videos WHERE channel=? AND video_id IS NOT NULL AND video_id != ''",
                    (ch_name,)).fetchall():
                _known_vids.add(_db_vid)
        except Exception:
            pass
        for _s_title, _s_year, _s_month, _s_filepath in _need_search:
            if cancel_event.is_set():
                break
            # Pause support during search phase
            if pause_event.is_set() and not cancel_event.is_set():
                log(f"  ⏸ Metadata paused at {_fmt_time()} — click Resume.\n", "pausestatus")
                _tray_stop_spin(force=True)
                while pause_event.is_set() and not cancel_event.is_set():
                    time.sleep(0.5)
                clear_pause_status()
                if not cancel_event.is_set():
                    _tray_start_spin()
                    log(f"  ▶ Metadata resumed at {_fmt_time()}...\n", "pauselog")
            _search_i += 1
            _trunc_s = _s_title[:50] + "..." if len(_s_title) > 50 else _s_title
            log(f"  \u2014 [{_search_i}/{len(_need_search)}] Searching: {_trunc_s}\n", "simpleline")
            try:
                _search_cmd = [
                    "yt-dlp", "--dump-json", "--no-download", "--no-warnings",
                    "--skip-download", "--cookies-from-browser", "firefox",
                    "--playlist-items", "1",
                    f"ytsearch1:{_s_title} {ch_name}"
                ]
                _search_proc = spawn_yt_dlp(_search_cmd)
                if _search_proc:
                    _search_out, _ = _search_proc.communicate(timeout=30)
                    cleanup_process(_search_proc)
                    if _search_proc.returncode == 0 and _search_out.strip():
                        _search_data = json.loads(_search_out)
                        _found_id = _search_data.get("id", "")
                        _found_channel = _search_data.get("channel", "") or _search_data.get("uploader", "")
                        # Verify the result is from the same channel AND not already used
                        _found_url = _search_data.get("uploader_url", "") or _search_data.get("channel_url", "")
                        _norm = lambda s: re.sub(r'[\s\-_\.]+', '', s).lower()
                        _ch_match = False
                        if _found_url and ch_url:
                            # Primary: compare channel URLs (handles renamed channels)
                            _ch_match = _found_url.rstrip('/').lower() == ch_url.rstrip('/').lower()
                        if not _ch_match and _found_channel:
                            # Fallback: compare normalized channel names
                            _ch_match = _norm(_found_channel) == _norm(ch_name)
                        if _found_id and _ch_match:
                            if _found_id in _known_vids:
                                log(f"    Skipped (ID already belongs to another video) \u2014\n", "simpleline_pink")
                            else:
                                _known_vids.add(_found_id)
                                _resolved_rows.append((_found_id, _s_title, _s_year, _s_month, _s_filepath))
                                _search_found += 1
                                _no_id_count -= 1
                                # Backfill into videos table
                                if _s_filepath:
                                    try:
                                        tp._db_execute(
                                            "UPDATE videos SET video_id=? WHERE filepath=? AND video_id IS NULL",
                                            (_found_id, _s_filepath))
                                    except Exception:
                                        pass
            except (subprocess.TimeoutExpired, json.JSONDecodeError, Exception):
                if '_search_proc' in dir() and _search_proc:
                    try:
                        _search_proc.kill()
                        cleanup_process(_search_proc)
                    except Exception:
                        pass
        if _search_found:
            log(f"  Found {_search_found} video ID(s) via YouTube search.\n", "dim")
            try:
                tp._db_commit()
            except Exception:
                pass

    if _resolved_rows:
        try:
            tp._db_commit()
        except Exception:
            pass
    if _no_id_count:
        log(f"  ({_no_id_count} video(s) skipped — no video ID found)\n", "dim")

    # Group videos by their target folder
    folder_groups = {}
    for vid_id, title, v_year, v_month, filepath in _resolved_rows:
        meta_path, subfolder = tp._get_metadata_jsonl_path(
            ch_name, folder_path, split_years, split_months,
            year=v_year, month=v_month)
        if meta_path not in folder_groups:
            folder_groups[meta_path] = {"subfolder": subfolder, "videos": []}
        folder_groups[meta_path]["videos"].append(
            (vid_id, title, v_year, v_month, filepath))

    total = sum(len(g["videos"]) for g in folder_groups.values())
    if total == 0:
        log(f"Metadata: {scope_label} — no videos with video IDs found.\n", "simpleline")
        return
    _meta_t0 = time.time()
    skipped = 0
    errors = 0

    refreshed = 0
    _mode_label = "Refreshing" if refresh else "Metadata"

    # Pre-count how many actually need fetching so the [X/Y] counter is accurate
    _to_fetch = []
    for meta_path, group in folder_groups.items():
        existing = tp._read_metadata_jsonl(meta_path)
        group["_existing"] = existing  # cache for reuse below
        for vid_id, title, v_year, v_month, filepath in group["videos"]:
            if vid_id in existing and not refresh:
                skipped += 1
            else:
                _to_fetch.append((meta_path, vid_id, title, v_year, v_month, filepath))

    _fetch_total = len(_to_fetch)
    if _fetch_total == 0 and skipped > 0:
        log(f"{_mode_label}: {scope_label} — all {skipped} videos already have metadata.\n", "simpleline")
        return
    if skipped:
        log(f"{_mode_label}: {scope_label} — {_fetch_total} to fetch ({skipped} already done).\n", "simpleline")
    else:
        log(f"{_mode_label}: {scope_label} — {_fetch_total} videos to process.\n", "simpleline")

    _fetch_done = 0
    _changed_paths = set()

    for meta_path, group in folder_groups.items():
        if cancel_event.is_set():
            log(f"{_mode_label}: cancelled.\n", "simpleline")
            return
        subfolder = group["subfolder"]
        existing = group["_existing"]

        thumb_dir = os.path.join(subfolder, ".Thumbnails")
        os.makedirs(thumb_dir, exist_ok=True)
        if os.name == "nt":
            try:
                ctypes.windll.kernel32.SetFileAttributesW(
                    os.path.normpath(thumb_dir), 0x02)
            except Exception:
                pass

        changed = False
        for vid_id, title, v_year, v_month, filepath in group["videos"]:
            if cancel_event.is_set():
                log(f"{_mode_label}: cancelled.\n", "simpleline")
                if changed:
                    tp._write_metadata_jsonl(meta_path, existing)
                return
            # Pause support
            if pause_event.is_set() and not cancel_event.is_set():
                log(f"  ⏸ Metadata paused at {_fmt_time()} — click Resume.\n", "pausestatus")
                _tray_stop_spin(force=True)
                while pause_event.is_set() and not cancel_event.is_set():
                    time.sleep(0.5)
                clear_pause_status()
                if not cancel_event.is_set():
                    _tray_start_spin()
                    log(f"  ▶ Metadata resumed at {_fmt_time()}...\n", "pauselog")

            if vid_id in existing and not refresh:
                continue

            _fetch_done += 1
            _is_refresh = vid_id in existing and refresh
            _prefix = "Refresh" if _is_refresh else "Metadata"
            _trunc = _trunc_pad_title(title, _MAX_TITLE_DISPLAY - len(_prefix) - 3)
            log(f"[{_fetch_done}/{_fetch_total}] {_prefix} - {_trunc}\n", "simpleline")

            entry = tp._fetch_video_metadata(vid_id, title)
            if entry:
                if _is_refresh:
                    # Merge: update counts and comments but keep original static fields
                    old = existing[vid_id]
                    old["view_count"] = entry.get("view_count", old.get("view_count", 0))
                    old["like_count"] = entry.get("like_count", old.get("like_count", 0))
                    old["comment_count"] = entry.get("comment_count", old.get("comment_count", 0))
                    old["comments"] = entry.get("comments", old.get("comments", []))
                    old["fetched_at"] = entry.get("fetched_at", "")
                    # Update thumbnail if it changed
                    if entry.get("thumbnail_url"):
                        old["thumbnail_url"] = entry["thumbnail_url"]
                    refreshed += 1
                else:
                    existing[vid_id] = entry
                changed = True
                thumb_url = entry.get("thumbnail_url", "")
                if thumb_url:
                    tp._download_thumbnail(thumb_url, thumb_dir, title, vid_id)
            else:
                errors += 1

        if changed:
            tp._write_metadata_jsonl(meta_path, existing)

    done = _fetch_done + skipped

    _parts = [f"{done} processed"]
    if refreshed:
        _parts.append(f"{refreshed} refreshed")
    if skipped:
        _parts.append(f"{skipped} already had metadata")
    if errors:
        _parts.append(f"{errors} failed")
    log(f"=== Metadata Complete: {scope_label} — {', '.join(_parts)} ===\n", "green")
    _meta_elapsed = time.time() - _meta_t0
    _new_count = done - skipped - errors
    _record_metadata(ch_name, _new_count, refreshed, skipped, errors, _meta_elapsed)

    # Invalidate grid cache for this channel so thumbnails refresh on next view
    if tp and (_new_count > 0 or refreshed > 0):
        def _invalidate():
            try:
                _stale = [k for k in tp._grid_cache if k[0] == ch_name]
                for k in _stale:
                    del tp._grid_cache[k]
                # If currently viewing this channel, force a reload
                if tp._grid_visible and tp._grid_scope and tp._grid_scope[0] == ch_name:
                    tp._grid_scope = None  # force _show_grid to reload
                    tp._show_grid(ch_name, year, month)
            except Exception:
                pass
        tp.after(0, _invalidate)


def _has_pending_redownload(ch_url):
    """Check if a channel has an incomplete redownload (progress file exists)."""
    with config_lock:
        _rd_base = config.get("output_dir", "").strip() or BASE_DIR
        _channels = list(config.get("channels", []))
    for ch in _channels:
        if ch.get("url") == ch_url:
            folder = os.path.join(_rd_base, sanitize_folder(ch.get("name", "")))
            pfile = os.path.join(folder, "_redownload_progress.json")
            if os.path.exists(pfile):
                try:
                    with open(pfile, "r", encoding="utf-8") as f:
                        data = json.load(f)
                    return data.get("resolution", "")
                except Exception:
                    pass
            break
    return ""


def _start_transcription(ch_name, ch_url, folder, split_years, split_months, combined,
                         cancel_ev=None, pause_ev=None, skip_model_dialog=False, _sync_mode=False,
                         captions_only=False, retranscribe=False):
    """Start transcribing a channel. Queues if something is already running.

    cancel_ev/pause_ev: optional threading.Events (default to global cancel_event/pause_event).
    skip_model_dialog: if True, skip model selection and use current _whisper_model_choice.
    _sync_mode: if True, run the worker body directly (blocking) instead of spawning a thread.
    captions_only: if True (always with _sync_mode=True), run only Phase A (auto-captions+punctuation)
                   inline; queue a GPU task for any videos that still need Whisper, then return.
    """
    global _transcribe_running

    if not _sync_mode and (_sync_running or _reorg_running or _transcribe_running or _redownload_running):
        with _transcribe_queue_lock:
            if not any(q[1] == ch_url for q in _transcribe_queue):
                _transcribe_queue.append((ch_name, ch_url, folder, split_years, split_months, combined))
                with _queue_order_lock:
                    _queue_order.append(("transcribe", ch_url))
                log(f"\n=== Added {ch_name} transcription to Sync List ===\n", "header")
            else:
                log(f"  ⚠ {ch_name} is already in the transcription queue.\n", "simpleline")
        _update_queue_btn()
        return

    def _worker():
        global _transcribe_running, _transcribe_sync_controlled, _whisper_model_choice
        _ce = cancel_ev or cancel_event
        _pe = pause_ev or pause_event
        _transcribe_running = True
        _update_global_pause_btn_sync()
        _start_internet_monitor()
        _transcribe_sync_controlled = (cancel_ev is None)  # True when sync pipeline, False when GPU-driven
        if not _sync_mode:
            _current_job["label"] = f"Transcribe {ch_name}"
            _current_job["url"] = ch_url
            _update_queue_btn()
        _tray_start_spin(red=True)
        _update_tray_tooltip(f"YT Archiver — Transcribing {ch_name}")
        _ui_queue.append(refresh_channel_dropdowns)
        _whisper_available = None  # None = not checked yet
        _user_skipped_whisper = False  # True if user chose "skip" at Whisper model prompt

        try:
            # Only clear cancel for standalone (non-sync) transcription jobs;
            # in sync mode the cancel_event is shared and clearing it would
            # erase an in-flight cancel from another operation.
            if not _sync_mode:
                _ce.clear()
                _ui_queue.append(_update_queue_btn)

            log(f"\n{'='*60}\n", "tx_sep")
            log(f"  TRANSCRIBING: {ch_name}\n", "tx_head")
            log(f"{'='*60}\n\n", "tx_sep")

            # ── Step 1: Scan local video files ──────────────────────────
            log("  — Scanning local video files...\n", "simpleline")
            local_files = {}  # filename_no_ext -> full_path
            for dirpath, _, files in os.walk(folder):
                for f in files:
                    if f.lower().endswith(_MEDIA_EXTS):
                        # Skip partial/temp files from interrupted downloads
                        if ".temp." in f.lower() or ".part" in f.lower():
                            continue
                        fname_no_ext = os.path.splitext(f)[0]
                        local_files[fname_no_ext] = os.path.join(dirpath, f)

            if not local_files:
                log("  ⚠ No video files found in channel folder.\n", "red")
                return

            log(f"  — Found {len(local_files)} video file(s) on disk.\n", "simpleline")

            if _ce.is_set():
                log(f"\n  ⛔ Transcription cancelled.\n", "red")
                return

            # ── Step 2: Scan existing transcripts to skip already-done ──
            already_done = _scan_existing_transcripts(folder, ch_name)
            if retranscribe:
                already_done = set()  # re-transcribe everything
            files_to_process = {}
            for fname, fpath in local_files.items():
                if fname not in already_done:
                    files_to_process[fname] = fpath

            if already_done:
                log(f"  — {len(already_done)} video(s) already transcribed — skipping.\n", "simpleline")

            _jsonl_existing = (
                _scan_existing_jsonl(folder, ch_name) if already_done else set())
            _jsonl_needed = already_done - _jsonl_existing if already_done else set()

            if not files_to_process:
                log(f"  ✓ All videos already transcribed!\n", "simpleline_green")
                if _jsonl_needed:
                    log(f"  — {len(_jsonl_needed)} video(s) need searchable .jsonl — will generate next transcription run.\n", "dim")
                # Record in activity log (0 transcribed — shows as uncolored/white tag)
                _record_transcription(0, 0, 0, channel_name=ch_name, skipped=0)
                # Mark channel as fully transcribed
                with config_lock:
                    for _cfg_ch in config.get("channels", []):
                        if _cfg_ch.get("url") == ch_url:
                            _cfg_ch["transcription_complete"] = True
                            _cfg_ch["transcription_pending"] = 0
                            break
                    save_config(config)
                return

            if _ce.is_set():
                log(f"\n  ⛔ Transcription cancelled.\n", "red")
                return

            # ── Whisper pending cache ────────────────────────────────────
            # If a previous run identified files needing Whisper but was cancelled before
            # Phase B ran, load those files so we skip re-fetching captions for them.
            _whisper_cache_path = os.path.join(folder, "_whisper_pending.json")
            _whisper_cache_set = set()  # set of fpaths known to need Whisper
            try:
                if os.path.exists(_whisper_cache_path):
                    with open(_whisper_cache_path, "r", encoding="utf-8") as _cf:
                        _cached_entries = json.load(_cf)
                    # Only keep files still on disk and not yet transcribed
                    _fp_to_process = set(files_to_process.values())
                    _whisper_cache_set = {
                        e["fpath"] for e in _cached_entries
                        if isinstance(e, dict) and e.get("fpath") and e["fpath"] in _fp_to_process
                    }
                    if _whisper_cache_set:
                        log(f"  — Resuming: {len(_whisper_cache_set)} file(s) already identified for Whisper — skipping caption re-check.\n", "simpleline")
            except Exception:
                _whisper_cache_set = set()

            # ── Step 3: Fetch YT playlist for title→ID matching ─────────
            log("  — Fetching YouTube video list for caption matching...\n", "simpleline")
            yt_title_to_id = {}  # yt_title -> video_id
            def _fetch_yt_title_map(use_cookies):
                """Fetch title→id map from YouTube playlist. Returns {} on failure.
                Cancel-aware: polls _ce every second so cancellation doesn't block 5 min.
                Uses --verbose so stderr shows page progress (yt-dlp buffers all stdout
                until the entire playlist is enumerated)."""
                _cmd = [
                    "yt-dlp", "--flat-playlist",
                    "--print", "%(id)s|||%(title)s",
                    "--no-warnings", "--verbose",
                ]
                if use_cookies:
                    _cmd += ["--cookies-from-browser", "firefox"]
                _cmd.append(ch_url)
                try:
                    _proc = subprocess.Popen(
                        _cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                        text=True, startupinfo=startupinfo
                    )
                    # Scale timeout with channel size: 5 min base + 30s per 1000 videos, up to 30 min
                    _timeout_s = min(1800, 300 + (len(local_files) // 1000) * 30)
                    _deadline = time.time() + _timeout_s
                    _result = {}
                    _stdout_lines = []
                    _stdout_queue = queue.Queue()
                    _stderr_queue = queue.Queue()
                    _stdout_done = threading.Event()
                    _stderr_done = threading.Event()
                    def _read_stdout():
                        try:
                            for _ln in _proc.stdout:
                                _stdout_queue.put(_ln)
                        except ValueError:
                            pass
                        finally:
                            _stdout_done.set()
                    def _read_stderr():
                        try:
                            for _ln in _proc.stderr:
                                _stderr_queue.put(_ln)
                        except ValueError:
                            pass
                        finally:
                            _stderr_done.set()
                    threading.Thread(target=_read_stdout, daemon=True).start()
                    threading.Thread(target=_read_stderr, daemon=True).start()
                    _last_page = 0
                    _page_re = re.compile(r'page (\d+)')
                    while True:
                        # Drain stdout
                        while not _stdout_queue.empty():
                            try:
                                _stdout_lines.append(_stdout_queue.get_nowait())
                            except queue.Empty:
                                break
                        # Drain stderr for page progress
                        while not _stderr_queue.empty():
                            try:
                                _se = _stderr_queue.get_nowait()
                                _pm = _page_re.search(_se)
                                if _pm:
                                    _pg = int(_pm.group(1))
                                    if _pg >= _last_page + 10:
                                        _last_page = _pg
                                        log(f"  — Scanning YouTube catalog (page {_pg})...\n", "simpleline")
                            except queue.Empty:
                                break
                        if _stdout_done.is_set() and _stderr_done.is_set() and _stdout_queue.empty():
                            break
                        if _ce.is_set():
                            _proc.terminate()
                            try:
                                _proc.wait(timeout=5)
                            except Exception:
                                _proc.kill()
                            return {}
                        if time.time() > _deadline:
                            _proc.terminate()
                            try:
                                _proc.wait(timeout=5)
                            except Exception:
                                _proc.kill()
                            log("  ⚠ YouTube list fetch timed out.\n", "red")
                            return {}
                        time.sleep(0.5)
                    for _line in _stdout_lines:
                        _line = _line.strip()
                        if "|||" in _line:
                            _vid_id, _yt_title = _line.split("|||", 1)
                            _vid_id = _vid_id.strip()
                            _yt_title = _yt_title.strip()
                            if re.fullmatch(r'[\w-]{11}', _vid_id):
                                _result[_yt_title] = _vid_id
                    return _result
                except Exception as _e:
                    log(f"  ⚠ Could not fetch YouTube list: {_e}\n", "red")
                    return {}

            # Fetch with internet-outage protection: if internet dropped during the
            # playlist fetch, the result is likely incomplete — wait for restore and
            # re-fetch from scratch rather than proceeding with a partial list.
            while not _ce.is_set():
                _internet_went_down_during.clear()  # arm the dirty flag
                if not _block_if_no_internet(cancel_ev=_ce):
                    break  # cancelled
                yt_title_to_id = _fetch_yt_title_map(use_cookies=True)
                if not yt_title_to_id and not _ce.is_set():
                    log("  No videos returned with cookies — retrying without cookies...\n", "simpleline")
                    yt_title_to_id = _fetch_yt_title_map(use_cookies=False)
                # Check if internet dropped during the fetch — if so, the list may be
                # incomplete.  Wait for restore and retry the whole fetch.
                if _internet_went_down_during.is_set() and not _ce.is_set():
                    log("  ⚠ Internet dropped during playlist fetch — will re-fetch after restore.\n", "red")
                    if not _block_if_no_internet(cancel_ev=_ce):
                        break  # cancelled
                    log("  Retrying YouTube video list fetch...\n", "simpleline")
                    continue  # retry from the top
                break  # clean fetch — proceed
            if not yt_title_to_id:
                log("  ⚠ Could not retrieve video list — all files will use Whisper.\n", "red")
            else:
                log(f"  — Found {len(yt_title_to_id)} video(s) on YouTube.\n", "simpleline")

            if _ce.is_set():
                log(f"\n  ⛔ Transcription cancelled.\n", "red")
                return

            # ── Step 3.5: Title normalization helper + punctuation sweep for already-done ─
            _re_unsafe_chars = re.compile(r'[\\/:*?"<>|]')
            _re_whitespace   = re.compile(r'\s+')
            def _normalize_title(title):
                """Normalize a title for matching: NFKC (fullwidth→ASCII), strip unsafe chars, lowercase."""
                s = unicodedata.normalize('NFKC', title)
                s = _re_unsafe_chars.sub('', s)
                s = _re_whitespace.sub(' ', s).strip()
                return s.lower()

            # Build normalized YT title → video_id lookup (used by backfill and Pass 2)
            _yt_norm_backfill = {}
            if yt_title_to_id:
                for yt_title, vid_id in yt_title_to_id.items():
                    _norm = _normalize_title(yt_title)
                    if _norm not in _yt_norm_backfill:
                        _yt_norm_backfill[_norm] = vid_id

            def _do_jsonl_backfill():
                """Generate .jsonl entries for already-transcribed videos that are missing them.
                Runs after new transcriptions so it doesn't delay resuming a paused session."""
                nonlocal _whisper_available
                if not _jsonl_needed or not yt_title_to_id or _ce.is_set():
                    return

                # Match needed titles to video IDs
                _backfill_list = []
                for title in _jsonl_needed:
                    vid_id = yt_title_to_id.get(title)
                    if not vid_id:
                        _norm_t = _normalize_title(title)
                        vid_id = _yt_norm_backfill.get(_norm_t)
                    if vid_id:
                        _backfill_list.append((title, vid_id))

                if _backfill_list:
                    _bf_total = len(_backfill_list)
                    log(f"  Generating searchable .jsonl for {_bf_total} video(s)...\n", "simpleline")
                    _bf_temp = os.path.join(folder, "_transcribe_temp")
                    os.makedirs(_bf_temp, exist_ok=True)
                    _bf_done = 0
                    _bf_skip = 0
                    _bf_idx = 0
                    for _bf_title, _bf_vid in _backfill_list:
                        # Pause check — allows the user to pause during long backfill runs
                        _bf_pl = "GPU Tasks" if _sync_mode else "Sync"
                        if _pe.is_set() and not _ce.is_set():
                            log(f"  ⏸ {_bf_pl} paused at {_fmt_time()} — click Resume.\n", "pausestatus")
                            while _pe.is_set() and not _ce.is_set():
                                time.sleep(0.25)
                            clear_pause_status()
                            if not _ce.is_set():
                                log(f"  ▶ {_bf_pl} resumed at {_fmt_time()}...\n", "pauselog")
                            # After resume: wipe temp dir so stale state cannot interfere.
                            try:
                                if os.path.isdir(_bf_temp):
                                    shutil.rmtree(_bf_temp, ignore_errors=True)
                                os.makedirs(_bf_temp, exist_ok=True)
                            except Exception:
                                pass
                        if _ce.is_set():
                            break
                        _bf_idx += 1
                        _bf_display = (_bf_title[:52] + "...") if len(_bf_title) > 52 else _bf_title

                        log(f"  [{_bf_idx}/{_bf_total}] Fetching captions: {_bf_display}\n", "simpleline")
                        _bf_segs = []
                        # Block if internet is down (background monitor handles detection)
                        if not _block_if_no_internet(cancel_ev=_ce):
                            break  # cancelled
                        try:
                            _, _bf_segs, _ = _fetch_auto_captions(_bf_vid, _bf_temp)
                        except Exception:
                            pass

                        # Fallback: if no YouTube captions, Whisper the local file
                        if not _bf_segs:
                            _bf_local = local_files.get(_bf_title)
                            if _bf_local and os.path.isfile(_bf_local) and _whisper_available is not False:
                                if _whisper_available is None:
                                    _whisper_available = os.path.isfile(_WHISPER_PYTHON)
                                if _whisper_available:
                                    log(f"    No captions — Whisper fallback: {_bf_display}\n", "dim")
                                    try:
                                        _, _bf_segs = _whisper_transcribe(
                                            _bf_local, duration=0, title=_bf_title,
                                            cancel_ev=_ce, pause_ev=_pe)
                                        _clear_whisper_progress()
                                    except Exception:
                                        _bf_segs = []

                        # Determine which transcript file this title belongs to
                        _bf_fpath = local_files.get(_bf_title)
                        if _bf_fpath:
                            _bf_mtime = datetime.fromtimestamp(os.path.getmtime(_bf_fpath))
                            _bf_txt, _ = _get_transcript_filename(
                                ch_name, folder, split_years, split_months, combined,
                                year=_bf_mtime.year, month=_bf_mtime.month)
                        else:
                            _bf_txt, _ = _get_transcript_filename(
                                ch_name, folder, split_years, split_months, combined)
                        _bf_jsonl = _get_jsonl_path(_bf_txt)

                        if _bf_segs:
                            _remove_jsonl_entries_for_title_all_files(folder, ch_name, _bf_title)
                            _write_jsonl_entry(_bf_jsonl, _bf_vid, _bf_title, _bf_segs)
                            _bf_done += 1
                        else:
                            # No captions and no local file for Whisper — write a
                            # minimal placeholder so this title is not retried every run.
                            _placeholder = [{"start": 0.0, "end": 0.01,
                                             "text": "(no captions available)"}]
                            _remove_jsonl_entries_for_title_all_files(folder, ch_name, _bf_title)
                            _write_jsonl_entry(_bf_jsonl, _bf_vid, _bf_title, _placeholder)
                            _bf_skip += 1
                    if _bf_done or _bf_skip:
                        _parts_msg = []
                        if _bf_done:
                            _parts_msg.append(f"{_bf_done} generated")
                        if _bf_skip:
                            _parts_msg.append(f"{_bf_skip} skipped (no captions/local file)")
                        log(f"  ✓ Searchable .jsonl: {', '.join(_parts_msg)}.\n", "simpleline_green")

            # ── Pass 2: Patch empty video_ids in existing JSONL entries ──────────────
            # Whisper-transcribed videos written before this fix had video_id = "".
            # If the video is actually a YouTube video (just had no captions), look up
            # its ID and write it in so the YT timestamp link works in search results.
            if yt_title_to_id and not _ce.is_set():
                _vid_id_patched = 0
                for _pd, _pdirs, _pfiles in os.walk(folder):
                    for _pf in _pfiles:
                        if not (_pf.startswith(".") and ch_name in _pf
                                and _pf.endswith("Transcript.jsonl")):
                            continue
                        _pfpath = os.path.join(_pd, _pf)
                        try:
                            with open(_pfpath, "r", encoding="utf-8") as _pfh:
                                _plines = _pfh.readlines()
                            _pnew = []
                            _pchanged = False
                            for _pl in _plines:
                                _ps = _pl.strip()
                                if not _ps:
                                    _pnew.append(_pl)
                                    continue
                                try:
                                    _pe2 = json.loads(_ps)
                                except Exception:
                                    _pnew.append(_pl)
                                    continue
                                if _pe2.get("video_id", "") == "":
                                    _pt = _pe2.get("title", "")
                                    _pvid = (yt_title_to_id.get(_pt)
                                             or _yt_norm_backfill.get(_normalize_title(_pt)))
                                    if _pvid:
                                        _pe2["video_id"] = _pvid
                                        _pnew.append(json.dumps(_pe2, ensure_ascii=False) + "\n")
                                        _pchanged = True
                                        _vid_id_patched += 1
                                        continue
                                _pnew.append(_pl)
                            if _pchanged:
                                _pftmp = _pfpath + ".tmp"
                                with open(_pftmp, "w", encoding="utf-8") as _pfh:
                                    _pfh.writelines(_pnew)
                                os.replace(_pftmp, _pfpath)
                                _hide_file_win(_pfpath)
                        except Exception:
                            log(f"  {traceback.format_exc()}\n", "dim")
                if _vid_id_patched:
                    log(f"  — ✓ Linked YouTube IDs for {_vid_id_patched} Whisper segment(s).\n",
                        "simpleline_green")

            # ── Punctuation sweep for already-transcribed entries ──
            if already_done and not _ce.is_set():
                _punct_sweep_needed = False
                # Scan existing transcript files for entries lacking punctuation
                _entry_pattern = re.compile(r'^===\((.+?)\),\s*\((\d{2}\.\d{2}\.\d{4})\),\s*\(([^)]*)\),\s*(\([^)]+\))===')
                _txt_files_to_sweep = []
                for dirpath, _dirs, files in os.walk(folder):
                    for f in files:
                        if f.startswith(ch_name) and f.endswith("Transcript.txt"):
                            _txt_files_to_sweep.append(os.path.join(dirpath, f))

                _punct_fixes = 0
                _punct_model_ok = True
                for _sw_path in _txt_files_to_sweep:
                    if not _punct_model_ok:
                        break
                    try:
                        with open(_sw_path, "r", encoding="utf-8") as _sf:
                            _sw_content = _sf.read()
                    except Exception:
                        continue

                    _sw_entries = _sw_content.split("\n\n\n")
                    _sw_modified = False
                    _new_entries = []
                    for _sw_entry in _sw_entries:
                        _sw_entry_stripped = _sw_entry.strip()
                        if not _sw_entry_stripped:
                            _new_entries.append(_sw_entry)
                            continue
                        # Parse header line and body
                        _sw_lines = _sw_entry_stripped.split("\n", 1)
                        if len(_sw_lines) < 2 or not _sw_lines[0].startswith("==="):
                            _new_entries.append(_sw_entry)
                            continue
                        _sw_header = _sw_lines[0]
                        _sw_body = _sw_lines[1]
                        # Skip exclusion entries
                        if "NO AUDIO DATA" in _sw_header:
                            _new_entries.append(_sw_entry)
                            continue
                        # Skip entries already punctuated (by model or Whisper)
                        if "YT+PUNCTUATION" in _sw_header or "WHISPER" in _sw_header:
                            _new_entries.append(_sw_entry)
                            continue
                        # Check punctuation density
                        _sw_p_count = sum(1 for ch in _sw_body if ch in ',.!?;')
                        if _sw_p_count >= max(3, len(_sw_body) // 200):
                            _new_entries.append(_sw_entry)
                            continue
                        if len(_sw_body) < 20:
                            _new_entries.append(_sw_entry)
                            continue
                        # Needs punctuation — load model if not already loaded
                        if not _punct_sweep_needed:
                            _punct_sweep_needed = True
                            if not _load_punctuation_model():
                                _punct_model_ok = False
                                break  # Can't load model, skip sweep
                            log(f"  Running punctuation sweep on previously transcribed entries...\n", "simpleline")
                        try:
                            _fixed_body = _punctuate_text(_sw_body)
                            # Update source tag to note punctuation was added
                            _new_header = _sw_header.replace("(YT CAPTIONS)", "(YT+PUNCTUATION)")
                            _new_entries.append(f"{_new_header}\n{_fixed_body}")
                            _sw_modified = True
                            _punct_fixes += 1
                        except Exception:
                            _new_entries.append(_sw_entry)
                    if _sw_modified:
                        try:
                            _new_content = "\n\n\n".join(_new_entries)
                            with open(_sw_path, "w", encoding="utf-8") as _sf:
                                _sf.write(_new_content)
                        except Exception:
                            pass
                if _punct_fixes:
                    log(f"  ✓ Punctuation added to {_punct_fixes} existing transcript(s).\n", "simpleline_green")

            # (files_to_process is guaranteed non-empty here — the empty case
            # returns early in Step 2 above, before the YouTube fetch.)

            if _ce.is_set():
                log(f"\n  ⛔ Transcription cancelled.\n", "red")
                return

            # ── Step 4: Split into matched (captions) vs unmatched (Whisper) ─
            matched = []    # (filename, filepath, video_id)  — can try auto-captions
            unmatched = []  # (filename, filepath)            — must use Whisper

            _normalize_for_match = _normalize_title  # alias for step 4

            # Build normalized lookup: normalized_yt_title → video_id
            _yt_normalized = {}
            for yt_title, vid_id in yt_title_to_id.items():
                _norm = _normalize_for_match(yt_title)
                if _norm not in _yt_normalized:  # first match wins (avoid rare collisions)
                    _yt_normalized[_norm] = vid_id

            for fname, fpath in files_to_process.items():
                # Files in the Whisper cache already failed captions — send directly to Whisper
                if fpath in _whisper_cache_set:
                    unmatched.append((fname, fpath))
                    continue
                # Try exact match first, then normalized match
                if fname in yt_title_to_id:
                    matched.append((fname, fpath, yt_title_to_id[fname]))
                else:
                    _norm_fname = _normalize_for_match(fname)
                    if _norm_fname in _yt_normalized:
                        matched.append((fname, fpath, _yt_normalized[_norm_fname]))
                    else:
                        unmatched.append((fname, fpath))

            # Sort by file modification time, newest first
            def _safe_mtime(x):
                try:
                    return os.path.getmtime(x[1])
                except OSError:
                    return 0
            matched.sort(key=_safe_mtime, reverse=True)
            unmatched.sort(key=_safe_mtime, reverse=True)

            log(f"  — {len(matched)} file(s) matched to YouTube titles (will try auto-captions).\n", "simpleline")
            if unmatched:
                log(f"  — {len(unmatched)} file(s) unmatched (will use Whisper).\n", "simpleline")
            log("\n", "simpleline")

            # Write initial whisper cache with pre-scan unmatched files so that
            # a restart mid-Phase A can skip re-checking files already identified.
            if unmatched:
                try:
                    with open(_whisper_cache_path, "w", encoding="utf-8") as _wf:
                        json.dump([{"fname": fn, "fpath": fp} for fn, fp in unmatched], _wf)
                except Exception:
                    pass

            total = len(matched) + len(unmatched)
            temp_dir = os.path.join(folder, "_transcribe_temp")
            # Wipe any stale temp dir from a previous cancelled/interrupted run.
            # yt-dlp's default no-overwrite behaviour means leftover .vtt files
            # would cause it to skip the subtitle download entirely, making
            # _fetch_auto_captions silently return None for those videos.
            try:
                import shutil as _shutil_init
                if os.path.isdir(temp_dir):
                    _shutil_init.rmtree(temp_dir, ignore_errors=True)
            except Exception:
                pass
            os.makedirs(temp_dir, exist_ok=True)

            # Load punctuation model if we have any matched files (for YT captions)
            _punct_loaded = False
            if matched:
                _punct_loaded = _load_punctuation_model()

            if _ce.is_set():
                log(f"\n  ⛔ Transcription cancelled.\n", "red")
                return

            _prior_done = len(already_done)  # count of videos transcribed before this session
            done_count = 0
            err_count = 0
            _whisper_skip_count = 0  # Whisper failures that will be retried (not real errors)
            idx = 0
            _check_idx = 0       # monotonically increasing caption-check counter (for simple mode [X/Y])
            _whisper_queued = len(unmatched)  # pre-scan unmatched + any that fail captions in Phase A
            _modified_txt_files = set()  # track which .txt files we wrote to, for post-sort
            _transcription_log = []  # [(fname, source, elapsed_secs, error_str_or_None)]
            _t_total_start = time.time()

            # ── Phase A: Process matched files (auto-captions first) ────
            _consec_caption_fails = 0  # track consecutive caption failures for backoff/retry
            _caption_successes = 0     # total successes so far (to detect regression)
            _cookies_forced = False    # adaptive: force cookies after repeated cookieless failures
            _consec_needed_cookies = 0 # track how many times cookieless failed but cookies worked
            _COOKIES_FORCE_THRESHOLD = 5  # switch to cookies-first after this many

            # Pipeline prefetch: overlap next video's yt-dlp fetch with current
            # video's punctuation + write.  Single-threaded executor ensures only
            # one yt-dlp process runs at a time — no extra YouTube load.
            _prefetch_future = None
            _prefetch_executor = concurrent.futures.ThreadPoolExecutor(max_workers=1)

            for _mi, (fname, fpath, vid_id) in enumerate(matched):
                idx += 1
                _check_idx += 1
                _fname_trunc_src = unicodedata.normalize('NFKC', fname)
                # Compute title width based on prefix so ... always lands at same column
                _fname_trunc = _trunc_pad_title(_fname_trunc_src, _MAX_TITLE_DISPLAY).rstrip()

                # Pause check
                _pl = "GPU Tasks" if _sync_mode else "Sync"
                if _pe.is_set() and not _ce.is_set():
                    # Cancel any in-flight prefetch — temp dir will be wiped
                    if _prefetch_future and not _prefetch_future.done():
                        _prefetch_future.cancel()
                    _prefetch_future = None
                    log(f"  ⏸ {_pl} paused at {_fmt_time()} — click Resume.\n", "pausestatus")
                    while _pe.is_set() and not _ce.is_set():
                        time.sleep(0.25)
                    clear_pause_status()
                    if not _ce.is_set():
                        log(f"  ▶ {_pl} resumed at {_fmt_time()}...\n", "pauselog")
                    # After resume: wipe temp dir and reset consecutive fail counter
                    # so stale state from the pre-pause session cannot interfere.
                    try:
                        if os.path.isdir(temp_dir):
                            shutil.rmtree(temp_dir, ignore_errors=True)
                        os.makedirs(temp_dir, exist_ok=True)
                    except Exception:
                        pass
                    _consec_caption_fails = 0
                    _consec_needed_cookies = 0
                    _cookies_forced = False
                if _ce.is_set():
                    log(f"\n  ⛔ Transcription cancelled ({done_count}/{total} completed).\n", "red")
                    break

                # Rate-limit backoff: if many consecutive captions failed, slow down
                # to avoid hitting YouTube throttling after pause/resume or heavy use.
                if _consec_caption_fails >= 5:
                    time.sleep(random.uniform(1.5, 3.0))
                elif _consec_caption_fails >= 3:
                    time.sleep(random.uniform(0.5, 1.5))

                _w_suffix = f" ({_whisper_queued} queued for Whisper)" if _whisper_queued > 0 else ""
                log(f"  [{idx}/{total}] {fname} — fetching captions...{_w_suffix}\n" if not _is_simple_mode else f"[{_check_idx}/{total}] Transcribing \"{_fname_trunc}\" - fetching captions...{_w_suffix}\n", "transcribe_using")
                _t_vid_start = time.time()

                # Block if internet is down (background monitor handles detection)
                if not _block_if_no_internet(cancel_ev=_ce):
                    break  # cancelled

                # Use prefetched result if available, otherwise fetch now
                if _prefetch_future is not None:
                    try:
                        text, _vtt_segments, _needed_cookies = _prefetch_future.result(timeout=120)
                    except Exception:
                        text, _vtt_segments, _needed_cookies = None, [], False
                    _prefetch_future = None
                else:
                    text, _vtt_segments, _needed_cookies = _fetch_auto_captions(vid_id, temp_dir, cookies_forced=_cookies_forced)
                source = "auto-captions"

                if not text:
                    # Check if failure is due to internet outage before queuing for Whisper.
                    # Use the background monitor's flag — if internet dropped during the
                    # fetch, wait for restore and retry instead of blindly queuing.
                    if _internet_down.is_set():
                        if _block_if_no_internet(cancel_ev=_ce):
                            # Internet restored — retry this file
                            text, _vtt_segments, _needed_cookies = _fetch_auto_captions(vid_id, temp_dir, cookies_forced=_cookies_forced)
                        else:
                            break  # cancelled
                    if not text:
                        _consec_caption_fails += 1
                        # Warn once when consecutive failures suggest a systemic issue
                        if _consec_caption_fails == 5 and _caption_successes > 0:
                            log(f"  ⚠ {_consec_caption_fails} consecutive caption failures — possible rate-limit; slowing down...\n", "red")
                        # Auto-captions genuinely unavailable — Whisper this file instead
                        log(f"  [{idx}/{total}] {fname} — no captions, queuing for Whisper.\n", "dim")
                        unmatched.append((fname, fpath))
                        _whisper_queued += 1
                        # Bump total: this file already incremented idx in Phase A, and will
                        # increment idx again in Phase B, so total needs +1 to stay in sync.
                        total += 1
                        # Update cache immediately so a restart skips this file in Phase A
                        try:
                            with open(_whisper_cache_path, "w", encoding="utf-8") as _wf:
                                json.dump([{"fname": fn, "fpath": fp} for fn, fp in unmatched], _wf)
                        except Exception:
                            pass
                        continue

                # Adaptive cookie forcing: if cookieless keeps failing but cookies
                # work, stop wasting time on the cookieless attempt
                if _needed_cookies:
                    _consec_needed_cookies += 1
                    if _consec_needed_cookies >= _COOKIES_FORCE_THRESHOLD and not _cookies_forced:
                        _cookies_forced = True
                        log(f"    ℹ Switching to cookies-first (cookieless failed {_consec_needed_cookies}x in a row).\n", "dim")
                else:
                    _consec_needed_cookies = 0  # reset on cookieless success

                # Kick off prefetch for the NEXT video before punctuation/write.
                # This overlaps the yt-dlp network fetch with GPU punctuation work.
                _next_i = _mi + 1
                if (_next_i < len(matched) and not _ce.is_set()
                        and not _pe.is_set() and _consec_caption_fails < 3):
                    _next_vid_id = matched[_next_i][2]
                    _prefetch_future = _prefetch_executor.submit(
                        _fetch_auto_captions, _next_vid_id, temp_dir,
                        cookies_forced=_cookies_forced)
                else:
                    _prefetch_future = None

                # Restore punctuation to YouTube captions
                _consec_caption_fails = 0  # reset on success
                _caption_successes += 1
                if _punct_loaded:
                    log(f"    Adding punctuation...{_w_suffix}\n" if not _is_simple_mode else f"[{_check_idx}/{total}] Transcribing \"{_fname_trunc}\" - Adding punctuation...{_w_suffix}\n", "transcribe_using")
                    text = _punctuate_text(text)

                # Get date/duration from local file mtime
                mtime = datetime.fromtimestamp(os.path.getmtime(fpath))
                year_num, month_num = mtime.year, mtime.month
                upload_date = mtime.strftime("%Y%m%d")

                dur_str = ""
                _dur_secs = 0
                try:
                    probe_cmd = ["ffprobe", "-v", "quiet", "-show_entries",
                                 "format=duration", "-of", "csv=p=0", fpath]
                    probe_result = subprocess.run(probe_cmd, capture_output=True, text=True, timeout=30, startupinfo=startupinfo)
                    _dur_secs = float(probe_result.stdout.strip())
                    hrs, remainder = divmod(int(_dur_secs), 3600)
                    mins, sec = divmod(remainder, 60)
                    dur_str = f"{hrs}:{mins:02d}:{sec:02d}" if hrs else f"{mins}:{sec:02d}"
                except Exception:
                    pass

                # Write transcript entry
                txt_path, subfolder = _get_transcript_filename(
                    ch_name, folder, split_years, split_months, combined,
                    year=year_num, month=month_num)
                os.makedirs(subfolder, exist_ok=True)

                date_fmt = _format_upload_date(upload_date)
                dur_fmt = _format_duration(dur_str)
                src_tag = "(YT+PUNCTUATION)" if _punct_loaded else "(YT CAPTIONS)"
                entry = f"===({fname}), {date_fmt}, {dur_fmt}, {src_tag}===\n{text}\n\n\n"

                try:
                    with open(txt_path, "a", encoding="utf-8") as f:
                        f.write(entry)
                    _modified_txt_files.add(txt_path)
                except Exception as e:
                    log(f"  ⚠ Error writing transcript: {e}\n", "red")
                    _transcription_log.append((fname, source, time.time() - _t_vid_start, str(e)))
                    err_count += 1
                    continue

                # Write hidden JSONL with timestamps for searchability
                if _vtt_segments:
                    _jsonl_path = _get_jsonl_path(txt_path)
                    _write_jsonl_entry(_jsonl_path, vid_id, fname, _vtt_segments)

                _vid_elapsed = time.time() - _t_vid_start
                _transcription_log.append((fname, source, _vid_elapsed, None))
                done_count += 1
                _ve_m, _ve_s = divmod(int(_vid_elapsed), 60)
                _ve_str = f"took {_ve_m}min {_ve_s:02d}sec" if _ve_m else f"took {_ve_s}sec"
                _src_part = f"{source},"
                # Duration string e.g. ", (6m 02s)"
                _vid_dur_str = ""
                if _dur_secs > 0:
                    _vd_m, _vd_s = divmod(int(_dur_secs), 60)
                    _vid_dur_str = f", ({_vd_m}m {_vd_s:02d}s)"
                # Realtime ratio e.g. ", 3.0x realtime"
                _rt_str = f", {_dur_secs / _vid_elapsed:.1f}x realtime" if _dur_secs > 0 and _vid_elapsed > 0 else ""
                if _is_simple_mode:
                    _prefix = f"[{idx}/{total}] "
                    _suffix = f"done ({_src_part} {_ve_str}{_rt_str})"
                    _fname_norm = unicodedata.normalize('NFKC', fname)
                    _dur_raw = f"({_vd_m}m {_vd_s:02d}s)" if _dur_secs > 0 else ""
                    _dur_display = f"{_dur_raw:>10} — " if _dur_raw else "— "
                    _name_padded = _trunc_pad_title(_fname_norm, _MAX_TITLE_DISPLAY)
                    _name_dash = f"{_name_padded} — {_dur_display}"
                    log(f"{_prefix}{_name_dash}{_suffix}\n", "simpleline_blue")
                else:
                    log(f"  [{idx}/{total}] {fname}{_vid_dur_str} — done ({_src_part} {_ve_str}{_rt_str})\n", "simpleline_blue")

            # Cleanup prefetch executor
            _prefetch_executor.shutdown(wait=False)

            # ── captions_only mode: finish up and optionally queue GPU task for Whisper ──
            if captions_only:
                if _modified_txt_files and done_count > 0:
                    _sort_transcript_entries(_modified_txt_files)
                _do_jsonl_backfill()
                try:
                    shutil.rmtree(temp_dir, ignore_errors=True)
                except Exception:
                    pass
                if not _ce.is_set():
                    if unmatched:
                        log(f"\n  — {len(unmatched)} video(s) need Whisper — queuing GPU task...\n", "simpleline")
                        _add_to_gpu_queue({
                            "type": "transcribe", "ch_name": ch_name, "ch_url": ch_url,
                            "folder": folder, "split_years": split_years, "split_months": split_months,
                            "combined": combined
                        })
                    else:
                        if done_count > 0:
                            log(f"\n  ✓ {done_count} video(s) captioned inline.\n", "simpleline_green")
                        with config_lock:
                            for _cfg_ch in config.get("channels", []):
                                if _cfg_ch.get("url") == ch_url:
                                    _cfg_ch["transcription_complete"] = True
                                    _cfg_ch["transcription_pending"] = 0
                                    break
                            save_config(config)
                        _stop_punct_process()  # free GPU memory; no GPU task to manage it
                # Write whisper pending cache so the GPU task's Whisper run can skip
                # Phase A caption re-check (cache is loaded at the top of this function).
                if unmatched:
                    try:
                        with open(_whisper_cache_path, "w", encoding="utf-8") as _wf:
                            json.dump([{"fname": fn, "fpath": fp} for fn, fp in unmatched], _wf)
                    except Exception:
                        pass
                return  # skip Phase B

            # ── Write Whisper pending cache ──────────────────────────────
            # Persist the unmatched list so a cancelled/paused run can resume
            # Phase B without repeating the entire Phase A caption scan.
            if unmatched:
                try:
                    with open(_whisper_cache_path, "w", encoding="utf-8") as _wf:
                        json.dump([{"fname": fn, "fpath": fp} for fn, fp in unmatched], _wf)
                except Exception:
                    pass

            # ── Phase B: Process unmatched files (Whisper) ──────────────
            if unmatched and not _ce.is_set():
                # Re-sort unmatched by mtime newest first (Phase A may have added failed items)
                def _safe_mtime_u(x):
                    try:
                        return os.path.getmtime(x[1])
                    except OSError:
                        return 0
                unmatched.sort(key=_safe_mtime_u, reverse=True)

                # ── Model selection ──
                log(f"\n  — {len(unmatched)} video(s) need Whisper AI transcription.\n", "simpleline")

                if skip_model_dialog:
                    # GPU Tasks mode — model already chosen, skip dialog
                    _stop_whisper_process()
                    log(f"  — Using Whisper model: {_whisper_model_choice}\n", "simpleline")
                    _model_result = [_whisper_model_choice]
                    _model_timed_out = [False]
                else:
                    _model_result = [None]
                    _model_timed_out = [False]

                    def _ask_model():
                        _dlg = tk.Toplevel(root)
                        _dlg.title("Whisper Model Selection")
                        _dlg.configure(bg=C_BG)
                        _dlg.resizable(False, False)
                        _dlg.transient(root)
                        _dlg.grab_set()
                        _dlg.update_idletasks()
                        _apply_dark_title_bar(_dlg)

                        # Center on root window
                        _dlg.update_idletasks()
                        _rx = root.winfo_rootx() + root.winfo_width() // 2
                        _ry = root.winfo_rooty() + root.winfo_height() // 2
                        _dlg.geometry(f"+{_rx - 160}+{_ry - 140}")

                        tk.Label(_dlg, text="Which model to use for Whisper?",
                                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10, "bold"),
                                 pady=10, padx=20).pack(fill="x")
                        tk.Label(_dlg, text=f"{len(unmatched)} video(s) without YouTube captions",
                                 bg=C_BG, fg=C_DIM, font=("Segoe UI", 9),
                                 padx=20).pack(fill="x")

                        _btn_frame = tk.Frame(_dlg, bg=C_BG, pady=10)
                        _btn_frame.pack(fill="x", padx=20)

                        _models = [
                            ("tiny",     "Fastest  (~120-200× realtime)",  "tiny"),
                            ("small",    "Fast  (~60-80× realtime)",     "small"),
                            ("medium",   "Balanced  (~28-40× realtime)",  "medium"),
                            ("large-v3", "Best quality  (~12-20× realtime)", "large-v3"),
                        ]

                        _DEFAULT_MODEL = "small"
                        _countdown = {"secs": 60, "job": None}

                        def _pick(m, dlg=_dlg):
                            if _countdown["job"]:
                                try:
                                    _dlg.after_cancel(_countdown["job"])
                                except Exception:
                                    pass
                            _model_result[0] = m
                            try:
                                dlg.destroy()
                            except Exception:
                                pass

                        # Countdown label
                        _timer_lbl = tk.Label(_dlg, text=f"Auto-selecting {_DEFAULT_MODEL} in 60s...",
                                              bg=C_BG, fg=C_DIM, font=("Segoe UI", 8),
                                              padx=20)
                        _timer_lbl.pack(fill="x", pady=(0, 4))

                        def _tick():
                            if _model_result[0] is not None:
                                return  # user already picked — avoid double destroy race
                            _countdown["secs"] -= 1
                            if _countdown["secs"] <= 0:
                                _model_timed_out[0] = True
                                _pick(_DEFAULT_MODEL)
                                return
                            try:
                                _timer_lbl.config(text=f"Auto-selecting {_DEFAULT_MODEL} in {_countdown['secs']}s...")
                                _countdown["job"] = _dlg.after(1000, _tick)
                            except Exception:
                                pass

                        _countdown["job"] = _dlg.after(1000, _tick)

                        for label, desc, model_id in _models:
                            _row = tk.Frame(_btn_frame, bg=C_BG)
                            _row.pack(fill="x", pady=2)
                            _b = tk.Button(_row, text=label, width=10,
                                           bg="#3a3a3a", fg=C_TEXT, activebackground="#555555",
                                           activeforeground=C_TEXT, relief="flat", bd=0,
                                           font=("Segoe UI", 9, "bold"), cursor="hand2",
                                           command=lambda m=model_id: _pick(m))
                            _b.pack(side="left", padx=(0, 8))
                            tk.Label(_row, text=desc, bg=C_BG, fg=C_DIM,
                                     font=("Segoe UI", 9)).pack(side="left")
                            if model_id == _DEFAULT_MODEL:
                                tk.Label(_row, text="(default)", bg=C_BG, fg="#5a8a5a",
                                         font=("Segoe UI", 8)).pack(side="left", padx=(4, 0))

                        # Skip button
                        tk.Frame(_dlg, bg=C_BG, height=5).pack()
                        tk.Button(_dlg, text="Skip Whisper (use only YT captions)",
                                  bg="#3a3a3a", fg=C_DIM, activebackground="#555555",
                                  activeforeground=C_TEXT, relief="flat", bd=0,
                                  font=("Segoe UI", 8), cursor="hand2",
                                  command=lambda: _pick("skip")).pack(pady=(0, 12))

                        _dlg.protocol("WM_DELETE_WINDOW", lambda: _pick(_DEFAULT_MODEL))

                    if _root_alive:
                        _ui_queue.append(_ask_model)
                        while _model_result[0] is None and not _ce.is_set():
                            time.sleep(0.1)

                if _ce.is_set():
                    log(f"\n  ⛔ Transcription cancelled.\n", "red")
                    # fall through — _whisper_available stays None, nothing will run
                elif _model_result[0] == "skip":
                    log(f"  Skipping {len(unmatched)} video(s) without YouTube captions.\n", "simpleline")
                    _whisper_available = False
                    _user_skipped_whisper = True
                else:
                    _whisper_model_choice = _model_result[0]
                    # If model changed, stop old process so it relaunches with new model
                    _stop_whisper_process()
                    if _model_timed_out[0]:
                        log(f"  — No user input, defaulting to {_whisper_model_choice} model\n", "simpleline")
                    else:
                        log(f"  — Selected Whisper model: {_whisper_model_choice}\n", "simpleline")

                # Check if Whisper is available (only once)
                if not _ce.is_set() and _model_result[0] != "skip" and _whisper_available is None:
                    # First check if CUDA GPU is even present on this system
                    _has_cuda = _check_cuda_available()

                    if not _has_cuda:
                        _whisper_available = False
                        log(f"  ⚠ No CUDA GPU detected — Whisper unavailable.\n", "simpleline")
                        log(f"  Skipping {len(unmatched)} video(s) without YouTube captions.\n", "simpleline")
                    else:
                        _whisper_available = _check_whisper_installed()
                        if not _whisper_available:
                            log("  Whisper AI is not installed (needed for files without captions).\n", "simpleline")
                            _install_result = [None]

                            def _ask_install():
                                _install_result[0] = messagebox.askyesno(
                                    "Install Whisper AI",
                                    f"{len(unmatched)} video(s) need Whisper AI for transcription.\n\n"
                                    "Whisper requires ~2.5 GB of downloads (plus model download on first use).\n\n"
                                    "Install now? (These videos will be skipped if you decline)")
                            if _root_alive:
                                _ui_queue.append(_ask_install)
                                while _install_result[0] is None and not _ce.is_set():
                                    time.sleep(0.1)
                                if _install_result[0]:
                                    _whisper_available = _install_whisper_blocking()
                                else:
                                    _whisper_available = False
                                    log(f"  Skipping {len(unmatched)} video(s) without captions.\n", "simpleline")

                if _whisper_available:
                    for fname, fpath in unmatched:
                        idx += 1

                        # Pause check
                        _pl = "GPU Tasks" if _sync_mode else "Sync"
                        if _pe.is_set() and not _ce.is_set():
                            log(f"  ⏸ {_pl} paused at {_fmt_time()} — click Resume.\n", "pausestatus")
                            while _pe.is_set() and not _ce.is_set():
                                time.sleep(0.25)
                            clear_pause_status()
                            if not _ce.is_set():
                                log(f"  ▶ {_pl} resumed at {_fmt_time()}...\n", "pauselog")
                        if _ce.is_set():
                            log(f"\n  ⛔ Transcription cancelled ({done_count}/{total} completed).\n", "red")
                            break

                        # Get duration BEFORE whisper (needed for progress %)
                        _dur_secs = 0
                        dur_str = ""
                        try:
                            probe_cmd = ["ffprobe", "-v", "quiet", "-show_entries",
                                         "format=duration", "-of", "csv=p=0", fpath]
                            probe_result = subprocess.run(probe_cmd, capture_output=True, text=True, timeout=30, startupinfo=startupinfo)
                            _dur_secs = float(probe_result.stdout.strip())
                            hrs, remainder = divmod(int(_dur_secs), 3600)
                            mins, sec = divmod(remainder, 60)
                            dur_str = f"{hrs}:{mins:02d}:{sec:02d}" if hrs else f"{mins}:{sec:02d}"
                        except Exception:
                            pass

                        if not _is_simple_mode:
                            _dur_hint = f" ({dur_str})" if dur_str else ""
                            log(f"  [{idx}/{total}] {fname}{_dur_hint} — using Whisper...\n", "transcribe_using")
                        _t_vid_start = time.time()
                        # Set counter for simple mode progress prefix
                        _whisper_counter["idx"] = idx
                        _whisper_counter["total"] = total
                        # Check if pause was requested — Whisper can't be interrupted mid-file,
                        # so inform the user it will pause after the current file finishes.
                        if _pe.is_set() and not _ce.is_set():
                            log(f"  ⏸ Pause requested — waiting for current transcription to finish...\n", "pauselog")
                        text, _vtt_segments = _whisper_transcribe(fpath, duration=_dur_secs, title=fname, cancel_ev=_ce, pause_ev=_pe)
                        _clear_whisper_progress()  # Remove progress line now that file is done
                        # Show "Loading next video..." during inter-video processing (punct fixup, file I/O)
                        # so the log doesn't go dark for ~30s between transcriptions.
                        if not _ce.is_set() and idx < total:
                            _wp_next = f"[{idx + 1}/{total}] " if _is_simple_mode and total else "    "
                            log(f"{_wp_next}Loading next video...\n", "whisper_progress")
                        if text:
                            text = _whisper_punct_fixup(text)
                        source = "Whisper"

                        if not text:
                            if _whisper_last_failed:
                                # Process stalled or crashed — do NOT exclude the video
                                # (it likely has speech; Whisper just failed to process it).
                                # It will be retried on the next transcription run.
                                # Count as skip, not error, so it doesn't block transcription_complete
                                log(f"  [{idx}/{total}] {fname} — Whisper failed, skipping (will retry next run).\n", "red")
                                _transcription_log.append((fname, source, time.time() - _t_vid_start, "skipped — process failure (will retry)"))
                                _whisper_skip_count += 1
                                continue
                            # Write exclusion entry so this video is skipped on future transcribes
                            log(f"  [{idx}/{total}] {fname} — no speech detected, excluding.\n", "simpleline")
                            _transcription_log.append((fname, source, time.time() - _t_vid_start, "excluded — no speech"))
                            try:
                                _excl_mtime = datetime.fromtimestamp(os.path.getmtime(fpath))
                                _excl_year, _excl_month = _excl_mtime.year, _excl_mtime.month
                                _excl_date = _excl_mtime.strftime("%Y%m%d")
                                _excl_txt, _excl_sub = _get_transcript_filename(
                                    ch_name, folder, split_years, split_months, combined,
                                    year=_excl_year, month=_excl_month)
                                os.makedirs(_excl_sub, exist_ok=True)
                                _excl_date_fmt = _format_upload_date(_excl_date)
                                _excl_dur_fmt = _format_duration(dur_str)
                                _excl_entry = f"===({fname}), {_excl_date_fmt}, {_excl_dur_fmt}, (NO AUDIO DATA — EXCLUDED)===\n[No speech detected]\n\n\n"
                                with open(_excl_txt, "a", encoding="utf-8") as _ef:
                                    _ef.write(_excl_entry)
                                # Write JSONL placeholder so backfill doesn't retry this video
                                try:
                                    _excl_jsonl = _get_jsonl_path(_excl_txt)
                                    _excl_placeholder = [{"start": 0.0, "end": 0.01, "text": "(no speech detected)"}]
                                    _write_jsonl_entry(_excl_jsonl, "", fname, _excl_placeholder)
                                except Exception:
                                    pass
                                _modified_txt_files.add(_excl_txt)
                                done_count += 1
                            except Exception as _excl_e:
                                log(f"    ⚠ Could not write exclusion: {_excl_e}\n", "red")
                                err_count += 1
                            continue

                        # Get date from file mtime
                        try:
                            mtime = datetime.fromtimestamp(os.path.getmtime(fpath))
                        except OSError:
                            log(f"    ⚠ File no longer accessible: {fname}\n", "red")
                            err_count += 1
                            continue
                        year_num, month_num = mtime.year, mtime.month
                        upload_date = mtime.strftime("%Y%m%d")

                        txt_path, subfolder = _get_transcript_filename(
                            ch_name, folder, split_years, split_months, combined,
                            year=year_num, month=month_num)
                        os.makedirs(subfolder, exist_ok=True)

                        date_fmt = _format_upload_date(upload_date)
                        dur_fmt = _format_duration(dur_str)
                        _w_model_tag = f"WHISPER {_whisper_model_choice.upper()}"
                        entry = f"===({fname}), {date_fmt}, {dur_fmt}, ({_w_model_tag})===\n{text}\n\n\n"

                        try:
                            with open(txt_path, "a", encoding="utf-8") as f:
                                f.write(entry)
                            _modified_txt_files.add(txt_path)
                        except Exception as e:
                            log(f"  ⚠ Error writing transcript: {e}\n", "red")
                            _transcription_log.append((fname, source, time.time() - _t_vid_start, str(e)))
                            err_count += 1
                            continue

                        # Write hidden JSONL with timestamps for searchability
                        if _vtt_segments:
                            _jsonl_path = _get_jsonl_path(txt_path)
                            # Use the video's YouTube ID if it exists (YT video with no captions
                            # available — Whisper was used as fallback). Falls back to "" for
                            # truly local/offline files that have no YouTube counterpart.
                            _w_vid_id = (yt_title_to_id.get(fname)
                                         or _yt_normalized.get(_normalize_for_match(fname), ""))
                            _write_jsonl_entry(_jsonl_path, _w_vid_id, fname, _vtt_segments)

                        _vid_elapsed = time.time() - _t_vid_start
                        _transcription_log.append((fname, source, _vid_elapsed, None))
                        done_count += 1
                        _ve_m, _ve_s = divmod(int(_vid_elapsed), 60)
                        _ve_str = f"took {_ve_m}min {_ve_s:02d}sec" if _ve_m else f"took {_ve_s}sec"
                        _src_part = f"{source},"
                        # Duration string e.g. ", (6m 02s)"
                        _vid_dur_str = ""
                        if _dur_secs > 0:
                            _vd_m, _vd_s = divmod(int(_dur_secs), 60)
                            _vid_dur_str = f", ({_vd_m}m {_vd_s:02d}s)"
                        # Realtime ratio e.g. ", 3.0x realtime"
                        _rt_str = f", {_dur_secs / _vid_elapsed:.1f}x realtime" if _dur_secs > 0 and _vid_elapsed > 0 else ""
                        if _is_simple_mode:
                            _prefix = f"[{idx}/{total}] "
                            _suffix = f"done ({_src_part} {_ve_str}{_rt_str})"
                            _fname_norm = unicodedata.normalize('NFKC', fname)
                            _dur_raw = f"({_vd_m}m {_vd_s:02d}s)" if _dur_secs > 0 else ""
                            _dur_display = f"{_dur_raw:>10} — " if _dur_raw else "— "
                            _name_padded = _trunc_pad_title(_fname_norm, _MAX_TITLE_DISPLAY)
                            _name_dash = f"{_name_padded} — {_dur_display}"
                            log(f"{_prefix}{_name_dash}{_suffix}\n", "simpleline_blue")
                        else:
                            log(f"  [{idx}/{total}] {fname}{_vid_dur_str} — done ({_src_part} {_ve_str}{_rt_str})\n", "simpleline_blue")
                else:
                    if not _user_skipped_whisper:
                        err_count += len(unmatched)

            # ── Post-process: sort entries chronologically in each .txt file ──
            if _modified_txt_files and done_count > 0:
                _sort_transcript_entries(_modified_txt_files)

            # ── JSONL backfill: generate entries for videos transcribed in earlier sessions ──
            _do_jsonl_backfill()

            # Cleanup temp dir
            try:
                shutil.rmtree(temp_dir, ignore_errors=True)
            except Exception:
                pass

            if not _ce.is_set():
                # Phase B complete — clear the Whisper pending cache
                try:
                    if os.path.exists(_whisper_cache_path):
                        os.remove(_whisper_cache_path)
                except Exception:
                    pass
                log(f"\n  ✓ Transcription complete: {done_count} done", "simpleline_green")
                if err_count:
                    log(f", {err_count} errors", "simpleline_green")
                if _whisper_skip_count:
                    log(f", {_whisper_skip_count} skipped (will retry)", "simpleline_green")
                log(".\n", "simpleline_green")
                # Mark channel as fully transcribed (only if not cancelled and no real errors)
                # Whisper skips (process failures) don't block completion — they retry next run
                if err_count == 0:
                    with config_lock:
                        for _cfg_ch in config.get("channels", []):
                            if _cfg_ch.get("url") == ch_url:
                                _cfg_ch["transcription_complete"] = True
                                _cfg_ch["transcription_pending"] = 0
                                break
                        save_config(config)

            # ── Transcription Summary ──
            if _transcription_log:
                _t_total_elapsed = time.time() - _t_total_start
                _t_hrs, _t_rem = divmod(int(_t_total_elapsed), 3600)
                _t_mins, _t_secs = divmod(_t_rem, 60)
                if _t_hrs:
                    _total_str = f"{_t_hrs}h {_t_mins}m {_t_secs}s"
                elif _t_mins:
                    _total_str = f"{_t_mins}m {_t_secs}s"
                else:
                    _total_str = f"{_t_secs}s"

                log("\n" + "=" * 50 + "\n", "summary")
                log(f"TRANSCRIPTION SUMMARY: {ch_name}\n", "summary")
                log(f"Total time: {_total_str}\n", "summary")
                log(f"Completed: {done_count}  |  Errors: {err_count}\n", "summary")
                log("-" * 50 + "\n", "summary")
                for _tl_name, _tl_source, _tl_secs, _tl_err in _transcription_log:
                    _tl_m, _tl_s = divmod(int(_tl_secs), 60)
                    _tl_time = f"{_tl_m}m {_tl_s:02d}s" if _tl_m else f"{_tl_s}s"
                    if _tl_err:
                        log(f"  ✗ {_tl_name}  [{_tl_source}]  {_tl_time}  ERROR: {_tl_err}\n", "red")
                    else:
                        log(f"  ✓ {_tl_name}  [{_tl_source}]  {_tl_time}\n", "dim")
                log("=" * 50 + "\n", "summary")

            # Record in autorun history
            if done_count > 0 or err_count > 0 or _whisper_skip_count > 0:
                _t_rec_elapsed = time.time() - _t_total_start
                _record_transcription(done_count + _prior_done, err_count, _t_rec_elapsed,
                                      channel_name=ch_name, skipped=_whisper_skip_count)

            # Notify transcription panel to offer re-index
            if done_count > 0 and _tp_panel_ref[0] is not None:
                _tp_panel_ref[0].prompt_reindex(ch_name)

        except Exception as e:
            log(f"\n  ⚠ Transcription error: {e}\n", "red")
        finally:
            _transcribe_running = False
            _transcribe_sync_controlled = False
            _clear_whisper_progress()  # Remove whisper progress line after transcription completes
            if not _sync_mode:
                _stop_whisper_process()  # Free GPU memory (skip in sync_mode — GPU worker manages this)
                _stop_punct_process()   # Free GPU memory
                if not _sync_running:
                    _tray_stop_spin()
                    _update_tray_tooltip("YT Archiver — Idle")
                    _current_job["label"] = None
                    _current_job["url"] = None
                _update_queue_btn()
            _ui_queue.append(refresh_channel_dropdowns)
            if not _sync_mode:
                _ui_queue.append(_sync_task_finished)
            # Process any queued jobs in insertion order (only when not in sync_mode)
            if not _sync_mode:
                if _skip_current.is_set():
                    _skip_current.clear()
                    cancel_event.clear()
                    _process_next_queued()
                elif not _ce.is_set():
                    _process_next_queued()

    if _sync_mode:
        _worker()  # Run synchronously — caller is the GPU worker thread
    else:
        threading.Thread(target=_worker, daemon=True).start()


def _process_mt_queue():
    """Process next queued manual transcription. Returns True if one was started."""
    with _mt_queue_lock:
        if not _mt_queue:
            return False
        file_path = _mt_queue.pop(0)
        remaining = len(_mt_queue)
    with _queue_order_lock:
        try:
            _queue_order.remove(("mt", file_path))
        except ValueError:
            pass
    fname = os.path.splitext(os.path.basename(file_path))[0]
    log(f"\n=== Processing queued manual transcription: {fname}", "header")
    if remaining:
        log(f" ({remaining} more in queue)", "header")
    log(f" ===\n", "header")
    _run_manual_transcription(file_path)
    return True


def _start_manual_transcription():
    """Prompt user to select a local video file or folder, then add to GPU Tasks queue."""
    _choice = [None]  # "file", "folder", or None (cancelled)

    if root.winfo_exists():
        _dlg = tk.Toplevel(root)
        _dlg.title("Manual Transcription")
        _dlg.configure(bg=C_BG)
        _dlg.resizable(False, False)
        _dlg.transient(root)
        _dlg.grab_set()
        _dlg.update_idletasks()
        _apply_dark_title_bar(_dlg)
        _rx = root.winfo_rootx() + root.winfo_width() // 2
        _ry = root.winfo_rooty() + root.winfo_height() // 2
        _dlg.geometry(f"+{_rx - 140}+{_ry - 60}")

        tk.Label(_dlg, text="Select a single file or an entire folder?",
                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10, "bold"),
                 pady=12, padx=20).pack(fill="x")

        _btn_row = tk.Frame(_dlg, bg=C_BG)
        _btn_row.pack(fill="x", padx=20, pady=(0, 14))

        def _pick(val):
            _choice[0] = val
            try:
                _dlg.destroy()
            except Exception:
                pass

        for lbl, val in [("\U0001F4C4  File", "file"), ("\U0001F4C1  Folder", "folder")]:
            b = tk.Button(_btn_row, text=lbl, bg=C_BTN, fg=C_TEXT,
                          activebackground=C_BTN_HVR, activeforeground=C_TEXT,
                          font=("Segoe UI", 10), relief="flat", bd=0,
                          cursor="hand2", padx=16, pady=6,
                          command=lambda v=val: _pick(v))
            b.pack(side="left", expand=True, fill="x", padx=4)

        _cancel_btn = tk.Button(_btn_row, text="Cancel", bg=C_BTN, fg=C_DIM,
                                activebackground=C_BTN_HVR, activeforeground=C_TEXT,
                                font=("Segoe UI", 9), relief="flat", bd=0,
                                cursor="hand2", padx=10, pady=6,
                                command=lambda: _pick(None))
        _cancel_btn.pack(side="left", padx=(8, 4))

        _dlg.protocol("WM_DELETE_WINDOW", lambda: _pick(None))
        root.wait_window(_dlg)

    if _choice[0] is None:
        return  # cancelled

    if _choice[0] == "file":
        file_path = filedialog.askopenfilename(
            title="Select video file to transcribe",
            filetypes=[
                ("Video files", "*.mp4 *.mkv *.webm *.avi *.mov *.flv *.wmv *.m4v"),
                ("Audio files", "*.wav *.mp3 *.m4a *.flac *.ogg *.aac"),
                ("All files", "*.*"),
            ]
        )
        if not file_path:
            return
        file_path = os.path.normpath(file_path)

        with _gpu_queue_lock:
            _cur_item = _gpu_current_item
            if any(item.get("file_path") == file_path and item.get("type") == "mt" for item in _gpu_queue) or \
               (_cur_item and _cur_item.get("file_path") == file_path and _cur_item.get("type") == "mt"):
                log(f"  File already in GPU Tasks queue.\n", "simpleline")
                return

        _add_to_gpu_queue({"type": "mt", "file_path": file_path})
    else:  # folder
        folder_path = filedialog.askdirectory(title="Select folder to transcribe")
        if not folder_path:
            return
        folder_path = os.path.normpath(folder_path)

        # Count video files
        _vid_exts = {".mp4", ".mkv", ".webm", ".avi", ".mov", ".flv", ".wmv", ".m4v",
                     ".wav", ".mp3", ".m4a", ".flac", ".ogg", ".aac"}
        vid_count = sum(1 for f in os.listdir(folder_path)
                        if os.path.isfile(os.path.join(folder_path, f))
                        and os.path.splitext(f)[1].lower() in _vid_exts)
        if vid_count == 0:
            log(f"  No video/audio files found in folder.\n", "red")
            return

        with _gpu_queue_lock:
            _cur_item = _gpu_current_item
            if any(item.get("folder_path") == folder_path and item["type"] == "mt" for item in _gpu_queue) or \
               (_cur_item and _cur_item.get("folder_path") == folder_path and _cur_item.get("type") == "mt"):
                log(f"  Folder already in GPU Tasks queue.\n", "simpleline")
                return

        folder_name = os.path.basename(folder_path)
        _add_to_gpu_queue({"type": "mt", "folder_path": folder_path, "folder_name": folder_name,
                           "vid_count": vid_count})


def _run_manual_transcription(file_path, cancel_ev=None, pause_ev=None,
                              skip_model_dialog=False, _sync_mode=False):
    """Run manual transcription of a single local file in a background thread.

    cancel_ev/pause_ev: optional threading.Events (default to global cancel_event/pause_event).
    skip_model_dialog: if True, skip model selection and use current _whisper_model_choice.
    _sync_mode: if True, run the worker body directly (blocking) instead of spawning a thread.
    """
    global _transcribe_running, _whisper_model_choice

    fname = os.path.splitext(os.path.basename(file_path))[0]

    def _worker():
        global _transcribe_running, _transcribe_sync_controlled, _whisper_model_choice
        _ce = cancel_ev or cancel_event
        _pe = pause_ev or pause_event
        _transcribe_running = True
        _update_global_pause_btn_sync()
        _start_internet_monitor()
        _transcribe_sync_controlled = False  # Manual transcription never blocks sync-pipeline jobs
        if not _sync_mode:
            _current_job["label"] = f"M.T. {fname}"
            _current_job["url"] = None
            _update_queue_btn()
        _tray_start_spin(red=True)
        _update_tray_tooltip(f"YT Archiver \u2014 Transcribing {fname}")

        try:
            if _ce.is_set():
                return
            if _sync_mode and cancel_ev is not None:
                _ce.clear()  # only clear if caller (GPU worker) manages this event
            if not _sync_mode:
                _ui_queue.append(_update_queue_btn)

            log(f"\n{'='*60}\n", "header")
            log(f"  MANUAL TRANSCRIPTION: {fname}\n", "header")
            log(f"{'='*60}\n\n", "header")

            if not os.path.isfile(file_path):
                log(f"  File not found: {file_path}\n", "red")
                return

            out_dir = os.path.dirname(file_path)
            out_path = os.path.join(out_dir, fname + ".txt")
            if os.path.isfile(out_path):
                log(f"  Transcript already exists: {os.path.basename(out_path)}\n", "simpleline")
                log(f"  Overwriting...\n", "simpleline")

            if skip_model_dialog:
                # GPU Tasks mode — model already chosen
                _stop_whisper_process()
                log(f"  — Using Whisper model: {_whisper_model_choice}\n", "simpleline")
            else:
                # Model selection dialog
                model_choice, timed_out = _ask_whisper_model_dialog(
                    prompt_text="Which Whisper model to use?",
                    subtitle_text=f"Transcribing: {fname}",
                    cancel_ev=_ce
                )
                if _ce.is_set() or model_choice is None:
                    log(f"\n  Cancelled.\n", "red")
                    return

                _whisper_model_choice = model_choice
                _stop_whisper_process()

                if timed_out:
                    log(f"  — No user input, defaulting to {_whisper_model_choice} model\n", "simpleline")
                else:
                    log(f"  — Selected Whisper model: {_whisper_model_choice}\n", "simpleline")

            # Check CUDA availability
            if not _check_cuda_available():
                log(f"  \u26a0 No CUDA GPU detected \u2014 Whisper unavailable.\n", "red")
                return

            # Check Whisper installation
            if not _check_whisper_installed():
                log("  Whisper AI is not installed.\n", "red")
                _install_result = [None]

                def _ask_install():
                    _install_result[0] = messagebox.askyesno(
                        "Install Whisper AI",
                        "Whisper AI is required for transcription.\n\n"
                        "This requires ~2.5 GB of downloads (plus model download on first use).\n\n"
                        "Install now?")

                _ui_queue.append(_ask_install)
                while _install_result[0] is None and not _ce.is_set():
                    time.sleep(0.1)
                if not _install_result[0]:
                    log(f"  Transcription cancelled \u2014 Whisper not installed.\n", "red")
                    return
                if not _install_whisper_blocking():
                    log(f"  Failed to install Whisper.\n", "red")
                    return

            # Get duration for progress reporting
            _dur_secs = 0
            try:
                probe_cmd = ["ffprobe", "-v", "quiet", "-show_entries",
                             "format=duration", "-of", "csv=p=0", file_path]
                probe_result = subprocess.run(probe_cmd, capture_output=True,
                                              text=True, timeout=30, startupinfo=startupinfo)
                _dur_secs = float(probe_result.stdout.strip())
            except Exception:
                pass

            if _ce.is_set():
                log(f"\n  Cancelled.\n", "red")
                return

            _whisper_counter["idx"] = 1
            _whisper_counter["total"] = 1
            _t_start = time.time()
            log(f"  Transcribing with Whisper ({_whisper_model_choice})...\n", "simpleline")

            text, _ = _whisper_transcribe(file_path, duration=_dur_secs, title=fname,
                                          cancel_ev=_ce, pause_ev=_pe)
            _clear_whisper_progress()  # Remove progress line now that file is done

            if not text:
                if _whisper_last_failed:
                    log(f"  Whisper process failed — please try again.\n", "red")
                else:
                    log(f"  Whisper returned empty result.\n", "red")
                return

            text = _whisper_punct_fixup(text)

            try:
                with open(out_path, "w", encoding="utf-8") as f:
                    f.write(text)
            except Exception as e:
                log(f"  Error writing transcript: {e}\n", "red")
                return

            elapsed = time.time() - _t_start
            _m, _s = divmod(int(elapsed), 60)
            _time_str = f"{_m}min {_s:02d}sec" if _m else f"{_s}sec"
            log(f"\n  Transcript saved: {os.path.basename(out_path)} ({_time_str})\n", "simpleline_blue")

        except Exception as e:
            log(f"\n  Manual transcription error: {e}\n", "red")
        finally:
            _transcribe_running = False
            _transcribe_sync_controlled = False
            _clear_whisper_progress()  # Remove whisper progress line after transcription completes
            if not _sync_mode:
                _stop_whisper_process()
                if not _sync_running:
                    _tray_stop_spin()
                    _update_tray_tooltip("YT Archiver \u2014 Idle")
                    _current_job["label"] = None
                    _current_job["url"] = None
                _update_queue_btn()
            if not _sync_mode:
                _ui_queue.append(_sync_task_finished)
            if not _sync_mode:
                if _skip_current.is_set():
                    _skip_current.clear()
                    if _ce is cancel_event:
                        cancel_event.clear()
                    _process_next_queued()
                elif not _ce.is_set():
                    _process_next_queued()

    if _sync_mode:
        _worker()  # Run synchronously — caller is the GPU worker thread
    else:
        threading.Thread(target=_worker, daemon=True).start()


def _run_manual_transcription_folder(folder_path, folder_name, cancel_ev=None, pause_ev=None,
                                      _sync_mode=False):
    """Run manual transcription of all video/audio files in a folder.

    All files are transcribed and written to a single (foldername) Transcript.txt
    using the same entry format as channel transcription.
    Always runs via GPU Tasks (_sync_mode=True from GPU worker).
    """
    global _transcribe_running, _whisper_model_choice

    _VID_EXTS = {".mp4", ".mkv", ".webm", ".avi", ".mov", ".flv", ".wmv", ".m4v",
                 ".wav", ".mp3", ".m4a", ".flac", ".ogg", ".aac"}

    def _worker():
        global _transcribe_running, _transcribe_sync_controlled, _whisper_model_choice
        _ce = cancel_ev or cancel_event
        _pe = pause_ev or pause_event
        _transcribe_running = True
        _update_global_pause_btn_sync()
        _start_internet_monitor()
        _transcribe_sync_controlled = False  # Manual folder transcription never blocks sync-pipeline jobs
        _tray_start_spin(red=True)
        _update_tray_tooltip(f"YT Archiver — Transcribing {folder_name}")

        try:
            if _ce.is_set():
                return
            _ce.clear()

            log(f"\n{'='*60}\n", "header")
            log(f"  MANUAL TRANSCRIPTION (FOLDER): {folder_name}\n", "header")
            log(f"{'='*60}\n\n", "header")

            if not os.path.isdir(folder_path):
                log(f"  Folder not found: {folder_path}\n", "red")
                return

            # Gather video/audio files, sorted chronologically by file modification date
            all_files = [f for f in os.listdir(folder_path)
                         if os.path.isfile(os.path.join(folder_path, f))
                         and os.path.splitext(f)[1].lower() in _VID_EXTS]
            files = sorted(all_files, key=lambda f: os.path.getmtime(os.path.join(folder_path, f)))

            if not files:
                log(f"  No video/audio files found in folder.\n", "red")
                return

            out_path = os.path.join(folder_path, f"{folder_name} Transcript.txt")

            # Check existing transcript for already-transcribed files (skip on re-run)
            _existing_titles = set()
            if os.path.isfile(out_path):
                try:
                    with open(out_path, "r", encoding="utf-8") as _ef:
                        for _line in _ef:
                            _m = re.match(r'^===\((.+?)\),', _line)
                            if _m:
                                _existing_titles.add(_m.group(1))
                except Exception:
                    pass
            if _existing_titles:
                _before_count = len(files)
                files = [f for f in files if os.path.splitext(f)[0] not in _existing_titles]
                _skipped_existing = _before_count - len(files)
                if _skipped_existing:
                    log(f"  Skipping {_skipped_existing} already-transcribed file(s)\n", "simpleline")
                if not files:
                    log(f"  All files already transcribed.\n", "simpleline_green")
                    return

            log(f"  Found {len(files)} files to transcribe\n", "simpleline")
            log(f"  Output: {folder_name} Transcript.txt\n\n", "simpleline")

            # Check CUDA availability
            if not _check_cuda_available():
                log(f"  ⚠ No CUDA GPU detected — Whisper unavailable.\n", "red")
                return

            # Check Whisper installation
            if not _check_whisper_installed():
                log("  Whisper AI is not installed.\n", "red")
                _install_result = [None]

                def _ask_install():
                    _install_result[0] = messagebox.askyesno(
                        "Install Whisper AI",
                        "Whisper AI is required for transcription.\n\n"
                        "This requires ~2.5 GB of downloads (plus model download on first use).\n\n"
                        "Install now?")

                _ui_queue.append(_ask_install)
                while _install_result[0] is None and not _ce.is_set():
                    time.sleep(0.1)
                if not _install_result[0]:
                    log(f"  Transcription cancelled — Whisper not installed.\n", "red")
                    return
                if not _install_whisper_blocking():
                    log(f"  Failed to install Whisper.\n", "red")
                    return

            _stop_whisper_process()
            log(f"  — Using Whisper model: {_whisper_model_choice}\n\n", "simpleline")

            _t_start = time.time()
            _whisper_counter["idx"] = 0
            _whisper_counter["total"] = len(files)
            _transcribed = 0
            _skipped = 0
            _excluded = 0

            for i, filename in enumerate(files):
                if _ce.is_set():
                    log(f"\n  Cancelled.\n", "red")
                    return

                # Handle pause
                if _pe.is_set():
                    log(f"  ⏸ Paused.\n", "dim")
                    _tray_stop_spin()
                    while _pe.is_set() and not _ce.is_set():
                        time.sleep(0.5)
                    if not _ce.is_set():
                        log(f"  ▶ Resumed.\n", "dim")
                        _tray_start_spin(red=True)
                if _ce.is_set():
                    log(f"\n  Cancelled.\n", "red")
                    return

                fpath = os.path.join(folder_path, filename)
                fname = os.path.splitext(filename)[0]
                _whisper_counter["idx"] = i + 1

                log(f"  [{i+1}/{len(files)}] {fname}\n", "simpleline")

                # Get duration
                dur_str = ""
                _dur_secs = 0
                try:
                    probe_cmd = ["ffprobe", "-v", "quiet", "-show_entries",
                                 "format=duration", "-of", "csv=p=0", fpath]
                    probe_result = subprocess.run(probe_cmd, capture_output=True,
                                                  text=True, timeout=30, startupinfo=startupinfo)
                    _dur_secs = float(probe_result.stdout.strip())
                    hrs, remainder = divmod(int(_dur_secs), 3600)
                    mins, sec = divmod(remainder, 60)
                    dur_str = f"{hrs}:{mins:02d}:{sec:02d}" if hrs else f"{mins}:{sec:02d}"
                except Exception:
                    pass

                # Get date from file mtime
                try:
                    mtime = datetime.fromtimestamp(os.path.getmtime(fpath))
                    upload_date = mtime.strftime("%Y%m%d")
                except Exception:
                    upload_date = ""

                # Transcribe
                text, _ = _whisper_transcribe(fpath, duration=_dur_secs, title=fname,
                                              cancel_ev=_ce, pause_ev=_pe)
                _clear_whisper_progress()  # Remove progress line now that file is done

                if _ce.is_set():
                    log(f"\n  Cancelled.\n", "red")
                    return

                if text:
                    text = _whisper_punct_fixup(text)

                if not text:
                    if _whisper_last_failed:
                        # Process stalled or crashed — do NOT exclude the video.
                        # It will be retried on the next transcription run.
                        log(f"    Whisper failed, skipping (will retry next run).\n", "red")
                        _skipped += 1
                        continue
                    # Write exclusion entry so this video is skipped on future transcribes
                    log(f"    no speech detected, excluding.\n", "simpleline")
                    try:
                        _excl_date_fmt = _format_upload_date(upload_date)
                        _excl_dur_fmt = _format_duration(dur_str)
                        _excl_entry = f"===({fname}), {_excl_date_fmt}, {_excl_dur_fmt}, (NO AUDIO DATA — EXCLUDED)===\n[No speech detected]\n\n\n"
                        with open(out_path, "a", encoding="utf-8") as _ef:
                            _ef.write(_excl_entry)
                        # Write JSONL placeholder so backfill doesn't retry this video
                        try:
                            _excl_jsonl = _get_jsonl_path(out_path)
                            _excl_placeholder = [{"start": 0.0, "end": 0.01, "text": "(no speech detected)"}]
                            _write_jsonl_entry(_excl_jsonl, "", fname, _excl_placeholder)
                        except Exception:
                            pass
                        _excluded += 1
                    except Exception:
                        _skipped += 1
                    continue

                # Build entry in channel transcription format
                date_fmt = _format_upload_date(upload_date)
                dur_fmt = _format_duration(dur_str)
                _w_model_tag = f"WHISPER {_whisper_model_choice.upper()}"
                entry = f"===({fname}), {date_fmt}, {dur_fmt}, ({_w_model_tag})===\n{text}\n\n\n"

                try:
                    with open(out_path, "a", encoding="utf-8") as f:
                        f.write(entry)
                    _transcribed += 1
                except Exception as e:
                    log(f"    ⚠ Error writing transcript: {e}\n", "red")
                    _skipped += 1

            # Sort the transcript file by date (newest first)
            if _transcribed > 0 and os.path.isfile(out_path):
                try:
                    _sort_transcript_entries([out_path])
                except Exception:
                    pass

            elapsed = time.time() - _t_start
            _m, _s = divmod(int(elapsed), 60)
            _h, _m = divmod(_m, 60)
            if _h:
                _time_str = f"{_h}hr {_m:02d}min {_s:02d}sec"
            elif _m:
                _time_str = f"{_m}min {_s:02d}sec"
            else:
                _time_str = f"{_s}sec"

            log(f"\n  Folder transcription complete: {_transcribed} transcribed", "simpleline_green")
            if _excluded:
                log(f", {_excluded} excluded (no speech)", "simpleline_green")
            if _skipped:
                log(f", {_skipped} skipped", "simpleline_green")
            log(f" ({_time_str})\n", "simpleline_green")
            log(f"  Saved: {folder_name} Transcript.txt\n", "simpleline_green")

        except Exception as e:
            log(f"\n  Manual folder transcription error: {e}\n", "red")
        finally:
            _transcribe_running = False
            _transcribe_sync_controlled = False
            _clear_whisper_progress()  # Remove whisper progress line after transcription completes
            if not _sync_mode:
                _stop_whisper_process()
                _stop_punct_process()   # Free GPU memory
                if not _sync_running:
                    _tray_stop_spin()
                    _update_tray_tooltip("YT Archiver — Idle")
                    _current_job["label"] = None
                    _current_job["url"] = None
                _update_queue_btn()
            if not _sync_mode:
                _ui_queue.append(_sync_task_finished)
            # Process any queued jobs in insertion order (only when not in sync_mode)
            if not _sync_mode:
                if _skip_current.is_set():
                    _skip_current.clear()
                    cancel_event.clear()
                    _process_next_queued()
                elif not _ce.is_set():
                    _process_next_queued()

    if _sync_mode:
        _worker()
    else:
        threading.Thread(target=_worker, daemon=True).start()


