def _continue_redownload():
    """Triggered by the Continue Redownload button in edit mode."""
    # Immediately disable and show feedback so user knows click registered
    continue_redownload_btn.config(state="disabled", text="↻ Queuing…")

    ch_url = _editing_channel.get("url") or new_url_var.get().strip()
    ch_name = _editing_channel.get("name") or new_name_var.get().strip()
    if not ch_url or not ch_name:
        continue_redownload_btn.config(state="normal", text="↻ Continue Redownload")
        return
    pending_res = _has_pending_redownload(ch_url)
    if not pending_res:
        log("  No pending redownload to continue.\n", "simpleline")
        continue_redownload_btn.config(state="normal", text="↻ Continue Redownload")
        return
    with config_lock:
        _rd_base = config.get("output_dir", "").strip() or BASE_DIR
    _rd_folder = os.path.join(_rd_base, sanitize_folder(ch_name))
    _add_to_redownload_queue(ch_name, ch_url, _rd_folder, pending_res)
    continue_redownload_btn.pack_forget()
    continue_redownload_btn.config(state="normal", text="↻ Continue Redownload")

continue_redownload_btn = ttk.Button(action_btn_frame, text="↻ Continue Redownload",
                                     command=_continue_redownload)
continue_redownload_btn.pack(side="left", padx=(0, 8))
continue_redownload_btn.pack_forget()

# ─── Show/hide add-channel detail options ─────────────────
_add_details_visible = True
_add_detail_widgets = []  # widgets to toggle, populated on first hide

def _set_add_details_visible(show):
    """Show or hide the channel detail options (resolution, mode, duration, etc.)."""
    global _add_details_visible
    if show == _add_details_visible:
        return
    _add_details_visible = show
    if show:
        # Restore all previously hidden widgets
        for child in _add_detail_widgets:
            try:
                child.grid()
            except Exception:
                pass
    else:
        # Collect and hide widgets in rows >= 2 (plus Duration Limit header in row 1)
        _add_detail_widgets.clear()
        for child in add_outer.winfo_children():
            try:
                info = child.grid_info()
                if not info:
                    continue
                row = int(info.get("row", 0))
                if row >= 2 or (row == 1 and child != url_error_label):
                    _add_detail_widgets.append(child)
                    child.grid_remove()
            except Exception:
                pass

def _check_add_details_visibility(*_):
    """Show detail options when user types in URL/name fields or is editing a channel."""
    try:
        n = _real_get(new_name_entry).strip()
        u = _real_get(_new_url_entry).strip()
        editing = _editing_channel.get("name")
        _set_add_details_visible(bool(n or u or editing))
    except Exception:
        pass

new_name_var.trace_add("write", _check_add_details_visibility)
new_url_var.trace_add("write", _check_add_details_visibility)

# Start collapsed
_set_add_details_visible(False)
