def _insert_hist_line(tw, entry, row_tags):
    """Insert one activity-log entry into the history Text widget with inline colours."""
    line = f"  {entry}"
    m = re.match(r'^(\s*\[\s*(\w+)\s*\])(.*)', line)
    if not m:
        tw.insert(tk.END, line + "\n", row_tags)
        return
    prefix, kind, rest = m.group(1), m.group(2).strip(), m.group(3)

    # Colour for the [Kind] tag
    if kind == "Trnscr":
        _tr_m = re.search(r'\b(\d+) transcribed\b', rest)
        _has_transcribed = _tr_m and int(_tr_m.group(1)) > 0
        prefix_tags = ("hist_blue",) + row_tags if _has_transcribed else row_tags
    elif kind == "Metdta":
        _fetched_m = re.search(r'\b(\d+) fetched\b', rest)
        _refreshed_m = re.search(r'\b(\d+) refreshed\b', rest)
        _has_work = ((_fetched_m and int(_fetched_m.group(1)) > 0) or
                     (_refreshed_m and int(_refreshed_m.group(1)) > 0))
        prefix_tags = ("hist_pink",) + row_tags if _has_work else row_tags
    elif kind in ("Manual", "Auto"):
        dl_m = re.search(r'\b(\d+) downloaded\b', rest)
        dl_count = int(dl_m.group(1)) if dl_m else 0
        prefix_tags = ("hist_green",) + row_tags if dl_count > 0 else row_tags
    elif kind == "ReDwnl":
        rdl_m = re.search(r'\b(\d+) replaced\b', rest)
        rdl_count = int(rdl_m.group(1)) if rdl_m else 0
        _is_running = "running..." in rest
        prefix_tags = ("hist_green",) + row_tags if (rdl_count > 0 or _is_running) else row_tags
    else:
        prefix_tags = row_tags
    tw.insert(tk.END, prefix, prefix_tags)

    # Inline highlight patterns for the rest of the line
    patterns = []
    if kind == "Trnscr":
        patterns.append((r'\b[1-9]\d* transcribed\b', "hist_blue"))
    elif kind == "Metdta":
        patterns.append((r'\b[1-9]\d* fetched\b', "hist_pink"))
        patterns.append((r'\b[1-9]\d* refreshed\b', "hist_pink"))
    elif kind in ("Manual", "Auto"):
        dl_m = re.search(r'\b(\d+) downloaded\b', rest)
        if dl_m and int(dl_m.group(1)) > 0:
            patterns.append((r'\b\d+ downloaded\b', "hist_green"))
    elif kind == "ReDwnl":
        if "running..." in rest:
            patterns.append((r'▶ running\.\.\.', "hist_green"))
        else:
            rdl_m = re.search(r'\b(\d+) replaced\b', rest)
            if rdl_m and int(rdl_m.group(1)) > 0:
                patterns.append((r'\b\d+ replaced\b', "hist_green"))
    # Amber skipped for any kind, only when non-zero
    patterns.append((r'\b[1-9]\d* skipped\b', "hist_amber"))

    matches = []
    for pat, colour in patterns:
        for mo in re.finditer(pat, rest):
            matches.append((mo.start(), mo.end(), colour))
    matches.sort(key=lambda x: x[0])

    pos = 0
    for start, end, colour in matches:
        if start > pos:
            tw.insert(tk.END, rest[pos:start], row_tags)
        tw.insert(tk.END, rest[start:end], (colour,) + row_tags)
        pos = end
    if pos < len(rest):
        tw.insert(tk.END, rest[pos:], row_tags)
    tw.insert(tk.END, "\n", row_tags)


def _parse_hist_entry(entry):
    """Split an activity-log entry into (prefix, channel_name, stats) or None."""
    dash1 = entry.find(" —")
    if dash1 < 0:
        return None
    rest = entry[dash1 + 2:]
    dash2 = rest.find("  —")
    if dash2 < 4:
        return None
    prefix = entry[:dash1 + 2]
    ch_name = rest[:dash2].strip()
    stats = rest[dash2 + 3:]
    if not ch_name:
        return None
    return prefix, ch_name, stats


def _rebuild_hist_line(prefix, ch_name, stats, col_width):
    """Reassemble an activity-log entry with a uniform channel column width."""
    if len(ch_name) > col_width:
        ch_disp = ch_name[:col_width - 1] + "\u2026"
    else:
        ch_disp = ch_name
    return f"{prefix}  {ch_disp:<{col_width}s}  —{stats}"


def _refresh_autorun_history():
    autorun_history_text.config(state="normal")
    autorun_history_text.delete("1.0", tk.END)
    # Calculate available character width
    try:
        tw_width = autorun_history_text.winfo_width()
        if tw_width > 1:
            _font = tkfont.Font(font=autorun_history_text.cget("font"))
            char_w = _font.measure("M")
            max_chars = max(40, tw_width // char_w) if char_w > 0 else 120
        else:
            max_chars = 120
    except Exception:
        max_chars = 120
    with config_lock:
        history = list(config.get("autorun_history", []))

    # Parse all entries to find channel names and determine uniform column width
    parsed = []
    longest_ch = 0
    for entry in history:
        p = _parse_hist_entry(entry)
        parsed.append(p)
        if p:
            longest_ch = max(longest_ch, len(p[1]))

    if longest_ch > 0:
        # Use the longest stats section to ensure all lines fit
        max_fixed = 0
        for p in parsed:
            if p:
                # 2 (indent) + len(prefix) + 2 ("  ") + ch_col + 3 ("  —") + len(stats)
                fixed = 2 + len(p[0]) + 2 + 3 + len(p[2])
                max_fixed = max(max_fixed, fixed)
        avail_for_ch = max(4, max_chars - max_fixed)
        # Column width: fit available space, but never wider than the longest name
        col_width = max(4, min(longest_ch, avail_for_ch))
    else:
        col_width = 22  # fallback

    for idx, entry in enumerate(history):
        row_tags = ("hist_row_alt",) if idx % 2 == 0 else ()
        p = parsed[idx]
        if p:
            fitted = _rebuild_hist_line(p[0], p[1], p[2], col_width)
        else:
            fitted = entry
        _insert_hist_line(autorun_history_text, fitted, row_tags)
    autorun_history_text.config(state="disabled")
    # Scroll to bottom so newest entry is visible
    autorun_history_text.see(tk.END)

    # Get the currently visible panes
    current_panes = [str(p) for p in log_paned.panes()]

    if history:
        autorun_clear_btn.grid(row=0, column=2, sticky="w", padx=(8, 0))
        # Bring the frame back if it's not currently shown
        if str(autorun_history_frame) not in current_panes:
            log_paned.insert(0, autorun_history_frame, weight=0)
    else:
        autorun_clear_btn.grid_remove()
        # Hide the frame if it's currently visible
        if str(autorun_history_frame) in current_panes:
            log_paned.forget(autorun_history_frame)


def _record_sync(dl, err, elapsed_secs, kind="Auto", channel_name="", skipped=0):
    _now = datetime.now()
    ts = _now.strftime("%-I:%M%p").lower().lstrip("0") if os.name != "nt" else _now.strftime("%I:%M%p").lower().lstrip("0")
    date = _now.strftime("%b {d}").replace("{d}", str(_now.day))
    mins = int(elapsed_secs // 60)
    secs = int(elapsed_secs % 60)
    if mins >= 60:
        hrs = mins // 60
        rem_mins = mins % 60
        dur = f"took {hrs}h {rem_mins:02d}m"
    elif mins:
        dur = f"took {mins}m {secs:02d}s"
    else:
        dur = f"took {secs}s"
    ts_date = f"{ts}, {date}".ljust(16)
    kind_tag = f"[{kind.center(6)}]" if len(kind) < 6 else f"[{kind}]"
    ch_part = f"  {channel_name}  —" if channel_name else " " * 7
    line = f"{kind_tag} {ts_date} —{ch_part}  {dl:>4} {'downloaded':<11} · {skipped:>4} skipped · {err:>1} errors · {dur}"
    with config_lock:
        hist = config.setdefault("autorun_history", [])
        hist.append(line)
        if len(hist) > AUTORUN_HISTORY_MAX:
            config["autorun_history"] = hist[-AUTORUN_HISTORY_MAX:]
    save_config(config)
    if _root_alive:
        _ui_queue.append(_refresh_autorun_history)




