    def __init__(self, parent):
        super().__init__(parent)
        self.configure(style="TFrame")
        self._loaded          = False
        self._conn            = None
        self._db_loading      = False
        self._db_lock         = threading.RLock()
        self._result_meta     = {}
        self._sort_col        = "date"
        self._sort_asc        = False
        self._index_running   = False
        self._viewer_section  = None
        self._viewer_header   = ""
        self._viewer_query    = ""
        self._viewer_win_start = 0
        self._viewer_win_end   = 0
        self._freq_all_keys   = []
        self._freq_words      = []
        self._freq_by_month   = False
        self._active_section  = "browse"
        self._pending_reindex = None
        self._tp_extra_roots  = []
        self._search_running  = False
        self._bookmarks_data  = []
        self._browse_seg_map  = []  # [(char_start, char_end, seg_tuple), ...] built at load time
        self._player_active   = False
        self._build_placeholder()

    def _db_execute(self, *args, **kwargs):
        """Thread-safe wrapper around self._conn.execute()."""
        with self._db_lock:
            return self._conn.execute(*args, **kwargs)

    def _db_commit(self):
        """Thread-safe wrapper around self._conn.commit()."""
        with self._db_lock:
            self._conn.commit()

    def _build_placeholder(self):
        self._placeholder = tk.Frame(self, bg=self._TP_BG)
        self._placeholder.place(relx=0, rely=0, relwidth=1, relheight=1)
        tk.Label(self._placeholder, text="Loading transcription index…",
                 bg=self._TP_BG, fg=self._TP_DIM,
                 font=("Segoe UI", 12)).place(relx=0.5, rely=0.5, anchor="center")

    def preload_db(self):
        """Pre-load the DB connection in the background at startup.
        The UI is NOT built here — that happens in on_shown() / _finish_load().
        This just warms up the DB so it's ready when the user clicks Browse."""
        if self._conn is not None or self._loaded or self._db_loading:
            return  # already loaded or in progress
        self._db_loading = True
        threading.Thread(target=self._preload_db_async, daemon=True).start()

    def _preload_db_async(self):
        try:
            conn = _tp_open_db(_TP_DB_PATH)
            self._conn = conn
        except Exception:
            pass  # on_shown() will retry if needed
        finally:
            self._db_loading = False
        # DB ready — eagerly build UI on the main thread so the Browse tab
        # is instant when the user eventually clicks it.
        if self._conn is not None and not self._loaded:
            self.after(0, self._eager_finish_load)

    def _eager_finish_load(self):
        """Build the Browse tab UI eagerly after DB preload, before user clicks."""
        if self._loaded:
            return  # on_shown() already ran
        self._loaded = True
        self._placeholder.place_forget()
        self._tp_extra_roots = list(config.get("tp_archive_roots", []))
        self._build_ui()
        self._refresh_stats_label()
        self._ensure_videos_populated()

    def on_shown(self):
        """Called the first time the Transcriptions tab is selected."""
        if self._loaded:
            if self._pending_reindex is not None:
                self._maybe_offer_reindex(self._pending_reindex)
                self._pending_reindex = None
            return
        self._loaded = True
        # If DB was pre-loaded at startup, skip the async load — just build UI
        if self._conn is not None:
            self.update_idletasks()  # render placeholder before UI build
            self.after(1, self._finish_load)  # defer so placeholder is visible
            return
        # If preload is still running, wait for it instead of opening a second connection
        if self._db_loading:
            self._wait_for_preload()
            return
        self.update_idletasks()  # render placeholder before thread starts
        threading.Thread(target=self._load_db_async, daemon=True).start()

    def _wait_for_preload(self):
        """Poll until the background preload finishes, then finish loading."""
        if self._db_loading:
            self.after(50, self._wait_for_preload)
            return
        if self._conn is not None:
            self.after(1, self._finish_load)
        else:
            # Preload failed — fall back to normal async load
            threading.Thread(target=self._load_db_async, daemon=True).start()

    def _load_db_async(self):
        try:
            conn = _tp_open_db(_TP_DB_PATH)
            self._conn = conn
        except Exception as e:
            def _on_db_error(err=e):
                self._loaded = False  # allow retry on next tab switch
                messagebox.showerror(
                    "DB Error", f"Could not open transcription index:\n{err}")
            self.after(0, _on_db_error)
            return
        self.after(0, self._finish_load)

    def _finish_load(self):
        self._placeholder.place_forget()
        self._tp_extra_roots = list(config.get("tp_archive_roots", []))
        self._build_ui()
        self._refresh_stats_label()
        # Auto-scan archive if videos table is empty (first-time migration)
        self._ensure_videos_populated()
        if self._pending_reindex is not None:
            self.after(300, lambda: self._maybe_offer_reindex(self._pending_reindex))
            self._pending_reindex = None

    def _get_archive_roots(self):
        roots = []
        with config_lock:
            out_dir = config.get("output_dir", "").strip()
            extra   = config.get("tp_archive_roots", [])
        if out_dir and os.path.isdir(out_dir):
            roots.append(out_dir)
        for r in extra:
            if r and os.path.isdir(r) and r not in roots:
                roots.append(r)
        return roots

    # ── Video registry (videos table) ────────────────────────────────────────

    def register_video(self, title, channel, year=None, month=None, filepath=None,
                       video_id=None, video_url=None, duration_s=None, size_bytes=None):
        """Insert a single video into the videos table (idempotent).
        Matches existing rows by normalized filepath first (case-insensitive on
        Windows), then by title+channel.  Updates metadata on existing rows
        rather than creating duplicates."""
        if not self._conn:
            return
        # Normalize filepath for consistent storage and matching
        if filepath:
            filepath = os.path.normpath(filepath)
        _norm_fp = os.path.normcase(filepath) if filepath else None
        try:
            _existing = None
            # 1) Match by normalized filepath (most reliable — same file on disk)
            if _norm_fp:
                for _row in self._db_execute(
                        "SELECT id, filepath, title FROM videos "
                        "WHERE filepath IS NOT NULL AND channel=?",
                        (channel,)).fetchall():
                    if _row[1] and os.path.normcase(os.path.normpath(_row[1])) == _norm_fp:
                        _existing = (_row[0], _row[1])
                        break
            # 2) Fall back to title+channel match
            if not _existing:
                _row = self._db_execute(
                    "SELECT id, filepath FROM videos WHERE title=? AND channel=?",
                    (title, channel)).fetchone()
                if _row:
                    _existing = (_row[0], _row[1])

            if _existing:
                _eid, _efp = _existing
                _sets, _vals = [], []
                # Always update filepath if the new one is valid and different
                if filepath and (not _efp or os.path.normcase(os.path.normpath(_efp or "")) != _norm_fp):
                    _sets.append("filepath=?")
                    _vals.append(filepath)
                # Update title if this is a filepath match with a different title
                # (prefer YouTube title over filename-derived title)
                if filepath and _norm_fp:
                    _sets.append("title=?")
                    _vals.append(title)
                if year is not None:
                    _sets.append("year=?")
                    _vals.append(year)
                if month is not None:
                    _sets.append("month=?")
                    _vals.append(month)
                if video_id:
                    _sets.append("video_id=COALESCE(video_id,?)")
                    _vals.append(video_id)
                if video_url:
                    _sets.append("video_url=COALESCE(video_url,?)")
                    _vals.append(video_url)
                if duration_s is not None:
                    _sets.append("duration_s=COALESCE(duration_s,?)")
                    _vals.append(duration_s)
                if size_bytes is not None:
                    _sets.append("size_bytes=COALESCE(size_bytes,?)")
                    _vals.append(size_bytes)
                if _sets:
                    _vals.append(_eid)
                    self._db_execute(
                        f"UPDATE videos SET {', '.join(_sets)} WHERE id=?", _vals)
            else:
                self._db_execute(
                    "INSERT OR IGNORE INTO videos "
                    "(title, channel, year, month, filepath, video_id, video_url, "
                    " duration_s, size_bytes, tx_status, added_ts) "
                    "VALUES (?,?,?,?,?,?,?,?,?,?,?)",
                    (title, channel, year, month, filepath, video_id, video_url,
                     duration_s, size_bytes, "pending", time.time()))
            self._db_commit()
        except Exception:
            pass

    def _scan_archive(self, auto=False):
        """Walk known channel folders and register every video file in the videos table."""
        if not self._conn:
            return
        roots = self._get_archive_roots()
        if not roots:
            return

        # Build list of channel folders to scan (from config only)
        with config_lock:
            channels_cfg = list(config.get("channels", []))
        channel_dirs = []
        for ch in channels_cfg:
            ch_name = ch.get("name", "")
            folder = ch.get("folder_override", "").strip() or ch_name
            folder = sanitize_folder(folder)
            if not folder:
                continue
            for root_dir in roots:
                ch_path = os.path.join(root_dir, folder)
                if os.path.isdir(ch_path):
                    channel_dirs.append((ch_name, ch_path, root_dir))

        if not channel_dirs:
            return

        # UI feedback
        def _set_scanning():
            try:
                self._browse_scan_btn.config(state="disabled")
                self._browse_scan_status.config(text="Scanning...")
            except Exception:
                pass
        self.after(0, _set_scanning)

        def _worker():
            count = 0
            # Single-pass scan: collect transcript dirs AND video files together
            # to avoid walking the same directory tree twice (was NEW-3 audit item).
            dirs_with_transcripts = set()
            pending_videos = []  # (ch_name, root_dir, dirpath, fn, fn_lower)
            for ch_name, ch_path, root_dir in channel_dirs:
                for dirpath, _, filenames in os.walk(ch_path, followlinks=False):
                    for fn in filenames:
                        fn_lower = fn.lower()
                        # Track dirs containing transcript/jsonl files
                        if (fn_lower.endswith('.txt') and 'transcript' in fn_lower) or fn_lower.endswith('.jsonl'):
                            dirs_with_transcripts.add(dirpath)
                        # Collect video files for DB insertion
                        if fn_lower.endswith(self._TP_VIDEO_EXTS) and ".temp." not in fn_lower and not fn_lower.endswith(".part"):
                            pending_videos.append((ch_name, root_dir, dirpath, fn, fn_lower))

            # Now process all collected video files with transcript info available
            for ch_name, root_dir, dirpath, fn, fn_lower in pending_videos:
                fp = os.path.normpath(os.path.join(dirpath, fn))
                # Derive year / month from path structure
                _, year, month = _tp_parse_path_meta(fp, [root_dir])
                title = os.path.splitext(fn)[0]
                # Extract video ID from yt-dlp filename pattern: "Title [VIDEO_ID].ext"
                _vid_id = None
                _bracket = title.rfind(" [")
                if _bracket >= 0 and title.endswith("]"):
                    _candidate = title[_bracket + 2:-1]
                    if 10 <= len(_candidate) <= 12 and re.match(r'^[\w-]+$', _candidate):
                        _vid_id = _candidate
                try:
                    sz = os.path.getsize(fp)
                except OSError:
                    sz = None
                # Check if transcript files exist on disk in this dir
                # or any parent dir (handles split_years/split_months)
                has_tx = False
                _chk = dirpath
                for _ in range(3):
                    if _chk in dirs_with_transcripts:
                        has_tx = True
                        break
                    _p = os.path.dirname(_chk)
                    if _p == _chk:
                        break
                    _chk = _p
                status = "transcribed" if has_tx else "pending"
                try:
                    self._db_execute(
                        "INSERT OR IGNORE INTO videos "
                        "(title, channel, year, month, filepath, video_id, tx_status, "
                        " size_bytes, added_ts) "
                        "VALUES (?,?,?,?,?,?,?,?,?)",
                        (title, ch_name, year, month, fp, _vid_id, status, sz,
                         time.time()))
                    # Backfill video_id for existing rows that are missing it
                    if _vid_id:
                        self._db_execute(
                            "UPDATE videos SET video_id=? "
                            "WHERE filepath=? AND video_id IS NULL",
                            (_vid_id, fp))
                    count += 1
                except Exception:
                    continue
            self._db_commit()
            # Reconcile: update any existing 'pending' videos that actually
            # have transcript files on disk (covers re-scans after transcription)
            try:
                pending = self._db_execute(
                    "SELECT id, filepath FROM videos "
                    "WHERE tx_status='pending' AND filepath IS NOT NULL"
                ).fetchall()
                for vid_id, fp in pending:
                    _chk = os.path.dirname(fp)
                    for _ in range(3):
                        if _chk in dirs_with_transcripts:
                            self._db_execute(
                                "UPDATE videos SET tx_status='transcribed' WHERE id=?",
                                (vid_id,))
                            break
                        _p = os.path.dirname(_chk)
                        if _p == _chk:
                            break
                        _chk = _p
                self._db_commit()
            except Exception:
                pass
            # Reconcile channel names: fix rows where the channel name from
            # yt-dlp metadata doesn't match the config name (e.g. "David
            # Pakman Show" vs "David Pakman") by matching filepath to channel folder
            try:
                _cfg_map = {}  # folder_name -> config channel name
                for _ch_cfg in channels_cfg:
                    _f = _ch_cfg.get("folder_override", "").strip() or sanitize_folder(_ch_cfg.get("name", ""))
                    if _f:
                        _cfg_map[_f] = _ch_cfg["name"]
                _all_rows = self._db_execute(
                    "SELECT id, channel, filepath FROM videos WHERE filepath IS NOT NULL"
                ).fetchall()
                for _rid, _rch, _rfp in _all_rows:
                    for _folder, _cfg_name in _cfg_map.items():
                        if _rch != _cfg_name and os.sep + _folder + os.sep in _rfp.replace("/", os.sep):
                            self._db_execute(
                                "UPDATE videos SET channel=? WHERE id=?",
                                (_cfg_name, _rid))
                            break
                self._db_commit()
            except Exception:
                pass
            # ── Deduplicate: remove DB rows for the same video file ──
            # Videos can end up with multiple rows when the disk scan uses the
            # filename as title while the download callback uses the YouTube
            # title (different punctuation/spacing).  Group by normalised
            # filepath (case-insensitive) and keep the best row per group.
            try:
                _all_vids = self._db_execute(
                    "SELECT id, title, channel, filepath, video_id FROM videos "
                    "WHERE title != '__ver__'"
                ).fetchall()
                # Group by (channel, normalised filepath)
                _fp_groups = {}  # (channel, norm_fp) -> [rows]
                for _r in _all_vids:
                    _rid, _rt, _rc, _rfp, _rvid = _r
                    if _rfp:
                        _nfp = os.path.normcase(os.path.normpath(_rfp))
                        _gkey = (_rc, _nfp)
                    else:
                        _gkey = (_rc, f"__null_{_rid}")  # unique key for NULL fps
                    _fp_groups.setdefault(_gkey, []).append(_r)
                _deleted = 0
                for _gkey, _group in _fp_groups.items():
                    if len(_group) <= 1:
                        continue
                    # Score: existing file > has video_id > newest id
                    def _score(r):
                        return (1 if r[3] and os.path.isfile(r[3]) else 0,
                                1 if r[4] else 0,
                                r[0])
                    _group.sort(key=_score, reverse=True)
                    for _dr in _group[1:]:
                        self._db_execute("DELETE FROM videos WHERE id=?", (_dr[0],))
                        _deleted += 1
                # Also deduplicate by fuzzy title within same channel
                # (catches case where filepaths differ but it's the same video)
                if not _deleted:
                    _by_ch = {}
                    for _r in _all_vids:
                        _by_ch.setdefault(_r[2], []).append(_r)
                    for _ch, _ch_rows in _by_ch.items():
                        _by_ntitle = {}  # norm_title -> [rows]
                        for _r in _ch_rows:
                            _nt = re.sub(r'[^a-z0-9]', '', _r[1].lower())
                            _by_ntitle.setdefault(_nt, []).append(_r)
                        for _nt, _group in _by_ntitle.items():
                            if len(_group) <= 1:
                                continue
                            def _score2(r):
                                return (1 if r[3] and os.path.isfile(r[3]) else 0,
                                        1 if r[4] else 0,
                                        r[0])
                            _group.sort(key=_score2, reverse=True)
                            for _dr in _group[1:]:
                                self._db_execute("DELETE FROM videos WHERE id=?", (_dr[0],))
                                _deleted += 1
                if _deleted:
                    self._db_commit()
            except Exception:
                pass
            # Backfill missing video_ids from the segments table
            # (segments/JSONL data almost always has the video_id even when
            # the filename doesn't include [VIDEO_ID])
            try:
                _null_ids = self._db_execute(
                    "SELECT v.id, v.title, v.channel FROM videos v "
                    "WHERE v.video_id IS NULL"
                ).fetchall()
                if _null_ids:
                    # Build title+channel → video_id lookup from segments
                    _seg_map = {}
                    for _st, _sv, _sc in self._db_execute(
                            "SELECT DISTINCT title, video_id, channel "
                            "FROM segments WHERE video_id != ''").fetchall():
                        if _sv:
                            _seg_map[(_st, _sc)] = _sv
                    _backfilled = 0
                    for _vid_row_id, _vtitle, _vch in _null_ids:
                        _found_id = _seg_map.get((_vtitle, _vch))
                        if _found_id:
                            self._db_execute(
                                "UPDATE videos SET video_id=? WHERE id=?",
                                (_found_id, _vid_row_id))
                            _backfilled += 1
                    if _backfilled:
                        self._db_commit()
            except Exception:
                pass
            _total = 0
            try:
                row = self._db_execute("SELECT COUNT(*) FROM videos").fetchone()
                _total = row[0] if row else 0
            except Exception:
                pass
            def _done(n=count, t=_total):
                self._refresh_browse()
                try:
                    self._browse_scan_btn.config(state="normal")
                    self._browse_scan_status.config(text=f"Found {t:,} videos")
                    # Clear status after 5 seconds
                    self.after(5000, lambda: self._browse_scan_status.config(text=""))
                except Exception:
                    pass
            self.after(0, _done)

        threading.Thread(target=_worker, daemon=True).start()

    _VIDEOS_SCHEMA_VER = 5  # bump to force clear — COLLATE NOCASE on filepath

    def _ensure_videos_populated(self):
        """Clear stale data if schema version changed.

        The actual population happens in _scan_channel_disk_info() which runs
        at startup as part of the normal disk scan — no separate walk needed.
        """
        if not self._conn:
            return
        try:
            ver = 0
            try:
                row = self._db_execute(
                    "SELECT tx_status FROM videos WHERE filepath='__schema_ver__' LIMIT 1"
                ).fetchone()
                ver = int(row[0]) if row else 0
            except Exception:
                pass
            if ver < self._VIDEOS_SCHEMA_VER:
                # Schema changed — clear old data; startup disk scan will repopulate
                self._db_execute("DELETE FROM videos")
                self._db_execute(
                    "INSERT OR REPLACE INTO videos (title,channel,filepath,tx_status) "
                    "VALUES ('__ver__','__ver__','__schema_ver__',?)",
                    (str(self._VIDEOS_SCHEMA_VER),))
                self._db_commit()
        except Exception:
            pass

    def navigate_to_video(self, title, channel, filepath="", auto_play=False):
        """Navigate the browse tree to a specific video, expanding parents as needed."""
        if not self._loaded or not self._conn:
            return False
        self._show_section("browse")

        # Ensure video is in the DB; insert if missing
        if filepath:
            self.register_video(title, channel, filepath=filepath)

        # Refresh the tree so the video appears — this is async (background thread
        # + self.after callback), so schedule the actual navigation after a delay
        # to let the tree rebuild complete.
        self._refresh_browse()
        self.after(300, lambda: self._navigate_to_video_find(
            title, channel, filepath, auto_play, _attempt=0))
        return True  # optimistic — actual navigation happens async

    def _navigate_to_video_find(self, title, channel, filepath, auto_play, _attempt=0):
        """Retry-aware helper for navigate_to_video — finds and selects the video in the tree."""
        # Normalise filepath for comparison
        norm_fp = os.path.normpath(filepath).lower() if filepath else ""

        tree = self._browse_tree
        # Find the channel node — if direct match fails, look up the DB-stored
        # channel name by filepath (yt-dlp names can differ from config names)
        ch_iid = None
        for iid in tree.get_children():
            meta = self._browse_items.get(iid)
            if meta and meta.get("channel") == channel:
                ch_iid = iid
                break
        if not ch_iid and filepath:
            try:
                row = self._db_execute(
                    "SELECT channel FROM videos WHERE filepath=?",
                    (filepath,)).fetchone()
                if row and row[0] != channel:
                    channel = row[0]
                    for iid in tree.get_children():
                        meta = self._browse_items.get(iid)
                        if meta and meta.get("channel") == channel:
                            ch_iid = iid
                            break
            except Exception:
                pass
        if not ch_iid:
            # Tree may not be rebuilt yet — retry
            if _attempt < 5:
                self.after(500, lambda: self._navigate_to_video_find(
                    title, channel, filepath, auto_play, _attempt + 1))
            return

        # Expand the channel to load year nodes
        tree.focus(ch_iid)
        tree.item(ch_iid, open=True)
        self._on_browse_open()

        # Search through all descendant nodes — match by filepath first, then title
        def _find_video(parent):
            for child in tree.get_children(parent):
                meta = self._browse_items.get(child)
                if not meta:
                    continue
                if meta["type"] == "title":
                    # Prefer filepath match (reliable) over title match (can differ)
                    if norm_fp and meta.get("filepath"):
                        if os.path.normpath(meta["filepath"]).lower() == norm_fp:
                            return child
                    if meta.get("title") == title:
                        return child
                if meta["type"] in ("year", "month"):
                    tree.focus(child)
                    tree.item(child, open=True)
                    self._on_browse_open()
                    found = _find_video(child)
                    if found:
                        return found
                    # Collapse if video wasn't found under this node
                    tree.item(child, open=False)
            return None

        target = _find_video(ch_iid)
        if target:
            tree.selection_set(target)
            tree.see(target)
            tree.focus(target)
            self._on_browse_select()
            if auto_play:
                self.after(150, self._on_browse_play_video)
        elif _attempt < 5:
            # Video node may still be loading (async population) — retry
            self.after(500, lambda: self._navigate_to_video_find(
                title, channel, filepath, auto_play, _attempt + 1))

    # ── Cross-communication ───────────────────────────────────────────────────

    def prompt_reindex(self, channel_name=""):
        """Called (from worker thread) when a transcription job finishes."""
        # Update tx_status for transcribed videos in this channel.
        # Check both the segments DB AND transcript files on disk (covers
        # channels that have been transcribed but not yet indexed).
        if self._conn and channel_name:
            try:
                with self._db_lock:
                    pending = self._db_execute(
                        "SELECT id, filepath FROM videos "
                        "WHERE channel=? AND tx_status='pending' AND filepath IS NOT NULL",
                        (channel_name,)).fetchall()
                _to_update = []
                for vid_id, fp in pending:
                    vid_dir = os.path.dirname(fp)
                    # Check disk for transcript files in video's dir tree
                    found = False
                    _chk = vid_dir
                    for _ in range(3):
                        try:
                            for fn in os.listdir(_chk):
                                fn_l = fn.lower()
                                if (fn_l.endswith('.jsonl') or
                                        (fn_l.endswith('.txt') and 'transcript' in fn_l)):
                                    found = True
                                    break
                        except OSError:
                            pass
                        if found:
                            break
                        _p = os.path.dirname(_chk)
                        if _p == _chk:
                            break
                        _chk = _p
                    if found:
                        _to_update.append(vid_id)
                if _to_update:
                    with self._db_lock:
                        for _uid in _to_update:
                            self._db_execute(
                                "UPDATE videos SET tx_status='transcribed' WHERE id=?",
                                (_uid,))
                        self._db_commit()
            except Exception:
                pass
        def _on_main():
            if not self._loaded:
                self._pending_reindex = channel_name
                return
            self._maybe_offer_reindex(channel_name)
            self._refresh_browse()
        self.after(0, _on_main)

    def _maybe_offer_reindex(self, channel_name):
        name_str = f" for \"{channel_name}\"" if channel_name else ""
        # Custom dialog with 60-second auto-dismiss (defaults to "No")
        _result = {"ans": False}
        dlg = tk.Toplevel(self.winfo_toplevel())
        dlg.title("Update Transcription Index")
        dlg.configure(bg="#2d2d2d")
        dlg.resizable(False, False)
        dlg.grab_set()
        dlg.update_idletasks()
        _apply_dark_title_bar(dlg)
        _auto_job = [None]
        _countdown = [60]

        msg = tk.Label(dlg,
                       text=f"Transcription{name_str} is complete.\n\n"
                            "Update the transcription search index now?",
                       bg="#2d2d2d", fg="#cccccc", font=("Segoe UI", 10),
                       wraplength=320, justify="left", padx=16, pady=16)
        msg.pack()

        countdown_lbl = tk.Label(dlg, text="Auto-declining in 60s",
                                 bg="#2d2d2d", fg="#888888",
                                 font=("Segoe UI", 8))
        countdown_lbl.pack(pady=(0, 4))

        btn_frame = tk.Frame(dlg, bg="#2d2d2d")
        btn_frame.pack(pady=(0, 12))

        def _yes():
            _result["ans"] = True
            if _auto_job[0]:
                dlg.after_cancel(_auto_job[0])
            dlg.grab_release()
            dlg.destroy()

        def _no():
            _result["ans"] = False
            if _auto_job[0]:
                dlg.after_cancel(_auto_job[0])
            dlg.grab_release()
            dlg.destroy()

        def _tick():
            _countdown[0] -= 1
            if _countdown[0] <= 0:
                _no()
                return
            try:
                countdown_lbl.config(text=f"Auto-declining in {_countdown[0]}s")
            except Exception:
                pass
            _auto_job[0] = dlg.after(1000, _tick)

        tk.Button(btn_frame, text="Yes", command=_yes, width=8,
                  bg="#3a6a3a", fg="white", activebackground="#4a8a4a",
                  relief="flat", font=("Segoe UI", 9)).pack(side="left", padx=6)
        tk.Button(btn_frame, text="No", command=_no, width=8,
                  bg="#555555", fg="white", activebackground="#666666",
                  relief="flat", font=("Segoe UI", 9)).pack(side="left", padx=6)

        dlg.protocol("WM_DELETE_WINDOW", _no)
        _auto_job[0] = dlg.after(1000, _tick)

        # Center on parent
        dlg.update_idletasks()
        pw = self.winfo_toplevel()
        x = pw.winfo_x() + (pw.winfo_width() - dlg.winfo_width()) // 2
        y = pw.winfo_y() + (pw.winfo_height() - dlg.winfo_height()) // 2
        dlg.geometry(f"+{x}+{y}")

        self.wait_window(dlg)
        if _result["ans"]:
            self._show_section("index")
            self.after(150, self._start_index)

