    def _show_section(self, key):
        self._active_section = key
        frames = {
            "browse":    self._browse_frame,
            "search":    self._search_frame,
            "frequency": self._freq_frame,
            "bookmarks": self._bookmarks_frame,
            "index":     self._index_frame,
            "player":    self._player_frame,
        }
        for k, f in frames.items():
            if k == key:
                f.grid(row=0, column=0, sticky="nsew")
            else:
                f.grid_remove()
        for k, btn in self._nav_btns.items():
            btn.config(bg=self._TP_ACCENT if k == key else self._TP_SIDEBAR,
                       fg="white" if k == key else self._TP_FG)

        # Stop embedded VLC player when navigating away from it
        if key != "player" and self._player_active:
            self._player_stop_vlc()

        # Show un-indexed video warnings for search/frequency sections
        if key in ("search", "frequency"):
            self._update_index_warning(key)

        # Auto-populate frequency words from a recent search and plot automatically
        if key == "frequency":
            query = self._search_var.get().strip()
            if query and not self._freq_words_var.get().strip():
                self._freq_words_var.set(query)
                self.after(50, self._do_frequency)
        elif key == "bookmarks":
            self._refresh_bookmarks()
        elif key == "browse" and not self._browse_items:
            # Only refresh if the tree is empty (first visit) — don't
            # rebuild when returning from the player or other sections,
            # as that destroys the user's expansion state.
            self._refresh_browse()

    def _update_index_warning(self, section_key):
        """Show/hide warning about un-indexed videos in search/frequency sections."""
        def _check():
            if not self._conn:
                return
            try:
                with self._db_lock:
                    vid_total = self._db_execute(
                        "SELECT COUNT(*) FROM videos WHERE filepath != '__schema_ver__'"
                    ).fetchone()[0]
                    seg_vids = self._db_execute(
                        "SELECT COUNT(DISTINCT video_id) FROM segments WHERE video_id != ''"
                    ).fetchone()[0]
                unindexed = max(0, vid_total - seg_vids)
            except Exception:
                unindexed = 0
            def _update(n=unindexed):
                warn_lbl = (self._search_index_warn if section_key == "search"
                            else self._freq_index_warn)
                if n > 0:
                    warn_lbl.config(
                        text=f"  \u26a0  {n:,} videos on disk are not yet indexed "
                             f"\u2014 rebuild the index (Index tab) to include "
                             f"them in search results")
                    warn_lbl.pack(fill="x", side="top")
                    # Move to top of parent
                    siblings = warn_lbl.master.pack_slaves()
                    if siblings and siblings[0] != warn_lbl:
                        warn_lbl.pack_configure(before=siblings[0])
                else:
                    warn_lbl.pack_forget()
            self.after(0, _update)
        threading.Thread(target=_check, daemon=True).start()

    def _refresh_stats_label(self):
        if not self._conn:
            return
        def _query():
            try:
                with self._db_lock:
                    segs = self._db_execute("SELECT COUNT(*) FROM segments").fetchone()[0]
                    vids = self._db_execute("SELECT COUNT(DISTINCT video_id) FROM segments").fetchone()[0]
                    chs  = self._db_execute("SELECT COUNT(DISTINCT channel) FROM segments").fetchone()[0]
                text = f"{segs:,} segments\n{vids:,} videos\n{chs} channels"
                self.after(0, lambda: self._stats_label.config(text=text))
            except Exception:
                pass
        threading.Thread(target=_query, daemon=True).start()

