    _BROWSE_PLACEHOLDER = "__placeholder__"

    def _refresh_browse(self):
        """Populate the browse tree — lazy: only top-level channels at first."""
        if not self._conn:
            return
        def _query():
            try:
                channels = self._db_execute(
                    "SELECT DISTINCT channel FROM videos WHERE channel != '__ver__' ORDER BY channel COLLATE NOCASE"
                ).fetchall()
            except Exception:
                try:
                    channels = self._db_execute(
                        "SELECT DISTINCT channel FROM segments ORDER BY channel COLLATE NOCASE"
                    ).fetchall()
                except Exception:
                    return
            self.after(0, lambda: self._apply_browse_channels(channels))
        threading.Thread(target=_query, daemon=True).start()

    def _apply_browse_channels(self, channels):
        """Apply channel list to browse tree (must run on main thread)."""
        # Dismiss loading overlay only after the startup disk scan is done
        if self._browse_loading_overlay and self._disk_scan_complete:
            self._browse_loading_overlay.place_forget()
            self._browse_loading_overlay.destroy()
            self._browse_loading_overlay = None
        tree = self._browse_tree

        # Save expansion state before clearing — keyed by (type, channel, year, month)
        _open_keys = set()
        for iid, meta in self._browse_items.items():
            if tree.exists(iid) and tree.item(iid, "open"):
                _key = (meta.get("type"), meta.get("channel"),
                        meta.get("year"), meta.get("month"))
                _open_keys.add(_key)

        tree.delete(*tree.get_children())
        self._browse_items.clear()
        for (ch,) in channels:
            _was_open = ("channel", ch, None, None) in _open_keys
            ch_iid = tree.insert("", "end", text=f"\U0001F4C1  {ch}", open=_was_open)
            self._browse_items[ch_iid] = {"type": "channel", "channel": ch}
            # Dummy child so the expand arrow appears
            tree.insert(ch_iid, "end", text="", tags=(self._BROWSE_PLACEHOLDER,))
            # If channel was previously expanded, re-populate its children
            if _was_open:
                self._on_browse_open_for_iid(ch_iid)

    def _on_browse_open_for_iid(self, iid):
        """Populate children for a specific iid (used during expansion state restore)."""
        meta = self._browse_items.get(iid)
        if not meta:
            return
        children = self._browse_tree.get_children(iid)
        if (len(children) == 1
                and self._BROWSE_PLACEHOLDER in self._browse_tree.item(children[0], "tags")):
            self._browse_tree.delete(children[0])
            self._populate_browse_children(iid, meta)

    def _on_browse_open(self, event=None):
        """Lazily populate children when a browse tree node is expanded."""
        iid = self._browse_tree.focus()
        meta = self._browse_items.get(iid)
        if not meta:
            return
        children = self._browse_tree.get_children(iid)
        # Only populate if the single child is the dummy placeholder
        if (len(children) == 1
                and self._BROWSE_PLACEHOLDER in self._browse_tree.item(children[0], "tags")):
            self._browse_tree.delete(children[0])
            self._populate_browse_children(iid, meta)

    def _get_channel_org(self, ch_name):
        """Return (split_years, split_months) for a channel from config."""
        with config_lock:
            for ch in config.get("channels", []):
                if ch.get("name") == ch_name:
                    return ch.get("split_years", False), ch.get("split_months", False)
        return False, False

    def _populate_browse_children(self, iid, meta):
        """Load the next level of children for a browse tree node.
        DB queries run in a background thread to avoid freezing the UI."""
        tree = self._browse_tree
        if meta["type"] == "channel":
            ch = meta["channel"]
            split_years, split_months = self._get_channel_org(ch)
            if not split_years:
                self._populate_browse_titles(iid, ch, None, None)
                return
            # Show placeholder while loading
            _load_iid = tree.insert(iid, "end", text="  Loading...",
                                     tags=(self._BROWSE_PLACEHOLDER,))
            def _query_years():
                try:
                    years = self._db_execute(
                        "SELECT DISTINCT year FROM videos WHERE channel=? AND year IS NOT NULL "
                        "ORDER BY year", (ch,)).fetchall()
                except Exception:
                    years = []
                def _apply():
                    if not tree.exists(iid):
                        return
                    try:
                        tree.delete(_load_iid)
                    except Exception:
                        pass
                    if not years:
                        self._populate_browse_titles(iid, ch, None, None)
                        return
                    for (yr,) in years:
                        yr_iid = tree.insert(iid, "end", text=f"📅  {yr}", open=False)
                        self._browse_items[yr_iid] = {"type": "year", "channel": ch, "year": yr,
                                                       "split_months": split_months}
                        tree.insert(yr_iid, "end", text="", tags=(self._BROWSE_PLACEHOLDER,))
                self.after(0, _apply)
            threading.Thread(target=_query_years, daemon=True).start()

        elif meta["type"] == "year":
            ch, yr = meta["channel"], meta["year"]
            if not meta.get("split_months", False):
                self._populate_browse_titles(iid, ch, yr, None)
                return
            _load_iid = tree.insert(iid, "end", text="  Loading...",
                                     tags=(self._BROWSE_PLACEHOLDER,))
            def _query_months():
                try:
                    months = self._db_execute(
                        "SELECT DISTINCT month FROM videos WHERE channel=? AND year=? "
                        "AND month IS NOT NULL ORDER BY month", (ch, yr)).fetchall()
                except Exception:
                    months = []
                def _apply():
                    if not tree.exists(iid):
                        return
                    try:
                        tree.delete(_load_iid)
                    except Exception:
                        pass
                    if months and len(months) > 1:
                        for (mo,) in months:
                            mo_name = _TP_MONTH_NAMES[mo - 1].capitalize() if 1 <= mo <= 12 else str(mo)
                            mo_iid = tree.insert(iid, "end", text=f"📄  {mo_name}", open=False)
                            self._browse_items[mo_iid] = {
                                "type": "month", "channel": ch, "year": yr, "month": mo}
                            tree.insert(mo_iid, "end", text="", tags=(self._BROWSE_PLACEHOLDER,))
                    else:
                        self._populate_browse_titles(iid, ch, yr, None)
                self.after(0, _apply)
            threading.Thread(target=_query_months, daemon=True).start()

        elif meta["type"] == "month":
            self._populate_browse_titles(iid, meta["channel"], meta["year"], meta["month"])

    _BROWSE_MONTH_SEP = "__month_sep__"

    def _populate_browse_titles(self, parent_iid, channel, year, month):
        """Insert individual video title nodes under a parent browse node.
        Heavy work (DB queries + file stat calls) runs in a background thread;
        the resulting tree inserts are batched back onto the main thread."""
        # Show a temporary "Loading..." node while the worker runs
        _loading_iid = self._browse_tree.insert(
            parent_iid, "end", text="  Loading...",
            tags=(self._BROWSE_PLACEHOLDER,))

        def _worker():
            """Background thread: DB + filesystem work."""
            try:
                sql = ("SELECT DISTINCT title, filepath, video_id, tx_status, month "
                       "FROM videos WHERE channel=?")
                params = [channel]
                if year is not None:
                    sql += " AND year=?"
                    params.append(year)
                if month is not None:
                    sql += " AND month=?"
                    params.append(month)
                sql += " ORDER BY title"
                with self._db_lock:
                    rows = self._db_execute(sql, params).fetchall()
            except Exception:
                self.after(0, lambda: self._browse_tree.delete(_loading_iid))
                return

            # Backfill missing video_ids from segments table or JSONL files
            _has_null_ids = any(r[2] is None for r in rows)
            if _has_null_ids:
                _id_map = {}  # title -> video_id
                # Try segments table first
                try:
                    with self._db_lock:
                        for _st, _sv in self._db_execute(
                                "SELECT DISTINCT title, video_id FROM segments "
                                "WHERE channel=? AND video_id != ''",
                                (channel,)).fetchall():
                            if _sv:
                                _id_map[_st] = _sv
                except Exception:
                    pass
                # If segments had nothing, read the JSONL files on disk
                if not _id_map:
                    try:
                        # Find the channel folder from any filepath
                        _sample_fp = next((r[1] for r in rows if r[1]), None)
                        if _sample_fp:
                            _search_dirs = set()
                            _search_dirs.add(os.path.dirname(_sample_fp))
                            # Also check parent dirs (handles year/month subfolders)
                            _p = os.path.dirname(_sample_fp)
                            for _ in range(3):
                                _search_dirs.add(_p)
                                _pp = os.path.dirname(_p)
                                if _pp == _p:
                                    break
                                _p = _pp
                            for _sd in _search_dirs:
                                try:
                                    for _fn in os.listdir(_sd):
                                        if _fn.endswith('.jsonl') and _fn.startswith('.'):
                                            _jf = os.path.join(_sd, _fn)
                                            with open(_jf, 'r', encoding='utf-8', errors='replace') as _fh:
                                                for _jline in _fh:
                                                    _jline = _jline.strip()
                                                    if not _jline:
                                                        continue
                                                    try:
                                                        _jd = json.loads(_jline)
                                                        _jvid = _jd.get("video_id", "")
                                                        _jtitle = _jd.get("title", "")
                                                        if _jvid and _jtitle and _jtitle not in _id_map:
                                                            _id_map[_jtitle] = _jvid
                                                    except (json.JSONDecodeError, Exception):
                                                        continue
                                except (OSError, PermissionError):
                                    continue
                    except Exception:
                        pass
                if _id_map:
                    _new_rows = []
                    with self._db_lock:
                        for r in rows:
                            if r[2] is None and r[0] in _id_map:
                                _new_rows.append((r[0], r[1], _id_map[r[0]], r[3], r[4]))
                                try:
                                    self._db_execute(
                                        "UPDATE videos SET video_id=? "
                                        "WHERE title=? AND channel=? AND video_id IS NULL",
                                        (_id_map[r[0]], r[0], channel))
                                except Exception:
                                    pass
                            else:
                                _new_rows.append(r)
                        try:
                            self._db_commit()
                        except Exception:
                            pass
                    rows = _new_rows

            # ── Deduplicate ──────────────────────────────────────────
            # Multiple DB rows can exist for the same video: the disk scan
            # uses the *filename* as title while the download callback uses
            # the *YouTube title* (different punctuation/spacing).  Deduplicate
            # by normalised filepath (most reliable) then by fuzzy title.
            def _norm_fp(fp):
                return os.path.normcase(os.path.normpath(fp)) if fp else None
            def _norm_title(t):
                """Strip punctuation/whitespace differences for fuzzy matching."""
                return re.sub(r'[^a-z0-9]', '', t.lower()) if t else ""

            _deduped = {}  # norm_key -> best row
            for row in rows:
                # Primary key: normalized filepath
                _nfp = _norm_fp(row[1])
                _key = _nfp or ("title:" + _norm_title(row[0]))
                if _key not in _deduped:
                    _deduped[_key] = row
                else:
                    prev = _deduped[_key]
                    _prev_exists = prev[1] and os.path.isfile(prev[1])
                    _cur_exists = row[1] and os.path.isfile(row[1])
                    if _cur_exists and not _prev_exists:
                        _deduped[_key] = row
                    elif not _cur_exists and _prev_exists:
                        pass
                    elif row[2] and not prev[2]:
                        _deduped[_key] = row
            # Second pass: also catch fuzzy title dupes across different filepaths
            _by_ntitle = {}
            for _key, row in _deduped.items():
                _nt = _norm_title(row[0])
                if _nt in _by_ntitle:
                    prev = _by_ntitle[_nt]
                    _prev_exists = prev[1] and os.path.isfile(prev[1])
                    _cur_exists = row[1] and os.path.isfile(row[1])
                    if _cur_exists and not _prev_exists:
                        _by_ntitle[_nt] = row
                    elif row[2] and not prev[2]:
                        _by_ntitle[_nt] = row
                    # else keep prev
                else:
                    _by_ntitle[_nt] = row
            rows = list(_by_ntitle.values())

            # Sort by file mtime (upload date) instead of alphabetically
            # Also derive month from mtime for separator lines
            import datetime as _dt
            _rows_with_mtime = []
            for row in rows:
                fp = row[1]
                _mtime = 0.0
                _mtime_month = None
                if fp:
                    try:
                        _mtime = os.path.getmtime(fp)
                        _mtime_month = _dt.datetime.fromtimestamp(_mtime).month
                    except OSError:
                        pass
                _effective_month = row[4] if row[4] else _mtime_month
                _rows_with_mtime.append((*row, _mtime, _effective_month))
            _rows_with_mtime.sort(key=lambda r: r[5])  # sort by mtime

            _show_month_seps = (year is not None and month is None
                                and len(set(r[6] for r in _rows_with_mtime if r[6])) > 1)

            # Pre-fetch jsonl paths for transcribed videos in one batch query
            _transcribed_titles = [r[0] for r in _rows_with_mtime if r[3] == "transcribed"]
            _jsonl_map = {}
            if _transcribed_titles:
                try:
                    # Batch to stay within SQLite's 999-variable limit
                    _BATCH_SZ = 998  # reserve 1 slot for the channel param
                    with self._db_lock:
                        for _bi in range(0, len(_transcribed_titles), _BATCH_SZ):
                            _batch = _transcribed_titles[_bi:_bi + _BATCH_SZ]
                            placeholders = ",".join("?" * len(_batch))
                            _jrows = self._db_execute(
                                f"SELECT title, jsonl_path FROM segments "
                                f"WHERE title IN ({placeholders}) AND channel=? "
                                f"GROUP BY title",
                                _batch + [channel]).fetchall()
                            _jsonl_map.update({r[0]: r[1] for r in _jrows if r[1]})
                except Exception:
                    pass

            # Build the list of items to insert (pure data, no UI calls)
            items = []  # list of (type, text, meta_dict) or ("sep", text, None)
            _last_month = None
            for title, filepath, video_id, tx_status, _db_month, _mtime, _eff_month in _rows_with_mtime:
                if _show_month_seps and _eff_month and _eff_month != _last_month:
                    _mo_name = _TP_MONTH_NAMES[_eff_month - 1].capitalize() if 1 <= _eff_month <= 12 else ""
                    if _mo_name:
                        items.append(("sep", f"  ── {_mo_name} ──", None))
                    _last_month = _eff_month

                disp = title if len(title) <= 60 else title[:57] + "..."
                if tx_status == "pending":
                    disp = f"  {disp}  (not processed)"
                elif tx_status == "no_captions":
                    disp = f"  {disp}  (no captions)"
                elif tx_status == "error":
                    disp = f"  {disp}  (error)"
                else:
                    disp = f"  {disp}"

                _jsonl = _jsonl_map.get(title)
                items.append(("title", disp, {
                    "type": "title", "channel": channel, "title": title,
                    "jsonl_path": _jsonl, "filepath": filepath,
                    "video_id": video_id, "tx_status": tx_status or "pending"}))

            # Schedule the tree inserts on the main thread as one batch
            self.after(0, lambda: self._browse_insert_batch(parent_iid, _loading_iid, items))

        threading.Thread(target=_worker, daemon=True).start()

    def _browse_insert_batch(self, parent_iid, loading_iid, items):
        """Insert pre-computed browse items into the tree (runs on main thread)."""
        # Guard: parent may have been deleted by a tree refresh while we were loading
        if not self._browse_tree.exists(parent_iid):
            return
        try:
            self._browse_tree.delete(loading_iid)
        except Exception:
            pass

        # Configure separator tag
        self._browse_tree.tag_configure(
            self._BROWSE_MONTH_SEP,
            foreground="#555555", font=("Segoe UI", 8))

        for kind, text, meta_dict in items:
            if kind == "sep":
                sep_iid = self._browse_tree.insert(
                    parent_iid, "end", text=text,
                    tags=(self._BROWSE_MONTH_SEP,))
                self._browse_items[sep_iid] = {"type": "separator"}
            else:
                t_iid = self._browse_tree.insert(parent_iid, "end", text=text)
                self._browse_items[t_iid] = meta_dict

    def _deselect_browse_tree(self):
        """Clear the browse tree selection and reset the viewer to its initial state."""
        self._browse_tree.selection_set([])
        self._hide_grid()
        self._hide_browse_thumbnail()
        self._clear_browse_drawer()
        self._browse_viewer_title.config(text="Select a transcription to read")
        self._browse_viewer.config(state="normal")
        self._browse_viewer.delete("1.0", "end")
        self._browse_viewer.config(state="disabled")
        self._browse_path_label.config(text="")
        self._browse_play_btn.config(state="disabled")
        self._browse_actions_btn.config(state="disabled")

    def _on_browse_select(self, event=None):
        """When a title node is selected in the browse tree, show its transcription.
        Heavy I/O (file search, file read, DB queries) runs in a background thread."""
        sel = self._browse_tree.selection()
        if not sel:
            return
        meta = self._browse_items.get(sel[0])
        if not meta:
            return
        if meta["type"] in ("channel", "year", "month"):
            channel = meta["channel"]
            year = meta.get("year")
            month = meta.get("month")
            self._show_grid(channel, year, month)
            return
        if meta["type"] != "title":
            return
        # Switching from grid to title view
        self._hide_grid()
        title      = meta["title"]
        tx_status  = meta.get("tx_status", "pending")
        filepath   = meta.get("filepath")
        txt_path   = self._get_txt_path(meta["jsonl_path"]) if meta.get("jsonl_path") else None
        channel    = meta.get("channel", "")

        # Stamp a generation counter so stale threads don't clobber a newer selection
        if not hasattr(self, '_browse_select_gen'):
            self._browse_select_gen = 0
        self._browse_select_gen += 1
        _gen = self._browse_select_gen

        # Immediate lightweight UI updates (no I/O)
        self._browse_viewer_title.config(text=title)
        self._browse_path_label.config(
            text=f"{channel}  •  {txt_path or filepath or ''}")

        # Set initial metadata (txt_path may be updated by the worker thread)
        _vid_id = meta.get("video_id")
        self._browse_current_meta = {
            "title": title, "channel": channel,
            "txt_path": txt_path, "jsonl_path": meta.get("jsonl_path"),
            "video_id": _vid_id, "filepath": filepath,
            "tx_status": tx_status,
        }

        # Set actions dropdown menu labels and state based on tx_status
        _transcribe_lbl = "  Re-transcribe"
        if tx_status in ("pending", "no_captions", "error"):
            _transcribe_lbl = "  Transcribe"
        self._browse_actions_menu.entryconfig(0, label=_transcribe_lbl)
        _enable_actions = True
        if not _vid_id and tx_status not in ("pending", "no_captions", "error"):
            _enable_actions = False
            _check_title, _check_txt = title, txt_path
            def _check_video():
                found = bool(self._find_video_file(_check_title, _check_txt))
                if found:
                    self.after(0, lambda: self._browse_actions_btn.config(state="normal"))
            threading.Thread(target=_check_video, daemon=True).start()
        self._browse_actions_btn.config(state="normal" if _enable_actions else "disabled")

        # Enable play button — if we have a filepath from DB, trust it and enable
        # immediately; verify + probe resolution in background thread.
        self._browse_play_btn.config(state="disabled")
        _play_title, _play_txt, _play_fp = title, txt_path, filepath
        _play_channel = channel
        if _play_fp:
            self._browse_current_meta["_video_path"] = _play_fp
            self._browse_play_btn.config(state="normal")
        def _check_play():
            vp = None
            if _play_fp:
                vp = _play_fp if os.path.isfile(_play_fp) else None
            if not vp:
                vp = self._find_video_file(_play_title, _play_txt)
            if vp:
                _res_h = _ffprobe_height(vp)
                _res_str = f"{_res_h}p" if _res_h else None
                def _update(p=vp, rs=_res_str):
                    if self._browse_current_meta and self._browse_current_meta.get("title") == _play_title:
                        self._browse_current_meta["_video_path"] = p
                        self._browse_play_btn.config(state="normal")
                        if rs:
                            self._browse_current_meta["resolution"] = rs
                            self._browse_viewer_title.config(
                                text=f"{_play_title}  ({rs})")
                self.after(0, _update)
            elif _play_fp:
                def _disable():
                    if self._browse_current_meta and self._browse_current_meta.get("title") == _play_title:
                        self._browse_play_btn.config(state="disabled")
                self.after(0, _disable)
        threading.Thread(target=_check_play, daemon=True).start()

        # For untranscribed videos, show a status message instead of transcript (no I/O needed)
        if tx_status in ("pending", "no_captions", "error"):
            self._browse_viewer.config(state="normal")
            self._browse_viewer.delete("1.0", "end")
            self._browse_seg_map = []
            if tx_status == "pending":
                self._browse_viewer.insert("end",
                    "Transcription not yet processed\n\n", "header")
                self._browse_viewer.insert("end",
                    "This video has not been transcribed yet. Use the Transcribe "
                    "button above, or right-click the channel or folder in the "
                    "tree to transcribe multiple videos at once.")
            elif tx_status == "no_captions":
                self._browse_viewer.insert("end",
                    "No captions available\n\n", "header")
                self._browse_viewer.insert("end",
                    "This video has no detectable speech or captions. "
                    "It may be a music-only video or have no spoken content.")
            elif tx_status == "error":
                self._browse_viewer.insert("end",
                    "Transcription error\n\n", "header")
                self._browse_viewer.insert("end",
                    "An error occurred during transcription. "
                    "Try re-transcribing the video.")
            self._browse_viewer.config(state="disabled")
            self._browse_viewer.yview_moveto(0)
            return

        # Show "Loading..." in the viewer while the worker fetches data
        self._browse_viewer.config(state="normal")
        self._browse_viewer.delete("1.0", "end")
        self._browse_seg_map = []
        self._browse_viewer.insert("end", "Loading...", "header")
        self._browse_viewer.config(state="disabled")

        # Heavy I/O runs in background: txt_path fallback search, DB query, file read
        def _load_transcript():
            nonlocal txt_path
            # Fallback: if no jsonl_path, search for .txt transcript files near the video
            if not txt_path and filepath:
                _search_dir = os.path.dirname(filepath)
                for _ in range(3):
                    try:
                        for fn in os.listdir(_search_dir):
                            if fn.lower().endswith('.txt') and 'transcript' in fn.lower():
                                txt_path = os.path.join(_search_dir, fn)
                                break
                    except OSError:
                        pass
                    if txt_path:
                        break
                    _p = os.path.dirname(_search_dir)
                    if _p == _search_dir:
                        break
                    _search_dir = _p

            # Look up video_id if not already known
            found_vid_id = _vid_id
            if not found_vid_id and self._conn and title:
                try:
                    _row = self._db_execute(
                        "SELECT video_id FROM segments WHERE title=? AND video_id!='' LIMIT 1",
                        (title,)).fetchone()
                    if _row:
                        found_vid_id = _row[0]
                except Exception:
                    pass

            # Fetch segments from DB for the position map
            db_rows = []
            if self._conn:
                try:
                    db_rows = self._db_execute(
                        "SELECT video_id, start_time, end_time, text, words "
                        "FROM segments WHERE title=? ORDER BY start_time",
                        (title,)).fetchall()
                except Exception:
                    db_rows = []

            # Fallback: if segments DB is empty, read from JSONL files on disk
            if not db_rows and txt_path:
                try:
                    _jsonl_path = _get_jsonl_path(txt_path)
                    if os.path.isfile(_jsonl_path):
                        with open(_jsonl_path, 'r', encoding='utf-8', errors='replace') as _jfh:
                            for _jl in _jfh:
                                _jl = _jl.strip()
                                if not _jl:
                                    continue
                                try:
                                    _jd = json.loads(_jl)
                                    if _jd.get("title") == title:
                                        db_rows.append((
                                            _jd.get("video_id", ""),
                                            _jd.get("start", 0.0),
                                            _jd.get("end", 0.0),
                                            _jd.get("text", ""),
                                            json.dumps(_jd["words"]) if "words" in _jd else ""
                                        ))
                                except (json.JSONDecodeError, Exception):
                                    continue
                except Exception:
                    pass

            # Read the .txt file (can be 100KB+)
            section = self._get_txt_section(txt_path, title) if txt_path else None

            # Build the segment position map (CPU work, fine in thread)
            body = ""
            header_line = ""
            header_char_len = 0
            seg_map = []
            if section:
                lines = section.split('\n', 1)
                header_line = lines[0]
                body = lines[1].strip() if len(lines) > 1 else ""
                header_char_len = len(header_line) + 2
            elif db_rows:
                body = " ".join(row[3] for row in db_rows)

            if db_rows and body:
                total_seg_chars = sum(len(row[3]) for row in db_rows)
                if total_seg_chars > 0:
                    _off = header_char_len
                    body_chars = len(body)
                    pending = []
                    for video_id, start, end, seg_text, words_json in db_rows:
                        proportion = len(seg_text) / total_seg_chars
                        cs = _off
                        _off += int(proportion * body_chars)
                        pending.append((cs, (video_id, start, end, seg_text, words_json or "")))
                    for i, (cs, data) in enumerate(pending):
                        ce = (pending[i + 1][0] if i + 1 < len(pending)
                              else header_char_len + body_chars)
                        seg_map.append((cs, ce, data))

            # Schedule UI update on main thread
            self.after(0, lambda: self._browse_apply_transcript(
                _gen, title, channel, txt_path, found_vid_id, filepath, tx_status,
                meta.get("jsonl_path"), section, header_line, body, db_rows, seg_map))

        threading.Thread(target=_load_transcript, daemon=True).start()

    def _browse_apply_transcript(self, gen, title, channel, txt_path, vid_id,
                                  filepath, tx_status, jsonl_path,
                                  section, header_line, body, db_rows, seg_map):
        """Apply loaded transcript data to the viewer (runs on main thread).
        Skips if a newer selection has been made (stale generation)."""
        if gen != self._browse_select_gen:
            return  # a newer selection superseded this one

        # Update metadata with resolved values from the worker thread,
        # preserving any _video_path already set by the _check_play thread
        _existing_vp = (self._browse_current_meta or {}).get("_video_path")
        _existing_res = (self._browse_current_meta or {}).get("resolution")
        self._browse_current_meta = {
            "title": title, "channel": channel,
            "txt_path": txt_path, "jsonl_path": jsonl_path,
            "video_id": vid_id, "filepath": filepath,
            "tx_status": tx_status,
        }
        if _existing_vp:
            self._browse_current_meta["_video_path"] = _existing_vp
        if _existing_res:
            self._browse_current_meta["resolution"] = _existing_res
        self._browse_path_label.config(
            text=f"{channel}  •  {txt_path or filepath or ''}")

        self._browse_viewer.config(state="normal")
        self._browse_viewer.delete("1.0", "end")
        self._browse_seg_map = []

        if not section and not db_rows:
            self._browse_viewer.insert("end",
                "(No .txt file found for this transcription.)\n\n", "header")
            if txt_path:
                self._browse_viewer.insert("end", f"Expected:\n{txt_path}")
            self._browse_viewer.config(state="disabled")
            self._browse_viewer.yview_moveto(0)
            return

        if section:
            self._browse_viewer.insert("end", header_line + "\n\n", "header")
            self._browse_viewer.insert("end", body)
        else:
            self._browse_viewer.insert("end", body)

        self._browse_seg_map = seg_map

        self._browse_viewer.config(state="disabled")
        self._browse_viewer.yview_moveto(0)

        # Load metadata (thumbnail + drawer) in background if available
        self._hide_browse_thumbnail()
        self._clear_browse_drawer()
        if vid_id and channel:
            threading.Thread(
                target=self._try_load_metadata_for_video,
                args=(vid_id, title, channel), daemon=True).start()

    def _try_load_metadata_for_video(self, video_id, title, channel):
        """Background: resolve channel config and load metadata for a video."""
        ch_cfg = None
        with config_lock:
            for ch in config.get("channels", []):
                if ch.get("name", "") == channel:
                    ch_cfg = ch
                    break
        if not ch_cfg:
            return
        folder = ch_cfg.get("folder_override") or sanitize_folder(channel)
        with config_lock:
            base = config.get("output_dir", "")
        folder_path = os.path.join(base, folder) if base else folder
        sy = ch_cfg.get("split_years", False)
        sm = ch_cfg.get("split_months", False)

        # Determine year/month for this video from the DB
        v_year, v_month = None, None
        if self._conn:
            try:
                row = self._db_execute(
                    "SELECT year, month FROM videos WHERE video_id=? LIMIT 1",
                    (video_id,)).fetchone()
                if row:
                    v_year, v_month = row
            except Exception:
                pass

        self._load_browse_metadata(
            video_id, title, channel, folder_path,
            sy, sm, v_year, v_month)

    def _on_browse_play_video(self):
        """Play Video button — open the current video in the embedded VLC player."""
        meta = self._browse_current_meta
        if not meta:
            return
        video_path = meta.get("_video_path")
        if not video_path:
            return
        title = meta.get("title", "")
        tx_status = meta.get("tx_status")
        # Fetch DB rows for transcript sync
        db_rows = None
        if self._conn and title:
            try:
                db_rows = self._db_execute(
                    "SELECT video_id, start_time, end_time, text, words "
                    "FROM segments WHERE title=? ORDER BY start_time",
                    (title,)).fetchall()
            except Exception:
                db_rows = None
        self._open_vlc(video_path, 0, title=title, db_rows=db_rows,
                       tx_status=tx_status)

    def _browse_find(self):
        """Highlight all occurrences of the find term in the browse viewer."""
        query = self._browse_find_var.get().strip()
        self._browse_viewer.tag_remove("find_hit", "1.0", "end")
        if not query:
            return
        idx = "1.0"
        first = None
        while True:
            pos = self._browse_viewer.search(query, idx, stopindex="end", nocase=True)
            if not pos:
                break
            end_pos = f"{pos}+{len(query)}c"
            self._browse_viewer.tag_add("find_hit", pos, end_pos)
            if first is None:
                first = pos
            idx = end_pos
        if first:
            self._browse_viewer.see(first)

    def _browse_delete_file(self, video_path, title, channel):
        """Delete a video file from the Browse tab context menu."""
        if not messagebox.askyesno(
                "Confirm Delete",
                f"Permanently delete this file from disk?\n\n"
                f"{os.path.basename(video_path)}\n\nThis cannot be undone.",
                icon="warning"):
            return
        try:
            fsize = _fmt_size(str(os.path.getsize(video_path)))
            size_str = f"  ({fsize})" if fsize else ""
            os.remove(video_path)
            log(f"  🗑 Deleted: {video_path}{size_str}\n", "green")
        except OSError as e:
            log(f"ERROR: Could not delete {video_path}: {e}\n", "red")
            return
        # Also remove from recent_downloads if present
        with config_lock:
            recent = config.get("recent_downloads", [])
            for i, entry in enumerate(recent):
                if entry.get("filepath", "") == video_path:
                    recent.pop(i)
                    break
            config["recent_downloads"] = recent
        save_config(config)
        refresh_recent_list()
        self._refresh_browse()
        # Also remove from grid view if visible
        if self._grid_visible and self._grid_videos:
            self._grid_videos = [v for v in self._grid_videos if v.get("filepath") != video_path]
            # Invalidate cache for this scope so it doesn't restore the deleted video
            if self._grid_scope and self._grid_scope in self._grid_cache:
                self._grid_cache[self._grid_scope]["videos"] = self._grid_videos
            self._grid_build_cards(reset=True, _keep_photos=True)

    def _on_browse_tree_rightclick(self, event):
        """Right-click on browse tree → context menu for titles or folders."""
        item = self._browse_tree.identify_row(event.y)
        if not item:
            return
        self._browse_tree.selection_set(item)
        meta = self._browse_items.get(item)
        if not meta:
            return

        menu = tk.Menu(self, tearoff=0, bg=self._TP_BG3, fg=self._TP_FG,
                       activebackground=self._TP_ACCENT, activeforeground="white",
                       disabledforeground="#666b75", relief="flat", bd=1)

        if meta["type"] == "title":
            # Title-level context menu
            title      = meta["title"]
            channel    = meta.get("channel", "")
            jsonl_path = meta.get("jsonl_path")
            filepath   = meta.get("filepath")
            txt_path   = self._get_txt_path(jsonl_path) if jsonl_path else None
            video_path = None
            if filepath and os.path.isfile(filepath):
                video_path = filepath
            else:
                video_path = self._find_video_file(title, txt_path)
            # If still not found, search channel folder by fuzzy title match
            if not video_path:
                video_path = self._find_video_in_channel(title, channel)

            _db_rows = None
            video_id = meta.get("video_id")
            if self._conn and title:
                try:
                    _db_rows = self._db_execute(
                        "SELECT video_id, start_time, end_time, text, words "
                        "FROM segments WHERE title=? ORDER BY start_time",
                        (title,)).fetchall()
                    if _db_rows and not video_id:
                        video_id = _db_rows[0][0]
                except Exception:
                    pass

            if video_path:
                menu.add_command(label="  ▶  Play Video",
                                 command=lambda: self._open_vlc(
                                     video_path, 0, title=title,
                                     db_rows=_db_rows))
            else:
                menu.add_command(label="  ▶  Play Video",
                                 state="disabled")

            if video_id:
                url = f"https://www.youtube.com/watch?v={video_id}"
                menu.add_command(label="  Open Video — YouTube",
                                 command=lambda u=url: _webbrowser.open(u))
            else:
                menu.add_command(label="  Open Video — YouTube",
                                 state="disabled")

            if video_id:
                menu.add_command(label="  Redownload...",
                                 command=lambda vi=video_id, t=title, vp=video_path, ch=channel:
                                     self._on_browse_redownload(vi, t, vp, ch))
            else:
                menu.add_command(label="  Redownload...", state="disabled")

            # Always show "Show in Explorer" — falls back to channel folder
            def _show_explorer(vp=video_path, t=title, ch=channel):
                _target = vp
                if _target and not os.path.isfile(_target):
                    _target = self._find_video_in_channel(t, ch)
                _ch_dir = self._get_channel_dir(ch) if not (_target and os.path.isfile(_target)) else None
                _show_in_explorer(_target, fallback_dir=_ch_dir)
            menu.add_command(label="  Show in Explorer",
                             command=_show_explorer)
            if video_path:
                menu.add_separator()
                menu.add_command(label="  Delete File",
                                 command=lambda vp=video_path, t=title, ch=channel:
                                     self._browse_delete_file(vp, t, ch))

        elif meta["type"] in ("channel", "year", "month"):
            # Folder-level context menu — Transcribe / Re-transcribe options
            channel = meta["channel"]
            year    = meta.get("year")
            month   = meta.get("month")

            # Count pending videos in scope
            _pending = 0
            try:
                sql = "SELECT COUNT(*) FROM videos WHERE channel=? AND tx_status='pending'"
                params = [channel]
                if year is not None:
                    sql += " AND year=?"
                    params.append(year)
                if month is not None:
                    sql += " AND month=?"
                    params.append(month)
                row = self._db_execute(sql, params).fetchone()
                _pending = row[0] if row else 0
            except Exception:
                pass

            scope_label = channel
            if year is not None:
                scope_label += f" / {year}"
            if month is not None and 1 <= (month or 0) <= 12:
                scope_label += f" / {_TP_MONTH_NAMES[month - 1].capitalize()}"

            if _pending > 0:
                menu.add_command(
                    label=f"  Transcribe untranscribed ({_pending})",
                    command=lambda: self._browse_transcribe_folder(
                        channel, year, month, retranscribe=False))
            else:
                menu.add_command(
                    label="  Transcribe untranscribed (0)",
                    state="disabled")
            menu.add_command(
                label="  Re-transcribe all",
                command=lambda: self._browse_transcribe_folder(
                    channel, year, month, retranscribe=True))

            menu.add_separator()
            menu.add_command(
                label="  Redownload at...",
                command=lambda ch=channel, y=year, m=month:
                    self._browse_redownload_folder(ch, y, m))
            menu.add_separator()
            menu.add_command(
                label="  Download Metadata",
                command=lambda ch=channel, y=year, m=month:
                    self._browse_download_metadata(ch, y, m))

        try:
            menu.tk_popup(event.x_root, event.y_root)
        finally:
            menu.grab_release()

    def _browse_transcribe_folder(self, channel, year=None, month=None,
                                  retranscribe=False):
        """Queue a transcription job for a channel/year/month folder from the browse tree."""
        # Find the channel in config to get url and folder info
        ch_cfg = None
        with config_lock:
            for ch in config.get("channels", []):
                if ch.get("name", "") == channel:
                    ch_cfg = ch
                    break
        if not ch_cfg:
            messagebox.showwarning("Channel not found",
                f"Could not find channel \"{channel}\" in your saved channels.\n"
                "You may need to add it in Settings first.")
            return

        ch_name = ch_cfg["name"]
        ch_url  = ch_cfg.get("url", "")
        folder  = ch_cfg.get("folder_override") or sanitize_folder(ch_name)
        with config_lock:
            base = config.get("output_dir", "")
        folder_path = os.path.join(base, folder) if base else folder
        sy = ch_cfg.get("split_years", False)
        sm = ch_cfg.get("split_months", False)

        _add_to_gpu_queue({
            "type": "transcribe",
            "ch_name": ch_name,
            "ch_url": ch_url,
            "folder": folder_path,
            "split_years": sy,
            "split_months": sm,
            "combined": not sy,
            "retranscribe": retranscribe,
        })

    def _browse_redownload_folder(self, channel, year=None, month=None):
        """Right-click → Redownload at... for a channel/year/month folder."""
        ch_cfg = None
        with config_lock:
            for ch in config.get("channels", []):
                if ch.get("name", "") == channel:
                    ch_cfg = ch
                    break
        if not ch_cfg:
            messagebox.showwarning("Channel not found",
                f"Could not find channel \"{channel}\" in your saved channels.\n"
                "You may need to add it in Settings first.")
            return

        ch_name = ch_cfg["name"]
        ch_url  = ch_cfg.get("url", "")
        folder  = ch_cfg.get("folder_override") or sanitize_folder(ch_name)
        with config_lock:
            base = config.get("output_dir", "")
        folder_path = os.path.join(base, folder) if base else folder

        # For year/month scoped redownloads, point to the subfolder
        if year is not None:
            folder_path = os.path.join(folder_path, str(year))
        if month is not None and 1 <= (month or 0) <= 12:
            folder_path = os.path.join(folder_path, f"{month:02d}")

        scope_label = ch_name
        if year is not None:
            scope_label += f" / {year}"
        if month is not None and 1 <= (month or 0) <= 12:
            scope_label += f" / {_TP_MONTH_NAMES[month - 1].capitalize()}"

        resolution = self._show_resolution_dialog(f"Redownload: {scope_label}")
        if not resolution:
            return

        _add_to_redownload_queue(ch_name, ch_url, folder_path, resolution)

    # ── Metadata download ─────────────────────────────────────────────────

    def _get_metadata_jsonl_path(self, ch_name, folder_path, split_years,
                                  split_months, year=None, month=None):
        """Build the hidden .Metadata.jsonl path matching transcript naming."""
        if not split_years:
            fname = f".{ch_name} Metadata.jsonl"
            return os.path.join(folder_path, fname), folder_path
        if split_years and split_months and year and month:
            month_num = int(month) if isinstance(month, str) and month.isdigit() else month
            month_name = MONTH_NAMES.get(month_num, f"{month_num:02d} Unknown").split(" ", 1)[1]
            yr_short = str(year)[-2:]
            subfolder = os.path.join(folder_path, str(year),
                                     MONTH_NAMES.get(month_num, f"{month_num:02d} Unknown"))
            fname = f".{ch_name} {month_name} {yr_short} Metadata.jsonl"
            return os.path.join(subfolder, fname), subfolder
        if split_years and year:
            subfolder = os.path.join(folder_path, str(year))
            fname = f".{ch_name} {year} Metadata.jsonl"
            return os.path.join(subfolder, fname), subfolder
        fname = f".{ch_name} Metadata.jsonl"
        return os.path.join(folder_path, fname), folder_path

    def _read_metadata_jsonl(self, jsonl_path):
        """Read existing metadata JSONL, return dict of video_id -> data."""
        existing = {}
        if not os.path.isfile(jsonl_path):
            return existing
        try:
            # Python can read hidden files on Windows — no need to unhide
            with open(jsonl_path, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        entry = json.loads(line)
                        vid = entry.get("video_id", "")
                        if vid:
                            existing[vid] = entry
                    except json.JSONDecodeError:
                        continue
        except Exception:
            pass
        return existing

    def _write_metadata_jsonl(self, jsonl_path, entries_dict):
        """Write all metadata entries to a JSONL file and hide it."""
        os.makedirs(os.path.dirname(jsonl_path), exist_ok=True)
        # Unhide first if exists
        norm = os.path.normpath(jsonl_path)
        if os.name == "nt" and os.path.isfile(norm):
            try:
                ctypes.windll.kernel32.SetFileAttributesW(norm, 0x80)
            except Exception:
                pass
        with open(jsonl_path, "w", encoding="utf-8") as f:
            for vid, data in entries_dict.items():
                f.write(json.dumps(data, ensure_ascii=False) + "\n")
        _hide_file_win(jsonl_path)

    def _browse_download_metadata(self, channel, year=None, month=None):
        """Add a metadata download task to the Sync-Tasks queue."""
        ch_cfg = None
        with config_lock:
            for ch in config.get("channels", []):
                if ch.get("name", "") == channel:
                    ch_cfg = ch
                    break
        if not ch_cfg:
            messagebox.showwarning("Channel not found",
                f"Could not find channel \"{channel}\" in your saved channels.\n"
                "You may need to add it in Settings first.")
            return

        ch_name = ch_cfg["name"]
        folder = ch_cfg.get("folder_override") or sanitize_folder(ch_name)
        with config_lock:
            base = config.get("output_dir", "")
        folder_path = os.path.join(base, folder) if base else folder
        sy = ch_cfg.get("split_years", False)
        sm = ch_cfg.get("split_months", False)

        ch_url = ch_cfg.get("url", "")
        scope_label = ch_name
        if year is not None:
            scope_label += f" / {year}"
        if month is not None and 1 <= (month or 0) <= 12:
            scope_label += f" / {_TP_MONTH_NAMES[month - 1].capitalize()}"

        # Check if metadata already exists for this scope
        refresh = False
        has_existing = False
        try:
            if sy and year is None:
                # Split channel at root — check if any per-year metadata exists
                for _yd in os.listdir(folder_path):
                    _yp = os.path.join(folder_path, _yd)
                    if os.path.isdir(_yp) and _yd.isdigit():
                        _mp, _ = self._get_metadata_jsonl_path(
                            ch_name, folder_path, sy, sm, year=int(_yd), month=None)
                        if os.path.isfile(_mp):
                            has_existing = True
                            break
            else:
                meta_path, _ = self._get_metadata_jsonl_path(
                    ch_name, folder_path, sy, sm, year=year, month=month)
                existing = self._read_metadata_jsonl(meta_path)
                has_existing = bool(existing)
        except Exception:
            pass

        if has_existing:
            # Show choice dialog: check for new, refresh counts, or cancel
            choice = self._metadata_choice_dialog(scope_label)
            if choice == "cancel":
                return
            refresh = (choice == "refresh")

        _add_to_metadata_queue(ch_name, ch_url, folder_path, sy, sm, year, month, scope_label, refresh=refresh)

        # For full-channel downloads, offer to enable auto-metadata for future syncs
        if year is None and month is None and not ch_cfg.get("auto_metadata", False):
            if messagebox.askyesno("Auto-download metadata",
                    f"Automatically download metadata for new {ch_name} videos in the future?"):
                with config_lock:
                    for ch in config.get("channels", []):
                        if ch.get("name", "") == ch_name:
                            ch["auto_metadata"] = True
                            break
                    save_config(config)

    def _metadata_choice_dialog(self, scope_label):
        """Show a 3-button dialog: Check for New / Refresh Counts / Cancel.
        Returns 'new', 'refresh', or 'cancel'."""
        _result = ["cancel"]

        _dlg = tk.Toplevel(root)
        _dlg.title("Metadata Already Downloaded")
        _dlg.configure(bg=C_BG)
        _dlg.resizable(False, False)
        _dlg.transient(root)
        _dlg.grab_set()
        _dlg.update_idletasks()
        _apply_dark_title_bar(_dlg)

        def _dismiss(val):
            _result[0] = val
            try:
                _dlg.destroy()
            except Exception:
                pass

        _dlg.protocol("WM_DELETE_WINDOW", lambda: _dismiss("cancel"))

        tk.Label(_dlg, text=f"{scope_label} already has metadata.\nWhat would you like to do?",
                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10), justify="left",
                 wraplength=420).pack(fill="x", padx=20, pady=(14, 4))

        btn_row = tk.Frame(_dlg, bg=C_BG)
        btn_row.pack(padx=20, pady=(6, 14))
        tk.Button(btn_row, text="Check for New", bg="#3a6a3a", fg="#cccccc",
                  relief="flat", font=("Segoe UI", 9, "bold"),
                  cursor="hand2", command=lambda: _dismiss("new"),
                  width=14).pack(side="left", padx=(0, 8))
        tk.Button(btn_row, text="Refresh Counts", bg="#4a5a6a", fg="#cccccc",
                  relief="flat", font=("Segoe UI", 9, "bold"),
                  cursor="hand2", command=lambda: _dismiss("refresh"),
                  width=14).pack(side="left", padx=(0, 8))
        tk.Button(btn_row, text="Cancel", bg=C_BTN, fg=C_TEXT,
                  relief="flat", font=("Segoe UI", 9),
                  cursor="hand2", command=lambda: _dismiss("cancel"),
                  width=10).pack(side="left")

        _dlg.update_idletasks()
        _rx = root.winfo_rootx() + root.winfo_width() // 2
        _ry = root.winfo_rooty() + root.winfo_height() // 2
        _dlg.geometry(f"+{_rx - _dlg.winfo_reqwidth() // 2}+{_ry - _dlg.winfo_reqheight() // 2}")

        root.wait_window(_dlg)
        return _result[0]

    def _fetch_video_metadata(self, video_id, title):
        """Fetch metadata for a single video via yt-dlp --dump-json.
        Returns a dict with video_id, description, view_count, comments, etc."""
        cmd = [
            "yt-dlp", "--dump-json", "--no-download", "--no-warnings",
            "--ignore-errors", "--skip-download",
            "--cookies-from-browser", "firefox",
            "--write-comments",
            "--extractor-args", "youtube:comment_sort=top;max_comments=50,50,0,0",
            f"https://www.youtube.com/watch?v={video_id}"
        ]

        proc = None
        try:
            proc = spawn_yt_dlp(cmd)
            if not proc:
                return None
            stdout, _ = proc.communicate(timeout=120)
            cleanup_process(proc)

            if proc.returncode != 0:
                return None

            data = json.loads(stdout)

            # Extract top 50 comments (no replies)
            comments = []
            for c in (data.get("comments") or [])[:50]:
                comments.append({
                    "author": c.get("author", ""),
                    "text": c.get("text", ""),
                    "likes": c.get("like_count", 0),
                    "time": c.get("timestamp") or c.get("time_text", ""),
                })

            return {
                "video_id": video_id,
                "title": data.get("title", title),
                "description": data.get("description", ""),
                "view_count": data.get("view_count", 0),
                "like_count": data.get("like_count", 0),
                "comment_count": data.get("comment_count", 0),
                "upload_date": data.get("upload_date", ""),
                "duration": data.get("duration", 0),
                "thumbnail_url": data.get("thumbnail", ""),
                "comments": comments,
                "fetched_at": datetime.now().isoformat(),
            }
        except subprocess.TimeoutExpired:
            if proc:
                proc.kill()
                cleanup_process(proc)
            log(f"Metadata: timeout fetching {title[:40]}\n", "red")
            return None
        except (json.JSONDecodeError, Exception) as e:
            if proc:
                cleanup_process(proc)
            return None

    def _download_thumbnail(self, url, thumb_dir, title, video_id):
        """Download a thumbnail image to the .Thumbnails folder."""
        # Build filename from title + video_id (matching video file naming)
        safe_title = re.sub(r'[<>:"/\\|?*]', '_', title)[:100]
        fname = f"{safe_title} [{video_id}].jpg"
        fpath = os.path.join(thumb_dir, fname)
        if os.path.isfile(fpath):
            return  # already downloaded
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=30) as resp:
                img_data = resp.read()
            with open(fpath, "wb") as f:
                f.write(img_data)
        except Exception:
            pass  # non-fatal — skip thumbnail on failure

    # ── Thumbnail display ─────────────────────────────────────────────────

    def _show_browse_thumbnail(self, video_id, title, channel, folder_path,
                                split_years, split_months, year, month):
        """Show the thumbnail for the selected video, if available."""
        self._hide_browse_thumbnail()

        # Find the .Thumbnails folder for this video's location
        _, subfolder = self._get_metadata_jsonl_path(
            channel, folder_path, split_years, split_months,
            year=year, month=month)
        thumb_dir = os.path.join(subfolder, ".Thumbnails")

        # Look for thumbnail file matching this video ID
        thumb_path = None
        if os.path.isdir(thumb_dir):
            for fn in os.listdir(thumb_dir):
                if video_id and f"[{video_id}]" in fn and fn.lower().endswith(
                        (".jpg", ".jpeg", ".png", ".webp")):
                    thumb_path = os.path.join(thumb_dir, fn)
                    break

        if not thumb_path or not os.path.isfile(thumb_path):
            return

        try:
            from PIL import Image, ImageTk
        except ImportError:
            return  # Pillow not available

        vf_width = self._browse_viewer.winfo_width()
        if vf_width < 100:
            vf_width = 600
        def _load_bg():
            try:
                img = Image.open(thumb_path)
                aspect = img.width / img.height
                target_w = min(vf_width - 24, img.width)
                target_h = int(target_w / aspect)
                if target_h > 280:
                    target_h = 280
                    target_w = int(target_h * aspect)
                img = img.resize((target_w, target_h), Image.LANCZOS)
                photo = ImageTk.PhotoImage(img)
                def _apply():
                    try:
                        self._browse_thumb_photo = photo
                        self._browse_thumb_label.config(image=photo)
                        self._browse_thumb_frame.config(height=target_h + 12)
                        self._browse_thumb_visible = True
                    except Exception:
                        pass
                self.after(0, _apply)
            except Exception:
                pass

        threading.Thread(target=_load_bg, daemon=True).start()

    def _hide_browse_thumbnail(self):
        """Hide the thumbnail display."""
        if self._browse_thumb_visible:
            self._browse_thumb_frame.config(height=0)
            self._browse_thumb_label.config(image="")
            self._browse_thumb_photo = None
            self._browse_thumb_visible = False

    # ── Pull-up metadata drawer ───────────────────────────────────────────

    def _toggle_browse_drawer(self):
        """Toggle the metadata drawer open/closed."""
        if self._browse_drawer_visible:
            self._hide_browse_drawer()
        else:
            self._show_browse_drawer()

    def _show_browse_drawer(self):
        """Expand the metadata drawer overlay from the bottom."""
        if self._browse_drawer_visible:
            return
        self._browse_drawer_visible = True
        self._browse_drawer_toggle_lbl.config(text="▼  Metadata")
        # Overlay bottom 60% of the viewer area
        self._browse_drawer_frame.place_forget()
        self._browse_drawer_frame.place(
            relx=0, rely=1.0, relwidth=1.0, relheight=0.6,
            anchor="sw")
        self._browse_drawer_frame.lift()

    def _hide_browse_drawer(self):
        """Collapse the metadata drawer back to just the handle bar."""
        if not self._browse_drawer_visible:
            return
        self._browse_drawer_visible = False
        self._browse_drawer_toggle_lbl.config(text="▲  Metadata")
        # Collapse to just the handle bar — place_forget first to clear relheight
        self._browse_drawer_frame.place_forget()
        self._browse_drawer_frame.place(
            relx=0, rely=1.0, relwidth=1.0, height=28,
            anchor="sw")
        self._browse_drawer_frame.lift()

    def _load_browse_metadata(self, video_id, title, channel, folder_path,
                               split_years, split_months, year, month):
        """Load metadata for the selected video into the drawer (if available).
        Also triggers thumbnail display. Runs from background thread context."""
        if not video_id:
            self.after(0, self._clear_browse_drawer)
            return

        meta_path, subfolder = self._get_metadata_jsonl_path(
            channel, folder_path, split_years, split_months,
            year=year, month=month)

        existing = self._read_metadata_jsonl(meta_path)
        entry = existing.get(video_id)

        if not entry:
            self.after(0, self._clear_browse_drawer)
            # Still attempt to show thumbnail even without metadata
            self._show_browse_thumbnail(
                video_id, title, channel, folder_path,
                split_years, split_months, year, month)
            return

        # Store the current metadata entry for player drawer access
        self._current_metadata_entry = entry

        def _apply():
            # Populate browse drawer
            self._populate_drawer_text(self._browse_drawer_text, entry)
            self._browse_drawer_toggle_lbl.config(
                text="▲  Metadata" if not self._browse_drawer_visible
                else "▼  Metadata")

            # Show the drawer handle at the bottom (collapsed)
            if not self._browse_drawer_visible:
                self._browse_drawer_frame.place_forget()
                self._browse_drawer_frame.place(
                    relx=0, rely=1.0, relwidth=1.0, height=28,
                    anchor="sw")
                self._browse_drawer_frame.lift()

            # Also populate player drawer so it's ready when the user plays
            self._populate_drawer_text(self._player_drawer_text, entry)
            self._player_drawer_toggle_lbl.config(
                text="▲  Metadata" if not self._player_drawer_visible
                else "▼  Metadata")
            # Show collapsed handle in player too
            if not self._player_drawer_visible:
                self._player_drawer_frame.place_forget()
                self._player_drawer_frame.place(
                    relx=0, rely=1.0, relwidth=1.0, height=28,
                    anchor="sw")
                self._player_drawer_frame.lift()

        self.after(0, _apply)

        # Show thumbnail
        self._show_browse_thumbnail(
            video_id, title, channel, folder_path,
            split_years, split_months, year, month)

    def _clear_browse_drawer(self):
        """Clear and hide the drawer when no metadata is available."""
        self._current_metadata_entry = None
        self._browse_drawer_frame.place_forget()
        self._browse_drawer_visible = False
        self._browse_drawer_text.config(state="normal")
        self._browse_drawer_text.delete("1.0", "end")
        self._browse_drawer_text.config(state="disabled")
        self._hide_browse_thumbnail()
        # Also clear player drawer
        self._player_drawer_frame.place_forget()
        self._player_drawer_visible = False
        self._player_drawer_text.config(state="normal")
        self._player_drawer_text.delete("1.0", "end")
        self._player_drawer_text.config(state="disabled")

    # ── Player metadata drawer ────────────────────────────────────────────

    def _toggle_player_drawer(self):
        if self._player_drawer_visible:
            self._hide_player_drawer()
        else:
            self._show_player_drawer()

    def _show_player_drawer(self):
        if self._player_drawer_visible:
            return
        self._player_drawer_visible = True
        self._player_drawer_toggle_lbl.config(text="▼  Metadata")
        self._player_drawer_frame.place_forget()
        self._player_drawer_frame.place(
            relx=0, rely=1.0, relwidth=1.0, relheight=0.6,
            anchor="sw")
        self._player_drawer_frame.lift()

    def _hide_player_drawer(self):
        if not self._player_drawer_visible:
            return
        self._player_drawer_visible = False
        self._player_drawer_toggle_lbl.config(text="▲  Metadata")
        self._player_drawer_frame.place_forget()
        self._player_drawer_frame.place(
            relx=0, rely=1.0, relwidth=1.0, height=28,
            anchor="sw")
        self._player_drawer_frame.lift()

    def _populate_drawer_text(self, text_widget, entry):
        """Fill a drawer text widget with metadata content."""
        text_widget.config(state="normal")
        text_widget.delete("1.0", "end")
        views = entry.get("view_count", 0)
        likes = entry.get("like_count", 0)
        views_str = f"{views:,}" if views else "N/A"
        likes_str = f"{likes:,}" if likes else "N/A"
        text_widget.insert("end", "Views: ", "meta_label")
        text_widget.insert("end", f"{views_str}    ")
        text_widget.insert("end", "Likes: ", "meta_label")
        text_widget.insert("end", f"{likes_str}\n\n")
        desc = entry.get("description", "").strip()
        if desc:
            text_widget.insert("end", "Description\n", "meta_label")
            text_widget.insert("end", desc + "\n\n")
        comments = entry.get("comments", [])
        if comments:
            text_widget.insert("end", f"Top Comments ({len(comments)})\n\n", "meta_label")
            for c in comments:
                author = c.get("author", "Unknown")
                text_c = c.get("text", "")
                clikes = c.get("likes", 0)
                text_widget.insert("end", f"{author}", "comment_author")
                if clikes:
                    text_widget.insert("end", f"  ({clikes:,} likes)", "comment_likes")
                text_widget.insert("end", f"\n{text_c}\n\n")
        text_widget.config(state="disabled")
        text_widget.yview_moveto(0)

    # ── Video grid view ────────────────────────────────────────────────────

    def _show_grid(self, channel, year=None, month=None):
        """Show the video grid for a folder scope. Hides the transcript viewer."""
        _new_scope = (channel, year, month)
        # Skip reload if already showing this exact scope
        if self._grid_visible and self._grid_scope == _new_scope and self._grid_videos:
            return
        # Save current grid's photos to cache before switching
        if self._grid_scope and self._grid_videos and self._grid_scope in self._grid_cache:
            self._grid_cache[self._grid_scope]["photos"].update(self._grid_photos)
        self._grid_scope = _new_scope
        # Bump generation counter to discard stale background results
        if not hasattr(self, '_grid_gen'):
            self._grid_gen = 0
        self._grid_gen += 1
        _gen = self._grid_gen
        # Swap: hide transcript container + viewer header, show grid
        self._transcript_container.pack_forget()
        self._browse_viewer_header.pack_forget()
        self._browse_back_btn.pack_forget()
        if not self._grid_visible:
            self._grid_frame.pack(fill="both", expand=True)
            self._grid_visible = True
        # Build clickable breadcrumb navigation
        self._grid_update_breadcrumb(channel, year, month)
        self._browse_path_label.config(text="")
        self._browse_play_btn.config(state="disabled")
        self._browse_actions_btn.config(state="disabled")
        # Check cache — instant restore if we've loaded this scope before
        cached = self._grid_cache.get(_new_scope)
        if cached:
            self._grid_cache.move_to_end(_new_scope)  # LRU: mark as recently used
            self._grid_videos = cached["videos"]
            self._grid_photos = dict(cached["photos"])  # copy so we don't mutate cache
            has_meta = cached.get("has_metadata", False)
            self._update_meta_banner(has_meta, channel, year, month)
            self._grid_loading_frame.place_forget()
            if not self._grid_canvas_frame.winfo_ismapped():
                self._grid_canvas_frame.pack(fill="both", expand=True)
            self._grid_build_cards(reset=True, _keep_photos=True)
            return
        # No cache — show loading overlay on top of canvas (canvas keeps its size)
        self._grid_canvas.delete("all")
        self._grid_cards.clear()
        self._grid_photos.clear()
        self._grid_videos = []
        self._grid_bg_rects.clear()
        self._grid_thumb_items.clear()
        self._grid_meta_banner.pack_forget()
        if not self._grid_canvas_frame.winfo_ismapped():
            self._grid_canvas_frame.pack(fill="both", expand=True)
        self._grid_loading_lbl.config(text=f"Loading {channel}...")
        self._grid_loading_progress.config(text="Querying database...")
        self._grid_loading_frame.place(relx=0, rely=0, relwidth=1, relheight=1)
        self._grid_loading_frame.lift()  # ensure overlay is on top of canvas
        # Load videos in background
        threading.Thread(target=self._grid_load_videos,
                         args=(channel, year, month, _gen), daemon=True).start()

    def _hide_grid(self):
        """Hide the video grid and restore the transcript viewer."""
        if not self._grid_visible:
            return
        # Remember the scope so the back button can return to it
        self._grid_return_scope = self._grid_scope
        self._grid_frame.pack_forget()
        self._grid_visible = False
        # Restore viewer header (must be packed before vf to appear at top)
        self._browse_viewer_header.pack(fill="x", before=self._browse_viewer_body)
        self._browse_back_btn.pack(side="left", padx=(6, 0), before=self._browse_viewer_title)
        self._transcript_container.pack(fill="both", expand=True)

    def _grid_load_videos(self, channel, year, month, gen=0):
        """Background: query videos and metadata for the grid."""
        if not self._conn:
            return
        if gen != self._grid_gen:
            return  # stale request
        sql = "SELECT title, filepath, video_id, tx_status FROM videos WHERE channel=?"
        params = [channel]
        if year is not None:
            sql += " AND year=?"
            params.append(year)
        if month is not None:
            sql += " AND month=?"
            params.append(month)
        try:
            with self._db_lock:
                rows = self._db_execute(sql, params).fetchall()
        except Exception:
            return
        if gen != self._grid_gen:
            return

        # Build video dicts
        self.after(0, lambda: self._grid_loading_progress.config(
            text=f"Found {len(rows)} videos — loading metadata..."))
        import datetime as _dt
        videos = []
        for title, filepath, video_id, tx_status in rows:
            videos.append({
                "title": title, "filepath": filepath,
                "video_id": video_id, "tx_status": tx_status,
                "mtime": 0.0, "date_str": "",
            })

        # Load metadata if available
        ch_cfg = None
        with config_lock:
            for ch in config.get("channels", []):
                if ch.get("name", "") == channel:
                    ch_cfg = ch
                    break
        metadata = {}
        has_metadata = False
        thumb_dir = None
        if ch_cfg:
            folder = ch_cfg.get("folder_override") or sanitize_folder(channel)
            with config_lock:
                base = config.get("output_dir", "")
            folder_path = os.path.join(base, folder) if base else folder
            sy = ch_cfg.get("split_years", False)
            sm = ch_cfg.get("split_months", False)
            # When viewing at channel root with split_years, merge metadata
            # from ALL per-year (and per-month) JSONL files so sorting works
            if sy and year is None:
                try:
                    for _yd in os.listdir(folder_path):
                        _yp = os.path.join(folder_path, _yd)
                        if os.path.isdir(_yp) and _yd.isdigit():
                            _yr = int(_yd)
                            if sm:
                                # Scan month subfolders for per-month metadata
                                try:
                                    for _md in os.listdir(_yp):
                                        _mp = os.path.join(_yp, _md)
                                        if os.path.isdir(_mp):
                                            # Extract month number from folder name
                                            _mn = _md.split(" ", 1)[0]
                                            if _mn.isdigit():
                                                _mpath, _ = self._get_metadata_jsonl_path(
                                                    channel, folder_path, sy, sm,
                                                    year=_yr, month=int(_mn))
                                                metadata.update(self._read_metadata_jsonl(_mpath))
                                except OSError:
                                    pass
                            else:
                                _mpath, _ = self._get_metadata_jsonl_path(
                                    channel, folder_path, sy, sm, year=_yr, month=None)
                                metadata.update(self._read_metadata_jsonl(_mpath))
                except OSError:
                    pass
                has_metadata = bool(metadata)
                subfolder = folder_path
            else:
                meta_path, subfolder = self._get_metadata_jsonl_path(
                    channel, folder_path, sy, sm, year=year, month=month)
                metadata = self._read_metadata_jsonl(meta_path)
                has_metadata = bool(metadata)
            thumb_dir = os.path.join(subfolder, ".Thumbnails")
            if not os.path.isdir(thumb_dir):
                thumb_dir = None

        if gen != self._grid_gen:
            return

        # Build title→video_id reverse map from metadata so videos without ID
        # in their filename can still be matched to metadata and thumbnails
        _meta_title_to_id = {}
        if metadata:
            for _vid, _mdata in metadata.items():
                _mt = _mdata.get("title", "")
                if _mt and _vid:
                    _meta_title_to_id[_mt] = _vid
        # Fill in missing video_ids from metadata title matches
        for v in videos:
            if not v["video_id"] and v["title"] in _meta_title_to_id:
                v["video_id"] = _meta_title_to_id[v["title"]]

        # Fallback: resolve remaining missing video_ids from segments table
        # (handles renamed videos where metadata title no longer matches filename)
        _missing_id = [v for v in videos if not v["video_id"]]
        if _missing_id:
            _seg_id_map = {}
            try:
                for _st, _sv in self._db_execute(
                        "SELECT DISTINCT title, video_id FROM segments "
                        "WHERE channel=? AND video_id != ''",
                        (channel,)).fetchall():
                    if _sv:
                        _seg_id_map[_st] = _sv
            except Exception:
                pass
            if _seg_id_map:
                for v in _missing_id:
                    _sid = _seg_id_map.get(v["title"])
                    if _sid:
                        v["video_id"] = _sid

        # Enrich videos with metadata
        for v in videos:
            m = metadata.get(v["video_id"]) if v["video_id"] else None
            v["view_count"] = m.get("view_count", 0) if m else 0
            v["like_count"] = m.get("like_count", 0) if m else 0
            v["duration"] = m.get("duration", 0) if m else 0
            v["upload_date"] = m.get("upload_date", "") if m else ""
            if m and m.get("upload_date"):
                try:
                    _ud = m["upload_date"]
                    v["date_str"] = f"{_TP_MONTH_NAMES[int(_ud[4:6]) - 1].capitalize()} {int(_ud[6:8]):02d}, {_ud[:4]}" if len(_ud) == 8 else ""
                except Exception:
                    v["date_str"] = ""

        # Fetch mtimes for all videos missing metadata dates (needed for sorting)
        for v in videos:
            if not v["date_str"] and v["filepath"]:
                try:
                    mt = os.path.getmtime(v["filepath"])
                    v["mtime"] = mt
                    v["date_str"] = _dt.datetime.fromtimestamp(mt).strftime("%b %d, %Y")
                except OSError:
                    pass

        # Deduplicate: if multiple videos share the same video_id, keep the first
        _seen_vids = set()
        _deduped = []
        for v in videos:
            vid = v["video_id"]
            if vid:
                if vid in _seen_vids:
                    continue
                _seen_vids.add(vid)
            _deduped.append(v)
        videos = _deduped

        self.after(0, lambda: self._grid_loading_progress.config(
            text=f"Scanning thumbnails..."))
        # Sort: prefer metadata upload_date, fall back to mtime
        def _sort_key(v):
            if v["upload_date"]:
                return v["upload_date"]
            if v["mtime"]:
                return _dt.datetime.fromtimestamp(v["mtime"]).strftime("%Y%m%d")
            return "00000000"
        videos.sort(key=_sort_key, reverse=True)

        # Find thumbnail paths — scan .Thumbnails folders.
        # For split channels, thumbnails live in per-year and/or per-month
        # subfolders, not necessarily in the root .Thumbnails.
        _thumb_files = {}      # video_id -> path
        _thumb_by_title = {}   # normalized title -> path (fallback for videos without ID in filename)
        import unicodedata as _ucd
        def _norm_title(t):
            """Normalize a title for fuzzy matching: NFKC (fullwidth→ASCII), sanitize, strip dots."""
            t = _ucd.normalize('NFKC', t)
            t = re.sub(r'[<>:"/\\|?*]', '_', t)
            return t.rstrip('. ').lower()
        def _scan_thumb_dir(td):
            if td and os.path.isdir(td):
                try:
                    for fn in os.listdir(td):
                        _b = fn.rfind("[")
                        _e = fn.rfind("]")
                        if _b >= 0 and _e > _b:
                            _fpath = os.path.join(td, fn)
                            _thumb_files[fn[_b + 1:_e]] = _fpath
                            # Also index by normalized title for fallback matching
                            _title_part = fn[:_b].rstrip()
                            if _title_part:
                                _thumb_by_title[_norm_title(_title_part)] = _fpath
                except OSError:
                    pass
        if thumb_dir:
            _scan_thumb_dir(thumb_dir)
        # If viewing at channel root with split_years, scan ALL year/month .Thumbnails
        if ch_cfg and ch_cfg.get("split_years", False) and not year:
            try:
                for _yd in os.listdir(folder_path):
                    _yp = os.path.join(folder_path, _yd)
                    if os.path.isdir(_yp) and _yd.isdigit():
                        _scan_thumb_dir(os.path.join(_yp, ".Thumbnails"))
                        # Also scan month subfolders
                        if ch_cfg.get("split_months", False):
                            try:
                                for _md in os.listdir(_yp):
                                    _mp = os.path.join(_yp, _md)
                                    if os.path.isdir(_mp):
                                        _scan_thumb_dir(os.path.join(_mp, ".Thumbnails"))
                            except OSError:
                                pass
            except OSError:
                pass
        # If viewing a specific year with split_months, also scan month .Thumbnails
        elif ch_cfg and ch_cfg.get("split_months", False) and year and not month:
            try:
                year_path = os.path.join(folder_path, str(year)) if ch_cfg.get("split_years", False) else folder_path
                for _md in os.listdir(year_path):
                    _mp = os.path.join(year_path, _md)
                    if os.path.isdir(_mp):
                        _scan_thumb_dir(os.path.join(_mp, ".Thumbnails"))
            except OSError:
                pass
        if gen != self._grid_gen:
            return
        for v in videos:
            if v["video_id"]:
                v["thumb_path"] = _thumb_files.get(v["video_id"])
            if not v.get("thumb_path"):
                # Fallback: match by normalized title (handles fullwidth chars, trailing dots, etc.)
                v["thumb_path"] = _thumb_by_title.get(_norm_title(v["title"][:100]))

        self._grid_videos = videos
        self.after(0, lambda: self._grid_render(has_metadata, channel, year, month, gen))

    def _grid_render(self, has_metadata, channel, year, month, gen=0):
        """Render the video grid on the main thread."""
        # Check scope hasn't changed while loading
        if gen and gen != self._grid_gen:
            return
        if self._grid_scope != (channel, year, month):
            return

        # Show/hide metadata banner
        self._update_meta_banner(has_metadata, channel, year, month)

        # Clear old canvas items
        self._grid_canvas.delete("all")
        self._grid_bg_rects.clear()
        self._grid_thumb_items.clear()
        self._grid_photos.clear()

        if not self._grid_videos:
            self._grid_loading_frame.place_forget()
            # Draw "No videos found" as canvas text
            self._grid_canvas.create_text(
                self._grid_canvas.winfo_width() // 2, 60,
                text="No videos found", fill=self._TP_DIM,
                font=("Segoe UI", 11))
            return

        # Cache this scope's data for instant restore later (LRU eviction at max size)
        _scope = (channel, year, month)
        self._grid_cache[_scope] = {
            "videos": self._grid_videos,
            "photos": {},  # will be populated as thumbnails load
            "has_metadata": has_metadata,
        }
        # Evict oldest cached scopes when over limit (frees PhotoImage memory)
        while len(self._grid_cache) > self._GRID_CACHE_MAX:
            self._grid_cache.popitem(last=False)
        # Update loading progress then build.
        # Block resize handler during initial build to prevent double-build.
        self._grid_loading_progress.config(
            text=f"Building grid — {len(self._grid_videos)} videos...")
        self._grid_suppress_resize = True
        self.update_idletasks()  # force geometry settle so canvas has real dimensions
        self._grid_build_cards()
        # Re-enable resize after a short delay (let any pending Configure events drain)
        self.after(500, self._grid_enable_resize)

    _GRID_MAX_CARDS = 500  # max cards per load batch (scroll loads more)

    def _grid_build_cards(self, reset=True, _keep_photos=False):
        """Build video cards as canvas-native items for tear-free scrolling.
        No embedded Frame widgets — everything is drawn directly on the canvas."""
        if reset:
            # Bump a build-specific generation to discard in-flight thumbnail loads
            _build_gen = getattr(self, '_grid_build_gen', 0) + 1
            self._grid_build_gen = _build_gen
            self._grid_canvas.delete("all")
            self._grid_bg_rects.clear()
            self._grid_thumb_items.clear()
            self._grid_hover_idx = -1
            if not _keep_photos:
                self._grid_photos.clear()
            self._grid_loaded_count = 0

        canvas_w = self._grid_canvas.winfo_width()
        if canvas_w < 50:
            canvas_w = 600
        self._grid_last_width = canvas_w

        pad = 8
        min_card = 200
        cols = max(1, (canvas_w - pad) // (min_card + pad))
        card_w = (canvas_w - pad * (cols + 1)) // cols
        if card_w < 150:
            card_w = 150
        thumb_h = int(card_w * 9 / 16)
        info_h = 52  # title + stats area height
        card_h = thumb_h + info_h
        row_h = card_h + pad
        self._grid_cols = cols
        self._grid_layout = {
            "cols": cols, "card_w": card_w, "pad": pad,
            "thumb_h": thumb_h, "card_h": card_h, "row_h": row_h,
        }

        try:
            from PIL import Image, ImageTk
            _has_pil = True
        except ImportError:
            _has_pil = False

        total = len(self._grid_videos)
        start = self._grid_loaded_count
        end = min(start + self._GRID_MAX_CARDS, total)
        if start >= end:
            return

        # Fill mtimes/date_str for this batch
        import datetime as _dt
        for v in self._grid_videos[start:end]:
            if not v["date_str"] and v["filepath"]:
                try:
                    mt = os.path.getmtime(v["filepath"])
                    v["mtime"] = mt
                    v["date_str"] = _dt.datetime.fromtimestamp(mt).strftime("%b %d, %Y")
                except OSError:
                    pass

        # Remove old "load more" indicator before appending
        self._grid_canvas.delete("load_more")

        _thumb_jobs = []
        for i in range(start, end):
            v = self._grid_videos[i]
            row = i // cols
            col = i % cols
            x = pad + col * (card_w + pad)
            y = pad + row * row_h

            # Card background rectangle
            bg_id = self._grid_canvas.create_rectangle(
                x, y, x + card_w, y + card_h,
                fill=self._TP_BG2, outline="", tags=("card",))
            self._grid_bg_rects[i] = bg_id

            # Thumbnail dark background
            self._grid_canvas.create_rectangle(
                x, y, x + card_w, y + thumb_h,
                fill="#0a0b0d", outline="", tags=("card",))

            # Thumbnail image — use cached photo or placeholder emoji
            _cached = self._grid_photos.get(v["title"]) if v["thumb_path"] else None
            _need_load = True
            if _cached:
                # Check if cached photo matches current card dimensions
                try:
                    if _cached.width() == card_w and _cached.height() == thumb_h:
                        _need_load = False
                except Exception:
                    _cached = None
            if _cached and not _need_load:
                img_id = self._grid_canvas.create_image(
                    x + card_w // 2, y + thumb_h // 2,
                    image=_cached, tags=("card",))
            else:
                img_id = self._grid_canvas.create_text(
                    x + card_w // 2, y + thumb_h // 2,
                    text="\U0001f3ac", fill="#333", font=("Segoe UI", 20),
                    tags=("card",))
                if v.get("thumb_path") and _has_pil:
                    _thumb_jobs.append((v["thumb_path"], i,
                                        x + card_w // 2, y + thumb_h // 2,
                                        card_w, thumb_h, v["title"]))
            self._grid_thumb_items[i] = img_id

            # Duration overlay
            if v["duration"]:
                _dur_m, _dur_s = divmod(int(v["duration"]), 60)
                _dur_h2, _dur_m = divmod(_dur_m, 60)
                _dur_str = f"{_dur_h2}:{_dur_m:02d}:{_dur_s:02d}" if _dur_h2 else f"{_dur_m}:{_dur_s:02d}"
                dur_text = f" {_dur_str} "
                bg_w = len(dur_text) * 5 + 6
                bg_hh = 15
                dx = x + card_w - 4
                dy = y + thumb_h - 4
                self._grid_canvas.create_rectangle(
                    dx - bg_w, dy - bg_hh, dx, dy,
                    fill="#000000", outline="", tags=("card",))
                self._grid_canvas.create_text(
                    dx - 3, dy - 2, text=dur_text,
                    fill="#ffffff", font=("Segoe UI", 7, "bold"),
                    anchor="se", tags=("card",))

            # Title text
            disp_title = v["title"]
            if len(disp_title) > 55:
                disp_title = disp_title[:52] + "..."
            self._grid_canvas.create_text(
                x + 6, y + thumb_h + 6,
                text=disp_title, fill=self._TP_FG,
                font=("Segoe UI", 8, "bold"),
                anchor="nw", width=card_w - 12,
                tags=("card",))

            # Stats text (views + date)
            stats_parts = []
            if v["view_count"]:
                vc = v["view_count"]
                if vc >= 1_000_000:
                    stats_parts.append(f"{vc / 1_000_000:.1f}M views")
                elif vc >= 1_000:
                    stats_parts.append(f"{vc / 1_000:.1f}K views")
                else:
                    stats_parts.append(f"{vc:,} views")
            if v["date_str"]:
                stats_parts.append(v["date_str"])
            if stats_parts:
                self._grid_canvas.create_text(
                    x + 6, y + thumb_h + 28,
                    text="  \u2022  ".join(stats_parts),
                    fill=self._TP_DIM, font=("Segoe UI", 7),
                    anchor="nw", tags=("card",))

        self._grid_loaded_count = end

        # Set scroll region
        total_rows = (end + cols - 1) // cols
        total_h = total_rows * row_h + pad

        # Show "load more" indicator if there are remaining videos
        if end < total:
            remaining = total - end
            self._grid_canvas.create_text(
                canvas_w // 2, total_h + 20,
                text=f"\u2193  {remaining} more videos \u2014 scroll to load  \u2193",
                fill=self._TP_DIM, font=("Segoe UI", 9),
                tags=("load_more",))
            total_h += 50

        self._grid_canvas.configure(scrollregion=(0, 0, canvas_w, total_h))

        if reset:
            self._grid_canvas.yview_moveto(0)

        # Reveal grid — hide loading overlay after a short delay so most
        # thumbnails finish loading before the user sees the grid.
        if _thumb_jobs and _has_pil:
            self._grid_load_thumbnails_canvas(_thumb_jobs)
            self.after(1800, lambda: self._grid_loading_frame.place_forget())
        else:
            self._grid_loading_frame.place_forget()

    def _grid_load_thumbnails_canvas(self, thumb_jobs):
        """Load thumbnail images via thread pool and replace canvas items."""
        from PIL import Image, ImageTk
        _scope = self._grid_scope
        _bgen = self._grid_build_gen  # build-specific gen to detect rebuilds

        def _load_one(path, idx, cx, cy, w, h, title_key):
            if getattr(self, '_grid_build_gen', 0) != _bgen:
                return
            try:
                img = Image.open(path)
                if hasattr(img, 'draft') and img.format == 'JPEG':
                    img.draft('RGB', (w, h))
                img = img.resize((w, h), Image.BILINEAR)
                # Pass PIL image to main thread — PhotoImage MUST be created on main thread
                def _apply(_img=img):
                    if getattr(self, '_grid_build_gen', 0) != _bgen:
                        return
                    try:
                        photo = ImageTk.PhotoImage(_img)
                        old_id = self._grid_thumb_items.get(idx)
                        if old_id:
                            self._grid_canvas.delete(old_id)
                        new_id = self._grid_canvas.create_image(
                            cx, cy, image=photo, tags=("card",))
                        self._grid_thumb_items[idx] = new_id
                        self._grid_photos[title_key] = photo
                        if _scope in self._grid_cache:
                            self._grid_cache[_scope]["photos"][title_key] = photo
                    except Exception:
                        pass
                self.after(0, _apply)
            except Exception:
                pass

        for job in thumb_jobs:
            self._thumb_pool.submit(_load_one, *job)

    def _grid_on_motion(self, event):
        """Hover highlight: calculate which card the mouse is over from coordinates."""
        if not self._grid_visible or not self._grid_layout:
            return
        idx = self._grid_idx_from_event(event)
        old = self._grid_hover_idx
        if idx == old:
            return
        # Unhighlight old card
        if old >= 0 and old in self._grid_bg_rects:
            try:
                self._grid_canvas.itemconfig(self._grid_bg_rects[old], fill=self._TP_BG2)
            except Exception:
                pass
        # Highlight new card
        if idx >= 0 and idx in self._grid_bg_rects:
            try:
                self._grid_canvas.itemconfig(self._grid_bg_rects[idx], fill="#252830")
            except Exception:
                pass
            self._grid_canvas.config(cursor="hand2")
        else:
            self._grid_canvas.config(cursor="")
        self._grid_hover_idx = idx

    def _grid_on_click(self, event):
        """Click: navigate to the clicked video card."""
        if not self._grid_visible or not self._grid_layout:
            return
        idx = self._grid_idx_from_event(event)
        if idx >= 0:
            self._grid_navigate_to_video(self._grid_videos[idx]["title"])

    def _grid_on_leave(self, event):
        """Clear hover highlight when mouse leaves canvas."""
        if self._grid_hover_idx >= 0 and self._grid_hover_idx in self._grid_bg_rects:
            try:
                self._grid_canvas.itemconfig(
                    self._grid_bg_rects[self._grid_hover_idx], fill=self._TP_BG2)
            except Exception:
                pass
        self._grid_hover_idx = -1
        self._grid_canvas.config(cursor="")

    def _grid_idx_from_event(self, event):
        """Return the card index under the mouse, or -1 if none."""
        L = self._grid_layout
        if not L:
            return -1
        x = self._grid_canvas.canvasx(event.x)
        y = self._grid_canvas.canvasy(event.y)
        col = int((x - L["pad"]) / (L["card_w"] + L["pad"]))
        row = int((y - L["pad"]) / L["row_h"])
        if col < 0 or col >= L["cols"]:
            return -1
        idx = row * L["cols"] + col
        if idx < 0 or idx >= self._grid_loaded_count:
            return -1
        cx = L["pad"] + col * (L["card_w"] + L["pad"])
        cy = L["pad"] + row * L["row_h"]
        if not (cx <= x <= cx + L["card_w"] and cy <= y <= cy + L["card_h"]):
            return -1
        return idx

    def _grid_update_breadcrumb(self, channel, year=None, month=None):
        """Build clickable breadcrumb: Channel > Year > Month. Each segment
        is clickable to navigate to that scope level's grid view."""
        for w in self._grid_breadcrumb_frame.winfo_children():
            w.destroy()
        _bg = self._TP_BG3
        _fg = self._TP_FG
        _dim = self._TP_DIM
        _font_link = ("Segoe UI", 10, "bold underline")
        _font_current = ("Segoe UI", 10, "bold")
        _font_sep = ("Segoe UI", 10)
        # Channel segment — clickable if viewing a year/month
        if year is not None or month is not None:
            ch_lbl = tk.Label(self._grid_breadcrumb_frame, text=channel, bg=_bg,
                              fg=self._TP_ACCENT, font=_font_link, cursor="hand2")
            ch_lbl.pack(side="left")
            ch_lbl.bind("<Button-1>", lambda e, c=channel: self._show_grid(c))
        else:
            tk.Label(self._grid_breadcrumb_frame, text=channel, bg=_bg,
                     fg=_fg, font=_font_current).pack(side="left")
        if year is not None:
            tk.Label(self._grid_breadcrumb_frame, text="  /  ", bg=_bg,
                     fg=_dim, font=_font_sep).pack(side="left")
            if month is not None:
                yr_lbl = tk.Label(self._grid_breadcrumb_frame, text=str(year), bg=_bg,
                                  fg=self._TP_ACCENT, font=_font_link, cursor="hand2")
                yr_lbl.pack(side="left")
                yr_lbl.bind("<Button-1>", lambda e, c=channel, y=year: self._show_grid(c, y))
            else:
                tk.Label(self._grid_breadcrumb_frame, text=str(year), bg=_bg,
                         fg=_fg, font=_font_current).pack(side="left")
        if month is not None and 1 <= (month or 0) <= 12:
            tk.Label(self._grid_breadcrumb_frame, text="  /  ", bg=_bg,
                     fg=_dim, font=_font_sep).pack(side="left")
            tk.Label(self._grid_breadcrumb_frame, text=_TP_MONTH_NAMES[month - 1].capitalize(),
                     bg=_bg, fg=_fg, font=_font_current).pack(side="left")

    def _grid_on_rightclick(self, event):
        """Right-click context menu on a grid card — mirrors the tree view menu."""
        if not self._grid_visible or not self._grid_videos:
            return
        idx = self._grid_idx_from_event(event)
        if idx < 0:
            return
        v = self._grid_videos[idx]
        title = v["title"]
        channel = self._grid_scope[0] if self._grid_scope else ""
        filepath = v.get("filepath")
        video_id = v.get("video_id")

        # Find video file
        video_path = filepath if filepath and os.path.isfile(filepath) else None
        if not video_path:
            video_path = self._find_video_in_channel(title, channel)

        # Get transcript segments for VLC timestamp jump
        _db_rows = None
        if self._conn and title:
            try:
                _db_rows = self._db_execute(
                    "SELECT video_id, start_time, end_time, text, words "
                    "FROM segments WHERE title=? ORDER BY start_time",
                    (title,)).fetchall()
                if _db_rows and not video_id:
                    video_id = _db_rows[0][0]
            except Exception:
                pass

        menu = tk.Menu(self, tearoff=0, bg=self._TP_BG3, fg=self._TP_FG,
                       activebackground=self._TP_ACCENT, activeforeground="white",
                       disabledforeground="#666b75", relief="flat", bd=1)

        if video_path:
            menu.add_command(label="  \u25b6  Play Video",
                             command=lambda: self._open_vlc(
                                 video_path, 0, title=title, db_rows=_db_rows))
        else:
            menu.add_command(label="  \u25b6  Play Video", state="disabled")

        if video_id:
            url = f"https://www.youtube.com/watch?v={video_id}"
            menu.add_command(label="  Open Video \u2014 YouTube",
                             command=lambda u=url: _webbrowser.open(u))
        else:
            menu.add_command(label="  Open Video \u2014 YouTube", state="disabled")

        if video_id:
            menu.add_command(label="  Redownload...",
                             command=lambda vi=video_id, t=title, vp=video_path, ch=channel:
                                 self._on_browse_redownload(vi, t, vp, ch))
        else:
            menu.add_command(label="  Redownload...", state="disabled")

        # Show in Explorer
        def _show_explorer(vp=video_path, t=title, ch=channel):
            _target = vp
            if _target and not os.path.isfile(_target):
                _target = self._find_video_in_channel(t, ch)
            _ch_dir = self._get_channel_dir(ch) if not (_target and os.path.isfile(_target)) else None
            _show_in_explorer(_target, fallback_dir=_ch_dir)
        menu.add_command(label="  Show in Explorer", command=_show_explorer)

        if video_path:
            menu.add_separator()
            menu.add_command(label="  Delete File",
                             command=lambda vp=video_path, t=title, ch=channel:
                                 self._browse_delete_file(vp, t, ch))

        menu.tk_popup(event.x_root, event.y_root)

    def _grid_check_load_more(self):
        """Scroll-triggered: load next batch of cards when near bottom."""
        if not self._grid_visible or not self._grid_videos:
            return
        if self._grid_loaded_count >= len(self._grid_videos):
            return
        try:
            _, y_end = self._grid_canvas.yview()
            if y_end > 0.85:
                self._grid_build_cards(reset=False, _keep_photos=True)
        except Exception:
            pass

    def _grid_enable_resize(self):
        """Re-enable resize handler after initial build."""
        self._grid_suppress_resize = False

    def _on_grid_canvas_resize(self, event):
        """Responsive: debounce resize and rebuild canvas items."""
        if not self._grid_visible or not self._grid_videos:
            return
        if getattr(self, '_grid_suppress_resize', False):
            return
        # Skip if canvas width hasn't meaningfully changed
        if abs(event.width - self._grid_last_width) < 10:
            return
        _pending = getattr(self, '_grid_resize_job', None)
        if _pending:
            try:
                self.after_cancel(_pending)
            except Exception:
                pass
        def _deferred_resize():
            self._grid_resize_job = None
            self._grid_build_cards(reset=True, _keep_photos=True)
        self._grid_resize_job = self.after(200, _deferred_resize)

    def _grid_resort(self):
        """Re-sort the grid based on the current sort selection."""
        import datetime as _dt
        sort = self._grid_sort_var.get()
        def _date_key(v):
            if v["upload_date"]:
                return v["upload_date"]
            if v["mtime"]:
                return _dt.datetime.fromtimestamp(v["mtime"]).strftime("%Y%m%d")
            return "00000000"
        if sort == "Most Viewed":
            self._grid_videos.sort(key=lambda x: x["view_count"], reverse=True)
        elif sort == "Oldest":
            self._grid_videos.sort(key=_date_key)
        else:  # Newest
            self._grid_videos.sort(key=_date_key, reverse=True)
        if self._grid_visible:
            self._grid_build_cards(reset=True, _keep_photos=True)

    def _on_browse_back_to_grid(self):
        """Back button: return from transcript view to the grid for the last scope."""
        scope = getattr(self, '_grid_return_scope', None)
        if scope:
            channel, year, month = scope
            # Force re-show by clearing the scope match check
            self._grid_scope = None
            self._show_grid(channel, year, month)

    def _grid_navigate_to_video(self, title):
        """Find the title node in the tree and select it (triggers transcript view).
        If the tree node isn't expanded yet, expand the parent hierarchy
        one level at a time, waiting for each level to populate."""
        # Check if title node already exists in the tree
        for iid, meta in self._browse_items.items():
            if meta.get("type") == "title" and meta.get("title") == title:
                self._browse_tree.selection_set(iid)
                self._browse_tree.see(iid)
                self._browse_tree.event_generate("<<TreeviewSelect>>")
                return
        if not self._grid_scope:
            return
        channel = self._grid_scope[0]
        # Look up the video's year/month from the DB
        _v_year, _v_month = None, None
        if self._conn:
            try:
                row = self._db_execute(
                    "SELECT year, month FROM videos WHERE title=? AND channel=? LIMIT 1",
                    (title, channel)).fetchone()
                if row:
                    _v_year, _v_month = row
            except Exception:
                pass
        # Build the expansion chain: channel → year → month → title
        # Each step expands one node, waits for children to populate, then continues
        _expand_chain = []
        # Step 1: expand channel node
        _expand_chain.append(("channel", channel, None, None))
        if _v_year is not None:
            _expand_chain.append(("year", channel, _v_year, None))
        if _v_month is not None:
            _expand_chain.append(("month", channel, _v_year, _v_month))
        self._grid_expand_chain(title, _expand_chain, 0)

    def _grid_expand_chain(self, title, chain, step):
        """Expand tree nodes one at a time. Each step finds the node, expands it
        using _on_browse_open_for_iid, then waits before continuing to next step."""
        # First, check if title node appeared
        for iid, meta in self._browse_items.items():
            if meta.get("type") == "title" and meta.get("title") == title:
                self._browse_tree.selection_set(iid)
                self._browse_tree.see(iid)
                self._browse_tree.event_generate("<<TreeviewSelect>>")
                return
        if step >= len(chain):
            # All nodes expanded but title not found — retry a few times
            self._grid_expand_retry(title, 0)
            return
        node_type, channel, year, month = chain[step]
        # Find and expand the matching node
        for iid, meta in self._browse_items.items():
            if meta.get("type") == node_type and meta.get("channel") == channel:
                if node_type == "channel" or \
                   (node_type == "year" and meta.get("year") == year) or \
                   (node_type == "month" and meta.get("year") == year and meta.get("month") == month):
                    self._browse_tree.item(iid, open=True)
                    self._on_browse_open_for_iid(iid)
                    # Wait for children to populate, then continue chain
                    self.after(200, lambda: self._grid_expand_chain(title, chain, step + 1))
                    return
        # Node not found at this level — skip and try next
        self.after(100, lambda: self._grid_expand_chain(title, chain, step + 1))

    def _grid_expand_retry(self, title, attempt):
        """Retry finding a title node after full expansion (up to 5 attempts)."""
        for iid, meta in self._browse_items.items():
            if meta.get("type") == "title" and meta.get("title") == title:
                self._browse_tree.selection_set(iid)
                self._browse_tree.see(iid)
                self._browse_tree.event_generate("<<TreeviewSelect>>")
                return
        if attempt < 5:
            self.after(300, lambda: self._grid_expand_retry(title, attempt + 1))

    def _is_metadata_queued_or_running(self, channel, year=None, month=None):
        """Check if a metadata download is queued or running for the given scope."""
        _key = f"metadata:{channel}:{year}:{month}"
        with _metadata_queue_lock:
            if any(q["_key"] == _key for q in _metadata_queue):
                return True
        if _metadata_running and _current_job.get("_metadata_key") == _key:
            return True
        return False

    def _update_meta_banner(self, has_metadata, channel, year, month):
        """Show/hide/update the metadata banner based on queue state."""
        if has_metadata:
            self._grid_meta_banner.pack_forget()
            return
        queued = self._is_metadata_queued_or_running(channel, year, month)
        if queued:
            self._grid_meta_banner_lbl.config(
                text="  Metadata download in queue",
                cursor="arrow")
        else:
            self._grid_meta_banner_lbl.config(
                text="  Download metadata for thumbnails, view counts, and more",
                cursor="hand2")
        self._grid_meta_banner.pack(fill="x", after=self._grid_header)

    def _grid_download_metadata(self):
        """Trigger metadata download for the current grid scope."""
        if not self._grid_scope:
            return
        channel, year, month = self._grid_scope
        self._browse_download_metadata(channel, year, month)
        # Update banner to reflect queued state
        self._update_meta_banner(False, channel, year, month)

    def _secret_download_all_metadata(self):
        """Queue metadata download for ALL saved channels at once."""
        if not _dark_askquestion("Download All Metadata",
                "Download metadata for all channels?\n\n"
                "This will queue a metadata download for every\n"
                "saved channel. It may take a while.",
                yes_text="Download All", no_text="Cancel"):
            return
        with config_lock:
            channels = list(config.get("channels", []))
        if not channels:
            log("No channels configured.\n", "red")
            return
        channels = sorted(channels, key=lambda c: c.get("name", "").lower())
        queued = 0
        for ch_cfg in channels:
            ch_name = ch_cfg.get("name", "")
            if not ch_name:
                continue
            ch_url = ch_cfg.get("url", "")
            folder = ch_cfg.get("folder_override") or sanitize_folder(ch_name)
            with config_lock:
                base = config.get("output_dir", "")
            folder_path = os.path.join(base, folder) if base else folder
            sy = ch_cfg.get("split_years", False)
            sm = ch_cfg.get("split_months", False)
            _add_to_metadata_queue(ch_name, ch_url, folder_path, sy, sm, None, None, ch_name)
            queued += 1
        log(f"\n=== Queued metadata download for {queued} channel(s) ===\n", "header")

    def _on_retranscribe(self):
        """Transcribe or re-transcribe the currently viewed video using Whisper."""
        meta = self._browse_current_meta
        if not meta:
            return
        title      = meta["title"]
        txt_path   = meta.get("txt_path")
        jsonl_path = meta.get("jsonl_path")
        video_id   = meta.get("video_id")
        channel    = meta.get("channel", "")
        filepath   = meta.get("filepath")

        # Find local video file — try stored filepath first, then search
        video_path = None
        if filepath and os.path.isfile(filepath):
            video_path = filepath
        if not video_path and txt_path:
            video_path = self._find_video_file(title, txt_path)
        if not video_path and filepath:
            video_path = self._find_video_file(title, filepath)

        if not video_path and not video_id:
            messagebox.showerror("Error",
                "No local video file found and no YouTube video ID available.\n"
                "Cannot transcribe.")
            return

        # Ask for Whisper model — show dialog directly on the main thread.
        # _ask_whisper_model_dialog uses _ui_queue which requires a background
        # thread, so we build a simple modal Toplevel here instead.
        _model_result = [None]
        _dlg = tk.Toplevel(root)
        _dlg.title("Whisper Model Selection")
        _dlg.configure(bg=C_BG)
        _dlg.resizable(False, False)
        _dlg.transient(root)
        _dlg.grab_set()
        _dlg.update_idletasks()
        _apply_dark_title_bar(_dlg)
        _rx = root.winfo_rootx() + root.winfo_width() // 2
        _ry = root.winfo_rooty() + root.winfo_height() // 2
        _dlg.geometry(f"+{_rx - 160}+{_ry - 140}")

        tk.Label(_dlg, text=f"Re-transcribe: {title[:60]}",
                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10, "bold"),
                 pady=10, padx=20).pack(fill="x")
        tk.Label(_dlg, text="Select Whisper model for re-transcription",
                 bg=C_BG, fg=C_DIM, font=("Segoe UI", 9),
                 padx=20).pack(fill="x")

        _btn_frame = tk.Frame(_dlg, bg=C_BG, pady=10)
        _btn_frame.pack(fill="x", padx=20)

        _models = [
            ("tiny",     "Fastest  (~30-50\u00d7 realtime)",    "tiny"),
            ("small",    "Fast  (~15-20\u00d7 realtime)",       "small"),
            ("medium",   "Balanced  (~7-10\u00d7 realtime)",    "medium"),
            ("large-v3", "Best quality  (~3-5\u00d7 realtime)", "large-v3"),
        ]

        def _pick(m):
            _model_result[0] = m
            try:
                _dlg.destroy()
            except Exception:
                pass

        for label, desc, model_id in _models:
            _row = tk.Frame(_btn_frame, bg=C_BG)
            _row.pack(fill="x", pady=2)
            _b = tk.Button(_row, text=label, width=10,
                           bg="#3a3a3a", fg=C_TEXT, activebackground="#555555",
                           activeforeground=C_TEXT, relief="flat", bd=0,
                           font=("Segoe UI", 9, "bold"), cursor="hand2",
                           command=lambda m=model_id: _pick(m))
            _b.pack(side="left", padx=(0, 8))
            tk.Label(_row, text=desc, bg=C_BG, fg=C_DIM,
                     font=("Segoe UI", 9)).pack(side="left")

        _dlg.protocol("WM_DELETE_WINDOW", lambda: _pick(None))
        _dlg.wait_window(_dlg)

        if not _model_result[0]:
            return  # User cancelled

        chosen_model = _model_result[0]
        self._browse_actions_btn.config(state="disabled")

        def _retranscribe_worker():
            global _whisper_model_choice
            _temp_audio = None
            try:
                audio_path = video_path
                _dur_secs = 0

                # If no local file, download audio from YouTube
                if not audio_path and video_id:
                    self._browse_retranscribe_status("Downloading audio...")
                    import tempfile
                    _temp_dir = tempfile.mkdtemp(prefix="ytarch_retrans_")
                    _temp_audio = os.path.join(_temp_dir, f"{video_id}.m4a")
                    _dl_cmd = [
                        "yt-dlp", "-f", "bestaudio[ext=m4a]/bestaudio",
                        "-o", _temp_audio, "--no-playlist",
                        "--cookies-from-browser", "firefox",
                        f"https://www.youtube.com/watch?v={video_id}",
                    ]
                    _dl_result = subprocess.run(
                        _dl_cmd, capture_output=True, text=True,
                        timeout=300, startupinfo=startupinfo)
                    if _dl_result.returncode != 0 or not os.path.exists(_temp_audio):
                        # Retry without cookies
                        _dl_cmd2 = [
                            "yt-dlp", "-f", "bestaudio[ext=m4a]/bestaudio",
                            "-o", _temp_audio, "--no-playlist",
                            f"https://www.youtube.com/watch?v={video_id}",
                        ]
                        _dl_result2 = subprocess.run(
                            _dl_cmd2, capture_output=True, text=True,
                            timeout=300, startupinfo=startupinfo)
                        if _dl_result2.returncode != 0 or not os.path.exists(_temp_audio):
                            self._browse_retranscribe_done(
                                False, "Failed to download audio from YouTube.")
                            return
                    audio_path = _temp_audio

                # Get duration via ffprobe
                try:
                    _probe = subprocess.run(
                        ["ffprobe", "-v", "quiet", "-show_entries",
                         "format=duration", "-of", "csv=p=0", audio_path],
                        capture_output=True, text=True, timeout=30,
                        startupinfo=startupinfo)
                    _dur_secs = float(_probe.stdout.strip())
                except Exception:
                    pass

                # Set whisper model and transcribe (locked to prevent race with other threads)
                with _whisper_model_lock:
                    _prev_model = _whisper_model_choice
                    _whisper_model_choice = chosen_model
                # Stop existing whisper process so it restarts with new model
                _stop_whisper_process()

                try:
                    self._browse_retranscribe_status(f"Transcribing ({chosen_model}) 0%...")
                    def _on_progress(pct):
                        self._browse_retranscribe_status(f"Transcribing ({chosen_model}) {pct}%...")
                    text, segments = _whisper_transcribe(
                        audio_path, duration=_dur_secs, title=title,
                        progress_cb=_on_progress)
                    _clear_whisper_progress()
                finally:
                    # Restore previous model choice no matter what
                    with _whisper_model_lock:
                        _whisper_model_choice = _prev_model
                    _stop_whisper_process()

                if not text:
                    self._browse_retranscribe_done(
                        False, "Whisper returned no text — no speech detected?")
                    return

                # Apply punctuation fixup
                self._browse_retranscribe_status("Restoring punctuation...")
                text = _whisper_punct_fixup(text)

                # --- Replace old entry in .txt ---
                self._browse_retranscribe_status("Replacing transcript...")
                self._replace_txt_entry(txt_path, title, text, chosen_model)

                # --- Replace old entry in .jsonl ---
                if jsonl_path:
                    self._replace_jsonl_entry(
                        jsonl_path, title, video_id or "", segments)

                    # --- Re-index this JSONL file in the DB ---
                    self._browse_retranscribe_status("Re-indexing...")
                    roots = self._get_archive_roots()
                    # Acquire lock — background indexer may hold it
                    _got_lock = self._db_lock.acquire(timeout=60)
                    if _got_lock:
                        try:
                            _tp_index_file(self._conn, jsonl_path, roots)
                        finally:
                            self._db_lock.release()

                self._browse_retranscribe_done(True)

            except Exception as e:
                self._browse_retranscribe_done(False, str(e))
            finally:
                # Clean up temp audio
                if _temp_audio:
                    try:
                        os.remove(_temp_audio)
                        os.rmdir(os.path.dirname(_temp_audio))
                    except Exception:
                        pass

        threading.Thread(target=_retranscribe_worker, daemon=True).start()

    def _browse_retranscribe_status(self, msg):
        """Update status from a worker thread (no-op now — actions button has no text label)."""
        pass

    def _browse_retranscribe_done(self, success, error_msg=None):
        """Called when re-transcription finishes (from worker thread)."""
        def _finish():
            self._browse_actions_btn.config(state="normal")
            if success:
                messagebox.showinfo("Re-transcribe",
                    "Transcription replaced successfully.\n"
                    "The viewer will now refresh.")
                # Refresh the viewer to show new content
                self._on_browse_select()
            else:
                messagebox.showerror("Re-transcribe Failed",
                    error_msg or "Unknown error occurred.")
        self.after(0, _finish)

