    def _on_browse_redownload(self, video_id=None, title=None, video_path=None, channel=None):
        """Redownload a single video at a user-chosen resolution."""
        # If called from the actions dropdown (no args), use current meta
        if video_id is None:
            meta = self._browse_current_meta
            if not meta:
                return
            video_id = meta.get("video_id")
            title = meta.get("title", "")
            video_path = meta.get("_video_path") or meta.get("filepath")
            channel = meta.get("channel", "")

        if not video_id:
            messagebox.showerror("Redownload", "No YouTube video ID available for this video.")
            return

        resolution = self._show_resolution_dialog(f"Redownload: {title[:60]}")
        if not resolution:
            return

        self._browse_actions_btn.config(state="disabled")
        _res_label = "Best" if resolution == "best" else f"{resolution}p"

        def _redownload_worker():
            temp_dir = None
            try:
                fmt = build_format_string(resolution)
                vid_url = f"https://www.youtube.com/watch?v={video_id}"

                # Determine output directory and filename
                if video_path and os.path.isfile(video_path):
                    out_dir = os.path.dirname(video_path)
                    orig_name = os.path.basename(video_path)
                else:
                    # No existing file — try to find channel folder
                    out_dir = None
                    with config_lock:
                        _base = config.get("output_dir", "")
                        for ch in config.get("channels", []):
                            if ch.get("name", "") == channel:
                                _ch_folder = ch.get("folder_override") or sanitize_folder(ch.get("name", ""))
                                out_dir = os.path.join(_base, _ch_folder) if _base else _ch_folder
                                break
                    if not out_dir:
                        self.after(0, lambda: messagebox.showerror("Redownload",
                            "Could not determine output folder."))
                        return
                    orig_name = None

                temp_dir = os.path.join(out_dir, "_REDOWNLOAD_TEMP")
                os.makedirs(temp_dir, exist_ok=True)
                dl_path = os.path.join(temp_dir, f"{video_id}.mp4")

                dl_cmd = [
                    "yt-dlp", "--newline", "--no-quiet",
                    "--trim-filenames", "200",
                    "--format", fmt, "--merge-output-format", "mp4",
                    "--ppa", "Merger:-c copy",
                    "--output", dl_path,
                    "--cookies-from-browser", "firefox",
                    "--no-download-archive",
                    vid_url,
                ]

                dl_proc = spawn_yt_dlp(dl_cmd)
                if dl_proc is None:
                    self.after(0, lambda: messagebox.showerror("Redownload",
                        "Could not start yt-dlp."))
                    return

                for line in dl_proc.stdout:
                    pass  # consume output
                try:
                    dl_proc.wait(timeout=300)
                except subprocess.TimeoutExpired:
                    dl_proc.kill()
                    dl_proc.wait()
                with proc_lock:
                    if dl_proc in active_processes:
                        active_processes.remove(dl_proc)

                # yt-dlp may produce a file with a different name
                if not os.path.exists(dl_path):
                    found_dl = None
                    try:
                        for f_temp in os.listdir(temp_dir):
                            if f_temp.startswith(video_id):
                                found_dl = os.path.join(temp_dir, f_temp)
                                break
                    except OSError:
                        pass
                    if found_dl:
                        dl_path = found_dl
                    else:
                        self.after(0, lambda: messagebox.showerror("Redownload",
                            "Download failed — no output file produced."))
                        return

                new_size = os.path.getsize(dl_path)
                if new_size < 10240:
                    try:
                        os.remove(dl_path)
                    except Exception:
                        pass
                    self.after(0, lambda: messagebox.showerror("Redownload",
                        "Downloaded file is too small — likely a download error."))
                    return

                # Replace existing file or place new file
                if orig_name and video_path and os.path.isfile(video_path):
                    os.replace(dl_path, video_path)
                    final_path = video_path
                else:
                    # Move from temp to output dir with title as filename
                    safe_title = re.sub(r'[<>:"/\\|?*]', '_', title)[:200]
                    final_path = os.path.join(out_dir, safe_title + ".mp4")
                    os.replace(dl_path, final_path)

                # Clean up temp dir
                try:
                    os.rmdir(temp_dir)
                except Exception:
                    pass

                # Probe new resolution for display
                _new_h = _ffprobe_height(final_path)
                _new_res = f"{_new_h}p" if _new_h else _res_label

                def _done():
                    self._browse_actions_btn.config(state="normal")
                    if self._browse_current_meta and self._browse_current_meta.get("title") == title:
                        self._browse_current_meta["resolution"] = _new_res
                        self._browse_current_meta["_video_path"] = final_path
                        _ch = self._browse_current_meta.get("channel", "")
                        _pp = self._browse_current_meta.get("txt_path") or final_path
                        self._browse_path_label.config(
                            text=f"{_ch}  •  {_new_res}  •  {_pp}")
                    messagebox.showinfo("Redownload",
                        f"Video redownloaded at {_new_res}.")
                self.after(0, _done)

            except Exception as e:
                def _err(msg=str(e)):
                    self._browse_actions_btn.config(state="normal")
                    messagebox.showerror("Redownload Failed", msg)
                self.after(0, _err)
            finally:
                try:
                    if temp_dir and os.path.isdir(temp_dir):
                        import shutil
                        shutil.rmtree(temp_dir, ignore_errors=True)
                except Exception:
                    pass

        threading.Thread(target=_redownload_worker, daemon=True).start()

    def _replace_txt_entry(self, txt_path, title, new_text, model_name):
        """Replace a single video's entry in the transcript .txt file."""
        try:
            with open(txt_path, "r", encoding="utf-8", errors="replace") as f:
                content = f.read()
        except FileNotFoundError:
            content = ""

        # Find and remove the old entry
        matches = list(self._HEADER_RE.finditer(content))
        new_content = content
        _found_old = False
        for i, m in enumerate(matches):
            if m.group(1).strip() == title.strip():
                end = matches[i + 1].start() if i + 1 < len(matches) else len(content)
                new_content = content[:m.start()] + content[end:]
                _found_old = True
                break
        if not _found_old and content.strip():
            log(f"  \u26a0 Could not find old entry for \"{title}\" in transcript file; appending new version.\n", "dim")

        # Parse old header for date/duration if available
        _date_fmt = "(Unknown date)"
        _dur_fmt = "(Unknown length)"
        _old_header_re = re.compile(
            r'^===\(' + re.escape(title) + r'\),\s*(\([^)]*\)),\s*(\([^)]*\)),',
            re.MULTILINE)
        _old_match = _old_header_re.search(content)
        if _old_match:
            _date_fmt = _old_match.group(1)
            _dur_fmt = _old_match.group(2)

        # Build new entry
        _model_tag = f"WHISPER {model_name.upper()}"
        new_entry = f"===({title}), {_date_fmt}, {_dur_fmt}, ({_model_tag})===\n{new_text}\n\n\n"

        # Append new entry
        # Ensure content ends cleanly before appending
        new_content = new_content.rstrip("\n") + "\n\n\n" if new_content.strip() else ""
        new_content += new_entry

        # Atomic write: write to temp file then replace, so a crash mid-write
        # can't leave the transcript empty or corrupt.
        _tmp = txt_path + ".tmp"
        with open(_tmp, "w", encoding="utf-8") as f:
            f.write(new_content)
        os.replace(_tmp, txt_path)

    def _replace_jsonl_entry(self, jsonl_path, title, video_id, new_segments):
        """Replace a single video's segments in the .jsonl file."""
        # Clear hidden + read-only attributes so we can write (re-set by _write_jsonl_entry)
        if os.name == "nt":
            try:
                _norm = os.path.normpath(jsonl_path)
                ctypes.windll.kernel32.SetFileAttributesW(
                    _norm, 0x80)  # FILE_ATTRIBUTE_NORMAL
            except Exception:
                pass
            # Belt-and-suspenders: also try via os.chmod
            try:
                import stat
                os.chmod(jsonl_path, stat.S_IWRITE | stat.S_IREAD)
            except Exception:
                pass

        # Read existing lines, filter out old entries for this title
        old_lines = []
        try:
            with open(jsonl_path, "r", encoding="utf-8") as f:
                old_lines = f.readlines()
        except FileNotFoundError:
            pass

        kept_lines = []
        for line in old_lines:
            line_s = line.strip()
            if not line_s:
                continue
            try:
                seg = json.loads(line_s)
                if seg.get("title", "").strip() == title.strip():
                    continue  # Skip old entries for this title
            except Exception:
                pass
            kept_lines.append(line if line.endswith("\n") else line + "\n")

        # Write kept lines back (atomic: write to temp, then replace)
        _tmp_path = jsonl_path + ".tmp"
        with open(_tmp_path, "w", encoding="utf-8") as f:
            f.writelines(kept_lines)
        os.replace(_tmp_path, jsonl_path)

        # Append new segments (also re-hides the file)
        _write_jsonl_entry(jsonl_path, video_id, title, new_segments)

    def _on_browse_word_double_click(self, event):
        """Double-clicking a word in the browse viewer opens the Open Local/YT menu."""
        sel = self._browse_tree.selection()
        if not sel:
            return
        meta = self._browse_items.get(sel[0])
        if not meta or meta["type"] != "title":
            return
        if not self._browse_seg_map:
            return

        click_idx  = self._browse_viewer.index(f"@{event.x},{event.y}")
        word_start = self._browse_viewer.index(f"{click_idx} wordstart")
        word_end   = self._browse_viewer.index(f"{click_idx} wordend")
        word = self._browse_viewer.get(word_start, word_end).strip()
        if not word:
            return

        # Resolve click → char offset → segment via the position map built at load time
        raw_count = self._browse_viewer.count("1.0", click_idx, "chars")
        if not raw_count:
            return
        char_offset = int(raw_count[0])
        seg_entry = self._browse_seg_lookup(char_offset)
        if seg_entry is None:
            return

        video_id, start_time, end_time, seg_text, words_json = seg_entry

        # Use per-word timestamp if available, else fall back to interpolation
        ts = self._word_ts_lookup(words_json, word, start_time or 0, end_time or start_time or 0)

        title      = meta["title"]
        channel    = meta.get("channel", "")
        jsonl_path = meta.get("jsonl_path")
        txt_path   = self._get_txt_path(jsonl_path) if jsonl_path else None
        video_path = self._find_video_file(title, txt_path)

        self.after(10, lambda: self._show_browse_open_menu(
            event.x_root, event.y_root,
            video_id, video_path, ts, word, seg_text, title, channel, start_time or 0))

    def _browse_seg_lookup(self, char_offset):
        """Binary search _browse_seg_map for the segment at char_offset.
        Returns (video_id, start, end, text, words_json) or None."""
        if not self._browse_seg_map:
            return None
        starts = [s[0] for s in self._browse_seg_map]
        i = bisect.bisect_right(starts, char_offset) - 1
        if 0 <= i < len(self._browse_seg_map):
            return self._browse_seg_map[i][2]
        return None

    _TS_LEAD_BROWSE = 1.5  # seconds of lead for external VLC / YouTube seeks

    def _word_ts_lookup(self, words_json, word, seg_start, seg_end):
        """Return the exact seek timestamp for word within a segment.
        Uses per-word timestamps when available; falls back to segment start.
        Lead offset is applied separately by the caller based on player type."""
        if words_json:
            try:
                word_list = json.loads(words_json)
                clean = word.lower().strip(".,!?;:\"'()-")
                for w in word_list:
                    if w.get("w", "").lower().strip(".,!?;:\"'()-") == clean:
                        return max(0.0, w["s"])
            except Exception:
                pass
        return max(0.0, seg_start)

    def _show_browse_open_menu(self, x, y, video_id, video_path, ts,
                                word, seg_text, title, channel, start_time):
        """Context menu shown after double-clicking a word in the browse viewer."""
        menu = tk.Menu(self, tearoff=0, bg=self._TP_BG3, fg=self._TP_FG,
                       activebackground=self._TP_ACCENT, activeforeground="white",
                       disabledforeground=self._TP_DIM, relief="flat", bd=1)

        # Fetch DB rows for embedded player transcript sync
        _browse_db_rows = None
        if self._conn and title:
            try:
                _browse_db_rows = self._db_execute(
                    "SELECT video_id, start_time, end_time, text, words "
                    "FROM segments WHERE title=? ORDER BY start_time",
                    (title,)).fetchall()
            except Exception:
                pass

        if video_path:
            menu.add_command(label="  ▶  Play from this point",
                             command=lambda: self._open_vlc(
                                 video_path, ts, title=title,
                                 db_rows=_browse_db_rows))
        else:
            menu.add_command(label="  ▶  Play from this point  (file not found)",
                             state="disabled")

        if video_id:
            _yt_t = max(0, int(ts - self._TS_LEAD_BROWSE))
            url = f"https://www.youtube.com/watch?v={video_id}&t={_yt_t}s"
            menu.add_command(label="  Open Video — YouTube",
                             command=lambda u=url: _webbrowser.open(u))
        else:
            menu.add_command(label="  Open Video — YouTube  (no ID)",
                             state="disabled")

        menu.add_separator()
        menu.add_command(label="  📋  Copy Segment Text",
                         command=lambda: self._copy_to_clipboard(seg_text))
        menu.add_command(label="  🔖  Bookmark This Segment",
                         command=lambda: self._add_bookmark(
                             None, video_id, title, channel, start_time, seg_text))

        try:
            menu.tk_popup(x, y)
        finally:
            menu.grab_release()

    # ── Bookmarks section ─────────────────────────────────────────────────────

    def _build_bookmarks_section(self, parent):
        f = tk.Frame(parent, bg=self._TP_BG)
        f.columnconfigure(0, weight=1)
        f.rowconfigure(1, weight=1)

        # Header bar
        hdr = tk.Frame(f, bg=self._TP_BG3, padx=10, pady=6)
        hdr.grid(row=0, column=0, sticky="ew")
        tk.Label(hdr, text="Bookmarks", bg=self._TP_BG3, fg=self._TP_FG,
                 font=("Segoe UI", 11, "bold")).pack(side="left")
        self._bm_count_label = tk.Label(hdr, text="", bg=self._TP_BG3, fg=self._TP_DIM,
                                        font=("Segoe UI", 9))
        self._bm_count_label.pack(side="right", padx=8)

        # Content: tree + viewer
        pane = tk.PanedWindow(f, orient="horizontal", bg="#0a0b0d",
                              sashwidth=5, sashpad=0, relief="flat")
        pane.grid(row=1, column=0, sticky="nsew", padx=6, pady=4)

        # Left: bookmarks list
        left = tk.Frame(pane, bg=self._TP_BG)
        cols = ("channel", "title", "note", "date")
        self._bm_tree = ttk.Treeview(left, columns=cols, show="headings",
                                      selectmode="browse", style="TP.Treeview")
        for col, label, w, stretch in [
            ("channel", "Channel", 100, False),
            ("title",   "Title",   180, False),
            ("note",    "Note",    200, True),
            ("date",    "Saved",    80, False),
        ]:
            self._bm_tree.heading(col, text=label)
            self._bm_tree.column(col, width=w, minwidth=50, stretch=stretch)
        bm_sb = ttk.Scrollbar(left, orient="vertical", command=self._bm_tree.yview)
        self._bm_tree.configure(yscrollcommand=bm_sb.set)
        bm_sb.pack(side="right", fill="y")
        self._bm_tree.pack(fill="both", expand=True)
        self._bm_tree.bind("<<TreeviewSelect>>", self._on_bookmark_select)
        self._bm_tree.bind("<Button-3>", self._on_bookmark_rightclick)
        pane.add(left, minsize=280)

        # Right: bookmark detail
        right = tk.Frame(pane, bg=self._TP_BG)
        self._bm_detail_title = tk.Label(right, text="Select a bookmark",
                                         bg=self._TP_BG3, fg=self._TP_FG,
                                         font=("Segoe UI", 11, "bold"),
                                         anchor="w", padx=10, pady=6)
        self._bm_detail_title.pack(fill="x")
        self._bm_detail_text = tk.Text(right, bg="#1a1c1f", fg=self._TP_FG,
                                        font=("Segoe UI", 10), wrap="word",
                                        relief="flat", padx=12, pady=10,
                                        state="disabled", cursor="arrow")
        self._bm_detail_text.tag_configure("note", foreground=self._TP_GREEN,
                                           font=("Segoe UI", 10, "italic"))
        self._bm_detail_text.tag_configure("meta", foreground=self._TP_DIM,
                                           font=("Segoe UI", 9))
        bm_vsb = ttk.Scrollbar(right, orient="vertical",
                                command=self._bm_detail_text.yview)
        self._bm_detail_text.configure(yscrollcommand=bm_vsb.set)
        bm_vsb.pack(side="right", fill="y")
        self._bm_detail_text.pack(fill="both", expand=True)
        pane.add(right, minsize=250)

        return f

    def _refresh_bookmarks(self):
        """Reload bookmarks from the database into the treeview."""
        if not self._conn:
            return
        self._bm_tree.delete(*self._bm_tree.get_children())
        self._bookmarks_data = []
        try:
            rows = self._db_execute(
                "SELECT id, segment_id, video_id, title, channel, start_time, text, note, created "
                "FROM bookmarks ORDER BY created DESC").fetchall()
        except Exception:
            return
        from datetime import datetime as _dt
        for row in rows:
            bm_id, seg_id, vid_id, title, ch, start, text, note, created = row
            title = title or ""
            note = note or ""
            try:
                date_str = _dt.fromtimestamp(created).strftime("%Y-%m-%d")
            except Exception:
                date_str = ""
            disp_title = title if len(title) <= 40 else title[:37] + "..."
            disp_note  = note if len(note) <= 50 else note[:47] + "..."
            iid = self._bm_tree.insert("", "end",
                                        values=(ch, disp_title, disp_note, date_str))
            self._bookmarks_data.append({
                "iid": iid, "bm_id": bm_id, "segment_id": seg_id,
                "video_id": vid_id, "title": title, "channel": ch,
                "start": start, "text": text, "note": note, "created": created,
            })
        self._bm_count_label.config(text=f"{len(rows)} bookmark{'s' if len(rows) != 1 else ''}")

    def _on_bookmark_select(self, event=None):
        sel = self._bm_tree.selection()
        if not sel:
            return
        bm = next((b for b in self._bookmarks_data if b["iid"] == sel[0]), None)
        if not bm:
            return
        self._bm_detail_title.config(text=bm["title"])
        self._bm_detail_text.config(state="normal")
        self._bm_detail_text.delete("1.0", "end")
        if bm["note"]:
            self._bm_detail_text.insert("end", f"📝  {bm['note']}\n\n", "note")
        self._bm_detail_text.insert("end",
            f"{bm['channel']}  •  {bm['video_id'] or ''}\n", "meta")
        self._bm_detail_text.insert("end", f"\n{bm['text']}")
        self._bm_detail_text.config(state="disabled")

    def _on_bookmark_rightclick(self, event):
        item = self._bm_tree.identify_row(event.y)
        if not item:
            return
        self._bm_tree.selection_set(item)
        bm = next((b for b in self._bookmarks_data if b["iid"] == item), None)
        if not bm:
            return
        menu = tk.Menu(self, tearoff=0, bg=self._TP_BG3, fg=self._TP_FG,
                       activebackground=self._TP_ACCENT, activeforeground="white",
                       disabledforeground=self._TP_DIM, relief="flat", bd=1)
        menu.add_command(label="  Edit Note",
                         command=lambda: self._edit_bookmark_note(bm))
        menu.add_command(label="  Copy Text",
                         command=lambda: self._copy_to_clipboard(bm["text"]))
        menu.add_separator()
        menu.add_command(label="  Delete Bookmark",
                         command=lambda: self._delete_bookmark(bm["bm_id"]))
        try:
            menu.tk_popup(event.x_root, event.y_root)
        finally:
            menu.grab_release()

    def _add_bookmark(self, segment_id, video_id, title, channel, start, text):
        """Add a bookmark for a search result segment."""
        if not self._conn:
            return
        note = ""
        # Ask for optional note
        dlg = tk.Toplevel(self.winfo_toplevel())
        dlg.title("Add Bookmark")
        dlg.configure(bg=self._TP_BG3)
        dlg.resizable(False, False)
        dlg.transient(self.winfo_toplevel())
        dlg.grab_set()
        dlg.update_idletasks()
        _apply_dark_title_bar(dlg)
        # Center on parent
        pw = self.winfo_toplevel()
        dlg.geometry(f"+{pw.winfo_x() + (pw.winfo_width() - 350) // 2}+{pw.winfo_y() + (pw.winfo_height() - 150) // 2}")
        tk.Label(dlg, text="Add a note (optional):", bg=self._TP_BG3, fg=self._TP_FG,
                 font=("Segoe UI", 10)).pack(padx=16, pady=(12, 4))
        note_var = tk.StringVar()
        note_entry = tk.Entry(dlg, textvariable=note_var, bg=self._TP_BG2, fg=self._TP_FG,
                              insertbackground=self._TP_FG, relief="flat",
                              font=("Segoe UI", 10), width=40)
        note_entry.pack(padx=16, ipady=4)
        note_entry.focus_set()
        result = [False]
        def _save():
            result[0] = True
            dlg.destroy()
        note_entry.bind("<Return>", lambda _: _save())
        btn_row = tk.Frame(dlg, bg=self._TP_BG3)
        btn_row.pack(padx=16, pady=(8, 12))
        tk.Button(btn_row, text="Save", command=_save,
                  bg=self._TP_GREEN, fg="white", relief="flat",
                  font=("Segoe UI", 9, "bold"), padx=12).pack(side="left", padx=(0, 6))
        tk.Button(btn_row, text="Cancel", command=dlg.destroy,
                  bg=self._TP_BG2, fg=self._TP_FG, relief="flat",
                  font=("Segoe UI", 9), padx=12).pack(side="left")
        dlg.wait_window()
        if not result[0]:
            return
        note = note_var.get().strip()
        try:
            self._db_execute(
                "INSERT INTO bookmarks (segment_id, video_id, title, channel, start_time, text, note) "
                "VALUES (?,?,?,?,?,?,?)",
                (segment_id, video_id, title, channel, start, text, note))
            self._db_commit()
            self._refresh_bookmarks()
        except Exception as e:
            try:
                messagebox.showerror("Bookmark Error", f"Failed to save bookmark:\n{e}")
            except Exception:
                pass

    def _edit_bookmark_note(self, bm):
        """Edit the note on an existing bookmark."""
        dlg = tk.Toplevel(self.winfo_toplevel())
        dlg.title("Edit Bookmark Note")
        dlg.configure(bg=self._TP_BG3)
        dlg.resizable(False, False)
        dlg.transient(self.winfo_toplevel())
        dlg.grab_set()
        dlg.update_idletasks()
        _apply_dark_title_bar(dlg)
        pw = self.winfo_toplevel()
        dlg.geometry(f"+{pw.winfo_x() + (pw.winfo_width() - 350) // 2}+{pw.winfo_y() + (pw.winfo_height() - 150) // 2}")
        tk.Label(dlg, text="Note:", bg=self._TP_BG3, fg=self._TP_FG,
                 font=("Segoe UI", 10)).pack(padx=16, pady=(12, 4))
        note_var = tk.StringVar(value=bm.get("note", ""))
        note_entry = tk.Entry(dlg, textvariable=note_var, bg=self._TP_BG2, fg=self._TP_FG,
                              insertbackground=self._TP_FG, relief="flat",
                              font=("Segoe UI", 10), width=40)
        note_entry.pack(padx=16, ipady=4)
        note_entry.focus_set()
        def _save():
            try:
                self._db_execute(
                    "UPDATE bookmarks SET note=? WHERE id=?",
                    (note_var.get().strip(), bm["bm_id"]))
                self._db_commit()
            except Exception:
                log(f"  {traceback.format_exc()}\n", "dim")
            dlg.destroy()
            self._refresh_bookmarks()
        note_entry.bind("<Return>", lambda _: _save())
        btn_row = tk.Frame(dlg, bg=self._TP_BG3)
        btn_row.pack(padx=16, pady=(8, 12))
        tk.Button(btn_row, text="Save", command=_save,
                  bg=self._TP_GREEN, fg="white", relief="flat",
                  font=("Segoe UI", 9, "bold"), padx=12).pack(side="left", padx=(0, 6))
        tk.Button(btn_row, text="Cancel", command=dlg.destroy,
                  bg=self._TP_BG2, fg=self._TP_FG, relief="flat",
                  font=("Segoe UI", 9), padx=12).pack(side="left")
        dlg.wait_window()

    def _delete_bookmark(self, bm_id):
        """Remove a bookmark from the database."""
        if not self._conn:
            return
        if not messagebox.askyesno("Delete Bookmark", "Delete this bookmark?", parent=self):
            return
        try:
            self._db_execute("DELETE FROM bookmarks WHERE id=?", (bm_id,))
            self._db_commit()
        except Exception:
            log(f"  {traceback.format_exc()}\n", "dim")
        self._refresh_bookmarks()

    def _copy_to_clipboard(self, text):
        """Copy text to the system clipboard."""
        try:
            self.clipboard_clear()
            self.clipboard_append(text)
        except Exception:
            pass

