    def _update_search_channels(self):
        if not self._conn:
            return
        try:
            rows = self._db_execute(
                "SELECT DISTINCT channel FROM segments ORDER BY channel COLLATE NOCASE").fetchall()
            self._s_channel_cb["values"] = ["All"] + [r[0] for r in rows]
        except Exception:
            self._s_channel_cb["values"] = ["All"]

    _SORT_EXPRS = {
        "channel": "s.channel, s.year, s.month, s.start_time",
        "date":    None,
        "title":   "s.title, s.start_time",
        "snippet": "s.text",
    }

    def _sort_by(self, col):
        if self._sort_col == col:
            self._sort_asc = not self._sort_asc
        else:
            self._sort_col = col
            self._sort_asc = True
        self._update_heading_labels()
        if self._search_var.get().strip():
            self._do_search()

    def _update_heading_labels(self):
        labels = {"channel": "Channel", "date": "Date",
                  "title": "Title", "snippet": "Snippet"}
        for col, base in labels.items():
            arrow = (" ▲" if self._sort_asc else " ▼") if col == self._sort_col else ""
            self._tree.heading(col, text=base + arrow)

    def _do_search(self):
        if not self._conn or self._search_running:
            return
        query = self._search_var.get().strip()
        if not query:
            return
        # Strip FTS5 special operators to prevent query injection / unintended semantics
        query = re.sub(r'\b(AND|OR|NOT|NEAR)\b', '', query, flags=re.IGNORECASE)
        query = query.replace('*', '').replace('+', '').replace('^', '').strip()
        self._search_running = True
        self._search_btn.config(state="disabled", text="Searching…")
        self._search_count.config(text="")
        channel   = self._s_channel_var.get()
        yr_from   = self._s_year_from_var.get().strip()
        yr_to     = self._s_year_to_var.get().strip()
        sort_col  = self._sort_col
        sort_asc  = self._sort_asc

        def _run_query():
          try:
            if sort_col == "date":
                order_clause = (
                    "COALESCE(s.year,9999) ASC, COALESCE(s.month,99) ASC, s.start_time ASC"
                    if sort_asc else
                    "COALESCE(s.year,0) DESC, COALESCE(s.month,0) DESC, s.start_time DESC")
            else:
                _base_expr = self._SORT_EXPRS.get(sort_col)
                if _base_expr:
                    _dir = "ASC" if sort_asc else "DESC"
                    order_clause = ", ".join(
                        f"{col.strip()} {_dir}" for col in _base_expr.split(","))
                else:
                    order_clause = None

            SEL = ("SELECT s.id, s.video_id, s.title, s.channel, s.year, s.month, "
                   "s.start_time, s.end_time, s.text, s.jsonl_path FROM segments s ")
            rows = None
            if order_clause:
                try:
                    fts_q  = '"' + query.replace('"', '""') + '"'
                    sql    = SEL + ("WHERE s.id IN "
                                    "(SELECT rowid FROM segments_fts WHERE segments_fts MATCH ?)")
                    params = [fts_q]
                    if channel != "All":
                        sql += " AND s.channel=?"
                        params.append(channel)
                    if yr_from.isdigit():
                        sql += " AND s.year >= ?"
                        params.append(int(yr_from))
                    if yr_to.isdigit():
                        sql += " AND s.year <= ?"
                        params.append(int(yr_to))
                    sql  += f" ORDER BY {order_clause} LIMIT 500"
                    rows  = self._db_execute(sql, params).fetchall()
                except Exception:
                    rows = None
            if rows is None:
                try:
                    fts_q  = '"' + query.replace('"', '""') + '"'
                    sql    = ("SELECT s.id, s.video_id, s.title, s.channel, s.year, s.month, "
                              "s.start_time, s.end_time, s.text, s.jsonl_path "
                              "FROM segments_fts f JOIN segments s ON f.rowid = s.id "
                              "WHERE segments_fts MATCH ?")
                    params = [fts_q]
                    if channel != "All":
                        sql += " AND s.channel=?"
                        params.append(channel)
                    if yr_from.isdigit():
                        sql += " AND s.year >= ?"
                        params.append(int(yr_from))
                    if yr_to.isdigit():
                        sql += " AND s.year <= ?"
                        params.append(int(yr_to))
                    sql  += " ORDER BY rank LIMIT 500"
                    rows  = self._db_execute(sql, params).fetchall()
                except Exception:
                    sql    = ("SELECT id, video_id, title, channel, year, month, "
                              "start_time, end_time, text, jsonl_path "
                              "FROM segments WHERE text LIKE ?")
                    params = [f"%{query}%"]
                    if channel != "All":
                        sql += " AND channel=?"
                        params.append(channel)
                    if yr_from.isdigit():
                        sql += " AND year >= ?"
                        params.append(int(yr_from))
                    if yr_to.isdigit():
                        sql += " AND year <= ?"
                        params.append(int(yr_to))
                    # Build ORDER BY without table alias (no 's.' prefix)
                    if order_clause:
                        _like_order = order_clause.replace("s.", "")
                        sql += f" ORDER BY {_like_order}"
                    sql  += " LIMIT 500"
                    rows  = self._db_execute(sql, params).fetchall()
            self.after(0, lambda: _populate(rows or []))
          except Exception:
            # Ensure _search_running is reset even if query fails
            try:
                self.after(0, lambda: _populate([]))
            except Exception:
                self._search_running = False
                try:
                    self._search_btn.config(state="normal", text="Search")
                except Exception:
                    pass

        def _populate(rows):
            self._search_running = False
            self._tree.delete(*self._tree.get_children())
            self._result_meta.clear()
            _deferred_iids = []
            for row in rows:
                rid, video_id, title, ch, year, month, start_time, end_time, text, jsonl_path = row
                date_str = (f"{year}-{month:02d}" if year and month
                            else str(year) if year else "")
                q   = query.lower()
                idx = text.lower().find(q)
                if idx >= 0:
                    s0      = max(0, idx - 60)
                    snippet = ("…" if s0 > 0 else "") + text[s0:s0 + 160].replace("\n", " ")
                else:
                    snippet = text[:160].replace("\n", " ")
                txt_path   = self._get_txt_path(jsonl_path) if jsonl_path else None
                iid = self._tree.insert("", "end", values=(ch, date_str, title, snippet))
                self._result_meta[iid] = {
                    "video_id":   video_id,
                    "start":      start_time or 0,
                    "end":        end_time or start_time or 0,
                    "seg_text":   text,
                    "title":      title,
                    "channel":    ch,
                    "date":       date_str,
                    "jsonl_path": jsonl_path,
                    "txt_path":   txt_path,
                    "video_path": None,
                    "segment_id": rid,
                }
                if txt_path:
                    _deferred_iids.append((iid, title, txt_path))

            # Resolve video file paths on background thread to avoid blocking UI
            if _deferred_iids:
                def _resolve_video_paths():
                    resolved = []
                    for _d_iid, _d_title, _d_txt in _deferred_iids:
                        vp = self._find_video_file(_d_title, _d_txt)
                        if vp:
                            resolved.append((_d_iid, vp))
                    def _apply():
                        for _d_iid, vp in resolved:
                            meta = self._result_meta.get(_d_iid)
                            if meta:
                                meta["video_path"] = vp
                    self.after(0, _apply)
                threading.Thread(target=_resolve_video_paths, daemon=True).start()

            n         = len(rows)
            sort_note = (f", sorted by {sort_col} "
                         f"{'↑' if sort_asc else '↓'}") if sort_col else ""
            self._search_count.config(
                text=f"{'500+' if n == 500 else n} result{'s' if n != 1 else ''}{sort_note}")
            if n == 500:
                self._search_status.config(
                    text="Results capped at 500 — there may be more. Add filters to narrow down.",
                    fg="#f0a020")
            else:
                self._search_status.config(
                    text="Left-click to read  •  Right-click for actions",
                    fg=self._TP_DIM)
            # Switch Search button to Clear mode
            self._search_btn.config(
                state="normal", text="Clear", bg=self._TP_RED,
                command=self._clear_search)

        threading.Thread(target=_run_query, daemon=True).start()

    def _clear_search(self):
        """Reset the search section — clear results, query, filters, and restore Search button."""
        self._search_var.set("")
        self._s_channel_var.set("All")
        self._s_year_from_var.set("")
        self._s_year_to_var.set("")
        self._tree.delete(*self._tree.get_children())
        self._result_meta.clear()
        self._search_count.config(text="")
        self._search_status.config(
            text="Left-click to read  •  Right-click for actions",
            fg=self._TP_DIM)
        self._sort_col = "date"
        self._sort_asc = False
        self._update_heading_labels()
        # Clear the viewer panel
        self._viewer_title.config(text="Select a result to read")
        self._viewer_meta.config(text="")
        self._viewer.config(state="normal")
        self._viewer.delete("1.0", "end")
        self._viewer.config(state="disabled")
        self._viewer_section = None
        # Restore Search button
        self._search_btn.config(
            text="Search", bg=self._TP_ACCENT,
            command=self._do_search)

    def _export_csv(self):
        rows = self._tree.get_children()
        if not rows:
            messagebox.showinfo("Export CSV", "No results to export.")
            return
        path = filedialog.asksaveasfilename(
            title="Save results as CSV", defaultextension=".csv",
            filetypes=[("CSV files", "*.csv"), ("All files", "*.*")])
        if not path:
            return
        try:
            with open(path, "w", newline="", encoding="utf-8") as fh:
                w = csv.writer(fh)
                w.writerow(["Channel", "Date", "Title", "Snippet",
                            "video_id", "start_time"])
                for iid in rows:
                    vals = self._tree.item(iid, "values")
                    meta = self._result_meta.get(iid, {})
                    w.writerow([*vals, meta.get("video_id", ""),
                                meta.get("start", "")])
            messagebox.showinfo("Export CSV", f"Saved {len(rows)} rows.")
        except Exception as e:
            messagebox.showerror("Export CSV", f"Failed to save:\n{e}")

    # ── Viewer ────────────────────────────────────────────────────────────────

    _TS_LEAD_SECONDS = 5.0  # seconds of lead for external VLC / YouTube seeks

    @staticmethod
    def _interpolate_ts(start, end, seg_text, query):
        """Return exact interpolated timestamp. Lead is applied by caller."""
        if not query or not seg_text or end <= start:
            return max(0.0, start)
        idx = seg_text.lower().find(query.lower())
        if idx < 0:
            return max(0.0, start)
        ts = start + (idx / max(1, len(seg_text))) * (end - start)
        return max(0.0, ts)

    def _get_txt_path(self, jsonl_path):
        d  = os.path.dirname(jsonl_path)
        fn = os.path.basename(jsonl_path).lstrip('.')
        if fn.endswith('.jsonl'):
            fn = fn[:-6] + '.txt'
        else:
            base, _ = os.path.splitext(fn)
            fn = base + '.txt'
        return os.path.join(d, fn)

    def _find_video_file(self, title, txt_path):
        if not txt_path:
            return None
        # Build candidate directories: transcript dir, then up to 2 parents.
        # Needed because transcripts may live in split_years/split_months
        # subfolders while the actual video files sit in the channel root.
        search_dirs = []
        d = os.path.dirname(txt_path)
        for _ in range(3):
            if d not in search_dirs:
                search_dirs.append(d)
            parent = os.path.dirname(d)
            if parent == d:
                break
            d = parent
        for sd in search_dirs:
            for ext in self._TP_VIDEO_EXTS:
                p = os.path.join(sd, title + ext)
                if os.path.exists(p):
                    return p
        return None

    def _get_channel_dir(self, channel):
        """Return the archive folder path for a channel, or None."""
        if not channel:
            return None
        with config_lock:
            _base = config.get("output_dir", "").strip() or ""
            for _cc in config.get("channels", []):
                if _cc.get("name") == channel:
                    _f = _cc.get("folder_override", "").strip() or sanitize_folder(channel)
                    _d = os.path.join(_base, _f) if _base else _f
                    return _d if os.path.isdir(_d) else None
        return None

    def _find_video_in_channel(self, title, channel):
        """Search the channel's archive folder for a video matching the title.
        Handles sanitised filenames that differ from the YouTube title."""
        if not title or not channel:
            return None
        # Locate the channel folder from config
        with config_lock:
            _base = config.get("output_dir", "").strip() or ""
            _channels = config.get("channels", [])
        _ch_folder = None
        for _cc in _channels:
            if _cc.get("name") == channel:
                _f = _cc.get("folder_override", "").strip() or sanitize_folder(channel)
                _ch_folder = os.path.join(_base, _f) if _base else _f
                break
        if not _ch_folder or not os.path.isdir(_ch_folder):
            return None
        # Normalise the title for fuzzy matching
        _norm = re.sub(r'[^a-z0-9]', '', title.lower())
        if len(_norm) < 4:
            return None
        try:
            for dirpath, _, filenames in os.walk(_ch_folder):
                for fn in filenames:
                    if fn.lower().endswith(self._TP_VIDEO_EXTS):
                        _fn_stem = os.path.splitext(fn)[0]
                        _fn_norm = re.sub(r'[^a-z0-9]', '', _fn_stem.lower())
                        if _fn_norm == _norm or (
                                len(_fn_norm) >= 10 and (
                                    _norm.startswith(_fn_norm) or
                                    _fn_norm.startswith(_norm))):
                            return os.path.join(dirpath, fn)
        except OSError:
            pass
        return None

    def _get_txt_section(self, txt_path, title):
        try:
            with open(txt_path, encoding='utf-8', errors='replace') as fh:
                content = fh.read()
        except Exception:
            return None
        matches = list(self._HEADER_RE.finditer(content))
        for i, m in enumerate(matches):
            if m.group(1).strip() == title.strip():
                end = matches[i + 1].start() if i + 1 < len(matches) else len(content)
                return content[m.start():end].strip()
        return None

    def _open_vlc(self, video_path, start_time=0, title="", db_rows=None,
                  tx_status=None):
        """Open video — embedded player uses exact timestamp, external VLC
        applies a small lead offset so the user lands just before the target."""
        if _HAS_VLC:
            self._open_embedded_player(video_path, start_time, title=title,
                                       db_rows=db_rows, tx_status=tx_status)
            return True
        # Fallback: external VLC — apply lead so user lands 1-2s early
        seek = max(0.0, float(start_time) - 1.5)
        for vlc in self._VLC_PATHS:
            try:
                subprocess.Popen([vlc, os.path.normpath(video_path),
                                  f'--start-time={seek:.1f}'])
                return True
            except (FileNotFoundError, OSError):
                continue
        self._show_vlc_not_found()
        return False

    def _show_vlc_not_found(self):
        """Show a dialog with a download button when VLC is not installed."""
        import webbrowser
        dlg = tk.Toplevel(self.winfo_toplevel())
        dlg.title("VLC not found")
        dlg.configure(bg=C_BG)
        dlg.resizable(False, False)
        dlg.transient(self.winfo_toplevel())
        dlg.grab_set()
        tk.Label(dlg, text="VLC media player is required for video playback\nbut was not found on this system.",
                 bg=C_BG, fg=C_TEXT, font=("Segoe UI", 10), wraplength=360, justify="center").pack(pady=(20, 10))
        tk.Label(dlg, text="Install VLC and restart YT Archiver to enable the player.",
                 bg=C_BG, fg=C_DIM, font=("Segoe UI", 9), wraplength=360, justify="center").pack(pady=(0, 15))
        btn_frame = tk.Frame(dlg, bg=C_BG)
        btn_frame.pack(pady=(0, 20))
        tk.Button(btn_frame, text="Download VLC", bg="#2a6e2a", fg="white",
                  activebackground="#3a8e3a", activeforeground="white",
                  font=("Segoe UI", 9, "bold"), relief="flat", padx=12, pady=4,
                  command=lambda: (webbrowser.open("https://www.videolan.org/vlc/"), dlg.destroy())).pack(side="left", padx=8)
        tk.Button(btn_frame, text="Close", bg=C_BORDER, fg=C_TEXT,
                  activebackground=C_BORDER, activeforeground=C_TEXT,
                  font=("Segoe UI", 9), relief="flat", padx=12, pady=4,
                  command=dlg.destroy).pack(side="left", padx=8)
        dlg.update_idletasks()
        w, h = dlg.winfo_reqwidth() + 40, dlg.winfo_reqheight()
        x = self.winfo_toplevel().winfo_x() + (self.winfo_toplevel().winfo_width() - w) // 2
        y = self.winfo_toplevel().winfo_y() + (self.winfo_toplevel().winfo_height() - h) // 2
        dlg.geometry(f"{w}x{h}+{x}+{y}")

    def _on_result_rightclick(self, event):
        item = self._tree.identify_row(event.y)
        if not item:
            return
        self._tree.selection_set(item)
        self._load_viewer()
        self.after(10, lambda: self._show_context_menu(event.x_root, event.y_root))

    def _load_viewer(self):
        sel = self._tree.selection()
        if not sel:
            return
        meta = self._result_meta.get(sel[0])
        if not meta:
            return
        title    = meta.get("title", "")
        txt_path = meta.get("txt_path")
        query    = self._search_var.get().strip().lower()

        self._viewer_title.config(text=title)
        self._viewer_meta.config(
            text=f"{meta.get('channel', '')}  •  {meta.get('date', '')}")

        section = self._get_txt_section(txt_path, title) if txt_path else None
        if not section:
            self._viewer_section = None
            self._btn_load_earlier.grid_remove()
            self._btn_load_later.grid_remove()
            self._viewer.config(state="normal")
            self._viewer.delete("1.0", "end")
            self._viewer.insert("end",
                "(No .txt file found for this result.)\n\n", "header")
            if txt_path:
                self._viewer.insert("end", f"Expected:\n{txt_path}")
            self._viewer.config(state="disabled")
            return

        lines       = section.split('\n', 1)
        header_line = lines[0]
        body        = lines[1].strip() if len(lines) > 1 else ""

        match_pos = body.lower().find(query) if query else -1
        if match_pos < 0:
            match_pos = 0

        win_start = self._pos_n_words_before(body, match_pos, self._VIEWER_WORDS)
        win_end   = self._pos_n_words_after(
            body, match_pos + max(len(query), 1), self._VIEWER_WORDS)

        self._viewer_section   = body
        self._viewer_header    = header_line
        self._viewer_query     = query
        self._viewer_win_start = win_start
        self._viewer_win_end   = win_end
        self._render_viewer_window()

    @staticmethod
    def _pos_n_words_before(text, pos, n):
        count, i, in_space = 0, pos - 1, True
        while i >= 0 and count < n:
            if text[i] in (' ', '\n', '\t'):
                in_space = True
            elif in_space:
                count   += 1
                in_space = False
            i -= 1
        return max(0, i + 1)

    @staticmethod
    def _pos_n_words_after(text, pos, n):
        count, i, in_word = 0, pos, False
        while i < len(text) and count < n:
            if text[i] in (' ', '\n', '\t'):
                if in_word:
                    count  += 1
                    in_word = False
            else:
                in_word = True
            i += 1
        return min(len(text), i)

    def _render_viewer_window(self):
        body = self._viewer_section
        if not body:
            self._viewer.config(state="normal")
            self._viewer.delete("1.0", "end")
            self._viewer.config(state="disabled")
            self._btn_load_earlier.grid_remove()
            self._btn_load_later.grid_remove()
            return
        win_start   = self._viewer_win_start
        win_end     = self._viewer_win_end
        query       = self._viewer_query
        can_earlier = win_start > 0
        can_later   = win_end < len(body)

        if can_earlier:
            self._btn_load_earlier.grid(row=0, column=0, sticky="ew")
        else:
            self._btn_load_earlier.grid_remove()
        if can_later:
            self._btn_load_later.grid(row=2, column=0, sticky="ew")
        else:
            self._btn_load_later.grid_remove()

        chunk = body[win_start:win_end]
        self._viewer.config(state="normal")
        self._viewer.delete("1.0", "end")
        self._viewer.insert("end", self._viewer_header + "\n\n", "header")
        if can_earlier:
            self._viewer.insert("end", "…\n\n", "ellipsis")
        self._viewer.insert("end", chunk)
        if can_later:
            self._viewer.insert("end", "\n\n…", "ellipsis")
        if query:
            idx = "1.0"
            while True:
                pos = self._viewer.search(query, idx, stopindex="end", nocase=True)
                if not pos:
                    break
                self._viewer.tag_add("hit", pos, f"{pos}+{len(query)}c")
                idx = f"{pos}+{len(query)}c"
            first = self._viewer.tag_ranges("hit")
            if first:
                self._viewer.see(first[0])
        self._viewer.config(state="disabled")

    def _viewer_load_earlier(self):
        if self._viewer_section is None:
            return
        self._viewer_win_start = self._pos_n_words_before(
            self._viewer_section, self._viewer_win_start, self._VIEWER_WORDS)
        self._render_viewer_window()
        self._viewer.after(30, lambda: self._viewer.yview_moveto(0))

    def _viewer_load_later(self):
        if self._viewer_section is None:
            return
        self._viewer_win_end = self._pos_n_words_after(
            self._viewer_section, self._viewer_win_end, self._VIEWER_WORDS)
        self._render_viewer_window()
        self._viewer.after(30, lambda: self._viewer.yview_moveto(1))

    def _show_context_menu(self, x, y):
        sel = self._tree.selection()
        if not sel:
            return
        meta = self._result_meta.get(sel[0])
        if not meta:
            return

        menu = tk.Menu(self, tearoff=0, bg=self._TP_BG3, fg=self._TP_FG,
                       activebackground=self._TP_ACCENT, activeforeground="white",
                       disabledforeground=self._TP_DIM, relief="flat", bd=1)

        has_txt = bool(meta.get("txt_path") and os.path.exists(meta["txt_path"]))
        if has_txt:
            menu.add_command(label="  Open .txt  (in viewer)",
                             command=self._load_viewer)
            menu.add_command(label="  Open .txt  in Notepad",
                             command=lambda p=meta["txt_path"]:
                                 subprocess.Popen(["notepad", p]))
        else:
            menu.add_command(label="  Open .txt  (not found)", state="disabled")

        menu.add_separator()

        query = self._search_var.get().strip()
        ts    = self._interpolate_ts(
            meta["start"], meta["end"], meta.get("seg_text", ""), query)

        # Fetch DB rows for embedded player
        _search_db_rows = None
        _search_title = meta.get("title", "")
        if self._conn and _search_title:
            try:
                _search_db_rows = self._db_execute(
                    "SELECT video_id, start_time, end_time, text, words "
                    "FROM segments WHERE title=? ORDER BY start_time",
                    (_search_title,)).fetchall()
            except Exception:
                pass

        if meta.get("video_path"):
            menu.add_command(label="  ▶  Play from this point",
                             command=lambda t=ts:
                                 self._open_vlc(meta["video_path"], t,
                                                title=_search_title,
                                                db_rows=_search_db_rows))
        else:
            menu.add_command(label="  ▶  Play from this point  (file not found)",
                             state="disabled")

        if meta.get("video_id"):
            _yt_t = max(0, int(ts - self._TS_LEAD_SECONDS))
            url = (f"https://www.youtube.com/watch?v={meta['video_id']}"
                   f"&t={_yt_t}s")
            menu.add_command(label="  Open Video — YouTube",
                             command=lambda u=url: _webbrowser.open(u))
        else:
            menu.add_command(label="  Open Video — YouTube  (no ID)",
                             state="disabled")

        menu.add_separator()
        menu.add_command(label="  📋  Copy Segment Text",
                         command=lambda: self._copy_to_clipboard(meta.get("seg_text", "")))
        menu.add_command(label="  🔖  Bookmark This Segment",
                         command=lambda: self._add_bookmark(
                             meta.get("segment_id"), meta.get("video_id", ""),
                             meta.get("title", ""), meta.get("channel", ""),
                             meta.get("start", 0), meta.get("seg_text", "")))

        try:
            menu.tk_popup(x, y)
        finally:
            menu.grab_release()

    # ── Frequency section ─────────────────────────────────────────────────────

    def _build_frequency_section(self, parent):
        f = tk.Frame(parent, bg=self._TP_BG)

        # Warning banner for un-indexed videos
        self._freq_index_warn = tk.Label(f, text="", bg="#2a2000", fg="#e0b000",
                                          font=("Segoe UI", 9), anchor="w",
                                          padx=10, pady=4)
        # Packed dynamically in _show_section when needed

        bar = tk.Frame(f, bg=self._TP_BG3, padx=10, pady=8)
        bar.pack(fill="x")

        tk.Label(bar, text="Words:", bg=self._TP_BG3, fg=self._TP_FG,
                 font=("Segoe UI", 10)).pack(side="left")
        self._freq_words_var = tk.StringVar()
        self._freq_words_var.trace_add("write", self._on_freq_words_changed)
        self._freq_plotted_text = None
        e = tk.Entry(bar, textvariable=self._freq_words_var, bg=self._TP_BG2,
                     fg=self._TP_FG, insertbackground=self._TP_FG,
                     relief="flat", font=("Segoe UI", 11), width=30)
        e.pack(side="left", padx=8, ipady=5)
        e.bind("<Return>", lambda _: self._do_frequency())
        tk.Label(bar, text="(comma-separated)", bg=self._TP_BG3, fg=self._TP_DIM,
                 font=("Segoe UI", 8)).pack(side="left", padx=(0, 12))

        tk.Label(bar, text="Channel:", bg=self._TP_BG3, fg=self._TP_DIM,
                 font=("Segoe UI", 9)).pack(side="left", padx=(0, 4))
        self._freq_channel_vars = {}       # channel_name → BooleanVar
        self._freq_channel_all  = tk.BooleanVar(value=True)
        self._freq_channel_btn  = tk.Menubutton(
            bar, text="All ▾", bg=self._TP_BG2, fg=self._TP_FG,
            activebackground=self._TP_BG3, activeforeground=self._TP_FG,
            relief="flat", font=("Segoe UI", 9), padx=8, pady=2,
            indicatoron=False, cursor="hand2", width=18, anchor="w")
        self._freq_channel_menu = tk.Menu(
            self._freq_channel_btn, tearoff=0,
            bg=self._TP_BG3, fg=self._TP_FG,
            activebackground=self._TP_ACCENT, activeforeground="white")
        self._freq_channel_btn["menu"] = self._freq_channel_menu
        self._freq_channel_btn.pack(side="left", padx=(0, 12))

        tk.Label(bar, text="Group:", bg=self._TP_BG3, fg=self._TP_DIM,
                 font=("Segoe UI", 9)).pack(side="left", padx=(0, 4))
        self._freq_group_var = tk.StringVar(value="Month")
        ttk.Combobox(bar, textvariable=self._freq_group_var,
                     values=["Year", "Month"], width=7,
                     state="readonly").pack(side="left", padx=(0, 12))

        tk.Label(bar, text="Chart:", bg=self._TP_BG3, fg=self._TP_DIM,
                 font=("Segoe UI", 9)).pack(side="left", padx=(0, 4))
        self._freq_chart_var = tk.StringVar(value="Line")
        ttk.Combobox(bar, textvariable=self._freq_chart_var,
                     values=["Line", "Bar", "Word Cloud"], width=10,
                     state="readonly").pack(side="left", padx=(0, 12))

        self._freq_normalize_var = tk.BooleanVar(value=False)
        _norm_cb = tk.Checkbutton(bar, text="Normalize", variable=self._freq_normalize_var,
                       bg=self._TP_BG3, fg=self._TP_DIM, selectcolor=self._TP_BG3,
                       activebackground=self._TP_BG3, activeforeground=self._TP_FG,
                       font=("Segoe UI", 9))
        _norm_cb.pack(side="left", padx=(0, 12))
        _ToolTip(_norm_cb,
                 "Normalize adjusts the graph so channels with more content don't dominate.\n"
                 "Instead of raw mention counts, it shows mentions per 1,000 transcript\n"
                 "segments — making it fair to compare channels of different sizes.")

        self._freq_plot_btn = tk.Button(bar, text="Plot", command=self._do_frequency,
                  bg=self._TP_GREEN, fg="white", relief="flat",
                  font=("Segoe UI", 10, "bold"), padx=14,
                  pady=2)
        self._freq_plot_btn.pack(side="left")

        tk.Button(bar, text="Export CSV", command=self._export_frequency_csv,
                  bg=self._TP_BG2, fg=self._TP_FG, relief="flat",
                  font=("Segoe UI", 9), padx=10, pady=2).pack(side="left", padx=(6, 0))

        self._freq_status = tk.Label(bar, text="", bg=self._TP_BG3, fg=self._TP_DIM,
                                     font=("Segoe UI", 9))
        self._freq_status.pack(side="right", padx=8)

        if not _HAS_MPL:
            tk.Label(f, text="matplotlib not installed.\nRun:  pip install matplotlib",
                     bg=self._TP_BG, fg=self._TP_RED,
                     font=("Segoe UI", 12)).pack(expand=True)
            self._freq_canvas = None
        else:
            self._fig = Figure(figsize=(10, 4.8), dpi=96, facecolor=self._TP_BG)
            self._ax  = self._fig.add_subplot(111)
            self._style_freq_ax()
            self._freq_canvas = FigureCanvasTkAgg(self._fig, master=f)
            self._freq_canvas.get_tk_widget().pack(fill="both", expand=True,
                                                   padx=6, pady=6)
            self._freq_canvas.draw()
            self._freq_canvas.mpl_connect("button_press_event",
                                          self._on_graph_click)
            self._freq_canvas.mpl_connect("pick_event",
                                          self._on_wc_pick)
            self._wc_texts = []      # word cloud text artists for click detection
            self._wc_channels = []   # channels used for current word cloud

        self._update_freq_channels()
        return f

    def _style_freq_ax(self):
        ax = self._ax
        ax.set_facecolor(self._TP_BG2)
        ax.tick_params(colors="#888", labelsize=8)
        ax.xaxis.label.set_color("#888")
        ax.yaxis.label.set_color("#888")
        for sp in ax.spines.values():
            sp.set_edgecolor("#444")
        ax.title.set_color(self._TP_FG)
        ax.grid(color="#333", linestyle="--", linewidth=0.5, alpha=0.7)

    def _update_freq_channels(self):
        if not self._conn:
            return
        try:
            rows = self._db_execute(
                "SELECT DISTINCT channel FROM segments ORDER BY channel COLLATE NOCASE").fetchall()
            channels = [r[0] for r in rows]
        except Exception:
            channels = []

        self._freq_channel_menu.delete(0, "end")
        self._freq_channel_vars.clear()

        def _on_all_toggle():
            if self._freq_channel_all.get():
                for v in self._freq_channel_vars.values():
                    v.set(False)
            self._refresh_freq_channel_label()

        def _on_ch_toggle(ch_name):
            any_checked = any(v.get() for v in self._freq_channel_vars.values())
            self._freq_channel_all.set(not any_checked)
            self._refresh_freq_channel_label()

        self._freq_channel_menu.add_checkbutton(
            label="All", variable=self._freq_channel_all,
            command=_on_all_toggle)
        self._freq_channel_menu.add_separator()
        for ch in channels:
            var = tk.BooleanVar(value=False)
            self._freq_channel_vars[ch] = var
            self._freq_channel_menu.add_checkbutton(
                label=ch, variable=var,
                command=lambda c=ch: _on_ch_toggle(c))

    def _refresh_freq_channel_label(self):
        """Update the Menubutton text to reflect the current channel selection."""
        selected = [ch for ch, v in self._freq_channel_vars.items() if v.get()]
        if not selected or self._freq_channel_all.get():
            self._freq_channel_btn.config(text="All ▾")
        elif len(selected) == 1:
            name = selected[0]
            if len(name) > 18:
                name = name[:15] + "..."
            self._freq_channel_btn.config(text=f"{name} ▾")
        else:
            self._freq_channel_btn.config(text=f"{len(selected)} channels ▾")

    def _get_freq_selected_channels(self):
        """Return list of selected channel names, or empty list for 'All'."""
        if self._freq_channel_all.get():
            return []
        return [ch for ch, v in self._freq_channel_vars.items() if v.get()]

    def _append_channel_filter(self, sql, params, channels, col="s.channel"):
        """Append an AND channel filter clause for multi-select channels.
        If channels is empty, no filter is added (= 'All')."""
        if not channels:
            return sql
        if len(channels) == 1:
            sql += f" AND {col}=?"
            params.append(channels[0])
        else:
            placeholders = ",".join("?" * len(channels))
            sql += f" AND {col} IN ({placeholders})"
            params.extend(channels)
        return sql

    def _on_freq_words_changed(self, *_args):
        """Revert the frequency Plot button when the user edits the search text."""
        if self._freq_plotted_text is not None and self._freq_words_var.get() != self._freq_plotted_text:
            self._freq_plotted_text = None
            self._freq_plot_btn.config(
                text="Plot", bg=self._TP_GREEN,
                command=self._do_frequency)

    def _do_frequency(self):
        if not _HAS_MPL or not self._conn or not self._freq_canvas:
            return
        self._wc_texts = []  # clear word cloud state when switching chart types
        raw = self._freq_words_var.get().strip()
        def _sanitize_fts(w):
            w = re.sub(r'\b(AND|OR|NOT|NEAR)\b', '', w, flags=re.IGNORECASE)
            return w.replace('*', '').replace('+', '').replace('^', '').strip()
        words     = [_sanitize_fts(w) for w in raw.split(",") if _sanitize_fts(w)][:6] if raw else []
        channels  = self._get_freq_selected_channels()
        chart_type = self._freq_chart_var.get()

        # Word Cloud mode — completely different rendering path
        # Word Cloud allows empty words (shows overall channel vocabulary)
        if chart_type == "Word Cloud":
            self._do_word_cloud(words, channels)
            return

        if not raw:
            return

        by_month  = self._freq_group_var.get() == "Month"
        use_bar   = chart_type == "Bar"
        normalize = self._freq_normalize_var.get()

        def _bg_query():
            """Run DB queries in background thread, then update chart on main thread."""
            self._do_frequency_query(words, channels, by_month, use_bar, normalize)

        threading.Thread(target=_bg_query, daemon=True).start()

    def _do_frequency_query(self, words, channels, by_month, use_bar, normalize):
        """Background: run DB queries for frequency chart, then schedule chart update on main thread."""
        all_keys = set()
        for word in words:
            fts_q = '"' + word.replace('"', '""') + '"'
            sql   = (("SELECT DISTINCT s.year*100+s.month FROM segments s "
                      "WHERE s.id IN (SELECT rowid FROM segments_fts "
                      "WHERE segments_fts MATCH ?) "
                      "AND s.year IS NOT NULL AND s.month IS NOT NULL")
                     if by_month else
                     ("SELECT DISTINCT s.year FROM segments s "
                      "WHERE s.id IN (SELECT rowid FROM segments_fts "
                      "WHERE segments_fts MATCH ?) "
                      "AND s.year IS NOT NULL"))
            params = [fts_q]
            sql = self._append_channel_filter(sql, params, channels)
            try:
                for r in self._db_execute(sql, params):
                    all_keys.add(r[0])
            except Exception:
                pass
        all_keys = sorted(all_keys)

        month_fallback = False
        if not all_keys and by_month:
            by_month = False
            month_fallback = True
            all_keys = set()
            for word in words:
                fts_q = '"' + word.replace('"', '""') + '"'
                sql   = ("SELECT DISTINCT s.year FROM segments s "
                         "WHERE s.id IN (SELECT rowid FROM segments_fts "
                         "WHERE segments_fts MATCH ?) "
                         "AND s.year IS NOT NULL")
                params = [fts_q]
                sql = self._append_channel_filter(sql, params, channels)
                try:
                    for r in self._db_execute(sql, params):
                        all_keys.add(r[0])
                except Exception:
                    pass
            all_keys = sorted(all_keys)

        if not all_keys:
            fts_q = '"' + words[0].replace('"', '""') + '"'
            try:
                chk = self._db_execute(
                    "SELECT COUNT(*) FROM segments_fts "
                    "WHERE segments_fts MATCH ?", [fts_q]).fetchone()[0]
                msg = (f"'{words[0]}': {chk:,} match(es) but none have year data."
                       if chk > 0 else
                       f"No data found for: {', '.join(words)}")
            except Exception:
                msg = "No data found."
            def _show_empty(m=msg):
                self._freq_status.config(text=m)
                self._ax.clear()
                self._style_freq_ax()
                self._freq_canvas.draw()
            self.after(0, _show_empty)
            return

        # Gather normalization totals (DB query)
        if normalize:
            tot_sql = (("SELECT year*100+month, COUNT(*) FROM segments "
                        "WHERE year IS NOT NULL AND month IS NOT NULL")
                       if by_month else
                       "SELECT year, COUNT(*) FROM segments WHERE year IS NOT NULL")
            tot_params = []
            tot_sql = self._append_channel_filter(tot_sql, tot_params, channels, col="channel")
            tot_sql += " GROUP BY year, month" if by_month else " GROUP BY year"
            totals = {r[0]: r[1] for r in self._db_execute(tot_sql, tot_params)}
        else:
            totals = {}

        # Gather per-word counts (DB queries)
        word_data = []  # list of (word, ys)
        for word in words:
            fts_q = '"' + word.replace('"', '""') + '"'
            sql   = (("SELECT s.year*100+s.month, COUNT(*) FROM segments s "
                      "WHERE s.id IN (SELECT rowid FROM segments_fts "
                      "WHERE segments_fts MATCH ?) "
                      "AND s.year IS NOT NULL AND s.month IS NOT NULL")
                     if by_month else
                     ("SELECT s.year, COUNT(*) FROM segments s "
                      "WHERE s.id IN (SELECT rowid FROM segments_fts "
                      "WHERE segments_fts MATCH ?) "
                      "AND s.year IS NOT NULL"))
            params = [fts_q]
            sql = self._append_channel_filter(sql, params, channels)
            sql += " GROUP BY s.year, s.month" if by_month else " GROUP BY s.year"
            try:
                counts = {r[0]: r[1] for r in self._db_execute(sql, params)}
            except Exception:
                counts = {}
            ys = [counts.get(k, 0) for k in all_keys]
            if normalize:
                ys = [1000 * c / max(1, totals.get(k, 1))
                      for c, k in zip(ys, all_keys)]
            word_data.append((word, ys))

        # Cache data for CSV export (reused by _export_frequency_csv to avoid re-querying)
        self._freq_all_keys = list(all_keys)
        self._freq_words    = words
        self._freq_by_month = by_month
        self._freq_word_data = word_data  # list of (word, ys) for CSV export

        # Schedule chart rendering on main thread
        def _render():
            self._freq_status.config(
                text="  (no month data — grouped by year)" if month_fallback else "")

            tick_labels = ([f"{k // 100}-{k % 100:02d}" for k in all_keys]
                           if by_month else [str(k) for k in all_keys])

            self._ax.clear()
            self._style_freq_ax()

            palette   = ["#4a9eff", "#ff6b6b", "#4caf50", "#ffd700", "#c792ea", "#89ddff"]
            n_words   = len(words)
            bar_width = 0.8 / max(n_words, 1)
            xs        = list(range(len(all_keys)))

            for i, (word, ys) in enumerate(word_data):
                color = palette[i % len(palette)]
                if use_bar:
                    offset = (i - (n_words - 1) / 2) * bar_width
                    self._ax.bar([x + offset for x in xs], ys,
                                 width=bar_width, color=color,
                                 label=word, alpha=0.85)
                else:
                    self._ax.plot(xs, ys, marker="o", markersize=4,
                                  linewidth=2, color=color, label=word)

            n = len(tick_labels)
            try:
                canvas_w = self._freq_canvas.get_tk_widget().winfo_width()
            except Exception:
                canvas_w = 900
            max_labels = max(4, canvas_w // 55)
            if n > max_labels:
                step    = (n + max_labels - 1) // max_labels
                visible = list(range(0, n, step))
            else:
                visible = list(range(n))
            self._ax.set_xticks(visible)
            self._ax.set_xticklabels([tick_labels[i] for i in visible],
                                      rotation=45, ha="right", fontsize=8)
            ylabel = ("Mentions per 1,000 segments" if normalize
                      else "Segment mentions")
            self._ax.set_ylabel(ylabel, color="#888", fontsize=9)
            if channels:
                ch_label = ", ".join(channels) if len(channels) <= 2 else f"{len(channels)} channels"
            else:
                ch_label = "all channels"
            self._ax.set_title(f"Word frequency — {ch_label}", fontsize=11)
            if len(words) > 1:
                self._ax.legend(facecolor=self._TP_BG2, edgecolor="#444",
                                labelcolor=self._TP_FG, fontsize=9)
            self._fig.tight_layout()
            self._freq_canvas.draw()

            # Switch Plot button to Clear mode
            self._freq_plotted_text = self._freq_words_var.get()
            self._freq_plot_btn.config(
                text="Clear", bg=self._TP_RED,
                command=self._clear_frequency)
        self.after(0, _render)

    def _clear_frequency(self):
        """Reset the frequency section — clear chart, words, and restore Plot button."""
        self._freq_plotted_text = None
        self._freq_words_var.set("")
        self._freq_status.config(text="")
        self._freq_all_keys = []
        self._freq_words    = []
        self._freq_by_month = False
        self._wc_texts = []
        self._wc_channels = []
        if self._freq_canvas:
            self._ax.clear()
            self._style_freq_ax()
            self._freq_canvas.draw()
        self._freq_plot_btn.config(
            text="Plot", bg=self._TP_GREEN,
            command=self._do_frequency)

    def _do_word_cloud(self, seed_words, channels):
        """Render a word cloud using top co-occurring words from transcription segments.
        If seed_words is empty, samples random segments from the selected channels.
        Clicking a word in the cloud re-seeds the cloud with that word (explore connections)."""
        if not _HAS_MPL or not self._conn or not self._freq_canvas:
            return
        def _bg():
            self._do_word_cloud_bg(seed_words, channels)
        threading.Thread(target=_bg, daemon=True).start()

    def _do_word_cloud_bg(self, seed_words, channels):
        """Background thread: gather word cloud data, then schedule rendering on main thread."""
        import random as _rng
        # Find segments containing the seed words and extract surrounding vocabulary
        word_counts = {}
        _stop = self._WC_STOP_WORDS

        def _clean_word(w):
            """Strip contraction suffixes and filter junk."""
            w = re.sub(r"'(s|t|re|ve|ll|d|m)$", "", w)
            if len(w) < 3 or w in _stop:
                return None
            return w

        seed_lower = {sw.lower() for sw in seed_words}
        if seed_words:
            for word in seed_words:
                fts_q = '"' + word.replace('"', '""') + '"'
                sql = ("SELECT s.text FROM segments s "
                       "WHERE s.id IN (SELECT rowid FROM segments_fts "
                       "WHERE segments_fts MATCH ?) LIMIT 2000")
                params = [fts_q]
                sql = self._append_channel_filter(sql, params, channels)
                try:
                    rows = self._db_execute(sql, params).fetchall()
                except Exception:
                    continue
                for (text,) in rows:
                    for raw in re.findall(r"[a-zA-Z']{3,}", text.lower()):
                        w = _clean_word(raw)
                        if w and w not in seed_lower:
                            word_counts[w] = word_counts.get(w, 0) + 1
            # Always include seed words with boosted counts
            for sw in seed_words:
                fts_q = '"' + sw.replace('"', '""') + '"'
                sql = ("SELECT COUNT(*) FROM segments_fts WHERE segments_fts MATCH ?")
                try:
                    cnt = self._db_execute(sql, (fts_q,)).fetchone()[0]
                except Exception:
                    cnt = 50
                word_counts[sw.lower()] = max(word_counts.get(sw.lower(), 0), cnt)
        else:
            # No seed words — sample random segments from selected channels
            sql = "SELECT s.text FROM segments s WHERE 1=1"
            params = []
            sql = self._append_channel_filter(sql, params, channels)
            sql += " ORDER BY RANDOM() LIMIT 5000"
            try:
                rows = self._db_execute(sql, params).fetchall()
            except Exception:
                rows = []
            for (text,) in rows:
                for raw in re.findall(r"[a-zA-Z']{3,}", text.lower()):
                    w = _clean_word(raw)
                    if w:
                        word_counts[w] = word_counts.get(w, 0) + 1

        if not word_counts:
            self.after(0, lambda: self._freq_status.config(text="No data for word cloud."))
            return

        # Get top 150 words
        top = sorted(word_counts.items(), key=lambda x: x[1], reverse=True)[:150]
        max_count = top[0][1] if top else 1

        # Schedule rendering on main thread
        def _render_wc():
            import random as _rng2
            self._ax.clear()
            self._ax.set_facecolor(self._TP_BG2)
            self._ax.set_xlim(0, 1)
            self._ax.set_ylim(0, 1)
            self._ax.axis("off")
            palette = ["#4a9eff", "#ff6b6b", "#4caf50", "#ffd700", "#c792ea",
                       "#89ddff", "#f78c6c", "#82aaff", "#c3e88d", "#ffcb6b",
                       "#e06c75", "#56b6c2", "#d19a66", "#98c379"]
            _rng2.seed(42)  # deterministic layout so the cloud doesn't jump on re-plot
            _WC_CENTER = 0.5
            _WC_MIN_R  = 0.10
            _WC_R_SCALE = 0.38
            self._wc_texts = []  # store text artists for click detection
            for i, (word, count) in enumerate(top):
                # Size: 6-28pt based on count proportion
                size = 6 + 22 * (count / max_count)
                color = palette[i % len(palette)]
                # Highlight seed words
                if word in seed_lower:
                    color = "#ffffff"
                    size = min(size * 1.3, 32)
                # Place words using a spiral-ish layout
                angle = i * 137.508  # golden angle in degrees
                r = _WC_MIN_R + _WC_R_SCALE * (i / max(len(top), 1))
                x = _WC_CENTER + r * _rng2.uniform(-1, 1)
                y = _WC_CENTER + r * _rng2.uniform(-1, 1)
                x = max(0.03, min(0.97, x))
                y = max(0.03, min(0.97, y))
                txt = self._ax.text(x, y, word, fontsize=size, color=color,
                              ha="center", va="center",
                              fontweight="bold" if count > max_count * 0.5 else "normal",
                              alpha=0.6 + 0.4 * (count / max_count),
                              picker=True)
                self._wc_texts.append(txt)
            ch_label = (", ".join(channels[:2]) if channels else "all channels")
            title_parts = ["Word Cloud"]
            if seed_words:
                title_parts.append(f"seeded: {', '.join(seed_words[:3])}")
            title_parts.append(ch_label)
            self._ax.set_title(" — ".join(title_parts), fontsize=11,
                              color=self._TP_FG)
            hint = "Click a word to explore its connections"
            self._ax.text(0.5, 0.01, hint, fontsize=7, color="#666",
                          ha="center", va="bottom", transform=self._ax.transAxes)
            self._fig.tight_layout()
            self._freq_canvas.draw()
            self._freq_status.config(text=f"{len(top)} words plotted  ·  click a word to explore")
            self._freq_all_keys = []
            self._freq_words    = seed_words
            self._freq_by_month = False
            self._freq_plotted_text = self._freq_words_var.get()
            self._wc_channels = channels  # remember channels for click-to-explore
            self._freq_plot_btn.config(
                text="Clear", bg=self._TP_RED,
                command=self._clear_frequency)
        self.after(0, _render_wc)

    def _export_frequency_csv(self):
        """Export the current frequency chart data to a CSV file."""
        if not self._freq_all_keys or not self._freq_words:
            messagebox.showinfo("Export", "No frequency data to export. Plot something first.")
            return
        path = filedialog.asksaveasfilename(
            title="Save frequency data as CSV", defaultextension=".csv",
            filetypes=[("CSV files", "*.csv"), ("All files", "*.*")])
        if not path:
            return
        try:
            by_month = self._freq_by_month
            # Use cached word_data from _do_frequency_query if available (avoids re-querying DB on main thread)
            _cached = getattr(self, '_freq_word_data', None)
            _word_ys = {}
            if _cached and len(_cached) == len(self._freq_words):
                for _w, _ys in _cached:
                    _word_ys[_w] = _ys
            with open(path, "w", newline="", encoding="utf-8") as fh:
                w = csv.writer(fh)
                w.writerow(["Period"] + self._freq_words)
                for ki, key in enumerate(self._freq_all_keys):
                    label = (f"{key // 100}-{key % 100:02d}" if by_month else str(key))
                    row_data = [label]
                    for word in self._freq_words:
                        if word in _word_ys and ki < len(_word_ys[word]):
                            cnt = _word_ys[word][ki]
                        else:
                            # Fallback: query DB (should not normally happen)
                            channels = self._get_freq_selected_channels()
                            fts_q = '"' + word.replace('"', '""') + '"'
                            sql = (("SELECT COUNT(*) FROM segments s "
                                    "WHERE s.id IN (SELECT rowid FROM segments_fts "
                                    "WHERE segments_fts MATCH ?) "
                                    "AND s.year*100+s.month=?")
                                   if by_month else
                                   ("SELECT COUNT(*) FROM segments s "
                                    "WHERE s.id IN (SELECT rowid FROM segments_fts "
                                    "WHERE segments_fts MATCH ?) "
                                    "AND s.year=?"))
                            params = [fts_q, key]
                            sql = self._append_channel_filter(sql, params, channels)
                            try:
                                cnt = self._db_execute(sql, params).fetchone()[0]
                            except Exception:
                                cnt = 0
                        row_data.append(cnt)
                    w.writerow(row_data)
            messagebox.showinfo("Export", f"Saved {len(self._freq_all_keys)} rows.")
        except Exception as e:
            messagebox.showerror("Export", f"Failed to save:\n{e}")

    def _on_wc_pick(self, event):
        """Handle click on a word cloud text — re-seed the cloud with the clicked word."""
        if not hasattr(self, '_wc_texts') or not self._wc_texts:
            return
        artist = event.artist
        if artist not in self._wc_texts:
            return
        clicked_word = artist.get_text()
        if not clicked_word:
            return
        # Set the clicked word as the new seed and re-run the word cloud
        self._freq_words_var.set(clicked_word)
        channels = getattr(self, '_wc_channels', [])
        self._do_word_cloud([clicked_word], channels)

    def _on_graph_click(self, event):
        if event.inaxes != self._ax:
            return
        if not self._freq_all_keys or not self._freq_words:
            return
        x = event.xdata
        if x is None:
            return
        idx = int(round(x))
        if idx < 0 or idx >= len(self._freq_all_keys):
            return
        key  = self._freq_all_keys[idx]
        year = key // 100 if self._freq_by_month else key
        self._s_year_from_var.set(str(year))
        self._s_year_to_var.set(str(year))
        self._search_var.set(", ".join(self._freq_words))
        self._show_section("search")
        self._do_search()

