    def _open_embedded_player(self, video_path, start_time=0, title="",
                              db_rows=None, tx_status=None):
        """Open a video in the embedded player with synced transcript."""
        if not _HAS_VLC:
            return self._open_vlc(video_path, start_time)

        self._player_video_path = video_path
        _player_display_title = title if title else os.path.basename(video_path)
        # Append resolution if known from browse meta
        if (self._browse_current_meta and
                self._browse_current_meta.get("title") == title and
                self._browse_current_meta.get("resolution")):
            _player_display_title += f"  ({self._browse_current_meta['resolution']})"
        self._player_title_lbl.config(text=_player_display_title)

        # ── Build transcript ──────────────────────────────────────────
        self._player_words = []
        self._player_segs = []
        self._player_prev_tag = None  # for efficient highlight removal
        self._player_transcript.config(state="normal")
        self._player_transcript.delete("1.0", "end")

        # Strategy: use the .txt file for display (punctuated, complete,
        # no duplicates), then map word-level timestamps proportionally.
        body = ""
        txt_body_found = False

        # Try to find the .txt transcript file from the video path
        if video_path and title:
            vdir = os.path.dirname(video_path)
            # Search for .txt files in the directory and up to 2 parents
            search_dirs = [vdir]
            for _ in range(2):
                p = os.path.dirname(search_dirs[-1])
                if p != search_dirs[-1]:
                    search_dirs.append(p)
            _tx_header = ""
            for sd in search_dirs:
                try:
                    for fn in os.listdir(sd):
                        if fn.lower().endswith('.txt') and not fn.startswith('.'):
                            fpath = os.path.join(sd, fn)
                            section = self._get_txt_section(fpath, title)
                            if section:
                                lines = section.split('\n', 1)
                                _tx_header = lines[0]
                                body = lines[1].strip() if len(lines) > 1 else ""
                                if body:
                                    txt_body_found = True
                            if txt_body_found:
                                break
                except Exception:
                    pass
                if txt_body_found:
                    break

        if not txt_body_found and db_rows:
            # Fallback: join seg_text but deduplicate overlapping portions.
            # Only include seg_text that starts AFTER the previous segment's
            # end time to avoid rolling-caption duplicates.
            parts = []
            max_end = -1.0
            for vid, start, end, seg_text, words_json in db_rows:
                if start >= max_end - 0.5:  # new content
                    parts.append(seg_text)
                max_end = max(max_end, end)
            body = " ".join(parts)

        _body_char_offset = 0  # chars before body in the text widget
        if body:
            # Show notice if transcript text exists but no word timing data
            if not db_rows:
                _notice = ("Word-by-word highlight unavailable — rebuild the index "
                           "(Browse → Index → Build / Update) to enable.\n\n")
                self._player_transcript.tag_configure(
                    "db_notice", foreground="#888888",
                    font=("Segoe UI", 9, "italic"))
                self._player_transcript.insert("end", _notice, "db_notice")
                _body_char_offset += len(_notice)
            # Show accuracy notice for YT-sourced transcripts (clickable)
            _is_yt_source = txt_body_found and _tx_header and (
                "YT+PUNCTUATION" in _tx_header or "YT CAPTIONS" in _tx_header)
            if _is_yt_source and db_rows:
                _yt_notice = "Highlight timing is approximate — "
                _yt_link = "re-transcribe with Whisper"
                _yt_suffix = " for word-accurate sync.\n\n"
                self._player_transcript.tag_configure(
                    "yt_notice", foreground="#7a6a3a",
                    font=("Segoe UI", 8, "italic"))
                self._player_transcript.tag_configure(
                    "yt_retranscribe", foreground="#9a8a4a",
                    font=("Segoe UI", 8, "italic underline"))
                self._player_transcript.tag_bind(
                    "yt_retranscribe", "<Enter>",
                    lambda e: self._player_transcript.config(cursor="hand2"))
                self._player_transcript.tag_bind(
                    "yt_retranscribe", "<Leave>",
                    lambda e: self._player_transcript.config(cursor="xterm"))
                self._player_transcript.tag_bind(
                    "yt_retranscribe", "<Button-1>",
                    lambda e: self._on_retranscribe())
                self._player_transcript.insert("end", _yt_notice, "yt_notice")
                self._player_transcript.insert("end", _yt_link, "yt_retranscribe")
                self._player_transcript.insert("end", _yt_suffix, "yt_notice")
                _body_char_offset += len(_yt_notice) + len(_yt_link) + len(_yt_suffix)
            self._player_transcript.insert("end", body + "\n")
        else:
            if tx_status == "no_captions":
                self._player_transcript.insert("end",
                    "No captions available — video contains no detectable speech.\n")
            elif tx_status == "error":
                self._player_transcript.insert("end",
                    "Transcription error — try re-transcribing this video.\n")
            elif tx_status == "pending":
                self._player_transcript.insert("end",
                    "Transcription not yet processed.\n")
            else:
                self._player_transcript.insert("end",
                    "(No transcript data available for this video.)\n")

        # ── Build word timing map ─────────────────────────────────────
        # Collect all words with timestamps from DB, deduplicate, sort.
        all_words = []
        if db_rows:
            for vid, start, end, seg_text, words_json in db_rows:
                if words_json:
                    try:
                        wlist = json.loads(words_json)
                        for w in wlist:
                            all_words.append((
                                w.get("s", start),
                                w.get("e", end),
                                w.get("w", "")
                            ))
                    except Exception:
                        pass
            all_words.sort(key=lambda x: x[0])
            # Deduplicate by time (overlapping VTT can repeat words)
            deduped = []
            for s, e, w in all_words:
                if deduped and abs(s - deduped[-1][0]) < 0.05:
                    continue
                deduped.append((s, e, w))
            all_words = deduped

        # Map word timestamps to character positions in the displayed body.
        # Uses sequential forward-matching: a cursor advances through the body
        # text so each word maps to a position AFTER the previous one.  This
        # guarantees monotonically increasing positions (no highlight jumping).
        # Performance: instead of creating thousands of individual tk.Text tags
        # (which degrades to near-quadratic), we store char offsets in a list
        # and move a single "active_word" tag during playback.
        if all_words and body:
            body_lower = body.lower()
            body_len = len(body)
            cursor = 0       # current search position — only moves forward

            for s, e, w in all_words:
                w_lower = w.lower().rstrip(".,!?;:'\"")
                if not w_lower:
                    continue

                # Search forward from cursor for this word
                best_offset = -1
                search_pos = cursor
                while search_pos <= body_len - len(w_lower):
                    idx = body_lower.find(w_lower, search_pos)
                    if idx == -1:
                        break
                    # Verify word boundary
                    before = body[idx - 1] if idx > 0 else " "
                    after_i = idx + len(w_lower)
                    after = body[after_i] if after_i < body_len else " "
                    if not before.isalpha() and (not after.isalpha()
                                                  or after in ".,!?;:'\""):
                        best_offset = idx
                        break
                    search_pos = idx + 1

                if best_offset >= 0:
                    # Determine actual word span (include trailing punctuation)
                    wend = best_offset + len(w_lower)
                    while wend < body_len and body[wend] in ".,!?;:'\")-":
                        wend += 1
                    # Store char offsets adjusted for any prefix text (notices)
                    self._player_words.append({
                        "w": w, "s": s, "e": e,
                        "cs": best_offset + _body_char_offset,
                        "ce": wend + _body_char_offset
                    })
                    cursor = wend  # advance cursor past this word
                # If word not found, skip it — don't create a bad mapping

        self._player_transcript.config(state="disabled")

        # Switch to player section
        self._show_section("player")

        # Initialize VLC — must wait for the canvas to be mapped
        self.after(100, lambda: self._player_start_vlc(video_path, start_time))

    def _player_start_vlc(self, video_path, start_time=0):
        """Create VLC instance and start playback."""
        # Clean up any existing player
        self._player_stop_vlc()

        try:
            _vol = self._player_vol.get()
            self._vlc_instance = _vlc_mod.Instance()
            self._vlc_player = self._vlc_instance.media_player_new()
            # Mute until pending volume is applied (prevents loud startup)
            self._vlc_player.audio_set_mute(True)

            # Embed in the tkinter frame
            hwnd = self._player_canvas.winfo_id()
            self._vlc_player.set_hwnd(hwnd)

            # Let mouse/keyboard events pass through to tkinter (click-to-pause)
            self._vlc_player.video_set_mouse_input(False)
            self._vlc_player.video_set_key_input(False)

            # Set media
            media = self._vlc_instance.media_new(video_path)
            self._vlc_player.set_media(media)

            # Start playback
            self._vlc_player.play()
            self._player_active = True
            self._player_vol_pending = True  # set volume once playing

            # Seek to start time after VLC begins playing
            if start_time > 0:
                self._player_seek_pending = float(start_time)
            else:
                self._player_seek_pending = 0.0

            # Start polling loop
            self._player_poll()
        except Exception as e:
            messagebox.showerror("Player Error",
                                 f"Failed to start embedded player:\n{e}\n\n"
                                 "Falling back to external VLC.")
            # Return UI to browse section before falling back to external VLC
            self._show_section("browse")
            # Fall back directly to external VLC (avoid recursion via _open_vlc)
            seek = max(0.0, float(start_time))
            _vlc_launched = False
            for vlc_path in self._VLC_PATHS:
                try:
                    subprocess.Popen([vlc_path, os.path.normpath(video_path),
                                      f'--start-time={seek:.1f}'])
                    _vlc_launched = True
                    break
                except (FileNotFoundError, OSError):
                    continue
            if not _vlc_launched:
                log("  ⚠ VLC not found — install VLC to play videos.\n", "red")

    def _player_stop_vlc(self):
        """Stop and release the VLC player."""
        if self._player_poll_id is not None:
            self.after_cancel(self._player_poll_id)
            self._player_poll_id = None
        if self._vlc_player:
            try:
                self._vlc_player.stop()
                self._vlc_player.release()
            except Exception:
                pass
            self._vlc_player = None
        if self._vlc_instance:
            try:
                self._vlc_instance.release()
            except Exception:
                pass
            self._vlc_instance = None
        self._player_active = False

    def _close_player(self):
        """Close the player and return to browse."""
        self._player_stop_vlc()
        self._player_last_word_idx = -1

        self._show_section("browse")

    def _player_toggle_pause(self):
        if not self._vlc_player:
            return
        if self._vlc_player.is_playing():
            self._vlc_player.pause()
            self._player_play_btn.config(text="▶")
        else:
            self._vlc_player.play()
            self._player_play_btn.config(text="⏸")

    def _player_seek(self, time_sec):
        """Seek to a specific time in seconds.
        Pauses briefly before seeking to work around VLC's set_time()
        becoming unresponsive after rapid successive calls during playback."""
        if not self._vlc_player:
            return
        ms = int(time_sec * 1000)
        was_playing = self._vlc_player.is_playing()
        if was_playing:
            self._vlc_player.pause()
        self._vlc_player.set_time(ms)
        # Reset word highlight tracking so it jumps to the new position
        self._player_last_word_idx = -1
        if was_playing:
            self._vlc_player.play()

    def _player_on_slider_drag(self, event):
        """Update the time label in real-time while the user drags the slider."""
        if not self._vlc_player:
            return
        dur_ms = self._vlc_player.get_length()
        if dur_ms > 0:
            pos = self._player_slider.get() / 1000.0
            preview_ms = int(pos * dur_ms)
            self._player_time_lbl.config(
                text=f"{self._fmt_player_time(preview_ms)} / {self._fmt_player_time(dur_ms)}")

    def _player_on_slider_release(self, event):
        self._player_seeking = False
        if not self._vlc_player:
            return
        duration = self._vlc_player.get_length()
        if duration > 0:
            pos = self._player_slider.get() / 1000.0
            self._vlc_player.set_position(pos)
            self._player_last_word_idx = -1  # reset word highlight

    def _player_on_follow_toggle(self):
        """When Follow is turned on, immediately scroll to the current word."""
        if self._player_follow_var.get() and self._player_last_word_idx >= 0:
            idx = self._player_last_word_idx
            if 0 <= idx < len(self._player_words):
                cs = f"1.0+{self._player_words[idx]['cs']}c"
                self._player_transcript.yview_pickplace(cs)

    def _player_on_volume(self, val):
        """Debounced volume change — only calls VLC after slider stops moving."""
        if self._player_vol_debounce_id is not None:
            self.after_cancel(self._player_vol_debounce_id)
        self._player_vol_debounce_id = self.after(
            50, lambda: self._player_apply_volume(int(float(val))))

    def _player_apply_volume(self, vol):
        """Actually set VLC volume (called after debounce delay)."""
        self._player_vol_debounce_id = None
        if self._vlc_player:
            try:
                self._vlc_player.audio_set_volume(vol)
            except Exception:
                pass

    def _player_on_transcript_click(self, event):
        """Click a word in the transcript to seek to it.
        Uses binary search on stored char offsets instead of per-word tags."""
        if not self._vlc_player or not self._player_words:
            return
        idx = self._player_transcript.index(f"@{event.x},{event.y}")
        # Convert text index to char offset from start
        try:
            char_offset = len(self._player_transcript.get("1.0", idx))
        except Exception:
            return
        # Binary search for the word whose char range contains this offset
        lo, hi = 0, len(self._player_words) - 1
        found = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            wd = self._player_words[mid]
            if char_offset < wd["cs"]:
                hi = mid - 1
            elif char_offset >= wd["ce"]:
                lo = mid + 1
            else:
                found = mid
                break
        # If click landed between words (on a space), use the nearest word
        if found < 0 and self._player_words:
            # lo is the insertion point — nearest word is lo or lo-1
            if lo >= len(self._player_words):
                found = len(self._player_words) - 1
            elif lo == 0:
                found = 0
            else:
                # Pick whichever word boundary is closer
                dist_prev = char_offset - self._player_words[lo - 1]["ce"]
                dist_next = self._player_words[lo]["cs"] - char_offset
                found = lo - 1 if dist_prev <= dist_next else lo
        if 0 <= found < len(self._player_words):
            seek_time = max(0, self._player_words[found]["s"])
            self._player_seek(seek_time)
            if not self._vlc_player.is_playing():
                self._vlc_player.play()
                self._player_play_btn.config(text="⏸")
            return

    def _fmt_player_time(self, ms):
        """Format milliseconds to M:SS or H:MM:SS."""
        s = max(0, ms // 1000)
        h, s = divmod(s, 3600)
        m, s = divmod(s, 60)
        if h:
            return f"{h}:{m:02d}:{s:02d}"
        return f"{m}:{s:02d}"

    def _player_poll(self):
        """Periodic update of slider, time label, and word highlighting."""
        if not self._player_active or not self._vlc_player:
            return

        try:
            state = self._vlc_player.get_state()
            if state in (_vlc_mod.State.Ended, _vlc_mod.State.Error):
                self._player_play_btn.config(text="▶")
                self._player_poll_id = None
                return

            # Apply pending volume/seek once VLC reports playing
            if self._vlc_player.is_playing():
                if getattr(self, '_player_vol_pending', False):
                    self._vlc_player.audio_set_volume(self._player_vol.get())
                    self._vlc_player.audio_set_mute(False)
                    self._player_vol_pending = False
                seek_t = getattr(self, '_player_seek_pending', 0.0)
                if seek_t > 0:
                    self._vlc_player.set_time(int(seek_t * 1000))
                    self._player_seek_pending = 0.0

            # Update play/pause button
            if self._vlc_player.is_playing():
                self._player_play_btn.config(text="⏸")
            else:
                self._player_play_btn.config(text="▶")

            # Update time and slider (skip slider update while user is dragging)
            cur_ms = self._vlc_player.get_time()
            dur_ms = self._vlc_player.get_length()
            if dur_ms > 0 and not self._player_seeking:
                self._player_time_lbl.config(
                    text=f"{self._fmt_player_time(cur_ms)} / {self._fmt_player_time(dur_ms)}")
                pos = self._vlc_player.get_position()
                self._player_slider.set(int(pos * 1000))

            # Highlight active word
            cur_sec = cur_ms / 1000.0
            self._player_highlight_word(cur_sec)

        except Exception as _poll_err:
            try:
                log(f"  Player poll error: {_poll_err}\n", "dim")
            except Exception:
                pass

        # Poll faster when playing (smooth word highlighting), slower when paused
        try:
            _interval = 100 if self._vlc_player.is_playing() else 500
        except Exception:
            _interval = 100
        self._player_poll_id = self.after(_interval, self._player_poll)

    def _player_highlight_word(self, cur_sec):
        """Highlight the word currently being spoken — single word, no skipping.
        Instead of jumping to wherever VLC reports, we step forward one word
        at a time so every word gets highlighted for at least one poll cycle.
        Uses char offsets stored in _player_words instead of per-word tags
        for O(1) highlight updates regardless of transcript length."""
        if not self._player_words:
            return

        # Binary search for the latest word with start <= cur_sec
        target = -1
        lo, hi = 0, len(self._player_words) - 1
        while lo <= hi:
            mid = (lo + hi) // 2
            if self._player_words[mid]["s"] <= cur_sec:
                target = mid
                lo = mid + 1
            else:
                hi = mid - 1

        prev = self._player_last_word_idx

        if target < prev:
            # Seeking backward - jump directly to target (or clear if -1)
            new_idx = target
        elif target == prev:
            return  # still on same word - no change
        else:
            # Step forward one word at a time for smooth playback,
            # but jump directly if the gap is large (indicates a user seek)
            if prev >= 0 and target > prev + 1:
                if target - prev > 5:
                    new_idx = target  # large gap = user seeked forward
                else:
                    new_idx = prev + 1  # small gap = normal playback, advance by one
            else:
                new_idx = target

        if new_idx == prev:
            return

        self._player_last_word_idx = new_idx

        # Remove previous highlight — use targeted removal if we know the previous word
        if 0 <= prev < len(self._player_words):
            _pd = self._player_words[prev]
            self._player_transcript.tag_remove(
                "active_word", f"1.0+{_pd['cs']}c", f"1.0+{_pd['ce']}c")
        else:
            self._player_transcript.tag_remove("active_word", "1.0", "end")

        # Add highlight to new word using stored char offsets
        if 0 <= new_idx < len(self._player_words):
            word_data = self._player_words[new_idx]
            cs = f"1.0+{word_data['cs']}c"
            ce = f"1.0+{word_data['ce']}c"
            self._player_transcript.tag_add("active_word", cs, ce)
            if self._player_follow_var.get():
                try:
                    bbox = self._player_transcript.bbox(cs)
                    if bbox:
                        _wid_h = self._player_transcript.winfo_height()
                        _word_y = bbox[1]
                        if _word_y > _wid_h * 0.5:
                            self._player_transcript.yview_pickplace(cs)
                except Exception:
                    self._player_transcript.see(cs)
            else:
                # Default: just ensure visible every ~5 words
                if abs(new_idx - (prev if prev >= 0 else 0)) >= 3:
                    self._player_transcript.see(cs)

    # ── Index section ─────────────────────────────────────────────────────────

    def _build_index_section(self, parent):
        f = tk.Frame(parent, bg=self._TP_BG)

        # Archive roots
        rf = tk.Frame(f, bg=self._TP_BG2)
        rf.pack(fill="x", padx=14, pady=(12, 6))
        tk.Label(rf, text="Archive Roots", bg=self._TP_BG2, fg=self._TP_ACCENT,
                 font=("Segoe UI", 9, "bold")).pack(anchor="w", padx=4, pady=(6, 2))

        self._roots_lb = tk.Listbox(rf, bg=self._TP_BG, fg=self._TP_FG,
                                     selectbackground=self._TP_ACCENT,
                                     font=("Segoe UI", 9), height=4, relief="flat",
                                     activestyle="none")
        self._roots_lb.pack(fill="x", padx=4, pady=(0, 4))
        self._roots_lb.bind("<Button-3>", self._roots_lb_rightclick)
        self._refresh_roots_listbox()

        btn_r = tk.Frame(rf, bg=self._TP_BG2)
        btn_r.pack(fill="x", padx=4, pady=(0, 6))
        for txt, cmd in [("Add Folder", self._tp_add_root),
                          ("Remove Selected", self._tp_remove_root)]:
            tk.Button(btn_r, text=txt, command=cmd, bg=self._TP_BG3, fg=self._TP_FG,
                      relief="flat", font=("Segoe UI", 9),
                      padx=10, pady=3).pack(side="left", padx=(0, 6))

        # Stats
        sf = tk.Frame(f, bg=self._TP_BG2)
        sf.pack(fill="x", padx=14, pady=6)
        tk.Label(sf, text="Index Stats", bg=self._TP_BG2, fg=self._TP_ACCENT,
                 font=("Segoe UI", 9, "bold")).pack(anchor="w", padx=4, pady=(6, 2))
        self._stats_txt = tk.Text(sf, bg=self._TP_BG, fg="#ccc",
                                   font=("Consolas", 9), height=7,
                                   relief="flat", state="disabled")
        self._stats_txt.pack(fill="x", padx=4, pady=(0, 6))

        # Action buttons
        bf = tk.Frame(f, bg=self._TP_BG, padx=14, pady=6)
        bf.pack(fill="x")
        tk.Button(bf, text="Build / Update Index", command=self._start_index,
                  bg=self._TP_GREEN, fg="white", relief="flat",
                  font=("Segoe UI", 11, "bold"), padx=18,
                  pady=5).pack(side="left")
        tk.Button(bf, text="Rebuild from Scratch",
                  command=self._confirm_rebuild,
                  bg=self._TP_BG3, fg=self._TP_FG, relief="flat",
                  font=("Segoe UI", 10), padx=12,
                  pady=5).pack(side="left", padx=10)
        self._idx_progress_var = tk.StringVar()
        tk.Label(bf, textvariable=self._idx_progress_var, bg=self._TP_BG,
                 fg=self._TP_DIM, font=("Segoe UI", 9)).pack(side="left", padx=8)

        # Log
        lf = tk.Frame(f, bg=self._TP_BG)
        lf.pack(fill="both", expand=True, padx=14, pady=6)
        tk.Label(lf, text="Log", bg=self._TP_BG, fg=self._TP_ACCENT,
                 font=("Segoe UI", 9, "bold")).pack(anchor="w")
        log_outer = tk.Frame(lf, bg=self._TP_BG)
        log_outer.pack(fill="both", expand=True)
        self._log_txt = tk.Text(log_outer, bg=self._TP_BG2, fg="#bbb",
                                 font=("Consolas", 9), relief="flat",
                                 wrap="word", state="disabled")
        log_sb = ttk.Scrollbar(log_outer, orient="vertical",
                                command=self._log_txt.yview)
        self._log_txt.configure(yscrollcommand=log_sb.set)
        log_sb.pack(side="right", fill="y")
        self._log_txt.pack(fill="both", expand=True)

        self._refresh_index_stats()
        return f

    def _refresh_roots_listbox(self):
        self._roots_lb.delete(0, "end")
        with config_lock:
            out_dir = config.get("output_dir", "").strip()
        if out_dir:
            self._roots_lb.insert("end", f"[auto] {out_dir}")
        for r in self._tp_extra_roots:
            self._roots_lb.insert("end", r)

    def _tp_add_root(self):
        folder = filedialog.askdirectory(title="Select Archive Root Folder")
        if not folder:
            return
        if folder not in self._tp_extra_roots:
            self._tp_extra_roots.append(folder)
            with config_lock:
                config["tp_archive_roots"] = list(self._tp_extra_roots)
            save_config(config)
            self._refresh_roots_listbox()

    def _tp_remove_root(self):
        sel = self._roots_lb.curselection()
        if not sel:
            return
        idx = sel[0]
        with config_lock:
            out_dir = config.get("output_dir", "").strip()
        extra_offset = 1 if out_dir else 0
        extra_idx    = idx - extra_offset
        if extra_idx < 0:
            messagebox.showinfo(
                "Cannot Remove",
                "The auto-detected output folder cannot be removed here.\n"
                "Change it in the Download tab settings.")
            return
        if extra_idx < len(self._tp_extra_roots):
            self._tp_extra_roots.pop(extra_idx)
            with config_lock:
                config["tp_archive_roots"] = list(self._tp_extra_roots)
            save_config(config)
            self._refresh_roots_listbox()

    def _roots_lb_rightclick(self, event):
        """Right-click context menu on archive roots listbox."""
        # Select the item under the cursor
        idx = self._roots_lb.nearest(event.y)
        if idx < 0:
            return
        self._roots_lb.selection_clear(0, "end")
        self._roots_lb.selection_set(idx)

        # Get the folder path
        entry_text = self._roots_lb.get(idx)
        if entry_text.startswith("[auto] "):
            folder = entry_text[7:]
        else:
            folder = entry_text

        if not folder or not os.path.isdir(folder):
            return

        menu = tk.Menu(self, tearoff=0, bg=self._TP_BG2, fg=self._TP_FG,
                       activebackground=self._TP_ACCENT, activeforeground="white",
                       font=("Segoe UI", 10))
        menu.add_command(
            label="🗑  Delete All Transcriptions",
            command=lambda f=folder: self._confirm_delete_all_transcriptions(f))
        menu.tk_popup(event.x_root, event.y_root)

    def _confirm_delete_all_transcriptions(self, folder):
        """Delete all .txt and .jsonl transcript files in a directory tree."""
        # Count files in background thread to avoid blocking main thread on large trees
        def _count_files():
            txt_files = []
            jsonl_files = []
            for dirpath, _dirs, files in os.walk(folder):
                for f in files:
                    fp = os.path.join(dirpath, f)
                    fl = f.lower()
                    if (fl.endswith("transcript.txt") or fl.endswith("transcription.txt")) and not f.startswith("."):
                        txt_files.append(fp)
                    elif fl.endswith(".jsonl") and f.startswith("."):
                        jsonl_files.append(fp)
            self.after(0, lambda: self._confirm_delete_all_transcriptions_ui(folder, txt_files, jsonl_files))
        threading.Thread(target=_count_files, daemon=True).start()

    def _confirm_delete_all_transcriptions_ui(self, folder, txt_files, jsonl_files):
        """Show confirmation dialog after background counting completes."""
        total = len(txt_files) + len(jsonl_files)
        if total == 0:
            messagebox.showinfo("No Transcriptions",
                                f"No transcript files found in:\n{folder}")
            return

        msg = (f"This will permanently delete ALL transcript files in:\n\n"
               f"{folder}\n\n"
               f"  •  {len(txt_files)} transcript .txt file(s)\n"
               f"  •  {len(jsonl_files)} hidden .jsonl file(s)\n\n"
               f"Total: {total} file(s)\n\n"
               f"This cannot be undone. Are you sure?")

        if not _dark_askquestion("Delete All Transcriptions", msg):
            return

        # Second confirmation
        if not _dark_askquestion(
                "Final Confirmation",
                f"Are you absolutely sure?\n\n"
                f"All {total} transcript file(s) will be permanently deleted."):
            return

        deleted = 0
        errors = 0
        for fp in txt_files + jsonl_files:
            try:
                # Un-hide before deleting (Windows hidden files)
                if os.name == "nt":
                    try:
                        ctypes.windll.kernel32.SetFileAttributesW(fp, 0x80)  # FILE_ATTRIBUTE_NORMAL
                    except Exception:
                        pass
                os.remove(fp)
                deleted += 1
            except Exception:
                errors += 1

        # Clear transcription_complete flag for any channel whose folder
        # is inside the deleted directory, so the checkmark goes away and
        # re-transcription is possible without manual config edits.
        # Also clear one-time migration keys so they re-run on fresh data.
        folder_norm = os.path.normpath(folder).lower()
        cleared = 0
        with config_lock:
            _out_dir = config.get("output_dir", "").strip() or BASE_DIR
            for ch in config.get("channels", []):
                _ch_folder_name = sanitize_folder(ch.get("folder_override", "").strip() or ch.get("name", ""))
                if not _ch_folder_name:
                    continue
                ch_folder = os.path.join(_out_dir, _ch_folder_name)
                if os.path.normpath(ch_folder).lower().startswith(folder_norm):
                    if ch.get("transcription_complete"):
                        ch["transcription_complete"] = False
                        cleared += 1
                    ch.pop("transcription_pending", None)
            # Clear JSONL migration keys so they re-run on fresh data
            keys_to_remove = [k for k in config
                              if k.startswith(("jsonl_migrations_",
                                               "jsonl_garbled_fix_",
                                               "jsonl_hallucination_purge_",
                                               "jsonl_v154_migrated_"))]
            for k in keys_to_remove:
                del config[k]
            save_config(config)

        result = f"Deleted {deleted} file(s)."
        if cleared:
            result += f"\nCleared transcription status for {cleared} channel(s)."
        if errors:
            result += f"\n{errors} file(s) could not be deleted."
        messagebox.showinfo("Transcriptions Deleted", result)

    def _refresh_index_stats(self):
        if not self._conn:
            return
        def _query():
            try:
                segs  = self._db_execute(
                    "SELECT COUNT(*) FROM segments").fetchone()[0]
                vids  = self._db_execute(
                    "SELECT COUNT(DISTINCT video_id) FROM segments").fetchone()[0]
                chs   = self._db_execute(
                    "SELECT COUNT(DISTINCT channel) FROM segments").fetchone()[0]
                files = self._db_execute(
                    "SELECT COUNT(*) FROM indexed_files").fetchone()[0]
                yr    = self._db_execute(
                    "SELECT MIN(year), MAX(year) FROM segments "
                    "WHERE year IS NOT NULL").fetchone()
                yr_str  = f"{yr[0]} – {yr[1]}" if yr and yr[0] else "N/A"
                db_mb   = (os.path.getsize(_TP_DB_PATH) / 1_048_576
                           if os.path.exists(_TP_DB_PATH) else 0)
                text = (f"Segments  : {segs:,}\n"
                        f"Videos    : {vids:,}\n"
                        f"Channels  : {chs}\n"
                        f"JSONL files: {files}\n"
                        f"Year range: {yr_str}\n"
                        f"DB size   : {db_mb:.1f} MB\n"
                        f"DB path   : {_TP_DB_PATH}")
                def _update():
                    try:
                        self._stats_txt.config(state="normal")
                        self._stats_txt.delete("1.0", "end")
                        self._stats_txt.insert("1.0", text)
                        self._stats_txt.config(state="disabled")
                        self._refresh_stats_label()
                    except Exception:
                        pass
                self.after(0, _update)
            except Exception:
                pass
        threading.Thread(target=_query, daemon=True).start()

    def _tp_log(self, msg):
        def _do():
            self._log_txt.config(state="normal")
            self._log_txt.insert("end", msg + "\n")
            self._log_txt.see("end")
            self._log_txt.config(state="disabled")
        self.after(0, _do)

    def _start_index(self, rebuild=False):
        if self._index_running:
            messagebox.showinfo("In Progress", "Index build already running.")
            return
        roots = self._get_archive_roots()
        if not roots:
            messagebox.showwarning(
                "No Roots",
                "Set an output folder in the Download tab settings,\n"
                "or add archive root folders here.")
            return
        threading.Thread(target=self._run_index,
                         args=(roots, rebuild), daemon=True).start()

    def _confirm_rebuild(self):
        if _dark_askquestion(
                "Rebuild Index",
                "Delete the entire index and rebuild from scratch?\n"
                "This can take a while for large archives."):
            self._start_index(rebuild=True)

    def _run_index(self, roots, rebuild):
        self._index_running = True
        try:
            self.after(0, lambda: self._idx_progress_var.set("Scanning..."))
            self._tp_log("─── Index build started ───")

            if rebuild:
                try:
                    self._db_execute("DELETE FROM segments")
                    self._db_execute("DELETE FROM segments_fts")
                    self._db_execute("DELETE FROM indexed_files")
                    self._db_commit()
                    self._tp_log("Cleared existing index.")
                except Exception as e:
                    self._tp_log(f"Error clearing index: {e}")
                    return

            files = _tp_find_jsonl_files(roots)
            self._tp_log(
                f"Found {len(files)} JSONL file(s) in {len(roots)} root(s).")

            # Warn about .txt transcript files that have no .jsonl counterpart
            _orphan_dirs = set()
            for root_dir in roots:
                if not os.path.isdir(root_dir):
                    continue
                for dirpath, _, filenames in os.walk(root_dir):
                    fl_lower = [f.lower() for f in filenames]
                    has_jsonl = any(f.endswith(".jsonl") for f in fl_lower)
                    if not has_jsonl:
                        has_txt = any(
                            ("transcript" in f or "transcription" in f)
                            and f.endswith(".txt")
                            for f in fl_lower)
                        if has_txt:
                            _orphan_dirs.add(dirpath)
            if _orphan_dirs:
                self._tp_log(
                    f"\n⚠ {len(_orphan_dirs)} folder(s) have transcript .txt "
                    f"files but no .jsonl timestamp data:")
                for od in sorted(_orphan_dirs):
                    self._tp_log(f"    {od}")
                self._tp_log(
                    "  Re-transcribe these folders to generate .jsonl files "
                    "and enable full indexing.\n")

            new_files = skip_files = total_segs = 0
            _uncommitted = 0
            _COMMIT_BATCH = 10  # commit every N files to reduce disk fsync overhead
            for i, fpath in enumerate(files):
                prog = f"{i + 1}/{len(files)}"
                self.after(0, lambda p=prog: self._idx_progress_var.set(p))
                with self._db_lock:
                    if not _tp_file_needs_update(self._conn, fpath):
                        skip_files += 1
                        continue
                try:
                    with self._db_lock:
                        n = _tp_index_file(self._conn, fpath, roots)
                    _uncommitted += 1
                    total_segs += n
                    new_files  += 1
                    # Batch commits for better throughput
                    if _uncommitted >= _COMMIT_BATCH:
                        self._db_commit()
                        _uncommitted = 0
                    self._tp_log(
                        f"  [{prog}] {os.path.basename(fpath)}  ({n:,} segments)")
                except Exception as e:
                    with self._db_lock:
                        try:
                            self._conn.rollback()
                        except Exception:
                            pass
                    _uncommitted = 0
                    self._tp_log(
                        f"  [{prog}] ERROR {os.path.basename(fpath)}: {e}")
            # Flush any remaining uncommitted files
            if _uncommitted > 0:
                self._db_commit()

            self._tp_log(
                f"\nDone. {new_files} indexed, {skip_files} up-to-date. "
                f"{total_segs:,} new segments added.")
            self.after(0, lambda: self._idx_progress_var.set("Done"))
            self.after(0, self._refresh_index_stats)
            self.after(0, self._update_search_channels)
            self.after(0, self._update_freq_channels)
        finally:
            self._index_running = False

    def on_destroy(self):
        if self._conn:
            try:
                self._db_commit()
                self._conn.close()
            except Exception:
                pass


