def record_download(title, channel, date, size_bytes="", duration_s="", filepath="", video_url=""):
    def _delayed_record():
        final_size = size_bytes
        # Give ffmpeg a brief moment to finish writing the file to disk to fetch the exact final byte count
        if filepath and not os.path.exists(filepath):
            pass  # file never appeared (download failed) — skip polling
        else:
            for _ in range(6):
                if filepath and os.path.exists(filepath):
                    try:
                        disk_size = os.path.getsize(filepath)
                        if disk_size > 0:
                            final_size = str(disk_size)
                            break
                    except OSError:
                        pass
                time.sleep(0.5)

        def _sync():
            global new_download_count
            if not ('recent_tree' in globals() and recent_tree.winfo_exists()): return
            with config_lock:
                recent = config.setdefault("recent_downloads", [])
                recent.insert(0, {"title": title, "channel": channel, "date": date,
                                  "size": final_size, "duration": duration_s, "filepath": filepath,
                                  "video_url": video_url, "download_ts": time.time()})
                if len(recent) > RECENT_MAX: config["recent_downloads"] = recent[:RECENT_MAX]
            save_config(config)
            refresh_recent_list()

            # Register in browse videos table for immediate visibility
            tp = _tp_panel_ref[0]
            if tp and tp._conn:
                _yr, _mo = None, None
                try:
                    # date is "YYYYMMDD" from yt-dlp
                    if date and len(date) >= 6:
                        _yr = int(date[:4])
                        _mo = int(date[4:6])
                except (ValueError, TypeError):
                    pass
                # Extract video_id from URL if available
                _vid = None
                if video_url:
                    for _pat in ("v=", "youtu.be/", "/shorts/"):
                        _idx = video_url.find(_pat)
                        if _idx >= 0:
                            _vid = video_url[_idx + len(_pat):][:11]
                            break
                # Resolve yt-dlp channel name to config channel name so the
                # browse tree doesn't show duplicates (e.g. "David Pakman Show"
                # vs "David Pakman" when the config name differs from YT name)
                _db_channel = channel
                if filepath:
                    with config_lock:
                        _cfg_channels = config.get("channels", [])
                        _out_dir = config.get("output_dir", "").strip() or ""
                    for _ch_cfg in _cfg_channels:
                        _ch_folder = _ch_cfg.get("folder_override", "").strip() or sanitize_folder(_ch_cfg.get("name", ""))
                        if _ch_folder and os.sep + _ch_folder + os.sep in filepath.replace("/", os.sep):
                            _db_channel = _ch_cfg["name"]
                            break
                tp.register_video(title, _db_channel, year=_yr, month=_mo,
                                  filepath=filepath, video_id=_vid,
                                  video_url=video_url,
                                  duration_s=float(duration_s) if duration_s else None,
                                  size_bytes=int(final_size) if final_size else None)
                tp._refresh_browse()

            if notebook.select() != str(tab_recent):
                with _new_dl_count_lock:
                    new_download_count += 1
                    _ct = new_download_count
                notebook.tab(tab_recent, text=f"  Recent ({_ct})  ")
                if _tab_btns.get(str(tab_recent)):
                    _tab_btns[str(tab_recent)].config(text=f"  Recent ({_ct})  ")
                _update_tray_badge()

        if _root_alive: _ui_queue.append(_sync)

    threading.Thread(target=_delayed_record, daemon=True).start()


refresh_channel_dropdowns()
refresh_recent_list()


def _first_launch_dep_check():
    """Show a dependency-setup dialog on first launch, then proceed to normal startup."""
    with config_lock:
        already_done = config.get("deps_checked", False)
    if already_done:
        check_dependencies()
        return

    # ── Detect what's installed ──────────────────────────────────────
    import importlib.util as _ilu

    deps = []  # list of dicts: name, installed, auto, size, note, pip_name/action

    # --- Auto-installable pip packages ---
    _pystray_ok = _ilu.find_spec("pystray") is not None
    _pillow_ok = _ilu.find_spec("PIL") is not None
    _mpl_ok = _HAS_MPL

    deps.append({"name": "pystray", "installed": _pystray_ok, "auto": True,
                  "size": "~1 MB", "pip": "pystray",
                  "note": "System tray icon"})
    deps.append({"name": "Pillow", "installed": _pillow_ok, "auto": True,
                  "size": "~5 MB", "pip": "Pillow",
                  "note": "Image processing (tray icon)"})
    deps.append({"name": "matplotlib", "installed": _mpl_ok, "auto": True,
                  "size": "~50 MB", "pip": "matplotlib",
                  "note": "Frequency analysis charts"})

    # --- Auto-downloadable binaries ---
    def _has_ytdlp():
        if shutil.which("yt-dlp"):
            return True
        for p in [os.path.join(BASE_DIR, "yt-dlp.exe"),
                  os.path.join(RESOURCE_PATH, "yt-dlp.exe")]:
            if os.path.isfile(p):
                return True
        return False

    def _has_ffmpeg():
        try:
            subprocess.run(["ffmpeg", "-version"], stdout=subprocess.PIPE,
                           stderr=subprocess.STDOUT, startupinfo=startupinfo)
            return True
        except FileNotFoundError:
            return False

    _ytdlp_ok = _has_ytdlp()
    _ffmpeg_ok = _has_ffmpeg()

    deps.append({"name": "yt-dlp", "installed": _ytdlp_ok, "auto": True,
                  "size": "~8 MB", "binary": "yt-dlp",
                  "note": "Video downloader"})
    deps.append({"name": "ffmpeg", "installed": _ffmpeg_ok, "auto": True,
                  "size": "~80 MB", "binary": "ffmpeg",
                  "note": "Audio/video processing"})

    # --- External (info-only) ---
    if not _HAS_VLC:
        deps.append({"name": "VLC", "installed": False, "auto": False,
                      "size": "~45 MB", "url": "https://www.videolan.org/vlc/",
                      "note": "Embedded video player (optional)"})

    _py311_ok = False
    try:
        r = subprocess.run([_WHISPER_PYTHON, "--version"], stdout=subprocess.PIPE,
                           stderr=subprocess.STDOUT, encoding="utf-8",
                           startupinfo=startupinfo, timeout=10)
        if r.returncode == 0 and "3.11" in (r.stdout or ""):
            _py311_ok = True
    except Exception:
        pass

    if not _py311_ok:
        deps.append({"name": "Python 3.11", "installed": False, "auto": False,
                      "size": "~25 MB",
                      "url": "https://www.python.org/downloads/release/python-3110/",
                      "note": "Required for Whisper transcription"})

    # --- Whisper (always info-only in this dialog) ---
    deps.append({"name": "Whisper AI", "installed": False, "auto": False,
                  "size": "~4 GB", "url": None,
                  "note": "Transcription — install later from app (needs Python 3.11 + NVIDIA GPU)"})

    # If everything auto-installable is already present, skip the dialog
    missing_auto = [d for d in deps if d["auto"] and not d["installed"]]
    missing_external = [d for d in deps if not d["auto"] and not d["installed"]
                        and d["name"] != "Whisper AI"]
    if not missing_auto and not missing_external:
        with config_lock:
            config["deps_checked"] = True
            save_config(config)
        check_dependencies()
        return

    # ── Build the dialog ─────────────────────────────────────────────
    dlg = tk.Toplevel(root)
    dlg.title("Setup — Install Dependencies")
    dlg.configure(bg=C_BG)
    dlg.resizable(False, False)
    dlg.transient(root)
    dlg.grab_set()
    dlg.update_idletasks()
    _apply_dark_title_bar(dlg)

    tk.Label(dlg, text="Install Dependencies", bg=C_BG, fg=C_TEXT,
             font=("Segoe UI", 14, "bold")).pack(padx=24, pady=(16, 2), anchor="w")
    tk.Label(dlg, text="The following components are needed for full functionality:",
             bg=C_BG, fg=C_ACCENT, font=("Segoe UI", 9)).pack(padx=24, pady=(0, 10), anchor="w")

    # Scrollable area isn't needed — list is short. Just a frame.
    list_frame = tk.Frame(dlg, bg=C_BG)
    list_frame.pack(fill="x", padx=24)

    status_labels = {}  # name -> Label widget (for updating during install)

    for d in deps:
        row = tk.Frame(list_frame, bg=C_BG)
        row.pack(fill="x", pady=2)

        if d["installed"]:
            icon_text, icon_color = "\u2714", "#5cb85c"  # green check
        elif d["auto"]:
            icon_text, icon_color = "\u2716", "#d9534f"  # red X
        else:
            icon_text, icon_color = "\u2014", "#888888"  # dash for external

        icon_lbl = tk.Label(row, text=icon_text, bg=C_BG, fg=icon_color,
                            font=("Segoe UI", 11), width=2)
        icon_lbl.pack(side="left")
        status_labels[d["name"]] = icon_lbl

        name_lbl = tk.Label(row, text=d["name"], bg=C_BG, fg=C_TEXT,
                            font=("Segoe UI", 10, "bold"), width=14, anchor="w")
        name_lbl.pack(side="left")

        note_text = d["note"]
        if d["installed"]:
            note_text += "  (installed)"
        elif d["auto"]:
            note_text += f"  ({d['size']})"
        else:
            note_text += f"  ({d['size']})"

        note_lbl = tk.Label(row, text=note_text, bg=C_BG, fg=C_ACCENT,
                            font=("Segoe UI", 9), anchor="w")
        note_lbl.pack(side="left", fill="x", expand=True)

        # External link button
        if not d["auto"] and not d["installed"] and d.get("url"):
            link_btn = tk.Button(row, text="Download \u2197", bg=C_BTN, fg="#66aaff",
                                 relief="flat", font=("Segoe UI", 8), cursor="hand2",
                                 command=lambda u=d["url"]: _webbrowser.open(u))
            link_btn.pack(side="right", padx=(4, 0))

    # ── Buttons ──────────────────────────────────────────────────────
    btn_frame = tk.Frame(dlg, bg=C_BG)
    btn_frame.pack(padx=24, pady=(14, 16))

    def _do_install():
        install_btn.config(state="disabled", text="Installing...")
        skip_btn.config(state="disabled")

        def _worker():
            for d in deps:
                if d["installed"] or not d["auto"]:
                    continue
                name = d["name"]

                # Update icon to spinner/working indicator
                def _set_working(n=name):
                    try:
                        status_labels[n].config(text="\u25CB", fg="#f0ad4e")  # yellow circle
                    except Exception:
                        pass
                _ui_queue.append(_set_working)

                success = False
                try:
                    if d.get("pip"):
                        r = subprocess.run(
                            [sys.executable, "-m", "pip", "install", d["pip"]],
                            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                            encoding="utf-8", errors="replace",
                            startupinfo=startupinfo, timeout=600
                        )
                        success = (r.returncode == 0)
                    elif d.get("binary") == "yt-dlp":
                        yt_name = "yt-dlp.exe" if os.name == 'nt' else "yt-dlp"
                        dl_url = f"https://github.com/yt-dlp/yt-dlp/releases/latest/download/{yt_name}"
                        target = os.path.join(BASE_DIR, yt_name)
                        tmp = target + ".tmp"
                        urllib.request.urlretrieve(dl_url, tmp)
                        os.replace(tmp, target)
                        success = True
                    elif d.get("binary") == "ffmpeg":
                        import zipfile
                        dl_url = "https://www.gyan.dev/ffmpeg/builds/ffmpeg-release-essentials.zip"
                        zip_path = os.path.join(BASE_DIR, "_ffmpeg_download.zip")
                        try:
                            urllib.request.urlretrieve(dl_url, zip_path)
                            with zipfile.ZipFile(zip_path, 'r') as zf:
                                for zn in zf.namelist():
                                    bn = os.path.basename(zn)
                                    if bn in ("ffmpeg.exe", "ffprobe.exe"):
                                        with zf.open(zn) as src, open(os.path.join(BASE_DIR, bn), 'wb') as dst:
                                            shutil.copyfileobj(src, dst)
                            success = True
                        finally:
                            try:
                                os.remove(zip_path)
                            except Exception:
                                pass
                except Exception:
                    pass

                icon_t = "\u2714" if success else "\u2716"
                icon_c = "#5cb85c" if success else "#d9534f"
                def _set_done(n=name, t=icon_t, c=icon_c):
                    try:
                        status_labels[n].config(text=t, fg=c)
                    except Exception:
                        pass
                _ui_queue.append(_set_done)

            # All done — update button and save config
            def _finish():
                try:
                    install_btn.config(text="Done", state="normal",
                                       command=lambda: _close(True))
                    skip_btn.pack_forget()
                except Exception:
                    pass
            _ui_queue.append(_finish)

        threading.Thread(target=_worker, daemon=True).start()

    def _close(save=True):
        if save:
            with config_lock:
                config["deps_checked"] = True
                save_config(config)
        try:
            dlg.destroy()
        except Exception:
            pass
        check_dependencies()

    dlg.protocol("WM_DELETE_WINDOW", lambda: _close(True))

    if missing_auto:
        install_btn = tk.Button(btn_frame, text="Install All", bg="#3a6a3a", fg="#cccccc",
                                relief="flat", font=("Segoe UI", 10, "bold"),
                                cursor="hand2", command=_do_install, width=12)
        install_btn.pack(side="left", padx=(0, 8))
    else:
        install_btn = None

    skip_btn = tk.Button(btn_frame, text="Skip", bg=C_BTN, fg=C_TEXT,
                         relief="flat", font=("Segoe UI", 10),
                         cursor="hand2", command=lambda: _close(True), width=12)
    skip_btn.pack(side="left")

    # Center on main window
    dlg.update_idletasks()
    rx = root.winfo_rootx() + root.winfo_width() // 2
    ry = root.winfo_rooty() + root.winfo_height() // 2
    dlg.geometry(f"+{rx - dlg.winfo_reqwidth() // 2}+{ry - dlg.winfo_reqheight() // 2}")


def check_dependencies():
    global HAS_TRAY
    # Auto-install tray icon dependencies if missing
    if not HAS_TRAY:
        tray_pkgs = []
        try:
            import pystray
        except ImportError:
            tray_pkgs.append("pystray")
        try:
            from PIL import Image
        except ImportError:
            tray_pkgs.append("Pillow")
        if tray_pkgs:
            def _install_tray():
                global HAS_TRAY
                for pkg in tray_pkgs:
                    try:
                        subprocess.run(
                            [sys.executable, "-m", "pip", "install", pkg],
                            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                            encoding="utf-8", errors="replace",
                            startupinfo=startupinfo
                        )
                    except Exception:
                        pass
                try:
                    import pystray as _pt
                    from PIL import Image as _img, ImageDraw as _drw
                    globals()["pystray"] = _pt
                    globals()["Image"] = _img
                    globals()["ImageDraw"] = _drw
                    HAS_TRAY = True
                    if _root_alive:
                        _ui_queue.append(_setup_tray_icon)
                except ImportError:
                    pass
            threading.Thread(target=_install_tray, daemon=True).start()


root.after(100, _first_launch_dep_check)


def _check_channel_folders():
    """Check that each subscribed channel's directory still exists on disk.
    If a folder is missing, prompt the user to remove the channel or locate the folder.

    Note: This intentionally blocks the startup thread (up to 300s via the dialog
    timeout) because the user must resolve missing folders before sync can proceed
    safely. This is by design — not a performance bug."""
    with config_lock:
        base = config.get("output_dir", "").strip() or BASE_DIR
        channels = list(config.get("channels", []))
    if not channels:
        return

    missing = []
    for ch in channels:
        folder_name = sanitize_folder(ch.get("folder_override", "").strip() or ch["name"])
        folder_path = os.path.join(base, folder_name)
        if not os.path.isdir(folder_path):
            # Only flag channels that have been initialized (new channels won't have folders yet)
            if ch.get("initialized", False):
                missing.append((ch["name"], ch["url"], folder_path))

    if not missing:
        return

    import queue as _q
    result_q = _q.Queue()

    def _prompt_missing():
        for ch_name, ch_url, expected_path in missing:
            answer = _dark_missing_channel_dialog(ch_name, expected_path)
            if answer == "remove":
                # Remove from sub list
                with config_lock:
                    config["channels"] = [c for c in config.get("channels", []) if c["url"] != ch_url]
                save_config(config)
                log(f"  Removed \"{ch_name}\" from sub list (folder missing).\n", "dim")
            elif answer == "locate":
                # Browse for folder
                new_path = filedialog.askdirectory(
                    title=f"Locate folder for \"{ch_name}\"",
                    initialdir=base
                )
                if new_path and os.path.isdir(new_path):
                    # Validate the folder is inside the parent output directory
                    norm_new = os.path.normpath(new_path)
                    norm_base = os.path.normpath(base)
                    if os.path.dirname(norm_new) == norm_base:
                        new_folder_name = os.path.basename(norm_new)
                        with config_lock:
                            for cfg_ch in config.get("channels", []):
                                if cfg_ch["url"] == ch_url:
                                    cfg_ch["folder_override"] = new_folder_name
                                    break
                        save_config(config)
                        log(f"  Updated folder for \"{ch_name}\" → {new_folder_name}\n", "green")
                    else:
                        messagebox.showwarning(
                            "Invalid Location",
                            f"The selected folder must be inside your output directory:\n{base}"
                        )
            # else: "skip" — do nothing
        result_q.put(True)
        if root.winfo_exists():
            root.after(0, refresh_channel_dropdowns)

    if _root_alive:
        _ui_queue.append(_prompt_missing)
        # Wait for the dialogs to complete before continuing startup
        try:
            result_q.get(timeout=300)
        except _q.Empty:
            pass


def _check_app_update():
    """Check GitHub releases for a newer version of YTArchiver and log a notice if found."""
    try:
        import urllib.request as _ur
        req = _ur.Request(
            "https://api.github.com/repos/skurbee/YTArchiver/releases/latest",
            headers={"User-Agent": "YTArchiver"}
        )
        with _ur.urlopen(req, timeout=8) as resp:
            data = json.loads(resp.read())
        latest_tag = data.get("tag_name", "").strip()       # e.g. "v23.8"
        release_url = data.get("html_url", "https://github.com/skurbee/YTArchiver/releases/latest")
        if not latest_tag:
            return

        def _ver_tuple(s):
            try:
                return tuple(int(x) for x in s.lstrip("v").split("."))
            except ValueError:
                return (0,)

        if _ver_tuple(latest_tag) > _ver_tuple(APP_VERSION):
            sep = "=" * 54
            log(f"\n{sep}\n", "update_sep")
            log(f"  \u2b06  Update available: {latest_tag}  (you have {APP_VERSION})\n", "update_head")
            log(f"  Download: {release_url}\n", "update_head")
            log(f"{sep}\n\n", "update_sep")
    except Exception:
        pass  # No network, rate-limited, etc. — silently skip


def run_startup_updates():
    def _download_yt_dlp_binary(target_path):
        """Download the latest yt-dlp binary from GitHub to target_path."""
        yt_name = "yt-dlp.exe" if os.name == 'nt' else "yt-dlp"
        dl_url = f"https://github.com/yt-dlp/yt-dlp/releases/latest/download/{yt_name}"
        import urllib.request
        tmp_path = target_path + ".tmp"
        try:
            urllib.request.urlretrieve(dl_url, tmp_path)
            os.replace(tmp_path, target_path)
        except Exception:
            try:
                os.remove(tmp_path)
            except OSError:
                pass
            raise

    def _get_yt_dlp_version():
        """Get the current yt-dlp version string."""
        try:
            r = subprocess.run(
                ["yt-dlp", "--version"],
                stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                encoding="utf-8", errors="replace",
                startupinfo=startupinfo
            )
            return r.stdout.strip() if r.stdout else "unknown"
        except Exception:
            return "unknown"

    def _download_ffmpeg(target_dir):
        """Download ffmpeg essentials from gyan.dev and extract binaries."""
        import urllib.request, zipfile
        dl_url = "https://www.gyan.dev/ffmpeg/builds/ffmpeg-release-essentials.zip"
        zip_path = os.path.join(target_dir, "_ffmpeg_download.zip")
        try:
            log("  Downloading ffmpeg (~80 MB), this may take a minute...\n", "dim")
            urllib.request.urlretrieve(dl_url, zip_path)
            with zipfile.ZipFile(zip_path, 'r') as zf:
                for name in zf.namelist():
                    basename = os.path.basename(name)
                    if basename in ("ffmpeg.exe", "ffprobe.exe"):
                        with zf.open(name) as src, open(os.path.join(target_dir, basename), 'wb') as dst:
                            shutil.copyfileobj(src, dst)
        finally:
            try:
                os.remove(zip_path)
            except Exception:
                pass

    def _update():
        # Restore preserved queue immediately so the user sees recovered jobs right away,
        # rather than waiting for all the startup checks (yt-dlp update, disk scan, etc.)
        _load_queue_state()

        log("--- Checking for yt-dlp updates... ---\n", "header")
        try:
            current_ver = _get_yt_dlp_version()
            log(f"Current version: {current_ver}\n", "dim")

            # Try yt-dlp -U for self-update and parse latest version
            proc = subprocess.Popen(
                ["yt-dlp", "-U"],
                stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                encoding="utf-8", errors="replace",
                startupinfo=startupinfo
            )
            update_output = []
            latest_ver = None
            for line in proc.stdout:
                line = line.rstrip("\n") + "\n"
                update_output.append(line)
                # Parse latest version from lines like "Latest version: stable@2026.03.03 from ..."
                m = re.search(r'(?:Latest|Newest)\s+version:\s*\S*@?(\d{4}\.\d{2}\.\d{2})', line, re.IGNORECASE)
                if m:
                    latest_ver = m.group(1)
                ll = line.lower()
                if "installed yt-dlp with pip" in ll or "use that to update" in ll:
                    continue
                if any(x in line for x in ["ERROR:", "Error:"]):
                    log(line, "red")
                elif any(x in line for x in ["up to date", "Updated", "yt-dlp"]):
                    log(line, "green")
                else:
                    log(line, "dim")
            try:
                proc.wait(timeout=45)
            except subprocess.TimeoutExpired:
                proc.kill()
                log("  ⚠ yt-dlp update check timed out (45s). Skipping update.\n", "red")

            full_output = "".join(update_output).lower()

            # If already up to date, skip everything
            if "up to date" in full_output:
                pass
            elif proc.returncode != 0 or "error" in full_output or "can't update" in full_output:
                # yt-dlp -U failed — try alternative update methods
                if "pip" in full_output or "pypi" in full_output:
                    log("  Updating yt-dlp via pip...\n", "dim")
                    try:
                        pip_proc = subprocess.run(
                            [sys.executable, "-m", "pip", "install", "-U", "yt-dlp"],
                            stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                            encoding="utf-8", errors="replace",
                            startupinfo=startupinfo
                        )
                        if pip_proc.returncode == 0:
                            log("  ✓ yt-dlp updated via pip.\n", "green")
                        else:
                            log(f"  ⚠ pip update failed (exit {pip_proc.returncode}).\n", "red")
                    except Exception as e:
                        log(f"  ⚠ Could not update via pip: {e}\n", "red")
                elif getattr(sys, 'frozen', False):
                    log("  Bundled yt-dlp can't self-update, downloading latest...\n", "dim")
                    try:
                        yt_name = "yt-dlp.exe" if os.name == 'nt' else "yt-dlp"
                        target = os.path.join(BASE_DIR, yt_name)
                        _download_yt_dlp_binary(target)
                        log(f"  ✓ Updated yt-dlp binary in {BASE_DIR}\n", "green")
                    except Exception as e:
                        log(f"  ⚠ Could not download yt-dlp update: {e}\n", "red")

            # Verify update actually took effect
            if latest_ver and current_ver != "unknown":
                new_ver = _get_yt_dlp_version()
                if new_ver == current_ver and new_ver != latest_ver:
                    # Update didn't take effect — a stale binary is shadowing the pip install
                    yt_name = "yt-dlp.exe" if os.name == 'nt' else "yt-dlp"
                    stale_path = shutil.which("yt-dlp")
                    # Also check common local locations
                    local_bin = os.path.join(BASE_DIR, yt_name)
                    resource_bin = os.path.join(RESOURCE_PATH, yt_name) if RESOURCE_PATH != BASE_DIR else None
                    target = stale_path or local_bin
                    log(f"  ⚠ Version still {new_ver} after update — stale binary detected.\n", "dim")
                    log(f"  Downloading latest yt-dlp to {target}...\n", "dim")
                    try:
                        _download_yt_dlp_binary(target)
                        # Also update resource path copy if separate
                        if resource_bin and os.path.exists(resource_bin) and resource_bin != target:
                            _download_yt_dlp_binary(resource_bin)
                        final_ver = _get_yt_dlp_version()
                        if final_ver != current_ver:
                            log(f"  ✓ yt-dlp updated: {current_ver} → {final_ver}\n", "green")
                        else:
                            log(f"  ⚠ Could not update yt-dlp. Try manually replacing yt-dlp.exe.\n", "red")
                    except Exception as e:
                        log(f"  ⚠ Could not download yt-dlp binary: {e}\n", "red")

        except FileNotFoundError:
            log("yt-dlp not found — downloading automatically...\n", "header")
            try:
                yt_name = "yt-dlp.exe" if os.name == 'nt' else "yt-dlp"
                target = os.path.join(BASE_DIR, yt_name)
                _download_yt_dlp_binary(target)
                ver = _get_yt_dlp_version()
                log(f"  ✓ yt-dlp {ver} installed to {BASE_DIR}\n", "green")
            except Exception as e:
                log(f"  ⚠ Could not download yt-dlp: {e}\n", "red")
                log("  Download manually: https://github.com/yt-dlp/yt-dlp/releases\n", "dim")

        log("--- Checking ffmpeg is installed... ---\n", "header")
        try:
            result = subprocess.run(
                ["ffmpeg", "-version"],
                stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                encoding="utf-8", errors="replace",
                startupinfo=startupinfo
            )
            first_line = result.stdout.splitlines()[0] if result.stdout else "unknown"
            log(f"ffmpeg: {first_line}\n", "green")
        except FileNotFoundError:
            log("ffmpeg not found — downloading automatically...\n", "header")
            try:
                _download_ffmpeg(BASE_DIR)
                result = subprocess.run(
                    ["ffmpeg", "-version"],
                    stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                    encoding="utf-8", errors="replace",
                    startupinfo=startupinfo
                )
                first_line = result.stdout.splitlines()[0] if result.stdout else "unknown"
                log(f"  ✓ ffmpeg installed: {first_line}\n", "green")
            except Exception as e:
                log(f"  ⚠ Could not download ffmpeg: {e}\n", "red")
                log("  Download manually: https://www.gyan.dev/ffmpeg/builds/\n", "dim")

        # Check for a newer YTArchiver release on GitHub
        _check_app_update()

        # Check that each subscribed channel's folder still exists
        _check_channel_folders()

        # Clean up any leftover partial/temp files from interrupted downloads.
        # Runs in a background thread so it doesn't block the Loading... screen —
        # the cleanup log message will appear shortly after startup completes.
        threading.Thread(target=_startup_cleanup_temps, daemon=True).start()

        log("--- Startup checks complete, ready to download ---\n", "simpleline_green")
        _stop_startup_loading()

        # Enable sync button now that startup is complete
        if _root_alive:
            def _enable_sync_btns():
                sync_btn.config(state="normal")
                _gpb_mode["ready"] = True
                _update_global_pause_btn_sync()
            _ui_queue.append(_enable_sync_btns)

        # Auto-resume any redownload jobs that were restored from the previous session
        with _redownload_queue_lock:
            _rd_pending = bool(_redownload_queue)
        if _rd_pending and _root_alive and not _sync_pipeline_busy():
            _ui_queue.append(_process_redownload_queue)

        # Scan disk info for any channels not yet in the cache.  This runs
        # after startup checks are done so the UI is already visible and
        # usable while the scan proceeds in this background thread.
        _run_startup_disk_scan()

    threading.Thread(target=_update, daemon=True).start()


root.after(200, run_startup_updates)
root.after(50, _start_startup_loading)


_save_queue_state_pending = {"job": None}


def _save_queue_state():
    """Debounced save — batches rapid queue changes into one write every 2 seconds."""
    if _save_queue_state_pending["job"] is not None:
        return  # already scheduled
    try:
        _save_queue_state_pending["job"] = root.after(2000, _save_queue_state_now)
    except Exception:
        _save_queue_state_now()  # fallback: save immediately if root is gone


def _save_queue_state_now():
    """Actually save current queue state to disk."""
    _save_queue_state_pending["job"] = None
    queue_data = {"sync": [], "reorg": [], "video": [], "transcribe": [], "redownload": [], "metadata": [], "order": [], "gpu": []}
    # Include the currently-running sync channel so it survives crashes
    # Snapshot under lock to prevent RuntimeError from concurrent dict mutation
    with _sync_queue_lock:
        _snap_sync = copy.deepcopy(_current_sync_ch) if _current_sync_ch is not None else None
    if _snap_sync is not None and _sync_running:
        with _sync_queue_lock:
            if not any(q["url"] == _snap_sync["url"] for q in _sync_queue):
                queue_data["sync"].append(_snap_sync)
    with _sync_queue_lock:
        for ch in _sync_queue:
            queue_data["sync"].append(copy.deepcopy(ch))
    with _reorg_queue_lock:
        for args in _reorg_queue:
            queue_data["reorg"].append(list(args))
    with _transcribe_queue_lock:
        for args in _transcribe_queue:
            queue_data["transcribe"].append(list(args))
    # Include the currently-running redownload so it survives crashes/restarts
    with _redownload_queue_lock:
        _snap_rd = copy.deepcopy(_current_redownload_item) if _current_redownload_item is not None else None
    if _snap_rd is not None and _redownload_running:
        with _redownload_queue_lock:
            if not any(q["ch_url"] == _snap_rd["ch_url"] for q in _redownload_queue):
                queue_data["redownload"].insert(0, _snap_rd)
    with _redownload_queue_lock:
        for item in _redownload_queue:
            queue_data["redownload"].append(copy.deepcopy(item))
    with _metadata_queue_lock:
        for item in _metadata_queue:
            queue_data["metadata"].append(copy.deepcopy(item))
    with _video_dl_queue_lock:
        # Video download commands contain subprocess args — skip them (not easily restorable)
        pass
    # Include the currently-running GPU item so it survives crashes
    with _gpu_queue_lock:
        if _gpu_current_item is not None:
            queue_data["gpu"].append(copy.deepcopy(_gpu_current_item))
    with _gpu_queue_lock:
        for item in _gpu_queue:
            queue_data["gpu"].append(copy.deepcopy(item))
    queue_data["gpu_paused"] = _gpu_pause.is_set()
    with _queue_order_lock:
        saved_order = list(_queue_order)
    # Prepend the currently-running item's order entry (it was removed from
    # _queue_order when it started running, so it would otherwise become an
    # orphan on load and appear AFTER queued items instead of before them)
    # Snapshot volatile references to avoid race with worker threads
    _snap_sync_ch = _current_sync_ch
    _snap_redownload = _current_redownload_item
    if _snap_sync_ch is not None and _sync_running:
        try:
            saved_order.insert(0, ("sync", _snap_sync_ch["url"]))
        except (KeyError, TypeError):
            pass
    if _snap_redownload is not None and _redownload_running:
        try:
            saved_order.insert(0, ("redownload", _snap_redownload["ch_url"]))
        except (KeyError, TypeError):
            pass
    queue_data["order"] = saved_order
    try:
        _tmp = QUEUE_FILE + ".tmp"
        with open(_tmp, "w", encoding="utf-8") as f:
            json.dump(queue_data, f, indent=2)
        os.replace(_tmp, QUEUE_FILE)
    except Exception:
        pass


def _load_queue_state():
    """Load preserved queue state from disk and populate queues."""
    try:
        if not os.path.exists(QUEUE_FILE):
            return False
        with open(QUEUE_FILE, "r", encoding="utf-8") as f:
            raw = f.read()
        # Rename to .bak before parsing — if JSON is corrupt, the backup survives
        # for manual recovery instead of being permanently lost.
        _bak = QUEUE_FILE + ".bak"
        try:
            os.replace(QUEUE_FILE, _bak)
        except Exception:
            try:
                os.remove(QUEUE_FILE)
            except Exception:
                pass
        try:
            queue_data = json.loads(raw)
        except (json.JSONDecodeError, ValueError):
            # Corrupt queue file — log and bail so it doesn't block every launch
            log("  ⚠ Queue state file was corrupt — discarded. Backup saved as .bak\n", "red")
            return False
        # Parse succeeded — remove the backup
        try:
            os.remove(_bak)
        except Exception:
            pass

        restored = 0
        sync_items = queue_data.get("sync", [])
        if sync_items:
            with _sync_queue_lock:
                for ch in sync_items:
                    if not any(q["url"] == ch["url"] for q in _sync_queue):
                        _sync_queue.append(ch)
                        restored += 1
        reorg_items = queue_data.get("reorg", [])
        if reorg_items:
            with _reorg_queue_lock:
                for args in reorg_items:
                    _reorg_queue.append(tuple(args))
                    restored += 1
        transcribe_items = queue_data.get("transcribe", [])
        if transcribe_items:
            with _transcribe_queue_lock:
                for args in transcribe_items:
                    _transcribe_queue.append(tuple(args))
                    restored += 1
        redownload_items = queue_data.get("redownload", [])
        if redownload_items:
            with _redownload_queue_lock:
                for item in redownload_items:
                    if not any(q["ch_url"] == item["ch_url"] for q in _redownload_queue):
                        _redownload_queue.append(item)
                        restored += 1
        metadata_items = queue_data.get("metadata", [])
        if metadata_items:
            with _metadata_queue_lock:
                for item in metadata_items:
                    if not any(q["_key"] == item["_key"] for q in _metadata_queue):
                        _metadata_queue.append(item)
                        restored += 1
        gpu_items = queue_data.get("gpu", [])
        gpu_restored = 0
        if gpu_items:
            with _gpu_queue_lock:
                _existing_keys = {(g.get("type"), g.get("ch_url"), g.get("batch_num")) for g in _gpu_queue}
                for item in gpu_items:
                    _key = (item.get("type"), item.get("ch_url"), item.get("batch_num"))
                    if _key not in _existing_keys:
                        _gpu_queue.append(item)
                        _existing_keys.add(_key)
                        restored += 1
                        gpu_restored += 1
        # Restore GPU pause state
        if queue_data.get("gpu_paused", False) and gpu_restored > 0:
            _gpu_pause.set()
        # Restore unified queue ordering
        saved_order = queue_data.get("order", [])
        if saved_order:
            with _queue_order_lock:
                for entry in saved_order:
                    if isinstance(entry, (list, tuple)) and len(entry) == 2:
                        _queue_order.append(tuple(entry))
        if restored:
            if gpu_restored:
                _pause_str = " (paused)" if _gpu_pause.is_set() else ""
                log(f"  💻 {gpu_restored} GPU task(s) restored{_pause_str}.\n", "simpleline_green")
                # Refresh channel list so restored GPU tasks show "Queued" in the Transcribed column
                if _root_alive:
                    _ui_queue.append(refresh_channel_dropdowns)
            if _root_alive:
                _ui_queue.append(_update_queue_btn)
                _ui_queue.append(_update_gpu_btn)
            return True
    except Exception:
        pass
    return False


def on_closing():
    global _root_alive, _INSTANCE_MUTEX
    # Cancel any pending debounced queue save, then save immediately.
    # Prevents the debounce timer from firing during the shutdown sequence.
    if _save_queue_state_pending["job"] is not None:
        try:
            root.after_cancel(_save_queue_state_pending["job"])
        except Exception:
            pass
        _save_queue_state_pending["job"] = None
    # Save queue state BEFORE releasing mutex — prevents a new instance from
    # reading a stale/missing queue file during our cleanup window.
    try:
        _save_queue_state_now()
    except Exception:
        pass
    # Release the single-instance mutex so a new launch isn't blocked
    # during the ~1 s cleanup sleep below.
    if _INSTANCE_MUTEX is not None:
        try:
            ctypes.windll.kernel32.CloseHandle(_INSTANCE_MUTEX)
        except Exception:
            pass
        _INSTANCE_MUTEX = None
    # Save window position, size, and column widths before closing
    with config_lock:
        try:
            geo = root.geometry()  # e.g. "900x800+100+200" or "900x800+-500+200"
            _m = re.match(r'(\d+)x(\d+)([+-]\d+)([+-]\d+)', geo)
            if _m:
                config["window_w"] = int(_m.group(1))
                config["window_h"] = int(_m.group(2))
                config["window_x"] = int(_m.group(3))
                config["window_y"] = int(_m.group(4))
        except Exception:
            pass

        # Collect column widths for both treeviews
        try:
            _chan_widths = {}
            for _col in ("folder", "res", "min", "max", "compress", "transcribed", "metadata", "last_sync", "num_vids", "size_on_disk"):
                try:
                    _chan_widths[_col] = settings_chan_tree.column(_col, "width")
                except Exception:
                    pass
            config["chan_col_widths"] = _chan_widths
            _recent_widths = {}
            for _col in ("title", "channel", "time", "duration", "size"):
                try:
                    _recent_widths[_col] = recent_tree.column(_col, "width")
                except Exception:
                    pass
            config["recent_col_widths"] = _recent_widths
        except Exception:
            pass

        # Single synchronous save to ensure both window geometry and column widths are persisted
        try:
            _cfg_snap = copy.deepcopy(config)
            temp_file = CONFIG_FILE + ".tmp"
            with open(temp_file, "w", encoding="utf-8") as f:
                json.dump(_cfg_snap, f, indent=2)
            os.replace(temp_file, CONFIG_FILE)
        except Exception:
            pass

    _root_alive = False  # Tell worker threads to stop touching Tkinter immediately

    # Stop embedded VLC player if active
    try:
        if hasattr(_tp_panel, '_player_stop_vlc'):
            _tp_panel._player_stop_vlc()
    except Exception:
        pass

    # Close Browse tab database connection (on_destroy handles commit + close)
    try:
        _tp_panel.on_destroy()
    except Exception:
        pass

    # Clear TuneShine sync progress so it doesn't show stale data
    _clear_sync_progress()

    # Stop the system tray icon
    global _tray_spin_active
    with _tray_spin_lock:
        _tray_spin_active = False
    _tray_spin_stop_ev.set()  # signal spin thread to exit
    if _tray_icon is not None:
        try:
            _tray_icon.stop()
        except Exception:
            pass

    # Stop Whisper/punctuation/ffmpeg subprocesses if running
    _stop_whisper_process()
    _stop_punct_process()
    _stop_ffmpeg_process()

    # Clear pause so worker threads can exit cleanly
    pause_event.clear()
    cancel_event.set()

    with proc_lock:
        procs = [p for p in active_processes if p is not None]
    for p in procs:
        try:
            if p.poll() is None:
                if os.name == 'nt':
                    subprocess.Popen(['taskkill', '/F', '/T', '/PID', str(p.pid)],
                                     stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                                     startupinfo=startupinfo)
                else:
                    p.kill()
        except Exception:
            pass

    # Destroy popup windows and stop recurring timers immediately so their after()
    # callbacks stop firing (prevents "ButtonProc called on an invalid HWND" during shutdown)
    for _popup_dict in [_queue_popup, _gpu_popup]:
        try:
            _pw = _popup_dict.get("win")
            if _pw and _pw.winfo_exists():
                _pw.destroy()
            _popup_dict["win"] = None
            _popup_dict["visible"] = False
        except Exception:
            pass
    # Stop blink timer
    _sync_blink["active"] = False
    _gpu_blink["active"] = False
    if _blink_clock.get("job"):
        try:
            root.after_cancel(_blink_clock["job"])
        except Exception:
            pass
        _blink_clock["job"] = None

    # Give worker threads a moment to notice cancel_event and save state
    # (they're daemon threads — root.destroy() will kill them)
    root.after(1000, root.destroy)


root.protocol("WM_DELETE_WINDOW", on_closing)


def _defocus_on_click(e):
    widget = e.widget

    if isinstance(widget, str):
        return
    # Don't steal focus from popup/toplevel windows (e.g., job queue)
    try:
        if widget.winfo_toplevel() != root:
            return
    except Exception:
        pass
    _skip_classes = {
        "Entry", "TEntry", "Text", "TCombobox",
        "Listbox", "Treeview",
        "Button", "TButton", "TCheckbutton",
    }
    if widget.winfo_class() not in _skip_classes:
        root.focus_set()


root.bind_all("<Button-1>", _defocus_on_click, add="+")

root.mainloop()